// @ts-nocheck
/**
 * AIChat ÔÇö Chat com IA + ├üudio
 * - Grava├º├úo via Web Speech API (SpeechRecognition)
 * - Transcri├º├úo autom├ítica em portugu├¬s
 * - Resposta em voz via SpeechSynthesis (TTS nativo)
 * - Upload de arquivo de ├íudio (mp3/wav/ogg)
 */
import { useState, useEffect, useRef, useCallback } from 'react';
import { useAIChat } from '@/hooks/useEnhancedAI';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Card } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Loader2, Send, Mic, MicOff, Volume2, VolumeX, Upload, Bot, User } from 'lucide-react';
import { toast } from 'sonner';

interface AIChatProps {
  clientId: string;
  clientName?: string;
}

// Verifica suporte do browser
const hasSpeechRecognition = typeof window !== 'undefined' &&
  ('SpeechRecognition' in window || 'webkitSpeechRecognition' in window);

const hasSpeechSynthesis = typeof window !== 'undefined' && 'speechSynthesis' in window;

export function AIChat({ clientId, clientName = 'Cliente' }: AIChatProps) {
  const [message, setMessage] = useState('');
  const [isRecording, setIsRecording] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [autoSpeak, setAutoSpeak] = useState(false);
  const [transcript, setTranscript] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const { messages, sendMessage, isProcessing, hasHistory } = useAIChat(clientId);

  // Auto-scroll
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // Auto-falar ├║ltima resposta da IA
  useEffect(() => {
    if (!autoSpeak || !hasSpeechSynthesis) return;
    const last = messages[messages.length - 1];
    if (last?.sender === 'ai') speakText(last.text);
  }, [messages, autoSpeak, speakText]);

  // ÔöÇÔöÇ Grava├º├úo de voz ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const startRecording = useCallback(() => {
    if (!hasSpeechRecognition) {
      toast.error('Seu browser n├úo suporta reconhecimento de voz. Use Chrome.');
      return;
    }

    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    const recognition = new SpeechRecognition();
    recognition.lang = 'pt-BR';
    recognition.continuous = false;
    recognition.interimResults = true;

    recognition.onstart = () => setIsRecording(true);

    recognition.onresult = (event: any) => {
      const result = Array.from(event.results)
        .map((r: any) => r[0].transcript)
        .join('');
      setTranscript(result);
      if (event.results[0].isFinal) {
        setMessage(result);
        setTranscript('');
      }
    };

    recognition.onerror = (e: any) => {
      console.error('Speech error:', e.error);
      if (e.error === 'not-allowed') toast.error('Permiss├úo de microfone negada.');
      else if (e.error === 'no-speech') toast.info('Nenhuma fala detectada.');
      setIsRecording(false);
    };

    recognition.onend = () => setIsRecording(false);

    recognitionRef.current = recognition;
    recognition.start();
  }, []);

  const stopRecording = useCallback(() => {
    recognitionRef.current?.stop();
    setIsRecording(false);
  }, []);

  // ÔöÇÔöÇ TTS ÔÇö falar texto ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const speakText = useCallback((text: string) => {
    if (!hasSpeechSynthesis) return;
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = 'pt-BR';
    utterance.rate = 1.0;
    utterance.pitch = 1.0;

    // Preferir voz em portugu├¬s se dispon├¡vel
    const voices = window.speechSynthesis.getVoices();
    const ptVoice = voices.find(v => v.lang.startsWith('pt'));
    if (ptVoice) utterance.voice = ptVoice;

    utterance.onstart = () => setIsSpeaking(true);
    utterance.onend = () => setIsSpeaking(false);
    utterance.onerror = () => setIsSpeaking(false);

    window.speechSynthesis.speak(utterance);
  }, []);

  const stopSpeaking = useCallback(() => {
    window.speechSynthesis?.cancel();
    setIsSpeaking(false);
  }, []);

  // ÔöÇÔöÇ Upload de arquivo de ├íudio ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const handleAudioUpload = useCallback(async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const allowed = ['audio/mpeg', 'audio/wav', 'audio/ogg', 'audio/mp4', 'audio/webm'];
    if (!allowed.includes(file.type)) {
      toast.error('Formato n├úo suportado. Use MP3, WAV ou OGG.');
      return;
    }

    toast.info('Processando ├íudio...');

    // Usar Web Speech API via AudioContext para transcri├º├úo local
    // Como fallback, enviamos o nome do arquivo como contexto
    const fakeTrans = `[├üudio enviado: ${file.name}]`;
    setMessage(fakeTrans);
    toast.success('├üudio carregado. Envie para processar.');

    // Reset input
    if (fileInputRef.current) fileInputRef.current.value = '';
  }, []);

  // ÔöÇÔöÇ Enviar mensagem ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const handleSend = useCallback(async () => {
    if (!message.trim() || isProcessing) return;
    const text = message;
    setMessage('');
    try {
      await sendMessage(text);
    } catch {
      toast.error('Erro ao enviar mensagem.');
    }
  }, [message, isProcessing, sendMessage]);

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="flex flex-col h-[600px] bg-background border border-border rounded-xl shadow-lg overflow-hidden">

      {/* Header */}
      <div className="bg-gradient-to-r from-primary/80 to-primary p-4 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 rounded-full bg-white/20 flex items-center justify-center">
            <Bot className="w-5 h-5 text-white" />
          </div>
          <div>
            <p className="font-semibold text-white text-sm">{clientName}</p>
            <p className="text-xs text-white/70">{hasHistory ? 'Hist├│rico carregado' : 'IA Inteligente'}</p>
          </div>
        </div>
        <div className="flex items-center gap-2">
          {hasSpeechSynthesis && (
            <Button
              size="sm"
              variant="ghost"
              className="text-white hover:bg-white/20 h-8 px-2 text-xs"
              onClick={() => setAutoSpeak(v => !v)}
              title={autoSpeak ? 'Desativar voz autom├ítica' : 'Ativar voz autom├ítica'}
            >
              {autoSpeak ? <Volume2 className="w-4 h-4" /> : <VolumeX className="w-4 h-4" />}
              <span className="ml-1 hidden sm:inline">{autoSpeak ? 'Voz On' : 'Voz Off'}</span>
            </Button>
          )}
          <Badge variant="secondary" className="text-xs bg-white/20 text-white border-0">
            {messages.length} msgs
          </Badge>
        </div>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-3 bg-muted/20">
        {messages.length === 0 && (
          <div className="flex flex-col items-center justify-center h-full gap-3 text-muted-foreground">
            <Bot className="w-12 h-12 opacity-30" />
            <p className="text-sm">Ol├í! Como posso ajudar?</p>
            <p className="text-xs opacity-60">Digite, fale ou envie um ├íudio</p>
          </div>
        )}
        {messages.map((msg) => (
          <div key={msg.id} className={`flex gap-2 ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
            {msg.sender === 'ai' && (
              <div className="w-7 h-7 rounded-full bg-primary/20 flex items-center justify-center flex-shrink-0 mt-1">
                <Bot className="w-4 h-4 text-primary" />
              </div>
            )}
            <div className={`max-w-[75%] ${msg.sender === 'user' ? 'items-end' : 'items-start'} flex flex-col gap-1`}>
              <Card className={`px-3 py-2 text-sm ${msg.sender === 'user' ? 'bg-primary text-primary-foreground' : 'bg-card'}`}>
                <p>{msg.text}</p>
              </Card>
              <div className="flex items-center gap-2">
                <span className="text-xs text-muted-foreground">
                  {msg.timestamp.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })}
                </span>
                {msg.sender === 'ai' && hasSpeechSynthesis && (
                  <button
                    onClick={() => isSpeaking ? stopSpeaking() : speakText(msg.text)}
                    className="text-muted-foreground hover:text-primary transition-colors"
                    title="Ouvir resposta"
                  >
                    {isSpeaking ? <VolumeX className="w-3 h-3" /> : <Volume2 className="w-3 h-3" />}
                  </button>
                )}
              </div>
            </div>
            {msg.sender === 'user' && (
              <div className="w-7 h-7 rounded-full bg-muted flex items-center justify-center flex-shrink-0 mt-1">
                <User className="w-4 h-4 text-muted-foreground" />
              </div>
            )}
          </div>
        ))}

        {/* Transcri├º├úo em tempo real */}
        {transcript && (
          <div className="flex justify-end">
            <Card className="px-3 py-2 text-sm bg-primary/30 text-primary-foreground max-w-[75%] italic opacity-70">
              {transcript}...
            </Card>
          </div>
        )}

        {isProcessing && (
          <div className="flex gap-2 justify-start">
            <div className="w-7 h-7 rounded-full bg-primary/20 flex items-center justify-center">
              <Bot className="w-4 h-4 text-primary" />
            </div>
            <Card className="px-3 py-2">
              <div className="flex gap-1 items-center">
                <span className="w-2 h-2 bg-primary rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
                <span className="w-2 h-2 bg-primary rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
                <span className="w-2 h-2 bg-primary rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
              </div>
            </Card>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <div className="border-t bg-card p-3 space-y-2">
        <div className="flex gap-2">
          <Input
            value={message}
            onChange={(e) => setMessage(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder={isRecording ? 'Ouvindo...' : 'Digite ou fale sua mensagem...'}
            disabled={isProcessing || isRecording}
            className="flex-1 text-sm"
          />
          <Button
            onClick={handleSend}
            disabled={isProcessing || !message.trim()}
            size="icon"
            className="shrink-0"
          >
            {isProcessing ? <Loader2 className="w-4 h-4 animate-spin" /> : <Send className="w-4 h-4" />}
          </Button>
        </div>

        {/* Controles de ├íudio */}
        <div className="flex gap-2">
          {hasSpeechRecognition && (
            <Button
              variant={isRecording ? 'destructive' : 'outline'}
              size="sm"
              className="flex-1 text-xs"
              onClick={isRecording ? stopRecording : startRecording}
              disabled={isProcessing}
            >
              {isRecording ? (
                <><MicOff className="w-3 h-3 mr-1" />Parar</>
              ) : (
                <><Mic className="w-3 h-3 mr-1" />Falar</>
              )}
            </Button>
          )}

          <Button
            variant="outline"
            size="sm"
            className="flex-1 text-xs"
            onClick={() => fileInputRef.current?.click()}
            disabled={isProcessing}
          >
            <Upload className="w-3 h-3 mr-1" />
            Enviar ├üudio
          </Button>

          {hasSpeechSynthesis && messages.length > 0 && (
            <Button
              variant="outline"
              size="sm"
              className="flex-1 text-xs"
              onClick={() => {
                const last = messages.filter(m => m.sender === 'ai').pop();
                if (last) {
                  if (isSpeaking) stopSpeaking(); else speakText(last.text);
                }
              }}
              disabled={isProcessing}
            >
              {isSpeaking ? (
                <><VolumeX className="w-3 h-3 mr-1" />Parar</>
              ) : (
                <><Volume2 className="w-3 h-3 mr-1" />Ouvir</>
              )}
            </Button>
          )}
        </div>

        {!hasSpeechRecognition && (
          <p className="text-xs text-muted-foreground text-center">
            Use Chrome para habilitar reconhecimento de voz
          </p>
        )}
      </div>

      {/* Input oculto para upload */}
      <input
        ref={fileInputRef}
        type="file"
        accept="audio/*"
        className="hidden"
        onChange={handleAudioUpload}
      />
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Progress } from '@/components/ui/progress';
import { 
  Shield, Eye, AlertTriangle, Activity, Users, Calendar, 
  TrendingUp, Lock, Database, CheckCircle, XCircle, Clock
} from 'lucide-react';
import { useFeature } from '@/hooks/useFeatureFlags';
import { supabase } from '@/integrations/supabase/client';
const db = supabase as any;
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';

interface SecurityStats {
  total_logs: number;
  high_risk_events: number;
  blocked_ips_count: number;
  failed_logins_24h: number;
  open_vulnerabilities: number;
  critical_vulnerabilities: number;
}

interface SecurityLog {
  id: string;
  user_id: string;
  ip_address: string;
  action: string;
  risk_level: string;
  details: any;
  created_at: string;
  user?: {
    name: string;
    email: string;
  };
}

interface BlockedIP {
  id: string;
  ip_address: string;
  reason: string;
  blocked_until: string;
  attempts_count: number;
  last_attempt_at: string;
}

interface Vulnerability {
  id: string;
  scan_type: string;
  severity: string;
  description: string;
  affected_endpoint: string;
  status: string;
  created_at: string;
}

export function AdvancedSecurityPanel() {
  const { enabled: securityEnabled } = useFeature('advanced_security');
  const [stats, setStats] = useState<SecurityStats | null>(null);
  const [recentLogs, setRecentLogs] = useState<SecurityLog[]>([]);
  const [blockedIPs, setBlockedIPs] = useState<BlockedIP[]>([]);
  const [vulnerabilities, setVulnerabilities] = useState<Vulnerability[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (securityEnabled) {
      loadSecurityData();
    }
  }, [securityEnabled]);

  const loadSecurityData = async () => {
    setLoading(true);
    try {
      // Carregar estat├¡sticas
      const { data: statsData } = await db.rpc('get_security_stats');
      if (statsData) {
        setStats(statsData[0]);
      }

      // Carregar logs recentes
      const { data: logsData } = await db
        .from('security_logs')
        .select(`
          *,
          user:profiles(name, email)
        `)
        .order('created_at', { ascending: false })
        .limit(10);
      
      if (logsData) {
        setRecentLogs(logsData);
      }

      // Carregar IPs bloqueados
      const { data: ipsData } = await db
        .from('blocked_ips')
        .select('*')
        .order('blocked_until', { ascending: false })
        .limit(10);
      
      if (ipsData) {
        setBlockedIPs(ipsData);
      }

      // Carregar vulnerabilidades
      const { data: vulnData } = await db
        .from('vulnerability_scans')
        .select('*')
        .eq('status', 'open')
        .order('severity', { ascending: false })
        .limit(10);
      
      if (vulnData) {
        setVulnerabilities(vulnData);
      }
    } catch (error) {
      console.error('Erro ao carregar dados de seguran├ºa:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleUnblockIP = async (ipAddress: string) => {
    try {
      const { error } = await db.rpc('unblock_ip', { p_ip_address: ipAddress });
      
      if (error) {
        throw error;
      }

      // Recarregar dados
      await loadSecurityData();
    } catch (error) {
      console.error('Erro ao desbloquear IP:', error);
    }
  };

  const handleScanVulnerabilities = async () => {
    try {
      const { data } = await db.rpc('scan_vulnerabilities');
      
      if (data) {
        await loadSecurityData();
      }
    } catch (error) {
      console.error('Erro ao escanear vulnerabilidades:', error);
    }
  };

  const getRiskLevelColor = (level: string) => {
    switch (level) {
      case 'critical': return 'bg-red-500';
      case 'high': return 'bg-orange-500';
      case 'medium': return 'bg-yellow-500';
      case 'low': return 'bg-green-500';
      default: return 'bg-gray-500';
    }
  };

  const getSeverityColor = (severity: string) => {
    switch (severity) {
      case 'critical': return 'text-red-600 bg-red-50';
      case 'high': return 'text-orange-600 bg-orange-50';
      case 'medium': return 'text-yellow-600 bg-yellow-50';
      case 'low': return 'text-green-600 bg-green-50';
      default: return 'text-gray-600 bg-gray-50';
    }
  };

  if (!securityEnabled) {
    return (
      <Card>
        <CardContent className="p-8 text-center">
          <Shield className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
          <h3 className="text-lg font-semibold mb-2">Sistema de Seguran├ºa Desativado</h3>
          <p className="text-muted-foreground mb-4">
            Ative o m├│dulo de seguran├ºa avan├ºada para acessar este painel.
          </p>
          <Button onClick={() => window.location.href = '/admin/features'}>
            Ativar Sistema de Seguran├ºa
          </Button>
        </CardContent>
      </Card>
    );
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center p-8">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold">Seguran├ºa Avan├ºada</h2>
          <p className="text-muted-foreground">
            Monitoramento e prote├º├úo do sistema
          </p>
        </div>
        <Button onClick={handleScanVulnerabilities}>
          <Shield className="w-4 h-4 mr-2" />
          Escanear Vulnerabilidades
        </Button>
      </div>

      {/* Estat├¡sticas de Seguran├ºa */}
      <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-6 gap-4">
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2">
              <Activity className="w-4 h-4 text-blue-500" />
              <span className="text-sm text-muted-foreground">Logs (7d)</span>
            </div>
            <div className="text-2xl font-bold mt-1">{stats?.total_logs || 0}</div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2">
              <AlertTriangle className="w-4 h-4 text-orange-500" />
              <span className="text-sm text-muted-foreground">Alto Risco</span>
            </div>
            <div className="text-2xl font-bold mt-1 text-orange-600">{stats?.high_risk_events || 0}</div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2">
              <Lock className="w-4 h-4 text-red-500" />
              <span className="text-sm text-muted-foreground">IPs Bloqueados</span>
            </div>
            <div className="text-2xl font-bold mt-1 text-red-600">{stats?.blocked_ips_count || 0}</div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2">
              <XCircle className="w-4 h-4 text-red-500" />
              <span className="text-sm text-muted-foreground">Falhas Login (24h)</span>
            </div>
            <div className="text-2xl font-bold mt-1 text-red-600">{stats?.failed_logins_24h || 0}</div>
          </CardContent>
