}

import { useState, useEffect, useCallback } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Progress } from '@/components/ui/progress';
import { 
  Shield, AlertTriangle, CheckCircle, TrendingUp, Users, 
  DollarSign, MapPin, Calendar, Activity, Eye
} from 'lucide-react';
import { useFeature } from '@/hooks/useFeatureFlags';
import { supabase } from '@/integrations/supabase/client';
const db = supabase as any;
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';

interface FraudAlert {
  id: string;
  barbershop_id: string;
  barbershop_name: string;
  alert_type: string;
  risk_score: number;
  description: string;
  status: string;
  created_at: string;
}

interface FraudMetric {
  barbershop_id: string;
  barbershop_name: string;
  date: string;
  total_appointments: number;
  total_payments: number;
  recorded_payments: number;
  discrepancy_amount: number;
  discrepancy_percentage: number;
  risk_level: string;
}

export function AntiFraudPanel() {
  const { enabled: antifraudEnabled } = useFeature('antifraud_system');
  const [alerts, setAlerts] = useState<FraudAlert[]>([]);
  const [metrics, setMetrics] = useState<FraudMetric[]>([]);
  const [loading, setLoading] = useState(true);
  const [analyzing, setAnalyzing] = useState(false);

  const loadFraudData = useCallback(async () => {
    setLoading(true);
    try {
      // Carregar alertas de fraude
      const { data: alertsData } = await db.rpc('get_fraud_alerts', {
        p_limit: 20
      });
      
      if (alertsData) {
        setAlerts(alertsData);
      }

      // Carregar m├®tricas recentes
      const { data: metricsData } = await db
        .from('fraud_metrics')
        .select(`
          *,
          barbershops(name)
        `)
        .order('date', { ascending: false })
        .limit(20);
      
      if (metricsData) {
        setMetrics(metricsData.map(m => ({
          ...m,
          barbershop_name: m.barbershops?.name || 'Barbearia desconhecida'
        })));
      }
    } catch (error) {
      console.error('Erro ao carregar dados anti-fraude:', error);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (antifraudEnabled) {
      loadFraudData();
    }
  }, [antifraudEnabled, loadFraudData]);

  const handleAnalyzeFraud = async () => {
    setAnalyzing(true);
    try {
      // Analisar todas as barbearias
      const { data: barbershops } = await db
        .from('barbershops')
        .select('id');
      
      if (barbershops) {
        for (const barbershop of barbershops) {
          await db.rpc('analyze_payment_discrepancy', {
            p_barbershop_id: barbershop.id
          });
          
          await db.rpc('detect_unusual_volume', {
            p_barbershop_id: barbershop.id
          });
        }
      }
      
      await loadFraudData();
    } catch (error) {
      console.error('Erro ao analisar fraudes:', error);
    } finally {
      setAnalyzing(false);
    }
  };

  const handleResolveAlert = async (alertId: string) => {
    try {
      const { error } = await db
        .from('fraud_alerts')
        .update({ 
          status: 'resolved',
          resolved_at: new Date().toISOString(),
          resolved_by: (await supabase.auth.getUser()).data.user?.id
        })
        .eq('id', alertId);
      
      if (error) {
        throw error;
      }
      
      await loadFraudData();
    } catch (error) {
      console.error('Erro ao resolver alerta:', error);
    }
  };

  const getRiskScoreColor = (score: number) => {
    if (score >= 70) return 'text-red-600 bg-red-50';
    if (score >= 40) return 'text-orange-600 bg-orange-50';
    if (score >= 20) return 'text-yellow-600 bg-yellow-50';
    return 'text-green-600 bg-green-50';
  };

  const getRiskLevelColor = (level: string) => {
    switch (level) {
      case 'critical': return 'bg-red-500';
      case 'high': return 'bg-orange-500';
      case 'medium': return 'bg-yellow-500';
      case 'low': return 'bg-green-500';
      default: return 'bg-gray-500';
    }
  };

  const getAlertTypeColor = (type: string) => {
    switch (type) {
      case 'payment_mismatch': return 'text-red-600';
      case 'unusual_volume': return 'text-orange-600';
      case 'suspicious_pattern': return 'text-purple-600';
      case 'multiple_accounts': return 'text-blue-600';
      case 'chargeback_risk': return 'text-yellow-600';
      case 'velocity_exceeded': return 'text-green-600';
      default: return 'text-gray-600';
    }
  };

  if (!antifraudEnabled) {
    return (
      <Card>
        <CardContent className="p-8 text-center">
          <Shield className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
          <h3 className="text-lg font-semibold mb-2">Sistema Anti-Fraude Desativado</h3>
          <p className="text-muted-foreground mb-4">
            Ative o m├│dulo anti-fraude para acessar este painel.
          </p>
          <Button onClick={() => window.location.href = '/admin/features'}>
            Ativar Sistema Anti-Fraude
          </Button>
        </CardContent>
      </Card>
    );
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center p-8">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
      </div>
    );
  }

  const criticalAlerts = alerts.filter(a => a.risk_score >= 70);
  const highRiskAlerts = alerts.filter(a => a.risk_score >= 40 && a.risk_score < 70);
  const totalDiscrepancy = metrics.reduce((acc, m) => acc + Math.abs(m.discrepancy_amount), 0);

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold">Sistema Anti-Fraude</h2>
          <p className="text-muted-foreground">
            Detec├º├úo autom├ítica de atividades suspeitas e fraudes
          </p>
        </div>
        <Button onClick={handleAnalyzeFraud} disabled={analyzing}>
          <Eye className="w-4 h-4 mr-2" />
          {analyzing ? 'Analisando...' : 'Analisar Sistema'}
        </Button>
      </div>

      {/* Estat├¡sticas de Risco */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2">
              <AlertTriangle className="w-4 h-4 text-red-500" />
              <span className="text-sm text-muted-foreground">Alertas Cr├¡ticos</span>
            </div>
            <div className="text-2xl font-bold mt-1 text-red-600">{criticalAlerts.length}</div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2">
              <AlertTriangle className="w-4 h-4 text-orange-500" />
              <span className="text-sm text-muted-foreground">Alto Risco</span>
            </div>
            <div className="text-2xl font-bold mt-1 text-orange-600">{highRiskAlerts.length}</div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2">
              <DollarSign className="w-4 h-4 text-yellow-500" />
              <span className="text-sm text-muted-foreground">Discrep├óncia Total</span>
            </div>
            <div className="text-2xl font-bold mt-1 text-yellow-600">
              R$ {totalDiscrepancy.toLocaleString('pt-BR')}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2">
              <Activity className="w-4 h-4 text-blue-500" />
              <span className="text-sm text-muted-foreground">Barbearias Monitoradas</span>
            </div>
            <div className="text-2xl font-bold mt-1">{metrics.length}</div>
          </CardContent>
        </Card>
      </div>

      {/* Alertas de Fraude */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <AlertTriangle className="w-5 h-5" />
            Alertas de Fraude
          </CardTitle>
          <CardDescription>
            Atividades suspeitas detectadas pelo sistema
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="space-y-3">
            {alerts.map((alert) => (
              <div key={alert.id} className="flex items-center justify-between p-3 border rounded-lg">
                <div className="flex items-center gap-3">
                  <div className={`w-2 h-2 rounded-full ${getRiskLevelColor(alert.status === 'resolved' ? 'low' : 'critical')}`} />
                  <div>
                    <div className="flex items-center gap-2">
                      <span className="font-medium">{alert.barbershop_name}</span>
                      <Badge className={`text-xs ${getRiskScoreColor(alert.risk_score)}`}>
                        Score: {alert.risk_score}/100
                      </Badge>
                      <Badge className={`text-xs ${getAlertTypeColor(alert.alert_type)}`}>
                        {alert.alert_type}
                      </Badge>
                      {alert.status === 'resolved' && (
                        <Badge className="bg-green-500 text-white text-xs">
                          Resolvido
                        </Badge>
                      )}
                    </div>
                    <div className="text-sm text-muted-foreground mt-1">
                      {alert.description}
                    </div>
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  <div className="text-right">
                    <div className="text-sm text-muted-foreground">
                      {format(new Date(alert.created_at), "dd/MM HH:mm", { locale: ptBR })}
                    </div>
                  </div>
                  {alert.status !== 'resolved' && (
                    <Button
                      size="sm"
                      variant="outline"
                      onClick={() => handleResolveAlert(alert.id)}
                    >
                      <CheckCircle className="w-4 h-4 mr-1" />
                      Resolver
                    </Button>
                  )}
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>

      {/* M├®tricas de Discrep├óncia */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <TrendingUp className="w-5 h-5" />
            An├ílise de Discrep├óncias
          </CardTitle>
          <CardDescription>
            Diferen├ºas entre agendamentos e pagamentos registrados
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="space-y-3">
            {metrics.map((metric) => (
              <div key={`${metric.barbershop_id}-${metric.date}`} className="flex items-center justify-between p-3 border rounded-lg">
                <div className="flex items-center gap-3">
                  <div className={`w-2 h-2 rounded-full ${getRiskLevelColor(metric.risk_level)}`} />
                  <div>
                    <div className="flex items-center gap-2">
                      <span className="font-medium">{metric.barbershop_name}</span>
                      <Badge className={`text-xs ${getRiskLevelColor(metric.risk_level)}`}>
                        {metric.risk_level}
                      </Badge>
                    </div>
                    <div className="text-sm text-muted-foreground">
                      {metric.total_appointments} agendamentos ÔÇó R$ {metric.total_payments.toFixed(2)} esperado ÔÇó R$ {metric.recorded_payments.toFixed(2)} registrado
                    </div>
                  </div>
                </div>
                <div className="text-right">
                  <div className={`font-medium ${Math.abs(metric.discrepancy_percentage) > 30 ? 'text-red-600' : 'text-green-600'}`}>
                    {metric.discrepancy_percentage > 0 ? '+' : ''}{metric.discrepancy_percentage.toFixed(1)}%
                  </div>
                  <div className="text-sm text-muted-foreground">
                    R$ {Math.abs(metric.discrepancy_amount).toFixed(2)}
                  </div>
                  <div className="text-xs text-muted-foreground">
                    {format(new Date(metric.date), "dd/MM", { locale: ptBR })}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>

      {/* Alerta de Monitoramento */}
      <Alert>
        <Shield className="h-4 w-4" />
        <AlertDescription>
          O sistema monitora automaticamente atividades suspeitas 24/7. 
          Alertas cr├¡ticos (score ÔëÑ 70) requerem aten├º├úo imediata.
        </AlertDescription>
      </Alert>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Progress } from '@/components/ui/progress';
import { 
  Database, Download, Upload, Calendar, CheckCircle, 
  XCircle, Clock, HardDrive, Shield, Settings
} from 'lucide-react';
import { useFeature } from '@/hooks/useFeatureFlags';
import { supabase } from '@/integrations/supabase/client';
const db = supabase as any;
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';

interface BackupStats {
  total_backups: number;
  completed_backups: number;
  failed_backups: number;
  total_size_gb: number;
  last_backup_date: string;
  oldest_backup_date: string;
  retention_days: number;
}

interface Backup {
  id: string;
  file_name: string;
  file_size: number;
  backup_type: string;
  status: string;
  started_at: string;
  completed_at: string;
  checksum: string;
}

interface BackupSettings {
  backup_frequency: string;
  retention_days: number;
  backup_location: string;
  encryption_enabled: boolean;
  compression_enabled: boolean;
  auto_cleanup: boolean;
  notification_emails: string[];
}

export function BackupSystemPanel() {
  const { enabled: backupEnabled } = useFeature('backup_system');
  const [stats, setStats] = useState<BackupStats | null>(null);
  const [backups, setBackups] = useState<Backup[]>([]);
  const [settings, setSettings] = useState<BackupSettings | null>(null);
  const [creating, setCreating] = useState(false);
  const [restoring, setRestoring] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (backupEnabled) {
      loadBackupData();
    }
  }, [backupEnabled]);

  const loadBackupData = async () => {
    setLoading(true);
    try {
      // Carregar estat├¡sticas
      const { data: statsData } = await db.rpc('get_backup_stats');
      if (statsData) {
        setStats(statsData[0]);
      }

      // Carregar backups recentes
      const { data: backupsData } = await db
        .from('backups')
        .select('*')
        .order('created_at', { ascending: false })
        .limit(20);
      
      if (backupsData) {
        setBackups(backupsData);
      }

      // Carregar configura├º├Áes
      const { data: settingsData } = await db
        .from('backup_settings')
        .select('*')
        .limit(1);
      
      if (settingsData) {
        setSettings(settingsData[0]);
      }
    } catch (error) {
      console.error('Erro ao carregar dados de backup:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleCreateBackup = async (type: string = 'full') => {
    setCreating(true);
    try {
      const { data } = await db.rpc('start_backup', { p_backup_type: type });
      
      if (data) {
        await loadBackupData();
      }
    } catch (error) {
      console.error('Erro ao criar backup:', error);
    } finally {
      setCreating(false);
    }
  };

  const handleRestoreBackup = async (backupId: string) => {
    setRestoring(backupId);
    try {
      const { data } = await db.rpc('restore_backup', { p_backup_id: backupId });
      
      if (data) {
        // Backup restaurado com sucesso
      }
    } catch (error) {
      console.error('Erro ao restaurar backup:', error);
    } finally {
      setRestoring(null);
    }
  };

  const handleCleanup = async () => {
    try {
      const { data } = await db.rpc('cleanup_old_backups');
      
      if (data) {
        await loadBackupData();
      }
    } catch (error) {
      console.error('Erro ao limpar backups:', error);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'completed': return 'text-green-600 bg-green-50';
      case 'failed': return 'text-red-600 bg-red-50';
      case 'running': return 'text-blue-600 bg-blue-50';
      case 'pending': return 'text-yellow-600 bg-yellow-50';
      default: return 'text-gray-600 bg-gray-50';
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'completed': return CheckCircle;
      case 'failed': return XCircle;
      case 'running': return Clock;
      case 'pending': return Clock;
      default: return Clock;
    }
  };

  const formatFileSize = (bytes: number) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  if (!backupEnabled) {
    return (
      <Card>
        <CardContent className="p-8 text-center">
          <Database className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
          <h3 className="text-lg font-semibold mb-2">Sistema de Backup Desativado</h3>
          <p className="text-muted-foreground mb-4">
            Ative o m├│dulo de backup autom├ítico para acessar este painel.
          </p>
          <Button onClick={() => window.location.href = '/admin/features'}>
            Ativar Sistema de Backup
          </Button>
        </CardContent>
      </Card>
    );
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center p-8">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold">Sistema de Backup</h2>
          <p className="text-muted-foreground">
            Backup autom├ítico e restaura├º├úo do banco de dados
          </p>
        </div>
        <div className="flex gap-2">
          <Button onClick={() => handleCreateBackup('full')} disabled={creating}>
            <Download className="w-4 h-4 mr-2" />
            {creating ? 'Criando...' : 'Criar Backup'}
          </Button>
