export function FeatureFlagsControl() {
  const { features, loading, toggleFeature } = useFeatureFlags();
  const [toggling, setToggling] = useState<string | null>(null);

  const handleToggle = async (featureKey: string, enabled: boolean) => {
    setToggling(featureKey);
    await toggleFeature(featureKey, enabled);
    setToggling(null);
  };

  const getImpactColor = (impact: string) => {
    switch (impact) {
      case 'critical': return 'bg-red-500';
      case 'high': return 'bg-orange-500';
      case 'medium': return 'bg-yellow-500';
      case 'low': return 'bg-green-500';
      default: return 'bg-gray-500';
    }
  };

  const getCategoryColor = (category: string) => {
    switch (category) {
      case 'Expans├úo': return 'bg-purple-500';
      case 'Seguran├ºa': return 'bg-red-500';
      case 'Intelig├¬ncia': return 'bg-blue-500';
      case 'Marketing': return 'bg-green-500';
      case 'Financeiro': return 'bg-yellow-500';
      default: return 'bg-gray-500';
    }
  };

  const groupedFeatures = features.reduce((acc, enabled, key) => {
    const feature = features.find(f => f.key === key);
    if (feature) {
      if (!acc[feature.category]) {
        acc[feature.category] = [];
      }
      acc[feature.category].push({ ...feature, enabled });
    }
    return acc;
  }, {} as Record<string, (FeatureConfig & { enabled: boolean })[]>);

  if (loading) {
    return (
      <div className="flex items-center justify-center p-8">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold">Controle de Sistema</h2>
          <p className="text-muted-foreground">
            Ative ou desative m├│dulos do sistema de forma segura
          </p>
        </div>
        <Badge variant="outline" className="text-sm">
          {Object.values(features).filter(Boolean).length} de {features.length} ativos
        </Badge>
      </div>

      <Alert>
        <Settings className="h-4 w-4" />
        <AlertDescription>
          Altera├º├Áes nos m├│dulos afetam todo o sistema. Desative m├│dulos com cuidado para n├úo impactar usu├írios ativos.
        </AlertDescription>
      </Alert>

      {Object.entries(groupedFeatures).map(([category, categoryFeatures]) => (
        <Card key={category}>
          <CardHeader>
            <div className="flex items-center gap-2">
              <div className={`w-3 h-3 rounded-full ${getCategoryColor(category)}`} />
              <CardTitle className="text-lg">{category}</CardTitle>
              <Badge variant="secondary" className="text-xs">
                {categoryFeatures.filter(f => f.enabled).length}/{categoryFeatures.length}
              </Badge>
            </div>
            <CardDescription>
              M├│dulos de {category.toLowerCase()} do sistema
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            {categoryFeatures.map((feature) => {
              const Icon = feature.icon;
              const isToggling = toggling === feature.key;
              const hasUnmetDependencies = feature.dependencies?.some(dep => !features[dep]);

              return (
                <div key={feature.key} className="flex items-center justify-between p-4 border rounded-lg">
                  <div className="flex items-center gap-3 flex-1">
                    <div className={`p-2 rounded-lg ${feature.enabled ? 'bg-primary/10' : 'bg-muted'}`}>
                      <Icon className={`w-5 h-5 ${feature.enabled ? 'text-primary' : 'text-muted-foreground'}`} />
                    </div>
                    <div className="flex-1">
                      <div className="flex items-center gap-2">
                        <h3 className="font-medium">{feature.name}</h3>
                        <Badge className={`text-xs ${getImpactColor(feature.impact)}`}>
                          {feature.impact}
                        </Badge>
                      </div>
                      <p className="text-sm text-muted-foreground mt-1">
                        {feature.description}
                      </p>
                      {hasUnmetDependencies && (
                        <p className="text-xs text-orange-600 mt-1">
                          Depend├¬ncias n├úo atendidas: {feature.dependencies?.filter(dep => !features[dep]).join(', ')}
                        </p>
                      )}
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <Switch
                      checked={feature.enabled}
                      onCheckedChange={(enabled) => handleToggle(feature.key, enabled)}
                      disabled={isToggling || hasUnmetDependencies}
                    />
                    {isToggling && (
                      <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-primary"></div>
                    )}
                  </div>
                </div>
              );
            })}
          </CardContent>
        </Card>
      ))}

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Rocket className="w-5 h-5" />
            Ativa├º├úo R├ípida
          </CardTitle>
          <CardDescription>
            Ative m├║ltiplos m├│dulos de uma vez
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex gap-2">
            <Button
              variant="outline"
              onClick={() => {
                features.forEach((enabled, key) => {
                  if (!enabled) {
                    handleToggle(key, true);
                  }
                });
              }}
            >
              Ativar Todos
            </Button>
            <Button
              variant="outline"
              onClick={() => {
                features.forEach((enabled, key) => {
                  if (enabled && key !== 'advanced_security') {
                    handleToggle(key, false);
                  }
                });
              }}
            >
              Desativar Todos (exceto seguran├ºa)
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Progress } from '@/components/ui/progress';
import { 
  TrendingUp, MapPin, Users, DollarSign, AlertTriangle, 
  CheckCircle, Target, BarChart3, Eye, Calendar
} from 'lucide-react';
import { useFeature } from '@/hooks/useFeatureFlags';
import { supabase } from '@/integrations/supabase/client';
const db = supabase as any;
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';

interface GrowthMetric {
  city: string;
  state: string;
  barbershops_count: number;
  new_barbershops_month: number;
  monthly_revenue: number;
  growth_rate: number;
  demand_score: number;
  potential_score: number;
  competition_level: string;
}

interface GrowthInsight {
  id: string;
  insight_type: string;
  title: string;
  description: string;
  target_cities: string[];
  priority: string;
  confidence_score: number;
  status: string;
  created_at: string;
}

interface GrowthForecast {
  forecast_type: string;
  target_entity: string;
  current_value: number;
  forecast_3m: number;
  forecast_6m: number;
  forecast_12m: number;
  confidence_level: number;
}

interface FranchiseRanking {
  franchise_id: string;
  franchise_name: string;
  total_barbershops: number;
  new_barbershops: number;
  total_revenue: number;
  growth_rate: number;
  performance_score: number;
  ranking_position: number;
  total_franchises: number;
}

export function GrowthIntelligencePanel() {
  const { enabled: growthEnabled } = useFeature('growth_intelligence');
  const [metrics, setMetrics] = useState<GrowthMetric[]>([]);
  const [insights, setInsights] = useState<GrowthInsight[]>([]);
  const [forecasts, setForecasts] = useState<GrowthForecast[]>([]);
  const [rankings, setRankings] = useState<FranchiseRanking[]>([]);
  const [loading, setLoading] = useState(true);
  const [analyzing, setAnalyzing] = useState(false);

  useEffect(() => {
    if (growthEnabled) {
      loadGrowthData();
    }
  }, [growthEnabled]);

  const loadGrowthData = async () => {
    setLoading(true);
    try {
      // Carregar m├®tricas de crescimento
      const { data: metricsData } = await db
        .from('growth_metrics')
        .select('*')
        .order('demand_score', { ascending: false })
        .limit(20);
      
      if (metricsData) {
        setMetrics(metricsData);
      }

      // Carregar insights
      const { data: insightsData } = await db
        .from('growth_insights')
        .select('*')
        .eq('status', 'open')
        .order('priority', { ascending: false })
        .limit(10);
      
      if (insightsData) {
        setInsights(insightsData);
      }

      // Carregar previs├Áes
      const { data: forecastsData } = await db
        .from('growth_forecasts')
        .select('*')
        .order('created_at', { ascending: false })
        .limit(10);
      
      if (forecastsData) {
        setForecasts(forecastsData);
      }

      // Carregar rankings de franqueados
      const { data: rankingsData } = await db.rpc('get_franchise_rankings');
      
      if (rankingsData) {
        setRankings(rankingsData);
      }
    } catch (error) {
      console.error('Erro ao carregar dados de crescimento:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleAnalyzeGrowth = async () => {
    setAnalyzing(true);
    try {
      // Atualizar m├®tricas
      await db.rpc('update_growth_metrics');
      
      // Gerar insights
      await db.rpc('generate_growth_insights');
      
      // Recarregar dados
      await loadGrowthData();
    } catch (error) {
      console.error('Erro ao analisar crescimento:', error);
    } finally {
      setAnalyzing(false);
    }
  };

  const getPriorityColor = (priority: string) => {
    switch (priority) {
      case 'critical': return 'bg-red-500';
      case 'high': return 'bg-orange-500';
      case 'medium': return 'bg-yellow-500';
      case 'low': return 'bg-green-500';
      default: return 'bg-gray-500';
    }
  };

  const getInsightTypeColor = (type: string) => {
    switch (type) {
      case 'market_opportunity': return 'text-green-600 bg-green-50';
      case 'growth_trend': return 'text-blue-600 bg-blue-50';
      case 'risk_alert': return 'text-red-600 bg-red-50';
      case 'performance_gap': return 'text-orange-600 bg-orange-50';
      case 'expansion_recommendation': return 'text-purple-600 bg-purple-50';
      default: return 'text-gray-600 bg-gray-50';
    }
  };

  const getCompetitionColor = (level: string) => {
    switch (level) {
      case 'low': return 'text-green-600';
      case 'medium': return 'text-yellow-600';
      case 'high': return 'text-red-600';
      default: return 'text-gray-600';
    }
  };

  if (!growthEnabled) {
    return (
      <Card>
        <CardContent className="p-8 text-center">
          <TrendingUp className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
          <h3 className="text-lg font-semibold mb-2">Intelig├¬ncia de Crescimento Desativada</h3>
          <p className="text-muted-foreground mb-4">
            Ative o m├│dulo de intelig├¬ncia de crescimento para acessar este painel.
          </p>
          <Button onClick={() => window.location.href = '/admin/features'}>
            Ativar Intelig├¬ncia de Crescimento
          </Button>
        </CardContent>
      </Card>
    );
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center p-8">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold">Intelig├¬ncia de Crescimento</h2>
          <p className="text-muted-foreground">
            An├ílise avan├ºada de m├®tricas e insights para expans├úo
          </p>
        </div>
        <Button onClick={handleAnalyzeGrowth} disabled={analyzing}>
          <BarChart3 className="w-4 h-4 mr-2" />
          {analyzing ? 'Analisando...' : 'Analisar Crescimento'}
        </Button>
      </div>

      {/* M├®tricas Principais */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2">
              <MapPin className="w-4 h-4 text-blue-500" />
              <span className="text-sm text-muted-foreground">Cidades Monitoradas</span>
            </div>
            <div className="text-2xl font-bold mt-1">{metrics.length}</div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2">
              <Users className="w-4 h-4 text-green-500" />
              <span className="text-sm text-muted-foreground">Alto Potencial</span>
            </div>
            <div className="text-2xl font-bold mt-1 text-green-600">
              {metrics.filter(m => m.potential_score > 70).length}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2">
              <TrendingUp className="w-4 h-4 text-purple-500" />
              <span className="text-sm text-muted-foreground">Crescimento M├®dio</span>
            </div>
            <div className="text-2xl font-bold mt-1">
              {metrics.length > 0 ? (metrics.reduce((acc, m) => acc + m.growth_rate, 0) / metrics.length).toFixed(1) : 0}%
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2">
              <DollarSign className="w-4 h-4 text-yellow-500" />
              <span className="text-sm text-muted-foreground">Receita Total</span>
            </div>
            <div className="text-2xl font-bold mt-1">
              R$ {metrics.reduce((acc, m) => acc + m.monthly_revenue, 0).toLocaleString('pt-BR')}
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Insights de Crescimento */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Eye className="w-5 h-5" />
            Insights de Crescimento
          </CardTitle>
          <CardDescription>
            Oportunidades e alertas identificados pelo sistema
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="space-y-3">
            {insights.map((insight) => (
              <div key={insight.id} className="flex items-center justify-between p-3 border rounded-lg">
                <div className="flex items-center gap-3">
                  <div className={`w-2 h-2 rounded-full ${getPriorityColor(insight.priority)}`} />
                  <div>
                    <div className="flex items-center gap-2">
                      <span className="font-medium">{insight.title}</span>
                      <Badge className={`text-xs ${getInsightTypeColor(insight.insight_type)}`}>
                        {insight.insight_type}
                      </Badge>
                      <Badge className={`text-xs ${getPriorityColor(insight.priority)}`}>
                        {insight.priority}
                      </Badge>
                    </div>
                    <div className="text-sm text-muted-foreground mt-1">
                      {insight.description}
                    </div>
                    {insight.target_cities.length > 0 && (
                      <div className="text-xs text-muted-foreground mt-1">
                        Cidades: {insight.target_cities.join(', ')}
                      </div>
                    )}
                  </div>
                </div>
                <div className="text-right">
                  <div className="text-sm text-muted-foreground">
                    Confian├ºa: {Math.round(insight.confidence_score * 100)}%
                  </div>
                  <div className="text-xs text-muted-foreground">
                    {format(new Date(insight.created_at), "dd/MM HH:mm", { locale: ptBR })}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>

      {/* M├®tricas por Cidade */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <MapPin className="w-5 h-5" />
            M├®tricas por Cidade
          </CardTitle>
          <CardDescription>
            An├ílise detalhada por mercado local
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="space-y-3">
            {metrics.slice(0, 10).map((metric) => (
              <div key={`${metric.city}-${metric.state}`} className="flex items-center justify-between p-3 border rounded-lg">
                <div className="flex items-center gap-3">
                  <MapPin className="w-4 h-4 text-blue-500" />
                  <div>
                    <div className="flex items-center gap-2">
                      <span className="font-medium">{metric.city}, {metric.state}</span>
                      <Badge variant="outline" className="text-xs">
                        {metric.competition_level}
                      </Badge>
                    </div>
                    <div className="text-sm text-muted-foreground">
                      {metric.barbershops_count} barbearias ÔÇó {metric.new_barbershops_month} novas/m├¬s
                    </div>
                  </div>
                </div>
                <div className="text-right">
                  <div className="flex items-center gap-2">
                    <div className="text-sm">
                      <div className="font-medium">Score: {metric.demand_score}/100</div>
                      <Progress value={metric.demand_score} className="w-20 h-2" />
                    </div>
                    <div className="text-sm">
                      <div className={`font-medium ${getCompetitionColor(metric.competition_level)}`}>
                        {metric.growth_rate > 0 ? '+' : ''}{metric.growth_rate}%
                      </div>
                      <div className="text-xs text-muted-foreground">crescimento</div>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>

      {/* Previs├Áes de Crescimento */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Target className="w-5 h-5" />
            Previs├Áes de Crescimento
          </CardTitle>
          <CardDescription>
            Proje├º├Áes baseadas em modelos de IA
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="space-y-3">
            {forecasts.map((forecast) => (
              <div key={`${forecast.forecast_type}-${forecast.target_entity}`} className="p-3 border rounded-lg">
                <div className="flex items-center justify-between mb-2">
                  <div className="flex items-center gap-2">
                    <span className="font-medium">{forecast.forecast_type}</span>
                    <Badge variant="outline" className="text-xs">
                      {forecast.target_entity}
                    </Badge>
                  </div>
                  <div className="text-sm text-muted-foreground">
                    Confian├ºa: {Math.round(forecast.confidence_level * 100)}%
                  </div>
                </div>
                <div className="grid grid-cols-4 gap-2 text-sm">
                  <div>
                    <div className="text-muted-foreground">Atual</div>
                    <div className="font-medium">
                      {forecast.forecast_type === 'revenue' ? `R$ ${forecast.current_value.toLocaleString('pt-BR')}` : forecast.current_value}
                    </div>
                  </div>
                  <div>
                    <div className="text-muted-foreground">3 meses</div>
                    <div className="font-medium text-green-600">
                      {forecast.forecast_type === 'revenue' ? `R$ ${forecast.forecast_3m.toLocaleString('pt-BR')}` : forecast.forecast_3m}
                    </div>
                  </div>
                  <div>
                    <div className="text-muted-foreground">6 meses</div>
                    <div className="font-medium text-green-600">
                      {forecast.forecast_type === 'revenue' ? `R$ ${forecast.forecast_6m.toLocaleString('pt-BR')}` : forecast.forecast_6m}
                    </div>
                  </div>
                  <div>
                    <div className="text-muted-foreground">12 meses</div>
                    <div className="font-medium text-green-600">
                      {forecast.forecast_type === 'revenue' ? `R$ ${forecast.forecast_12m.toLocaleString('pt-BR')}` : forecast.forecast_12m}
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>

      {/* Ranking de Franqueados */}
      {rankings.length > 0 && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Users className="w-5 h-5" />
              Ranking de Franqueados
            </CardTitle>
            <CardDescription>
              Performance dos franqueados da rede
            </CardDescription>
          </CardHeader>
          <CardContent>
            <div className="space-y-3">
              {rankings.slice(0, 10).map((ranking, index) => (
                <div key={ranking.franchise_id} className="flex items-center justify-between p-3 border rounded-lg">
                  <div className="flex items-center gap-3">
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold ${
                      index < 3 ? 'bg-yellow-500 text-white' : 'bg-gray-200'
                    }`}>
                      {ranking.ranking_position}
                    </div>
                    <div>
                      <div className="font-medium">{ranking.franchise_name}</div>
                      <div className="text-sm text-muted-foreground">
                        {ranking.total_barbershops} barbearias ÔÇó {ranking.new_barbershops} novas
                      </div>
                    </div>
                  </div>
                  <div className="text-right">
                    <div className="font-medium">R$ {ranking.total_revenue.toLocaleString('pt-BR')}</div>
                    <div className="text-sm text-muted-foreground">
                      {ranking.growth_rate > 0 ? '+' : ''}{ranking.growth_rate}% ÔÇó Score: {ranking.performance_score}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Alerta de An├ílise */}
      <Alert>
        <AlertTriangle className="h-4 w-4" />
        <AlertDescription>
          As an├ílises s├úo baseadas em dados hist├│ricos e padr├Áes identificados. 
          As previs├Áes t├¬m margem de erro e devem ser usadas como refer├¬ncia para decis├Áes estrat├®gicas.
        </AlertDescription>
      </Alert>
    </div>
  );
}

import { useState, useEffect } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { 
  TestTube, 
  CheckCircle, 
  XCircle, 
  Clock, 
  Loader2, 
  RefreshCw,
  Play,
  AlertTriangle,
  Activity
} from "lucide-react";
import { toast } from "sonner";
import { IntegrationTester, IntegrationTest } from "@/services/integrations/IntegrationTester";

export const IntegrationTestsPanel = () => {
  const [tests, setTests] = useState<IntegrationTest[]>([]);
  const [isRunning, setIsRunning] = useState(false);
  const [currentTest, setCurrentTest] = useState<string | null>(null);

  useEffect(() => {
    // Carregar resultados anteriores se existirem
    setTests(IntegrationTester.getTestResults());
  }, []);

  const runAllTests = async () => {
    setIsRunning(true);
    setCurrentTest('Iniciando testes...');
    
    try {
      const results = await IntegrationTester.runAllTests();
      setTests(results);
      
      const summary = IntegrationTester.getTestSummary();
      
      if (summary.failed === 0) {
        toast.success(`Todos os ${summary.total} testes passaram com sucesso!`);
      } else {
        toast.warning(`${summary.passed} testes passaram, ${summary.failed} falharam`);
      }
    } catch (error: any) {
      toast.error(`Erro ao executar testes: ${error.message}`);
    } finally {
      setIsRunning(false);
      setCurrentTest(null);
    }
  };

  const runSingleTest = async (testType: string) => {
    setIsRunning(true);
    setCurrentTest(testType);

    try {
      let result: IntegrationTest;
      
      switch (testType) {
        case 'payment':
          result = await IntegrationTester.testPaymentGateway();
          break;
        case 'sms':
          result = await IntegrationTester.testSMS();
          break;
        case 'email':
          result = await IntegrationTester.testEmail();
          break;
        case 'webhook':
          result = await IntegrationTester.testWebhooks();
          break;
        default:
          throw new Error('Tipo de teste desconhecido');
      }

      // Atualizar o teste espec├¡fico na lista
      setTests(prev => prev.map(t => t.id === result.id ? result : t));
      
      if (result.status === 'success') {
        toast.success(`${result.name} testado com sucesso!`);
      } else {
        toast.error(`Erro em ${result.name}: ${result.error}`);
      }
    } catch (error: any) {
      toast.error(`Erro no teste: ${error.message}`);
    } finally {
      setIsRunning(false);
      setCurrentTest(null);
    }
  };

  const clearResults = () => {
    IntegrationTester.clearResults();
    setTests([]);
    toast.info('Resultados dos testes limpos');
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'success':
        return <CheckCircle className="w-4 h-4 text-green-600" />;
      case 'error':
        return <XCircle className="w-4 h-4 text-red-600" />;
      case 'running':
        return <Loader2 className="w-4 h-4 text-blue-600 animate-spin" />;
      default:
        return <Clock className="w-4 h-4 text-gray-400" />;
    }
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'success':
        return <Badge className="bg-green-100 text-green-800">Sucesso</Badge>;
      case 'error':
        return <Badge className="bg-red-100 text-red-800">Erro</Badge>;
      case 'running':
        return <Badge className="bg-blue-100 text-blue-800">Executando</Badge>;
      default:
        return <Badge variant="outline">Pendente</Badge>;
    }
  };

  const summary = IntegrationTester.getTestSummary();

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold flex items-center gap-2">
            <TestTube className="w-6 h-6" />
            Testes de Integra├º├úo
          </h2>
          <p className="text-muted-foreground">
            Verifique o funcionamento de todas as integra├º├Áes externas
          </p>
        </div>
        
        <div className="flex gap-2">
          <Button 
            variant="outline" 
            onClick={clearResults}
            disabled={isRunning}
          >
            <RefreshCw className="w-4 h-4 mr-2" />
            Limpar
          </Button>
          <Button 
            onClick={runAllTests}
            disabled={isRunning}
          >
            {isRunning ? (
              <>
                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                Executando...
              </>
            ) : (
              <>
                <Play className="w-4 h-4 mr-2" />
                Executar Todos
              </>
            )}
          </Button>
        </div>
      </div>

      {/* Resumo dos Testes */}
      {tests.length > 0 && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Activity className="w-5 h-5" />
              Resumo dos Testes
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="grid grid-cols-4 gap-4">
              <div className="text-center">
                <div className="text-2xl font-bold">{summary.total}</div>
                <div className="text-sm text-muted-foreground">Total</div>
              </div>
              <div className="text-center">
                <div className="text-2xl font-bold text-green-600">{summary.passed}</div>
                <div className="text-sm text-muted-foreground">Passaram</div>
              </div>
              <div className="text-center">
                <div className="text-2xl font-bold text-red-600">{summary.failed}</div>
                <div className="text-sm text-muted-foreground">Falharam</div>
              </div>
              <div className="text-center">
                <div className="text-2xl font-bold text-gray-600">{summary.pending}</div>
                <div className="text-sm text-muted-foreground">Pendentes</div>
              </div>
            </div>
            
            {summary.total > 0 && (
              <div className="mt-4">
                <Progress 
                  value={(summary.passed / summary.total) * 100} 
                  className="h-2"
                />
                <p className="text-sm text-muted-foreground mt-1">
                  {Math.round((summary.passed / summary.total) * 100)}% dos testes passaram
                </p>
              </div>
            )}
          </CardContent>
        </Card>
      )}

      {/* Lista de Testes */}
      <div className="grid gap-4">
        {[
          { id: 'payment', name: 'Gateway de Pagamento', description: 'Testar conex├úo com Asaas', icon: '­ƒÆ│' },
          { id: 'sms', name: 'SMS', description: 'Testar integra├º├úo com Twilio', icon: '­ƒô▒' },
          { id: 'email', name: 'Email', description: 'Testar integra├º├úo com Resend', icon: '­ƒôº' },
          { id: 'webhook', name: 'Webhooks', description: 'Testar webhooks configurados', icon: '­ƒöù' }
        ].map((testInfo) => {
          const test = tests.find(t => t.id === `${testInfo.id}-gateway` || t.id === `sms-${testInfo.id}` || t.id === `email-${testInfo.id}` || t.id === testInfo.id);
          
          return (
            <Card key={testInfo.id}>
              <CardContent className="p-6">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3 flex-1">
                    <div className="text-2xl">{testInfo.icon}</div>
                    <div className="flex-1">
                      <h3 className="font-semibold">{testInfo.name}</h3>
                      <p className="text-sm text-muted-foreground">{testInfo.description}</p>
                      
                      {test && (
                        <div className="mt-2 space-y-1">
                          <div className="flex items-center gap-2">
                            {getStatusIcon(test.status)}
                            {getStatusBadge(test.status)}
                            {test.duration && (
                              <span className="text-xs text-muted-foreground">
                                {test.duration}ms
                              </span>
                            )}
                          </div>
                          
                          {test.error && (
                            <p className="text-sm text-red-600">{test.error}</p>
                          )}
                          
                          {test.result && (
                            <div className="text-xs text-muted-foreground">
                              {Object.entries(test.result).map(([key, value]) => (
                                <div key={key}>
                                  <strong>{key}:</strong> {JSON.stringify(value)}
                                </div>
                              ))}
                            </div>
                          )}
                        </div>
                      )}
                    </div>
                  </div>
                  
                  <Button
                    size="sm"
                    variant="outline"
                    onClick={() => runSingleTest(testInfo.id)}
                    disabled={isRunning && currentTest !== testInfo.id}
                  >
                    {isRunning && currentTest === testInfo.id ? (
                      <Loader2 className="w-4 h-4 animate-spin" />
                    ) : (
                      <TestTube className="w-4 h-4" />
                    )}
                  </Button>
                </div>
              </CardContent>
            </Card>
          );
        })}
      </div>

      {tests.length === 0 && !isRunning && (
        <Card>
          <CardContent className="py-12 text-center">
            <TestTube className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
            <p className="text-muted-foreground mb-4">
              Nenhum teste executado ainda.
            </p>
            <Button onClick={runAllTests}>
              <Play className="w-4 h-4 mr-2" />
              Executar Primeiros Testes
            </Button>
          </CardContent>
        </Card>
      )}

      {isRunning && (
        <Card className="border-blue-200 bg-blue-50">
          <CardContent className="p-4">
            <div className="flex items-center gap-3">
              <Loader2 className="w-5 h-5 text-blue-600 animate-spin" />
              <div>
                <p className="font-medium text-blue-900">Executando testes...</p>
                <p className="text-sm text-blue-700">
                  {currentTest || 'Aguarde...'}
                </p>
              </div>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
};

import { useState, useEffect } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { 
  TrendingUp, 
  TrendingDown, 
  Users, 
  DollarSign, 
  Calendar, 
  Activity,
  CreditCard,
  Smartphone,
  Mail,
  MessageSquare,
  AlertTriangle,
  CheckCircle,
  Clock,
  BarChart3,
  PieChart,
  Target
} from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
const db = supabase as any;
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";

interface RealTimeMetrics {
  totalUsers: number;
  activeUsers: number;
  totalBarbershops: number;
  activeBarbershops: number;
  todayRevenue: number;
  monthRevenue: number;
  todayAppointments: number;
  monthAppointments: number;
  pendingPayments: number;
  failedWebhooks: number;
  systemHealth: 'healthy' | 'warning' | 'critical';
  lastUpdate: Date;
}

export const RealTimeMetricsPanel = () => {
  const [metrics, setMetrics] = useState<RealTimeMetrics>({
    totalUsers: 0,
    activeUsers: 0,
    totalBarbershops: 0,
    activeBarbershops: 0,
    todayRevenue: 0,
    monthRevenue: 0,
    todayAppointments: 0,
    monthAppointments: 0,
    pendingPayments: 0,
    failedWebhooks: 0,
    systemHealth: 'healthy',
    lastUpdate: new Date()
  });
  const [loading, setLoading] = useState(true);
  const [autoRefresh, setAutoRefresh] = useState(true);

  const fetchMetrics = async () => {
    setLoading(true);
    try {
      const today = format(new Date(), 'yyyy-MM-dd');
      const monthStart = format(new Date(new Date().getFullYear(), new Date().getMonth(), 1), 'yyyy-MM-dd');

      // Buscar m├®tricas em paralelo
      const [
        usersCount,
        activeUsersCount,
        barbershopsCount,
        activeBarbershopsCount,
        todayMetrics,
        monthMetrics,
        paymentsCount,
        webhooksCount
      ] = await Promise.all([
        // Total de usu├írios
        db.from('profiles').select('id', { count: 'exact' }),
        
        // Usu├írios ativos (├║ltimos 7 dias)
        db.from('profiles').select('id', { count: 'exact' })
          .gte('last_sign_in_at', new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString()),
        
        // Total de barbearias
        db.from('barbershops').select('id', { count: 'exact' }),
        
        // Barbearias ativas (com agendamentos nos ├║ltimos 30 dias)
        db.from('barbershops').select('id', { count: 'exact' })
          .in('id', 
            db.from('appointments').select('barbershop_id')
              .gte('scheduled_at', new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString())
          ),
        
        // M├®tricas de hoje
        db.from('daily_metrics').select('revenue, services_count, appointments_count')
          .eq('date', today),
        
        // M├®tricas do m├¬s
        db.from('daily_metrics').select('revenue, services_count, appointments_count')
          .gte('date', monthStart),
        
        // Pagamentos pendentes
        db.from('payments').select('id', { count: 'exact' })
          .eq('status', 'pending'),
        
        // Webhooks com falha nas ├║ltimas 24h
        db.from('webhook_logs').select('id', { count: 'exact' })
          .lt('response_status', 200)
          .gte('created_at', new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString())
      ]);

      // Calcular m├®tricas de hoje
      const todayData = todayMetrics.data?.[0] || { revenue: 0, services_count: 0, appointments_count: 0 };
      const monthData = monthMetrics.data?.reduce((acc, day) => ({
        revenue: acc.revenue + (day.revenue || 0),
        services_count: acc.services_count + (day.services_count || 0),
        appointments_count: acc.appointments_count + (day.appointments_count || 0)
      }), { revenue: 0, services_count: 0, appointments_count: 0 });

      // Determinar sa├║de do sistema
      let systemHealth: 'healthy' | 'warning' | 'critical' = 'healthy';
      if ((webhooksCount.count || 0) > 10) systemHealth = 'critical';
      else if ((webhooksCount.count || 0) > 5 || (paymentsCount.count || 0) > 100) systemHealth = 'warning';

      setMetrics({
        totalUsers: usersCount.count || 0,
        activeUsers: activeUsersCount.count || 0,
        totalBarbershops: barbershopsCount.count || 0,
        activeBarbershops: activeBarbershopsCount.count || 0,
        todayRevenue: todayData.revenue || 0,
        monthRevenue: monthData.revenue || 0,
        todayAppointments: todayData.appointments_count || 0,
        monthAppointments: monthData.appointments_count || 0,
        pendingPayments: paymentsCount.count || 0,
        failedWebhooks: webhooksCount.count || 0,
        systemHealth,
        lastUpdate: new Date()
      });
    } catch (error) {
      console.error('Erro ao buscar m├®tricas:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchMetrics();
    
    if (autoRefresh) {
      const interval = setInterval(fetchMetrics, 30000); // Atualizar a cada 30 segundos
      return () => clearInterval(interval);
    }
  }, [autoRefresh]);

  const getHealthColor = (health: string) => {
    switch (health) {
      case 'healthy':
        return 'bg-green-100 text-green-800';
      case 'warning':
        return 'bg-yellow-100 text-yellow-800';
      case 'critical':
        return 'bg-red-100 text-red-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const getHealthIcon = (health: string) => {
    switch (health) {
      case 'healthy':
        return <CheckCircle className="w-4 h-4" />;
      case 'warning':
        return <AlertTriangle className="w-4 h-4" />;
      case 'critical':
        return <AlertTriangle className="w-4 h-4" />;
      default:
        return <Clock className="w-4 h-4" />;
    }
  };

  const getChangeIcon = (current: number, previous: number) => {
    if (current > previous) return <TrendingUp className="w-4 h-4 text-green-600" />;
    if (current < previous) return <TrendingDown className="w-4 h-4 text-red-600" />;
    return <div className="w-4 h-4" />;
  };

  const formatCurrency = (value: number) => {
    return new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL'
    }).format(value);
  };

  if (loading) {
    return (
      <div className="flex justify-center py-12">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold flex items-center gap-2">
            <BarChart3 className="w-6 h-6" />
            M├®tricas em Tempo Real
          </h2>
          <p className="text-muted-foreground">
            Vis├úo geral do sistema em tempo real
          </p>
        </div>
        
        <div className="flex items-center gap-4">
          <Badge className={getHealthColor(metrics.systemHealth)}>
            {getHealthIcon(metrics.systemHealth)}
            Sistema {metrics.systemHealth === 'healthy' ? 'Saud├ível' : 
                    metrics.systemHealth === 'warning' ? 'Aten├º├úo' : 'Cr├¡tico'}
          </Badge>
          
          <div className="flex items-center gap-2 text-sm text-muted-foreground">
            <Clock className="w-4 h-4" />
            ├Ültima atualiza├º├úo: {format(metrics.lastUpdate, 'HH:mm:ss')}
          </div>
          
          <button
            onClick={() => setAutoRefresh(!autoRefresh)}
            className={`px-3 py-1 rounded text-sm ${
              autoRefresh 
                ? 'bg-green-100 text-green-800' 
                : 'bg-gray-100 text-gray-800'
            }`}
          >
            Auto-refresh: {autoRefresh ? 'ON' : 'OFF'}
          </button>
        </div>
      </div>

      {/* Cards Principais */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <Card>
          <CardHeader className="pb-2">
            <CardDescription>Usu├írios Totais</CardDescription>
            <CardTitle className="text-2xl">{metrics.totalUsers.toLocaleString()}</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="flex items-center gap-2 text-sm">
              <Users className="w-4 h-4 text-blue-600" />
              <span>{metrics.activeUsers} ativos esta semana</span>
              <Progress value={(metrics.activeUsers / metrics.totalUsers) * 100} className="h-1" />
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-2">
            <CardDescription>Barbearias</CardDescription>
            <CardTitle className="text-2xl">{metrics.totalBarbershops.toLocaleString()}</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="flex items-center gap-2 text-sm">
              <Target className="w-4 h-4 text-green-600" />
              <span>{metrics.activeBarbershops} ativas</span>
              <Progress value={(metrics.activeBarbershops / metrics.totalBarbershops) * 100} className="h-1" />
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-2">
            <CardDescription>Faturamento Hoje</CardDescription>
            <CardTitle className="text-2xl">{formatCurrency(metrics.todayRevenue)}</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="flex items-center gap-2 text-sm">
              <DollarSign className="w-4 h-4 text-green-600" />
              <span>{metrics.todayAppointments} atendimentos</span>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-2">
            <CardDescription>Faturamento Mensal</CardDescription>
            <CardTitle className="text-2xl">{formatCurrency(metrics.monthRevenue)}</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="flex items-center gap-2 text-sm">
              <Calendar className="w-4 h-4 text-blue-600" />
              <span>{metrics.monthAppointments} atendimentos</span>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* M├®tricas de Sistema */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <CreditCard className="w-5 h-5" />
              Pagamentos
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-2">
              <div className="flex justify-between">
                <span className="text-sm text-muted-foreground">Pendentes</span>
                <span className="font-semibold">{metrics.pendingPayments}</span>
              </div>
              {metrics.pendingPayments > 50 && (
                <Badge className="bg-yellow-100 text-yellow-800">
                  Aten├º├úo: Muitos pagamentos pendentes
                </Badge>
              )}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <MessageSquare className="w-5 h-5" />
              Webhooks
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-2">
              <div className="flex justify-between">
                <span className="text-sm text-muted-foreground">Falhas (24h)</span>
                <span className="font-semibold">{metrics.failedWebhooks}</span>
              </div>
              {metrics.failedWebhooks > 0 && (
                <Badge className="bg-red-100 text-red-800">
                  {metrics.failedWebhooks} falhas detectadas
                </Badge>
              )}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Activity className="w-5 h-5" />
              Sa├║de do Sistema
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-2">
              <div className="flex justify-between items-center">
                <span className="text-sm text-muted-foreground">Status</span>
                <Badge className={getHealthColor(metrics.systemHealth)}>
                  {getHealthIcon(metrics.systemHealth)}
                  {metrics.systemHealth === 'healthy' ? 'Saud├ível' : 
                   metrics.systemHealth === 'warning' ? 'Aten├º├úo' : 'Cr├¡tico'}
                </Badge>
              </div>
              <div className="text-xs text-muted-foreground">
                {metrics.systemHealth === 'healthy' && 'Todos os sistemas funcionando normalmente'}
                {metrics.systemHealth === 'warning' && 'Alguns sistemas precisam de aten├º├úo'}
                {metrics.systemHealth === 'critical' && 'Sistemas cr├¡ticos com problemas'}
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Gr├íficos (placeholders para implementa├º├úo futura) */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <PieChart className="w-5 h-5" />
              Distribui├º├úo de Usu├írios
            </CardTitle>
            <CardDescription>
              Usu├írios por tipo (Clientes, Profissionais, Donos, etc.)
            </CardDescription>
          </CardHeader>
          <CardContent>
            <div className="h-64 flex items-center justify-center text-muted-foreground">
              Gr├ífico em desenvolvimento...
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <TrendingUp className="w-5 h-5" />
              Crescimento Mensal
            </CardTitle>
            <CardDescription>
              Evolu├º├úo de usu├írios e faturamento
            </CardDescription>
          </CardHeader>
          <CardContent>
            <div className="h-64 flex items-center justify-center text-muted-foreground">
              Gr├ífico em desenvolvimento...
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
};

// @ts-nocheck
/**
 * RemarketingPanel ÔÇö Super Admin
 * Automa├º├Áes de remarketing: usu├írio inativo 1d/3d/7d
 * Usa m├│dulo de notifica├º├Áes e marketing existentes
 */
import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Bell, Mail, MessageCircle, Smartphone, Play, Pause, Clock, Users, Zap } from "lucide-react";
import { toast } from "sonner";
import { supabase } from "@/integrations/supabase/client";

interface AutomationRule {
  id: string;
  trigger: "1d" | "3d" | "7d" | "cadastro_sem_uso" | "pagamento_falhou";
  channel: "push" | "email" | "whatsapp";
  title: string;
  message: string;
  active: boolean;
}

const DEFAULT_RULES: AutomationRule[] = [
  {
    id: "1d_push",
    trigger: "1d",
    channel: "push",
    title: "Sentimos sua falta!",
    message: "Voc├¬ n├úo acessa o app h├í 1 dia. Que tal agendar hoje?",
    active: true,
  },
  {
    id: "3d_whatsapp",
    trigger: "3d",
    channel: "whatsapp",
    title: "Volte e ganhe desconto",
    message: "Ol├í! Faz 3 dias que voc├¬ n├úo usa o app. Temos uma oferta especial esperando por voc├¬.",
    active: true,
  },
  {
    id: "7d_email",
    trigger: "7d",
    channel: "email",
    title: "Voc├¬ est├í perdendo muito!",
    message: "Faz 7 dias sem atividade. Veja o que h├í de novo no sistema.",
    active: false,
  },
  {
    id: "cadastro_sem_uso",
    trigger: "cadastro_sem_uso",
    channel: "push",
    title: "Complete seu cadastro",
    message: "Voc├¬ se cadastrou mas ainda n├úo usou o sistema. Vamos come├ºar?",
    active: true,
  },
  {
    id: "pagamento_falhou",
    trigger: "pagamento_falhou",
    channel: "whatsapp",
    title: "Problema no pagamento",
    message: "Identificamos um problema no seu pagamento. Clique aqui para resolver.",
    active: true,
  },
];

const TRIGGER_LABELS: Record<string, string> = {
  "1d": "1 dia sem uso",
  "3d": "3 dias sem uso",
  "7d": "7 dias sem uso",
  "cadastro_sem_uso": "Cadastrou e n├úo usou",
  "pagamento_falhou": "Pagamento falhou",
};

const CHANNEL_ICONS: Record<string, React.ReactNode> = {
  push: <Smartphone className="w-4 h-4" />,
  email: <Mail className="w-4 h-4" />,
  whatsapp: <MessageCircle className="w-4 h-4" />,
};

export function RemarketingPanel() {
  const [rules, setRules] = useState<AutomationRule[]>(DEFAULT_RULES);
  const [editing, setEditing] = useState<string | null>(null);
  const [running, setRunning] = useState(false);

  const toggleRule = (id: string) => {
    setRules(prev =>
      prev.map(r => (r.id === id ? { ...r, active: !r.active } : r))
    );
    toast.success("Automa├º├úo atualizada");
  };

  const updateMessage = (id: string, message: string) => {
    setRules(prev => prev.map(r => (r.id === id ? { ...r, message } : r)));
  };

  const runManual = async (rule: AutomationRule) => {
    setRunning(true);
    try {
      // Buscar usu├írios inativos e disparar notifica├º├úo
      const { data: users } = await (supabase as any)
        .from("profiles")
        .select("user_id, name")
        .limit(50);

      let sent = 0;
      for (const user of users || []) {
        await (supabase as any).from("notifications").insert({
          user_id: user.user_id,
          title: rule.title,
          message: rule.message,
          type: "info",
          read: false,
        });
        sent++;
      }

      toast.success(`Disparado para ${sent} usu├írios`);
    } catch {
      toast.error("Erro ao disparar automa├º├úo");
    } finally {
      setRunning(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-xl font-bold flex items-center gap-2">
            <Zap className="w-5 h-5 text-primary" />
            Remarketing Inteligente
          </h2>
          <p className="text-sm text-muted-foreground mt-1">
            Automa├º├Áes de reengajamento por inatividade
          </p>
        </div>
        <Badge variant="outline" className="gap-1">
          <Users className="w-3 h-3" />
          {rules.filter(r => r.active).length} ativas
        </Badge>
      </div>

      <div className="grid gap-4">
        {rules.map(rule => (
          <Card key={rule.id} className={rule.active ? "border-primary/30" : "opacity-60"}>
            <CardHeader className="pb-3">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  {CHANNEL_ICONS[rule.channel]}
                  <CardTitle className="text-sm font-semibold">{rule.title}</CardTitle>
                  <Badge variant="secondary" className="text-xs">
                    <Clock className="w-3 h-3 mr-1" />
                    {TRIGGER_LABELS[rule.trigger]}
                  </Badge>
                </div>
                <div className="flex items-center gap-2">
                  <Switch
                    checked={rule.active}
                    onCheckedChange={() => toggleRule(rule.id)}
                  />
                  <Button
                    size="sm"
                    variant="outline"
                    onClick={() => runManual(rule)}
                    disabled={running || !rule.active}
                  >
                    <Play className="w-3 h-3 mr-1" />
                    Disparar
                  </Button>
                </div>
              </div>
            </CardHeader>
            <CardContent className="pt-0">
              {editing === rule.id ? (
                <div className="space-y-2">
                  <Textarea
                    value={rule.message}
                    onChange={e => updateMessage(rule.id, e.target.value)}
                    rows={2}
                    className="text-sm"
                  />
                  <Button size="sm" onClick={() => setEditing(null)}>Salvar</Button>
                </div>
              ) : (
                <p
                  className="text-sm text-muted-foreground cursor-pointer hover:text-foreground transition-colors"
                  onClick={() => setEditing(rule.id)}
                >
                  {rule.message}
                </p>
              )}
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Fluxo p├│s-cadastro */}
      <Card>
        <CardHeader>
          <CardTitle className="text-sm flex items-center gap-2">
            <Bell className="w-4 h-4" />
            Fluxo P├│s-Cadastro
          </CardTitle>
          <CardDescription>
            Sequ├¬ncia autom├ítica ap├│s novo cadastro
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="space-y-2 text-sm">
            {[
              { step: 1, delay: "Imediato", msg: "Boas-vindas + tutorial" },
              { step: 2, delay: "24h", msg: "Lembrete de configurar perfil" },
              { step: 3, delay: "3 dias", msg: "Dicas de uso do sistema" },
              { step: 4, delay: "7 dias", msg: "Oferta especial de upgrade" },
            ].map(item => (
              <div key={item.step} className="flex items-center gap-3 p-2 rounded-lg bg-muted/40">
                <Badge variant="outline" className="w-6 h-6 flex items-center justify-center p-0 text-xs">
                  {item.step}
                </Badge>
                <span className="text-muted-foreground w-20 shrink-0">{item.delay}</span>
                <span>{item.msg}</span>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import { useState, useEffect } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { toast } from "sonner";
import { supabase } from "@/integrations/supabase/client";
const db = supabase as any;
import { 
  Webhook, 
  RefreshCw, 
  Copy, 
  Eye, 
  EyeOff, 
  CheckCircle, 
  XCircle, 
  Loader2,
  Key,
  Link as LinkIcon,
  TestTube
} from "lucide-react";

interface WebhookConfig {
  id: string;
  service_name: string;
  webhook_url: string;
  webhook_secret: string;
  is_active: boolean;
  last_triggered: string | null;
  last_success: string | null;
  created_at: string;
  updated_at: string;
}

export const WebhookManagementPanel = () => {
  const [webhooks, setWebhooks] = useState<WebhookConfig[]>([]);
  const [loading, setLoading] = useState(true);
  const [showSecret, setShowSecret] = useState<{ [key: string]: boolean }>({});
  const [editingWebhook, setEditingWebhook] = useState<WebhookConfig | null>(null);
  const [saving, setSaving] = useState(false);
  const [testing, setTesting] = useState<{ [key: string]: boolean }>({});

  const loadWebhooks = async () => {
    setLoading(true);
    try {
      const { data, error } = await db
        .from("webhook_configs")
        .select("*")
        .order("service_name");

      if (error) throw error;
      setWebhooks(data || []);
    } catch (error: any) {
      console.error("Erro ao carregar webhooks:", error);
      toast.error("Erro ao carregar webhooks");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadWebhooks();
  }, []);

  const generateSecret = () => {
    const array = new Uint8Array(32);
    crypto.getRandomValues(array);
    return Array.from(array, byte => byte.toString(16).padStart(2, '0')).join('');
  };

  const saveWebhook = async () => {
    if (!editingWebhook) return;

    setSaving(true);
    try {
      const webhookData = {
        service_name: editingWebhook.service_name,
        webhook_url: editingWebhook.webhook_url,
        webhook_secret: editingWebhook.webhook_secret || generateSecret(),
        is_active: editingWebhook.is_active,
        updated_at: new Date().toISOString()
      };

      if (editingWebhook.id) {
        const { error } = await db
          .from("webhook_configs")
          .update(webhookData)
          .eq("id", editingWebhook.id);

        if (error) throw error;
        toast.success("Webhook atualizado com sucesso!");
      } else {
        const { error } = await db
          .from("webhook_configs")
          .insert(webhookData);

        if (error) throw error;
        toast.success("Webhook criado com sucesso!");
      }

      setEditingWebhook(null);
      loadWebhooks();
    } catch (error: any) {
      console.error("Erro ao salvar webhook:", error);
      toast.error(error.message || "Erro ao salvar webhook");
    } finally {
      setSaving(false);
    }
  };

  const regenerateSecret = async (webhook: WebhookConfig) => {
    try {
      const newSecret = generateSecret();
      const { error } = await db
        .from("webhook_configs")
        .update({
          webhook_secret: newSecret,
          updated_at: new Date().toISOString()
        })
        .eq("id", webhook.id);

      if (error) throw error;
      
      toast.success("Segredo do webhook regenerado!");
      loadWebhooks();
    } catch (error: any) {
      console.error("Erro ao regenerar segredo:", error);
      toast.error("Erro ao regenerar segredo");
    }
  };

  const testWebhook = async (webhook: WebhookConfig) => {
    setTesting({ ...testing, [webhook.id]: true });
    try {
      const testPayload = {
        event: "test",
        timestamp: new Date().toISOString(),
        data: {
          message: "Webhook test realizado com sucesso!",
          service: webhook.service_name
        }
      };

      const response = await fetch(webhook.webhook_url, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'X-Webhook-Secret': webhook.webhook_secret
        },
        body: JSON.stringify(testPayload)
      });

      if (response.ok) {
        toast.success("Webhook testado com sucesso!");
        
        await db
          .from("webhook_configs")
          .update({
            last_success: new Date().toISOString(),
            last_triggered: new Date().toISOString()
          })
          .eq("id", webhook.id);
        
        loadWebhooks();
      } else {
        throw new Error(`Status: ${response.status}`);
      }
    } catch (error: any) {
      console.error("Erro ao testar webhook:", error);
      toast.error(`Erro no teste: ${error.message}`);
    } finally {
      setTesting({ ...testing, [webhook.id]: false });
    }
  };

  const toggleWebhook = async (webhook: WebhookConfig) => {
    try {
      const { error } = await db
        .from("webhook_configs")
        .update({
          is_active: !webhook.is_active,
          updated_at: new Date().toISOString()
        })
        .eq("id", webhook.id);

      if (error) throw error;
      
      toast.success(`Webhook ${!webhook.is_active ? 'ativado' : 'desativado'}!`);
      loadWebhooks();
    } catch (error: any) {
      console.error("Erro ao alternar webhook:", error);
      toast.error("Erro ao alterar webhook");
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    toast.success("Copiado para a ├írea de transfer├¬ncia!");
  };

  const getStatusBadge = (webhook: WebhookConfig) => {
    if (!webhook.is_active) {
      return <Badge variant="secondary">Inativo</Badge>;
    }
    
    if (webhook.last_success) {
      const lastSuccess = new Date(webhook.last_success);
      const now = new Date();
      const diffHours = (now.getTime() - lastSuccess.getTime()) / (1000 * 60 * 60);
      
      if (diffHours < 24) {
        return <Badge className="bg-green-100 text-green-800">Funcionando</Badge>;
      }
    }
    
    return <Badge variant="outline">Sem resposta recente</Badge>;
  };

  if (loading) {
    return (
      <div className="flex justify-center py-12">
        <Loader2 className="w-8 h-8 animate-spin" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold flex items-center gap-2">
            <Webhook className="w-6 h-6" />
            Gest├úo de Webhooks
          </h2>
          <p className="text-muted-foreground">
            Configure e monitore os webhooks do sistema
          </p>
        </div>
        
        <Button onClick={() => setEditingWebhook({
          id: '',
          service_name: '',
          webhook_url: '',
          webhook_secret: '',
          is_active: true,
          last_triggered: null,
          last_success: null,
          created_at: '',
          updated_at: ''
        })}>
          <LinkIcon className="w-4 h-4 mr-2" />
          Novo Webhook
        </Button>
      </div>

      {/* Lista de Webhooks */}
      <div className="grid gap-4">
        {webhooks.map((webhook) => (
          <Card key={webhook.id}>
            <CardContent className="p-6">
              <div className="flex items-start justify-between">
                <div className="space-y-3 flex-1">
                  <div className="flex items-center gap-3">
                    <h3 className="font-semibold text-lg">{webhook.service_name}</h3>
                    {getStatusBadge(webhook)}
                  </div>
                  
                  <div className="space-y-2">
                    <div className="flex items-center gap-2">
                      <Label className="text-sm text-muted-foreground">URL:</Label>
                      <div className="flex items-center gap-2 flex-1">
                        <Input
                          value={webhook.webhook_url}
                          readOnly
                          className="font-mono text-sm"
                        />
                        <Button
                          variant="outline"
                          size="sm"
                          onClick={() => copyToClipboard(webhook.webhook_url)}
                        >
                          <Copy className="w-4 h-4" />
                        </Button>
                      </div>
                    </div>
                    
                    <div className="flex items-center gap-2">
                      <Label className="text-sm text-muted-foreground">Segredo:</Label>
                      <div className="flex items-center gap-2 flex-1">
                        <Input
                          type={showSecret[webhook.id] ? "text" : "password"}
                          value={webhook.webhook_secret}
                          readOnly
                          className="font-mono text-sm"
                        />
                        <Button
                          variant="outline"
                          size="sm"
                          onClick={() => setShowSecret({
                            ...showSecret,
                            [webhook.id]: !showSecret[webhook.id]
                          })}
                        >
                          {showSecret[webhook.id] ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                        </Button>
                        <Button
                          variant="outline"
                          size="sm"
                          onClick={() => copyToClipboard(webhook.webhook_secret)}
                        >
                          <Copy className="w-4 h-4" />
                        </Button>
                      </div>
                    </div>
                  </div>

                  <div className="flex items-center gap-4 text-sm text-muted-foreground">
                    {webhook.last_triggered && (
                      <span>├Ültimo disparo: {new Date(webhook.last_triggered).toLocaleString('pt-BR')}</span>
                    )}
                    {webhook.last_success && (
                      <span className="flex items-center gap-1">
                        <CheckCircle className="w-3 h-3 text-green-600" />
                        ├Ültimo sucesso: {new Date(webhook.last_success).toLocaleString('pt-BR')}
                      </span>
                    )}
                  </div>
                </div>

                <div className="flex flex-col gap-2 ml-4">
                  <Button
                    size="sm"
                    variant={webhook.is_active ? "default" : "outline"}
                    onClick={() => toggleWebhook(webhook)}
                  >
                    {webhook.is_active ? "Desativar" : "Ativar"}
                  </Button>
                  
                  <Button
                    size="sm"
                    variant="outline"
                    onClick={() => testWebhook(webhook)}
                    disabled={testing[webhook.id]}
                  >
                    {testing[webhook.id] ? (
                      <Loader2 className="w-4 h-4 animate-spin" />
                    ) : (
                      <TestTube className="w-4 h-4" />
                    )}
                  </Button>
                  
                  <Button
                    size="sm"
                    variant="outline"
                    onClick={() => regenerateSecret(webhook)}
                  >
                    <Key className="w-4 h-4 mr-1" />
                    Regenerar
                  </Button>
                  
                  <Button
                    size="sm"
                    variant="outline"
                    onClick={() => setEditingWebhook(webhook)}
                  >
                    Editar
                  </Button>
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {webhooks.length === 0 && (
        <Card>
          <CardContent className="py-12 text-center">
            <Webhook className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
            <p className="text-muted-foreground">Nenhum webhook configurado.</p>
            <Button 
              variant="outline" 
              className="mt-4"
              onClick={() => setEditingWebhook({
                id: '',
                service_name: '',
                webhook_url: '',
                webhook_secret: '',
                is_active: true,
                last_triggered: null,
                last_success: null,
                created_at: '',
                updated_at: ''
              })}
            >
              Criar primeiro webhook
            </Button>
          </CardContent>
        </Card>
      )}

      {/* Modal de Edi├º├úo */}
      {editingWebhook && (
        <Card className="border-primary/20 bg-primary/5">
          <CardHeader>
            <CardTitle>
              {editingWebhook.id ? "Editar Webhook" : "Novo Webhook"}
            </CardTitle>
            <CardDescription>
              Configure as informa├º├Áes do webhook
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>Nome do Servi├ºo</Label>
                <Input
                  value={editingWebhook.service_name}
                  onChange={(e) => setEditingWebhook({
                    ...editingWebhook,
                    service_name: e.target.value
                  })}
                  placeholder="Ex: Asaas, Twilio"
                />
              </div>
              
              <div className="space-y-2">
                <Label>URL do Webhook</Label>
                <Input
                  value={editingWebhook.webhook_url}
                  onChange={(e) => setEditingWebhook({
                    ...editingWebhook,
                    webhook_url: e.target.value
                  })}
                  placeholder="https://sua-api.com/webhook"
                />
              </div>
            </div>

            <div className="flex items-center space-x-2">
              <input
                type="checkbox"
                id="active"
                checked={editingWebhook.is_active}
                onChange={(e) => setEditingWebhook({
                  ...editingWebhook,
                  is_active: e.target.checked
                })}
                className="rounded"
              />
              <Label htmlFor="active">Webhook ativo</Label>
            </div>

            <div className="flex gap-2 pt-4">
              <Button 
                onClick={saveWebhook} 
                disabled={saving || !editingWebhook.service_name || !editingWebhook.webhook_url}
              >
                {saving ? (
                  <>
                    <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                    Salvando...
                  </>
                ) : (
                  "Salvar"
                )}
              </Button>
              <Button 
                variant="outline" 
                onClick={() => setEditingWebhook(null)}
              >
                Cancelar
              </Button>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
};

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Switch } from "@/components/ui/switch";
import { Textarea } from "@/components/ui/textarea";
import { Button } from "@/components/ui/button";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Badge } from "@/components/ui/badge";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "@/hooks/use-toast";
import { Bot, Mic, MessageSquare, Volume2, Settings2, Zap } from "lucide-react";

interface AIAudioConfigPanelProps {
  barbershopId: string;
}

interface AIConfig {
  response_type: string;
  personality: string;
  voice_id: string | null;
  language: string;
  auto_booking: boolean;
  auto_register_client: boolean;
  auto_reactivation: boolean;
  auto_billing: boolean;
  greeting_message: string;
}

const defaultConfig: AIConfig = {
  response_type: "text",
  personality: "friendly",
  voice_id: null,
  language: "pt-BR",
  auto_booking: true,
  auto_register_client: true,
  auto_reactivation: true,
  auto_billing: false,
  greeting_message: "Ol├í! Sou o assistente virtual. Como posso ajudar?",
};

export function AIAudioConfigPanel({ barbershopId }: AIAudioConfigPanelProps) {
  const [config, setConfig] = useState<AIConfig>(defaultConfig);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    const loadConfig = async () => {
      try {
        const { data, error } = await (supabase as any)
          .from("ai_config")
          .select("*")
          .eq("barbershop_id", barbershopId)
          .maybeSingle();

        if (data) {
          setConfig({
            response_type: data.response_type,
            personality: data.personality,
            voice_id: data.voice_id,
            language: data.language,
            auto_booking: data.auto_booking,
            auto_register_client: data.auto_register_client,
            auto_reactivation: data.auto_reactivation,
            auto_billing: data.auto_billing,
            greeting_message: data.greeting_message,
          });
        }
      } catch (err) {
        console.error("Error loading AI config:", err);
      } finally {
        setLoading(false);
      }
    };
    loadConfig();
  }, [barbershopId]);

  const saveConfig = async () => {
    setSaving(true);
    try {
      const { error } = await (supabase as any)
        .from("ai_config")
        .upsert({
          barbershop_id: barbershopId,
          ...config,
          updated_at: new Date().toISOString(),
        }, { onConflict: "barbershop_id" });

      if (error) throw error;
      toast({ title: "Configura├º├Áes salvas!", description: "A IA foi atualizada com sucesso." });
    } catch (err: any) {
      toast({ title: "Erro ao salvar", description: err.message, variant: "destructive" });
    } finally {
      setSaving(false);
    }
  };

  if (loading) {
    return <div className="flex items-center justify-center p-8"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary" /></div>;
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold flex items-center gap-2">
            <Bot className="w-6 h-6 text-primary" />
            Assistente Inteligente
          </h2>
          <p className="text-muted-foreground">Configure a IA de atendimento autom├ítico do seu neg├│cio</p>
        </div>
        <Button onClick={saveConfig} disabled={saving}>
          {saving ? "Salvando..." : "Salvar Configura├º├Áes"}
        </Button>
      </div>

      <Tabs defaultValue="response">
        <TabsList className="grid w-full grid-cols-3">
          <TabsTrigger value="response"><MessageSquare className="w-4 h-4 mr-1" />Resposta</TabsTrigger>
          <TabsTrigger value="automation"><Zap className="w-4 h-4 mr-1" />Automa├º├Áes</TabsTrigger>
          <TabsTrigger value="voice"><Volume2 className="w-4 h-4 mr-1" />Voz</TabsTrigger>
        </TabsList>

        <TabsContent value="response" className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle className="text-lg">Tipo de Resposta</CardTitle>
              <CardDescription>Como a IA deve responder aos clientes no WhatsApp</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label>Formato de resposta</Label>
                <Select value={config.response_type} onValueChange={(v) => setConfig(p => ({ ...p, response_type: v }))}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="text">­ƒôØ Apenas Texto</SelectItem>
                    <SelectItem value="audio">­ƒÄñ Apenas ├üudio</SelectItem>
                    <SelectItem value="auto">­ƒñû Autom├ítico (detecta se cliente enviou ├íudio)</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label>Personalidade da IA</Label>
                <Select value={config.personality} onValueChange={(v) => setConfig(p => ({ ...p, personality: v }))}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="formal">­ƒæö Formal e Profissional</SelectItem>
                    <SelectItem value="friendly">­ƒÿè Amig├ível e Caloroso</SelectItem>
                    <SelectItem value="premium">Ô£¿ Premium e Exclusivo</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label>Mensagem de Boas-vindas</Label>
                <Textarea
                  value={config.greeting_message}
                  onChange={(e) => setConfig(p => ({ ...p, greeting_message: e.target.value }))}
                  placeholder="Mensagem inicial quando o cliente entra em contato"
                  rows={3}
                />
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="automation" className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle className="text-lg">Fun├º├Áes Autom├íticas</CardTitle>
              <CardDescription>O que a IA pode fazer automaticamente</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              {[
                { key: "auto_booking" as const, label: "Agendamento Autom├ítico", desc: "IA pode marcar hor├írios diretamente", icon: "­ƒôà" },
                { key: "auto_register_client" as const, label: "Cadastro de Clientes", desc: "Registrar novos clientes durante conversa", icon: "­ƒæñ" },
                { key: "auto_reactivation" as const, label: "Reativa├º├úo de Inativos", desc: "Enviar mensagens para clientes que n├úo voltaram", icon: "­ƒöä" },
                { key: "auto_billing" as const, label: "Envio de Cobran├ºas", desc: "Gerar e enviar links de pagamento", icon: "­ƒÆ░" },
              ].map(item => (
                <div key={item.key} className="flex items-center justify-between p-3 rounded-lg border">
                  <div className="flex items-center gap-3">
                    <span className="text-xl">{item.icon}</span>
                    <div>
                      <p className="font-medium">{item.label}</p>
                      <p className="text-sm text-muted-foreground">{item.desc}</p>
                    </div>
                  </div>
                  <Switch
                    checked={config[item.key]}
                    onCheckedChange={(v) => setConfig(p => ({ ...p, [item.key]: v }))}
                  />
                </div>
              ))}
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="voice" className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle className="text-lg flex items-center gap-2">
                <Mic className="w-5 h-5" />
                Configura├º├úo de Voz
              </CardTitle>
              <CardDescription>Personalize a voz da IA para respostas em ├íudio</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label>Voz (OpenAI TTS)</Label>
                <Select value={config.voice_id || "nova"} onValueChange={(v) => setConfig(p => ({ ...p, voice_id: v }))}>
