import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { toast } from "sonner";
import { supabase } from "@/integrations/supabase/client";
const db = supabase as any;
import { 
  CreditCard, 
  DollarSign, 
  QrCode, 
  Smartphone, 
  CheckCircle, 
  Loader2,
  Calendar,
  User,
  Scissors
} from "lucide-react";

interface Appointment {
  id: string;
  client_name: string;
  client_user_id?: string;
  service_id: string;
  professional_id: string;
  barbershop_id: string;
  scheduled_at: string;
  status: string;
  services?: {
    name: string;
    price: number;
    duration_minutes: number;
  };
  professionals?: {
    name: string;
    commission_percent: number;
  };
}

interface FinalizarAtendimentoModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  appointment: Appointment | null;
  onSuccess: () => void;
}

export const FinalizarAtendimentoModal = ({ 
  open, 
  onOpenChange, 
  appointment, 
  onSuccess 
}: FinalizarAtendimentoModalProps) => {
  const [paymentMethod, setPaymentMethod] = useState<"cash" | "pix">("cash");
  const [amount, setAmount] = useState("");
  const [loading, setLoading] = useState(false);
  const [pixGenerated, setPixGenerated] = useState(false);
  const [pixData, setPixData] = useState<any>(null);

  useEffect(() => {
    if (appointment?.services?.price) {
      setAmount(appointment.services.price.toString());
    }
  }, [appointment]);

  const handleFinalize = async () => {
    if (!appointment || !amount) {
      toast.error("Informe o valor do atendimento");
      return;
    }

    setLoading(true);

    try {
      // 1. Atualizar status do agendamento
      const { error: appointmentError } = await (supabase as any)
        .from("appointments")
        .update({ 
          status: "completed",
          updated_at: new Date().toISOString()
        })
        .eq("id", appointment.id);

      if (appointmentError) {
        throw appointmentError;
      }

      // 2. Registrar pagamento
      const paymentData: any = {
        appointment_id: appointment.id,
        barbershop_id: appointment.barbershop_id,
        client_user_id: appointment.client_user_id,
        amount: Number(amount),
        payment_method: paymentMethod === "cash" ? "cash" : "pix",
        status: paymentMethod === "cash" ? "paid" : "pending",
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString()
      };

      if (paymentMethod === "cash") {
        paymentData.paid_at = new Date().toISOString();
      }

      const { data: payment, error: paymentError } = await (supabase as any)
        .from("payments")
        .insert(paymentData)
        .select()
        .single();

      if (paymentError) {
        throw paymentError;
      }

      // 3. Calcular e registrar comiss├úo do profissional
      if (appointment.professionals?.commission_percent) {
        const commissionAmount = (Number(amount) * appointment.professionals.commission_percent) / 100;
        
        await db
          .from("professional_commissions")
          .insert({
            professional_id: appointment.professional_id,
            appointment_id: appointment.id,
            payment_id: payment.id,
            commission_percent: appointment.professionals.commission_percent,
            commission_amount: commissionAmount,
            total_amount: Number(amount),
            status: "pending",
            created_at: new Date().toISOString()
          });
      }

      // 4. Atualizar m├®tricas da barbearia
      const today = new Date().toISOString().split('T')[0];
      await db.rpc('update_daily_metrics', {
        p_barbershop_id: appointment.barbershop_id,
        p_date: today,
        p_revenue: Number(amount),
        p_services_count: 1,
        p_appointments_count: 1,
        p_clients_count: 1,
        p_cash_revenue: paymentMethod === "cash" ? Number(amount) : 0,
        p_pix_revenue: paymentMethod === "pix" ? Number(amount) : 0
      });

      // 5. Gerar PIX se m├®todo for PIX
      if (paymentMethod === "pix") {
        const { data: pixResponse, error: pixError } = await supabase.functions.invoke('process-payment', {
          body: {
            amount: Number(amount),
            description: `Atendimento: ${appointment.services?.name || 'Servi├ºo'}`,
            customerInfo: {
              name: appointment.client_name,
              email: "cliente@example.com"
            },
            paymentMethod: "pix"
          }
        });

        if (pixError) {
          throw pixError;
        }

        setPixData(pixResponse);
        setPixGenerated(true);

        // Atualizar pagamento com dados do PIX
        await (supabase as any)
          .from("payments")
          .update({
            asaas_payment_id: pixResponse.paymentId,
            asaas_pix_qr_code: pixResponse.qrCode?.encodedImage,
            asaas_pix_copy_paste: pixResponse.qrCode?.payload,
            split_data: pixResponse.splitData
          })
          .eq("id", payment.id);
      } else {
        // Pagamento em dinheiro j├í conclu├¡do
        toast.success("Atendimento finalizado com sucesso!");
        onSuccess();
        onOpenChange(false);
      }

    } catch (error: any) {
      console.error("Erro ao finalizar atendimento:", error);
      toast.error(error.message || "Erro ao finalizar atendimento");
    } finally {
      setLoading(false);
    }
  };

  const handleConfirmPayment = async () => {
    if (!pixData?.paymentId) return;

    setLoading(true);
    try {
      // Verificar status do pagamento no Asaas
      const { data: statusResponse, error: statusError } = await supabase.functions.invoke('check-payment-status', {
        body: { paymentId: pixData.paymentId }
      });

      if (statusError) {
        throw statusError;
      }

      if (statusResponse.status === 'CONFIRMED' || statusResponse.status === 'RECEIVED') {
        // Atualizar pagamento como confirmado
        await (supabase as any)
          .from("payments")
          .update({
            status: "paid",
            paid_at: new Date().toISOString()
          })
          .eq("appointment_id", appointment?.id);

        toast.success("Pagamento PIX confirmado!");
        onSuccess();
        onOpenChange(false);
      } else {
        toast.error("Pagamento ainda n├úo confirmado. Aguarde o cliente pagar.");
      }
    } catch (error: any) {
      console.error("Erro ao confirmar pagamento:", error);
      toast.error(error.message || "Erro ao verificar pagamento");
    } finally {
      setLoading(false);
    }
  };

  if (!appointment) return null;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-md">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <CheckCircle className="w-5 h-5 text-green-600" />
            Finalizar Atendimento
          </DialogTitle>
        </DialogHeader>

        <div className="space-y-4">
          {/* Informa├º├Áes do atendimento */}
          <Card>
            <CardContent className="pt-4">
              <div className="space-y-2">
                <div className="flex items-center gap-2">
                  <User className="w-4 h-4 text-muted-foreground" />
                  <span className="font-medium">{appointment.client_name}</span>
                </div>
                <div className="flex items-center gap-2">
                  <Scissors className="w-4 h-4 text-muted-foreground" />
                  <span className="text-sm">{appointment.services?.name || "Servi├ºo"}</span>
                </div>
                <div className="flex items-center gap-2">
                  <Calendar className="w-4 h-4 text-muted-foreground" />
                  <span className="text-sm">
                    {new Date(appointment.scheduled_at).toLocaleDateString('pt-BR', {
                      day: '2-digit',
                      month: '2-digit',
                      hour: '2-digit',
                      minute: '2-digit'
                    })}
                  </span>
                </div>
              </div>
            </CardContent>
          </Card>

          {!pixGenerated ? (
            <>
              {/* Forma de pagamento */}
              <div className="space-y-2">
                <Label>Forma de Pagamento</Label>
                <RadioGroup value={paymentMethod} onValueChange={(value: "cash" | "pix") => setPaymentMethod(value)}>
                  <div className="flex items-center space-x-2 p-3 border rounded-lg">
                    <RadioGroupItem value="cash" id="cash" />
                    <Label htmlFor="cash" className="flex items-center gap-2 cursor-pointer">
                      <DollarSign className="w-4 h-4" />
                      Dinheiro
                    </Label>
                  </div>
                  <div className="flex items-center space-x-2 p-3 border rounded-lg">
                    <RadioGroupItem value="pix" id="pix" />
                    <Label htmlFor="pix" className="flex items-center gap-2 cursor-pointer">
                      <QrCode className="w-4 h-4" />
                      PIX
                    </Label>
                  </div>
                </RadioGroup>
              </div>

              {/* Valor */}
              <div className="space-y-2">
                <Label htmlFor="amount">Valor do Atendimento (R$)</Label>
                <Input
                  id="amount"
                  type="number"
                  step="0.01"
                  placeholder="0,00"
                  value={amount}
                  onChange={(e) => setAmount(e.target.value)}
                />
              </div>

              {/* Bot├úo finalizar */}
              <Button 
                onClick={handleFinalize} 
                disabled={loading || !amount}
                className="w-full"
              >
                {loading ? (
                  <>
                    <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                    Processando...
                  </>
                ) : (
                  <>
                    <CheckCircle className="w-4 h-4 mr-2" />
                    Finalizar Atendimento
                  </>
                )}
              </Button>
            </>
          ) : (
            <>
              {/* PIX gerado */}
              <Card>
                <CardHeader>
                  <CardTitle className="text-center">QR Code PIX</CardTitle>
                  <CardDescription className="text-center">
                    Escaneie o QR Code ou copie o c├│digo PIX
                  </CardDescription>
                </CardHeader>
                <CardContent className="space-y-4">
                  {pixData?.qrCode?.encodedImage && (
                    <div className="flex justify-center">
                      <img 
                        src={`data:image/png;base64,${pixData.qrCode.encodedImage}`}
                        alt="QR Code PIX"
                        className="w-48 h-48"
                      />
                    </div>
                  )}
                  
                  {pixData?.qrCode?.payload && (
                    <div className="space-y-2">
                      <Label>C├│digo PIX (Copiar e Colar)</Label>
                      <div className="flex gap-2">
                        <Input 
                          value={pixData.qrCode.payload}
                          readOnly
                          className="text-xs"
                        />
                        <Button
                          variant="outline"
                          size="sm"
                          onClick={() => {
                            navigator.clipboard.writeText(pixData.qrCode.payload);
                            toast.success("C├│digo PIX copiado!");
                          }}
                        >
                          Copiar
                        </Button>
                      </div>
                    </div>
                  )}

                  <div className="text-center text-sm text-muted-foreground">
                    Valor: R$ {Number(amount).toFixed(2)}
                  </div>
                </CardContent>
              </Card>

              {/* Bot├Áes de a├º├úo */}
              <div className="space-y-2">
                <Button 
                  onClick={handleConfirmPayment} 
                  disabled={loading}
                  className="w-full"
                >
                  {loading ? (
                    <>
                      <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                      Verificando...
                    </>
                  ) : (
                    <>
                      <CheckCircle className="w-4 h-4 mr-2" />
                      Confirmar Pagamento
                    </>
                  )}
                </Button>
                
                <Button 
                  variant="outline" 
                  onClick={() => {
                    setPixGenerated(false);
                    setPixData(null);
                  }}
                  className="w-full"
                >
                  Voltar
                </Button>
              </div>
            </>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
};

import { useState, useEffect } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { 
  Settings, 
  Calendar, 
  Bell, 
  Shield, 
  AlertTriangle, 
  CheckCircle, 
  Info,
  Users,
  BarChart3,
  Eye,
  EyeOff
} from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
const db = supabase as any;
import { toast } from "sonner";
import { useBarbershop } from "@/hooks/useBarbershop";

interface AutomationSettings {
  blockIfHasAppointment: boolean;
  blockOnlyConfirmed: boolean;
  enableLogging: boolean;
  notifyOnBlock: boolean;
}

interface BlockedLog {
  id: string;
  automation_type: string;
  block_reason: string;
  created_at: string;
  client_name?: string;
}

export const AutomationSettingsPanel = () => {
  const { barbershop } = useBarbershop();
  const [settings, setSettings] = useState<AutomationSettings>({
    blockIfHasAppointment: true,
    blockOnlyConfirmed: false,
    enableLogging: true,
    notifyOnBlock: false
  });
  const [saving, setSaving] = useState(false);
  const [blockedLogs, setBlockedLogs] = useState<BlockedLog[]>([]);
  const [loadingLogs, setLoadingLogs] = useState(false);
  const [showLogs, setShowLogs] = useState(false);

  useEffect(() => {
    if (barbershop?.automation_schedule) {
      const parsed = typeof barbershop.automation_schedule === 'object' 
        ? barbershop.automation_schedule as any 
        : {};
      
      setSettings({
        blockIfHasAppointment: parsed.blockIfHasAppointment ?? true,
        blockOnlyConfirmed: parsed.blockOnlyConfirmed ?? false,
        enableLogging: parsed.enableLogging ?? true,
        notifyOnBlock: parsed.notifyOnBlock ?? false
      });
    }
  }, [barbershop]);

  const loadBlockedLogs = async () => {
    if (!barbershop?.id) return;
    
    setLoadingLogs(true);
    try {
      const { data, error } = await db
        .from('automation_blocked_logs')
        .select(`
          *,
          profiles:client_id(name)
        `)
        .eq('barbershop_id', barbershop.id)
        .order('created_at', { ascending: false })
        .limit(50);

      if (error) throw error;
      
      const formattedLogs = (data || []).map(log => ({
        ...log,
        client_name: (log as any).profiles?.name || 'Cliente'
      }));
      
      setBlockedLogs(formattedLogs);
    } catch (error) {
      console.error('Erro ao carregar logs de bloqueio:', error);
      toast.error('Erro ao carregar logs');
    } finally {
      setLoadingLogs(false);
    }
  };

  const saveSettings = async () => {
    if (!barbershop?.id) {
      toast.error('Barbearia n├úo encontrada');
      return;
    }

    setSaving(true);
    try {
      const currentSchedule = typeof barbershop.automation_schedule === 'object' 
        ? barbershop.automation_schedule as any 
        : {};

      const newSchedule = {
        ...currentSchedule,
        ...settings
      };

      const { error } = await (supabase as any)
        .from('barbershops')
        .update({ automation_schedule: newSchedule })
        .eq('id', barbershop.id);

      if (error) throw error;

      toast.success('Configura├º├Áes de automa├º├úo salvas!');
    } catch (error) {
      console.error('Erro ao salvar configura├º├Áes:', error);
      toast.error('Erro ao salvar configura├º├Áes');
    } finally {
      setSaving(false);
    }
  };

  const getStats = () => {
    const last7Days = blockedLogs.filter(log => {
      const logDate = new Date(log.created_at);
      const weekAgo = new Date();
      weekAgo.setDate(weekAgo.getDate() - 7);
      return logDate >= weekAgo;
    });

    const byType = last7Days.reduce((acc, log) => {
      acc[log.automation_type] = (acc[log.automation_type] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    return { total: last7Days.length, byType };
  };

  const stats = getStats();

  return (
    <div className="space-y-6">
      {/* Estat├¡sticas de Bloqueio */}
      {settings.blockIfHasAppointment && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <AlertTriangle className="w-5 h-5" />
              Automa├º├Áes Bloqueadas (├Ültimos 7 dias)
            </CardTitle>
            <CardDescription>
              Visualize o impacto das regras de bloqueio
            </CardDescription>
          </CardHeader>
          <CardContent>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
              <div className="text-center p-4 border rounded-lg">
                <div className="text-2xl font-bold text-orange-600">{stats.total}</div>
                <div className="text-sm text-muted-foreground">Total bloqueado</div>
              </div>
              <div className="text-center p-4 border rounded-lg">
                <div className="text-2xl font-bold text-green-600">
                  {stats.total > 0 ? Math.round((1 - stats.total / 100) * 100) : 100}%
                </div>
                <div className="text-sm text-muted-foreground">Taxa de entrega</div>
              </div>
            </div>

            {Object.keys(stats.byType).length > 0 && (
              <div className="space-y-2">
                <Label className="text-sm font-medium">Por tipo de automa├º├úo:</Label>
                {Object.entries(stats.byType).map(([type, count]) => (
                  <div key={type} className="flex items-center justify-between p-2 border rounded">
                    <span className="text-sm">{type}</span>
                    <Badge variant="secondary">{count}</Badge>
                  </div>
                ))}
              </div>
            )}

            <Button
              variant="outline"
              onClick={() => {
                setShowLogs(!showLogs);
                if (!showLogs) loadBlockedLogs();
              }}
              className="w-full mt-4"
            >
              {showLogs ? <EyeOff className="w-4 h-4 mr-2" /> : <Eye className="w-4 h-4 mr-2" />}
              {showLogs ? 'Ocultar Logs' : 'Ver Logs Detalhados'}
            </Button>
          </CardContent>
        </Card>
      )}

      {/* Logs Detalhados */}
      {showLogs && (
        <Card>
          <CardHeader>
            <CardTitle>Logs de Bloqueio Detalhados</CardTitle>
            <CardDescription>
              Hist├│rico de automa├º├Áes bloqueadas
            </CardDescription>
          </CardHeader>
          <CardContent>
            {loadingLogs ? (
              <div className="text-center py-8">
                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary mx-auto"></div>
              </div>
            ) : blockedLogs.length === 0 ? (
              <div className="text-center py-8 text-muted-foreground">
                <CheckCircle className="w-12 h-12 mx-auto mb-4" />
                <p>Nenhuma automa├º├úo bloqueada no per├¡odo</p>
              </div>
            ) : (
              <div className="space-y-2">
                {blockedLogs.map((log) => (
                  <div key={log.id} className="p-3 border rounded-lg">
                    <div className="flex items-center justify-between">
                      <div className="flex items-center gap-2">
                        <Badge variant="outline">{log.automation_type}</Badge>
                        <span className="font-medium">{log.client_name}</span>
                      </div>
                      <span className="text-xs text-muted-foreground">
                        {new Date(log.created_at).toLocaleString('pt-BR')}
                      </span>
                    </div>
                    <p className="text-sm text-muted-foreground mt-1">{log.block_reason}</p>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      )}

      {/* Informa├º├Áes Adicionais */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Info className="w-5 h-5" />
            Como Funciona
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="p-4 bg-green-50 border border-green-200 rounded-lg">
            <h4 className="font-medium text-green-800 mb-2">Ô£à Automa├º├Áes que SEMPRE funcionam:</h4>
            <ul className="text-sm text-green-700 space-y-1">
              <li>ÔÇó Lembretes de agendamento (24h, 12h, 7h, 5h, 2h, 1h antes)</li>
              <li>ÔÇó Confirma├º├úo de agendamento</li>
              <li>ÔÇó Avisos de altera├º├úo de hor├írio</li>
              <li>ÔÇó Mensagens de cancelamento ou reagendamento</li>
            </ul>
          </div>

          <div className="p-4 bg-orange-50 border border-orange-200 rounded-lg">
            <h4 className="font-medium text-orange-800 mb-2">­ƒÜ½ Automa├º├Áes que podem ser bloqueadas:</h4>
            <ul className="text-sm text-orange-700 space-y-1">
              <li>ÔÇó Campanhas de marketing</li>
              <li>ÔÇó Reativa├º├úo de clientes inativos</li>
              <li>ÔÇó Mensagens promocionais</li>
              <li>ÔÇó Agradecimento p├│s-atendimento</li>
              <li>ÔÇó Disparos em massa</li>
            </ul>
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Settings className="w-5 h-5" />
            Configura├º├Áes de Automa├º├úo
          </CardTitle>
          <CardDescription>
            Controle quando as automa├º├Áes devem ser enviadas para evitar spam em clientes j├í agendados
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-6">
          <div className="flex items-center justify-between p-4 border rounded-lg bg-blue-50">
            <div className="flex items-center gap-3">
              <Shield className="w-5 h-5 text-blue-600" />
              <div>
                <Label className="font-medium">Bloquear automa├º├Áes para clientes com agendamento na semana</Label>
                <p className="text-sm text-muted-foreground mt-1">
