const CHANNEL_ICONS: Record<Channel, React.ReactNode> = {
  app: <Bell className="w-4 h-4" />,
  sms: <Smartphone className="w-4 h-4" />,
  whatsapp: <MessageCircle className="w-4 h-4" />,
};

const CHANNEL_LABELS: Record<Channel, string> = {
  app: "­ƒô▒ App",
  sms: "­ƒÆ¼ SMS",
  whatsapp: "­ƒô▓ WhatsApp",
};

export const SmartMessagingPanel = () => {
  const { barbershop } = useBarbershop();
  const [rules, setRules] = useState<MessageRule[]>(DEFAULT_RULES);
  const [editing, setEditing] = useState<SegmentType | null>(null);
  const [editMsg, setEditMsg] = useState("");
  const [sending, setSending] = useState<SegmentType | null>(null);
  const [clientCounts, setClientCounts] = useState<Record<string, number>>({});

  useEffect(() => {
    if (!barbershop?.id) return;
    const loadClientCounts = async () => {
      if (!barbershop?.id) return;
      const now = new Date();
      const d30 = new Date(now); d30.setDate(d30.getDate() - 30);
      const d60 = new Date(now); d60.setDate(d60.getDate() - 60);
      const d90 = new Date(now); d90.setDate(d90.getDate() - 90);
      const d2 = new Date(now); d2.setDate(d2.getDate() - 2);

      const [newNoApt, i30, i60, i90] = await Promise.all([
        (supabase as any).from("profiles").select("user_id", { count: "exact", head: true })
          .eq("role", "cliente")
          .lt("created_at", d2.toISOString())
          .not("user_id", "in",
            `(SELECT DISTINCT client_user_id FROM appointments WHERE barbershop_id='${barbershop.id}' AND client_user_id IS NOT NULL)`
          ),
        (supabase as any).from("appointments").select("client_user_id", { count: "exact", head: true })
          .eq("barbershop_id", barbershop.id)
          .lt("scheduled_at", d30.toISOString())
          .gte("scheduled_at", d60.toISOString()),
        (supabase as any).from("appointments").select("client_user_id", { count: "exact", head: true })
          .eq("barbershop_id", barbershop.id)
          .lt("scheduled_at", d60.toISOString())
          .gte("scheduled_at", d90.toISOString()),
        (supabase as any).from("appointments").select("client_user_id", { count: "exact", head: true })
          .eq("barbershop_id", barbershop.id)
          .lt("scheduled_at", d90.toISOString()),
      ]);

      setClientCounts({
        new_no_appointment: newNoApt.count || 0,
        inactive_30: i30.count || 0,
        inactive_60: i60.count || 0,
        inactive_90: i90.count || 0,
      });
    };
    const loadSavedRules = async () => {
      if (!barbershop?.id) return;
      const { data } = await (supabase as any)
        .from("barbershops")
        .select("automation_schedule")
        .eq("id", barbershop.id)
        .single();
      if (data?.automation_schedule) {
        const saved = (data.automation_schedule as any)?.smart_messages;
        if (saved) {
          setRules(prev => prev.map(r => ({ ...r, ...(saved[r.id] || {}) })));
        }
      }
    };
    loadClientCounts();
    loadSavedRules();
  }, [barbershop?.id]);

  const toggleRule = (id: SegmentType) => {
    setRules(prev => prev.map(r => r.id === id ? { ...r, active: !r.active } : r));
    toast.success("Regra atualizada");
  };

  const startEdit = (rule: MessageRule) => {
    setEditing(rule.id);
    setEditMsg(rule.message);
  };

  const saveEdit = (id: SegmentType) => {
    setRules(prev => prev.map(r => r.id === id ? { ...r, message: editMsg } : r));
    setEditing(null);
    toast.success("Mensagem salva");
  };

  const changeChannel = (id: SegmentType, channel: Channel) => {
    setRules(prev => prev.map(r => r.id === id ? { ...r, channel } : r));
  };

  const saveAllRules = async () => {
    if (!barbershop?.id) return;
    const saved = rules.reduce((acc, r) => {
      acc[r.id] = { active: r.active, channel: r.channel, message: r.message };
      return acc;
    }, {} as Record<string, any>);

    const current = (barbershop as any).automation_schedule || {};
    const { error } = await (supabase as any)
      .from("barbershops")
      .update({ automation_schedule: { ...current, smart_messages: saved } })
      .eq("id", barbershop.id);

    if (error) toast.error("Erro ao salvar");
    else toast.success("Configura├º├Áes salvas!");
  };

  const dispatchManual = async (rule: MessageRule) => {
    if (!barbershop?.id) return;
    setSending(rule.id);
    try {
      const { data: clients } = await (supabase as any)
        .from("profiles")
        .select("user_id, name")
        .eq("role", "cliente")
        .limit(100);

      let sent = 0;
      for (const c of clients || []) {
        const msg = rule.message.replace("{nome}", c.name || "Cliente");
        await (supabase as any).from("notifications").insert({
          user_id: c.user_id,
          title: rule.label,
          message: msg,
          type: "info",
          priority: "normal",
        });
        sent++;
      }
      toast.success(`Enviado para ${sent} clientes via ${CHANNEL_LABELS[rule.channel]}`);
    } catch {
      toast.error("Erro ao disparar mensagem");
    } finally {
      setSending(null);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-xl font-bold flex items-center gap-2">
            <MessageCircle className="w-5 h-5 text-primary" />
            Mensagens Inteligentes por Segmento
          </h2>
          <p className="text-sm text-muted-foreground mt-1">
            Configure mensagens autom├íticas por perfil de cliente
          </p>
        </div>
        <div className="flex gap-2">
          <Badge variant="outline" className="gap-1">
            <Users className="w-3 h-3" />
            {rules.filter(r => r.active).length} ativas
          </Badge>
          <Button size="sm" variant="gold" onClick={saveAllRules}>
            <Save className="w-4 h-4 mr-1" /> Salvar Tudo
          </Button>
        </div>
      </div>

      <div className="grid gap-4">
        {rules.map(rule => (
          <Card key={rule.id} className={rule.active ? "border-primary/30" : "opacity-60"}>
            <CardHeader className="pb-2">
              <div className="flex items-start justify-between gap-2">
                <div className="flex items-center gap-2 flex-1">
                  <span className={rule.color}>{rule.icon}</span>
                  <div>
                    <CardTitle className="text-sm font-semibold">{rule.label}</CardTitle>
                    <CardDescription className="text-xs">{rule.description}</CardDescription>
                  </div>
                  {clientCounts[rule.id] !== undefined && (
                    <Badge variant="secondary" className="text-xs ml-2">
                      {clientCounts[rule.id]} clientes
                    </Badge>
                  )}
                </div>
                <div className="flex items-center gap-2 shrink-0">
                  <Switch checked={rule.active} onCheckedChange={() => toggleRule(rule.id)} />
                </div>
              </div>
            </CardHeader>
            <CardContent className="pt-0 space-y-3">
              <div className="flex items-center gap-2">
                <Label className="text-xs text-muted-foreground">Canal:</Label>
                <div className="flex gap-1">
                  {(["app", "sms", "whatsapp"] as Channel[]).map(ch => (
                    <Button
                      key={ch}
                      size="sm"
                      variant={rule.channel === ch ? "gold" : "outline"}
                      className="h-7 text-xs px-2"
                      onClick={() => changeChannel(rule.id, ch)}
                    >
                      {CHANNEL_ICONS[ch]} <span className="ml-1">{CHANNEL_LABELS[ch]}</span>
                    </Button>
                  ))}
                </div>
              </div>

              {editing === rule.id ? (
                <div className="space-y-2">
                  <Textarea
                    value={editMsg}
                    onChange={e => setEditMsg(e.target.value)}
                    rows={3}
                    className="text-sm"
                    placeholder="Use {nome} para personalizar com o nome do cliente"
                  />
                  <p className="text-xs text-muted-foreground">Use {"{nome}"} para inserir o nome do cliente</p>
                  <div className="flex gap-2">
                    <Button size="sm" variant="gold" onClick={() => saveEdit(rule.id)}>
                      <Save className="w-3 h-3 mr-1" /> Salvar
                    </Button>
                    <Button size="sm" variant="ghost" onClick={() => setEditing(null)}>
                      <X className="w-3 h-3 mr-1" /> Cancelar
                    </Button>
                  </div>
                </div>
              ) : (
                <div className="flex items-start justify-between gap-2">
                  <p className="text-sm text-muted-foreground flex-1 italic">"{rule.message}"</p>
                  <div className="flex gap-1 shrink-0">
                    <Button size="sm" variant="ghost" className="h-7 px-2" onClick={() => startEdit(rule)}>
                      <Edit2 className="w-3 h-3" />
                    </Button>
                    <Button
                      size="sm"
                      variant="outline"
                      className="h-7 px-2 text-xs"
                      disabled={!rule.active || sending === rule.id}
                      onClick={() => dispatchManual(rule)}
                    >
                      <Play className="w-3 h-3 mr-1" />
                      {sending === rule.id ? "Enviando..." : "Disparar"}
                    </Button>
                  </div>
                </div>
              )}
            </CardContent>
          </Card>
        ))}
      </div>
    </div>
  );
};

// @ts-nocheck
import { useState, useEffect, useCallback } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Label } from "@/components/ui/label";
import { toast } from "sonner";
import {
  RefreshCw, CreditCard, Copy, Loader2, QrCode,
  CheckCircle, XCircle, AlertCircle, Plus, Calendar
} from "lucide-react";
import { useAuth } from "@/lib/auth";
import { ContadorBuscaPanel } from "./ContadorBuscaPanel";

interface Assinatura {
  id: string;
  contador_id: string;
  valor_mensal: number;
  status: string;
  data_inicio: string;
  data_proxima_cobranca: string;
  data_cancelamento: string | null;
}

interface Historico {
  id: string;
  valor: number;
  status: string;
  pix_copy_paste: string | null;
  data_vencimento: string;
  data_pagamento: string | null;
}

const STATUS_BADGE: Record<string, { label: string; variant: string; icon: React.ReactNode }> = {
  active:    { label: "Ativa", variant: "success", icon: <CheckCircle className="w-3 h-3" /> },
  paused:    { label: "Pausada", variant: "secondary", icon: <AlertCircle className="w-3 h-3" /> },
  cancelled: { label: "Cancelada", variant: "destructive", icon: <XCircle className="w-3 h-3" /> },
  past_due:  { label: "Em Atraso", variant: "warning", icon: <AlertCircle className="w-3 h-3" /> },
};

interface Props {
  barbershopId?: string;
}

export function AssinaturaContabilPanel({ barbershopId }: Props) {
  const { user } = useAuth();
  const [assinaturas, setAssinaturas] = useState<Assinatura[]>([]);
  const [historico, setHistorico] = useState<Historico[]>([]);
  const [contadoresMapa, setContadoresMapa] = useState<Record<string, string>>({});
  const [step, setStep] = useState<"lista" | "busca_contador" | "confirmar">("lista");
  const [contadorSel, setContadorSel] = useState<{ id: string; name: string; valor_mensalidade: number | null } | null>(null);
  const [valorMensal, setValorMensal] = useState("");
  const [loading, setLoading] = useState(false);
  const [cancelando, setCancelando] = useState<string | null>(null);
  const [split, setSplit] = useState<{ pct_app: number; pct_contador: number; valor_app: number; valor_contador: number } | null>(null);

  const fetchAssinaturas = useCallback(async () => {
    if (!user) return;
    const { data } = await (supabase as any)
      .from("assinaturas_contabeis")
      .select("id, contador_id, valor_mensal, status, data_inicio, data_proxima_cobranca, data_cancelamento")
      .eq("usuario_id", user.id)
      .order("created_at", { ascending: false });
    setAssinaturas((data as Assinatura[]) || []);

    const ids = [...new Set((data || []).map((a) => a.contador_id))];
    if (ids.length > 0) {
      const { data: conts } = await (supabase as any)
        .from("accountants")
        .select("id, name")
        .in("id", ids);
      const mapa: Record<string, string> = {};
      (conts || []).forEach((c) => { mapa[c.id] = c.name; });
      setContadoresMapa(mapa);
    }

    if (data && data.length > 0) {
      const { data: hist } = await (supabase as any)
        .from("historico_assinaturas")
        .select("id, valor, status, pix_copy_paste, data_vencimento, data_pagamento")
        .eq("usuario_id", user.id)
        .order("created_at", { ascending: false })
        .limit(10);
      setHistorico((hist as Historico[]) || []);
    }
  }, [user]);

  useEffect(() => { if (user) { fetchAssinaturas(); } }, [user, fetchAssinaturas]);

  const handleSelecionarContador = async (c: { id: string; name: string; valor_mensalidade: number | null }) => {
    setContadorSel(c);
    const v = c.valor_mensalidade ?? 0;
    setValorMensal(v > 0 ? String(v) : "");
    const { data } = await (supabase as any).rpc("calcular_split_comissao", { _valor: v > 0 ? v : 100 });
    if (data && data[0]) setSplit(data[0] as any);
    setStep("confirmar");
  };

  const handleCriarAssinatura = async () => {
    if (!user || !contadorSel) return;
    const valor = Number(valorMensal);
    if (!valor || valor <= 0) { toast.error("Informe um valor v├ílido."); return; }
    setLoading(true);

    const splitData = await (supabase as any).rpc("calcular_split_comissao", { _valor: valor });
    const sp = splitData.data?.[0] as any;

    const proxCobranca = new Date();
    proxCobranca.setMonth(proxCobranca.getMonth() + 1);

    const { data: assin, error } = await (supabase as any)
      .from("assinaturas_contabeis")
      .insert({
        usuario_id: user.id,
        contador_id: contadorSel.id,
        valor_mensal: valor,
        data_proxima_cobranca: proxCobranca.toISOString(),
        porcentagem_app: sp?.pct_app ?? 20,
        porcentagem_contador: sp?.pct_contador ?? 80,
        valor_app: sp?.valor_app ?? valor * 0.2,
        valor_contador: sp?.valor_contador ?? valor * 0.8,
      })
      .select()
      .single();

    if (error) { toast.error("Erro: " + error.message); setLoading(false); return; }

    const { data: charge, error: chargeErr } = await supabase.functions.invoke("process-payment", {
      body: {
        action: "charge",
        amount: valor,
        description: `Assinatura Cont├íbil - ${contadorSel.name}`,
        billing_type: "PIX",
        external_reference: (assin as any).id,
      },
    });

    if (!chargeErr && charge) {
      await (supabase as any).from("historico_assinaturas").insert({
        assinatura_id: (assin as any).id,
        usuario_id: user.id,
        valor,
        status: "pending",
        asaas_payment_id: charge.payment_id,
        pix_copy_paste: charge.pix_copy_paste,
        data_vencimento: new Date().toISOString(),
      });
      toast.success("Assinatura criada! Efetue o pagamento via PIX.");
    } else {
      toast.success("Assinatura criada! Aguardando cobran├ºa.");
    }

    setLoading(false);
    await fetchAssinaturas();
    setStep("lista");
  };

  const handleCancelar = async (id: string) => {
    setCancelando(id);
    const { error } = await (supabase as any)
      .from("assinaturas_contabeis")
      .update({ status: "cancelled", data_cancelamento: new Date().toISOString() })
      .eq("id", id);
    setCancelando(null);
    if (error) { toast.error("Erro ao cancelar: " + error.message); return; }
    toast.success("Assinatura cancelada.");
    await fetchAssinaturas();
  };

  const copiarPix = (codigo: string) => {
    navigator.clipboard?.writeText(codigo);
    toast.success("C├│digo PIX copiado!");
  };

  if (step === "busca_contador") {
    return (
      <div className="space-y-4">
        <div className="flex items-center gap-3">
          <Button variant="outline" size="sm" onClick={() => setStep("lista")}>ÔåÉ Voltar</Button>
          <h2 className="font-semibold">Selecionar Contador para Assinatura</h2>
        </div>
        <ContadorBuscaPanel
          barbershopId={barbershopId}
          onContadorSelecionado={(c) => handleSelecionarContador({
            id: c.id, name: c.name, valor_mensalidade: c.valor_mensalidade ?? null
          })}
        />
      </div>
    );
  }

  if (step === "confirmar" && contadorSel) {
    return (
      <div className="space-y-4">
        <div className="flex items-center gap-3">
          <Button variant="outline" size="sm" onClick={() => setStep("busca_contador")}>ÔåÉ Voltar</Button>
          <h2 className="font-semibold">Confirmar Assinatura</h2>
        </div>
        <Card>
          <CardHeader>
            <CardTitle>Assinatura com {contadorSel.name}</CardTitle>
            <CardDescription>Contabilidade mensal recorrente</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div>
              <Label>Valor Mensal (R$) *</Label>
              <Input
                type="number"
                min="1"
                step="0.01"
                placeholder="Ex: 299.00"
                value={valorMensal}
                onChange={(e) => setValorMensal(e.target.value)}
                className="mt-1"
              />
              {split && Number(valorMensal) > 0 && (
                <p className="text-xs text-muted-foreground mt-1">
                  Contador recebe: R$ {(Number(valorMensal) * split.pct_contador / 100).toFixed(2)} ┬À
                  App: R$ {(Number(valorMensal) * split.pct_app / 100).toFixed(2)}
                </p>
              )}
            </div>
            <div className="p-3 bg-muted rounded-lg space-y-1 text-sm">
              <p className="flex items-center gap-1 text-muted-foreground">
                <Calendar className="w-4 h-4" />
                Primeiro pagamento gerado hoje via PIX
              </p>
              <p className="flex items-center gap-1 text-muted-foreground">
                <RefreshCw className="w-4 h-4" />
                Renova├º├úo autom├ítica mensal
              </p>
            </div>
            <Button variant="gold" className="w-full" onClick={handleCriarAssinatura} disabled={loading}>
              {loading ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <CreditCard className="w-4 h-4 mr-2" />}
              Assinar e Gerar PIX
            </Button>
          </CardContent>
        </Card>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="font-display text-xl font-bold">Assinatura Cont├íbil</h2>
          <p className="text-sm text-muted-foreground">Contabilidade recorrente mensal</p>
        </div>
        <Button variant="gold" onClick={() => setStep("busca_contador")}>
          <Plus className="w-4 h-4 mr-2" />Nova Assinatura
        </Button>
      </div>

      {assinaturas.length === 0 ? (
        <Card>
          <CardContent className="py-12 text-center">
            <RefreshCw className="w-12 h-12 text-muted-foreground mx-auto mb-3" />
            <p className="text-muted-foreground">Nenhuma assinatura ativa.</p>
            <p className="text-sm text-muted-foreground mt-1">Contrate contabilidade recorrente com um contador verificado.</p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-3">
          {assinaturas.map((a) => {
            const sb = STATUS_BADGE[a.status] || STATUS_BADGE.active;
            return (
              <Card key={a.id} className="border-primary/10">
                <CardContent className="p-4 flex items-start justify-between gap-3">
                  <div className="space-y-1">
                    <p className="font-medium">{contadoresMapa[a.contador_id] || "Contador"}</p>
                    <div className="flex items-center gap-1 text-xs">
                      {sb.icon}
                      <span className={a.status === "active" ? "text-green-600" : "text-muted-foreground"}>
                        {sb.label}
                      </span>
                    </div>
                    <p className="text-xs text-muted-foreground">
                      Pr├│x. cobran├ºa: {new Date(a.data_proxima_cobranca).toLocaleDateString("pt-BR")}
                    </p>
                  </div>
                  <div className="text-right space-y-2 shrink-0">
                    <p className="font-bold text-primary">R$ {a.valor_mensal.toFixed(2)}/m├¬s</p>
                    {a.status === "active" && (
                      <Button
                        size="sm"
                        variant="destructive"
                        disabled={cancelando === a.id}
                        onClick={() => handleCancelar(a.id)}
                      >
                        {cancelando === a.id ? <Loader2 className="w-4 h-4 animate-spin" /> : "Cancelar"}
                      </Button>
                    )}
                  </div>
                </CardContent>
              </Card>
            );
          })}
        </div>
      )}

      {historico.length > 0 && (
        <div className="space-y-3">
          <h3 className="font-semibold text-sm text-muted-foreground uppercase tracking-wide">Hist├│rico de Cobran├ºas</h3>
          {historico.map((h) => (
            <Card key={h.id} className="border-muted">
              <CardContent className="p-3 flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium">R$ {h.valor.toFixed(2)}</p>
                  <p className="text-xs text-muted-foreground">
                    Venc: {new Date(h.data_vencimento).toLocaleDateString("pt-BR")}
                    {h.data_pagamento && ` ┬À Pago: ${new Date(h.data_pagamento).toLocaleDateString("pt-BR")}`}
                  </p>
                </div>
                <div className="flex items-center gap-2">
                  <Badge variant={h.status === "confirmed" ? "default" : "secondary"} className="text-xs">
                    {h.status === "confirmed" ? "Pago" : h.status === "failed" ? "Falhou" : "Pendente"}
                  </Badge>
                  {h.status !== "confirmed" && h.pix_copy_paste && (
                    <Button size="sm" variant="outline" className="h-7 px-2"
                      onClick={() => copiarPix(h.pix_copy_paste!)}>
                      <Copy className="w-3 h-3 mr-1" />PIX
                    </Button>
                  )}
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </div>
  );
}

export default AssinaturaContabilPanel;

// @ts-nocheck
import { useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { toast } from "sonner";
import {
  UserCheck, Plus, Loader2, Search, CheckCircle, XCircle,
  Clock, Edit2, Save, X, Phone, Mail, MapPin, Building2
} from "lucide-react";

interface Contador {
  id: string;
  name: string;
  email: string;
  whatsapp: string | null;
  cpf_cnpj: string | null;
  crc_registro: string | null;
  empresa_contabil: string | null;
  cidade: string | null;
  estado: string | null;
  telefone: string | null;
  status_verificado: string;
  bio: string | null;
  is_active: boolean;
  aceita_novos_clientes: boolean;
  valor_mensalidade: number | null;
  commission_mei: number | null;
  commission_me: number | null;
  commission_declaration: number | null;
}

const STATUS_CONFIG = {
  pending:  { label: "Pendente", color: "bg-yellow-500/10 text-yellow-600 border-yellow-500/20", icon: <Clock className="w-3 h-3" /> },
  verified: { label: "Verificado", color: "bg-green-500/10 text-green-600 border-green-500/20",  icon: <CheckCircle className="w-3 h-3" /> },
  rejected: { label: "Rejeitado", color: "bg-red-500/10 text-red-600 border-red-500/20",         icon: <XCircle className="w-3 h-3" /> },
};

const EMPTY_FORM = {
  name: "", email: "", whatsapp: "", cpf_cnpj: "",
  crc_registro: "", empresa_contabil: "", cidade: "", estado: "",
  telefone: "", bio: "", valor_mensalidade: "",
  commission_mei: "", commission_me: "", commission_declaration: "",
};

export function CadastroContadorPanel() {
  const [contadores, setContadores] = useState<Contador[]>([]);
  const [loading, setLoading] = useState(true);
  const [busca, setBusca] = useState("");
  const [showForm, setShowForm] = useState(false);
  const [editId, setEditId] = useState<string | null>(null);
  const [saving, setSaving] = useState(false);
  const [form, setForm] = useState(EMPTY_FORM);

  useEffect(() => { fetchContadores(); }, []);

  const fetchContadores = async () => {
    setLoading(true);
    const { data, error } = await (supabase as any)
      .from("accountants")
      .select("id, name, email, whatsapp, cpf_cnpj, crc_registro, empresa_contabil, cidade, estado, telefone, status_verificado, bio, is_active, aceita_novos_clientes, valor_mensalidade, commission_mei, commission_me, commission_declaration")
      .order("created_at", { ascending: false });
    setLoading(false);
    if (error) { toast.error("Erro: " + error.message); return; }
    setContadores((data as Contador[]) || []);
  };

  const handleEditar = (c: Contador) => {
    setEditId(c.id);
    setForm({
      name: c.name,
      email: c.email,
      whatsapp: c.whatsapp || "",
      cpf_cnpj: c.cpf_cnpj || "",
      crc_registro: c.crc_registro || "",
      empresa_contabil: c.empresa_contabil || "",
      cidade: c.cidade || "",
      estado: c.estado || "",
      telefone: c.telefone || "",
      bio: c.bio || "",
      valor_mensalidade: c.valor_mensalidade != null ? String(c.valor_mensalidade) : "",
      commission_mei: c.commission_mei != null ? String(c.commission_mei) : "",
      commission_me: c.commission_me != null ? String(c.commission_me) : "",
      commission_declaration: c.commission_declaration != null ? String(c.commission_declaration) : "",
    });
    setShowForm(true);
  };

  const handleSalvar = async () => {
    if (!form.name || !form.email) { toast.error("Nome e email s├úo obrigat├│rios."); return; }
    setSaving(true);
    const payload = {
      name: form.name,
      email: form.email,
      whatsapp: form.whatsapp || null,
      cpf_cnpj: form.cpf_cnpj || null,
      crc_registro: form.crc_registro || null,
      empresa_contabil: form.empresa_contabil || null,
      cidade: form.cidade || null,
      estado: form.estado || null,
      telefone: form.telefone || null,
      bio: form.bio || null,
      valor_mensalidade: form.valor_mensalidade ? Number(form.valor_mensalidade) : null,
      commission_mei: form.commission_mei ? Number(form.commission_mei) : 0,
      commission_me: form.commission_me ? Number(form.commission_me) : 0,
      commission_declaration: form.commission_declaration ? Number(form.commission_declaration) : 0,
    };

    if (editId) {
      const { error } = await (supabase as any).from("accountants").update(payload).eq("id", editId);
      setSaving(false);
      if (error) { toast.error("Erro ao atualizar: " + error.message); return; }
      toast.success("Contador atualizado!");
    } else {
      toast.error("Novo cadastro de contador precisa de um user_id. Use via cadastro do pr├│prio contador.");
      setSaving(false);
      return;
    }

    setShowForm(false);
    setEditId(null);
    setForm(EMPTY_FORM);
    await fetchContadores();
  };

  const handleVerificar = async (id: string, status: "verified" | "rejected") => {
    const { error } = await (supabase as any)
      .from("accountants")
      .update({ status_verificado: status, is_active: status === "verified" })
      .eq("id", id);
    if (error) { toast.error("Erro: " + error.message); return; }
    toast.success(status === "verified" ? "Contador verificado!" : "Contador rejeitado.");
    await fetchContadores();
  };

  const handleToggleAtivo = async (id: string, atual: boolean) => {
    const { error } = await (supabase as any)
      .from("accountants")
      .update({ is_active: !atual })
      .eq("id", id);
    if (error) { toast.error("Erro: " + error.message); return; }
    toast.success(atual ? "Contador desativado." : "Contador ativado.");
    await fetchContadores();
  };

  const filtrados = contadores.filter((c) =>
    busca === "" ||
    c.name.toLowerCase().includes(busca.toLowerCase()) ||
    c.email.toLowerCase().includes(busca.toLowerCase()) ||
    (c.cidade || "").toLowerCase().includes(busca.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <h2 className="font-display text-xl font-bold">Contadores Cadastrados</h2>
          <p className="text-sm text-muted-foreground">Gerencie verifica├º├úo e dados dos contadores</p>
        </div>
        <div className="flex gap-2">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
            <Input
              className="pl-9 w-48"
              placeholder="Buscar..."
              value={busca}
              onChange={(e) => setBusca(e.target.value)}
            />
          </div>
        </div>
      </div>

      {showForm && (
        <Card className="border-primary/30">
          <CardHeader>
            <div className="flex items-center justify-between">
              <CardTitle>{editId ? "Editar Contador" : "Novo Contador"}</CardTitle>
              <Button variant="ghost" size="icon" onClick={() => { setShowForm(false); setEditId(null); setForm(EMPTY_FORM); }}>
                <X className="w-4 h-4" />
              </Button>
            </div>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {[
                { key: "name", label: "Nome Completo *", type: "text" },
                { key: "email", label: "Email *", type: "email" },
                { key: "whatsapp", label: "WhatsApp", type: "text" },
                { key: "cpf_cnpj", label: "CPF/CNPJ", type: "text" },
                { key: "crc_registro", label: "Registro CRC", type: "text" },
                { key: "empresa_contabil", label: "Empresa Cont├íbil", type: "text" },
                { key: "cidade", label: "Cidade", type: "text" },
                { key: "estado", label: "Estado (UF)", type: "text" },
                { key: "telefone", label: "Telefone Comercial", type: "text" },
                { key: "valor_mensalidade", label: "Mensalidade (R$)", type: "number" },
                { key: "commission_mei", label: "Comiss├úo MEI (R$)", type: "number" },
                { key: "commission_me", label: "Comiss├úo ME (R$)", type: "number" },
                { key: "commission_declaration", label: "Comiss├úo Declara├º├úo (R$)", type: "number" },
              ].map(({ key, label, type }) => (
                <div key={key}>
                  <Label>{label}</Label>
                  <Input
                    type={type}
                    className="mt-1"
                    value={form[key as keyof typeof form]}
                    onChange={(e) => setForm({ ...form, [key]: e.target.value })}
                  />
                </div>
              ))}
            </div>
            <div>
              <Label>Bio / Apresenta├º├úo</Label>
              <Input
                className="mt-1"
                value={form.bio}
                onChange={(e) => setForm({ ...form, bio: e.target.value })}
                placeholder="Descreva a especialidade e experi├¬ncia do contador"
              />
            </div>
            <div className="flex gap-2">
              <Button variant="gold" onClick={handleSalvar} disabled={saving}>
                {saving ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <Save className="w-4 h-4 mr-2" />}
                Salvar
              </Button>
              <Button variant="outline" onClick={() => { setShowForm(false); setEditId(null); setForm(EMPTY_FORM); }}>
                Cancelar
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      {loading ? (
        <div className="flex justify-center py-12">
          <Loader2 className="w-8 h-8 animate-spin text-primary" />
        </div>
      ) : filtrados.length === 0 ? (
        <Card>
          <CardContent className="py-12 text-center">
            <UserCheck className="w-12 h-12 text-muted-foreground mx-auto mb-3" />
            <p className="text-muted-foreground">Nenhum contador cadastrado.</p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-3">
          {filtrados.map((c) => {
            const sc = STATUS_CONFIG[c.status_verificado as keyof typeof STATUS_CONFIG] || STATUS_CONFIG.pending;
            return (
              <Card key={c.id} className="border-primary/10">
                <CardContent className="p-4">
                  <div className="flex items-start justify-between gap-4 flex-wrap">
                    <div className="space-y-1 flex-1 min-w-0">
                      <div className="flex items-center gap-2 flex-wrap">
                        <p className="font-semibold">{c.name}</p>
                        <Badge className={`text-xs ${sc.color} flex items-center gap-1`}>
                          {sc.icon}{sc.label}
                        </Badge>
                        {!c.is_active && <Badge variant="secondary" className="text-xs">Inativo</Badge>}
                      </div>
                      <div className="flex flex-wrap gap-3 text-sm text-muted-foreground">
                        <span className="flex items-center gap-1"><Mail className="w-3 h-3" />{c.email}</span>
                        {c.whatsapp && <span className="flex items-center gap-1"><Phone className="w-3 h-3" />{c.whatsapp}</span>}
                        {c.empresa_contabil && <span className="flex items-center gap-1"><Building2 className="w-3 h-3" />{c.empresa_contabil}</span>}
                        {c.cidade && <span className="flex items-center gap-1"><MapPin className="w-3 h-3" />{c.cidade}/{c.estado}</span>}
                        {c.crc_registro && <span className="text-xs">CRC: {c.crc_registro}</span>}
                      </div>
                      {c.valor_mensalidade != null && c.valor_mensalidade > 0 && (
                        <p className="text-sm text-primary font-medium">
                          Mensalidade: R$ {c.valor_mensalidade.toFixed(2)}
                        </p>
                      )}
                    </div>
                    <div className="flex flex-col gap-2 shrink-0">
                      <Button size="sm" variant="outline" onClick={() => handleEditar(c)}>
                        <Edit2 className="w-3 h-3 mr-1" />Editar
                      </Button>
                      {c.status_verificado === "pending" && (
                        <>
                          <Button size="sm" variant="gold"
                            onClick={() => handleVerificar(c.id, "verified")}
                            className="text-xs">
                            <CheckCircle className="w-3 h-3 mr-1" />Verificar
                          </Button>
                          <Button size="sm" variant="destructive"
                            onClick={() => handleVerificar(c.id, "rejected")}
                            className="text-xs">
                            <XCircle className="w-3 h-3 mr-1" />Rejeitar
                          </Button>
                        </>
                      )}
                      {c.status_verificado === "verified" && (
                        <Button size="sm" variant="destructive"
                          onClick={() => handleVerificar(c.id, "rejected")}
                          className="text-xs">
                          <XCircle className="w-3 h-3 mr-1" />Revogar
                        </Button>
                      )}
                      {c.status_verificado === "rejected" && (
                        <Button size="sm" variant="outline"
                          onClick={() => handleVerificar(c.id, "verified")}
                          className="text-xs">
                          <CheckCircle className="w-3 h-3 mr-1" />Re-verificar
                        </Button>
                      )}
                      <Button size="sm" variant="ghost" className="text-xs"
                        onClick={() => handleToggleAtivo(c.id, c.is_active)}>
                        {c.is_active ? "Desativar" : "Ativar"}
                      </Button>
                    </div>
                  </div>
                </CardContent>
              </Card>
            );
          })}
        </div>
      )}
    </div>
  );
}

export default CadastroContadorPanel;

// @ts-nocheck
import { useState, useEffect, useRef } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { toast } from "sonner";
import { MessageCircle, Send, Loader2, UserCheck, User } from "lucide-react";
import { useAuth } from "@/lib/auth";

interface Msg {
  id: string;
  mensagem: string;
  remetente: string;
  data_envio: string;
  lido: boolean;
}

interface ContadorInfo {
  id: string;
  name: string;
  empresa_contabil: string | null;
}

interface Props {
  contadorId: string;
  modo: "usuario" | "contador";
  usuarioId?: string;
}

export function ChatContadorPanel({ contadorId, modo, usuarioId }: Props) {
  const { user } = useAuth();
  const [msgs, setMsgs] = useState<Msg[]>([]);
  const [contador, setContador] = useState<ContadorInfo | null>(null);
  const [texto, setTexto] = useState("");
  const [loading, setLoading] = useState(true);
  const [enviando, setEnviando] = useState(false);
  const bottomRef = useRef<HTMLDivElement>(null);

  const uid = modo === "usuario" ? user?.id : usuarioId;

  useEffect(() => {
    if (!uid && modo === "contador") return;
    const carregarContador = async () => {
      const { data } = await (supabase as any)
        .from("accountants")
        .select("id, name, empresa_contabil")
        .eq("id", contadorId)
        .maybeSingle();
      if (data) setContador(data as ContadorInfo);
    };
    const carregarMensagens = async () => {
      setLoading(true);
      let query = (supabase as any)
        .from("chat_contador")
        .select("id, mensagem, remetente, data_envio, lido")
        .eq("contador_id", contadorId)
        .order("data_envio", { ascending: true });

      if (modo === "usuario" && user?.id) {
        query = query.eq("usuario_id", user.id);
      } else if (modo === "contador" && uid) {
        query = query.eq("usuario_id", uid);
      }

      const { data, error } = await query;
      setLoading(false);
      if (error) { toast.error("Erro ao carregar mensagens."); return; }
      setMsgs((data as Msg[]) || []);

      if (modo === "contador" && uid) {
        await (supabase as any)
          .from("chat_contador")
          .update({ lido: true })
          .eq("contador_id", contadorId)
          .eq("usuario_id", uid)
          .eq("remetente", "usuario");
      }
    };
    carregarContador();
    carregarMensagens();
    const channel = supabase
      .channel(`chat_${contadorId}_${uid}`)
      .on("postgres_changes", {
        event: "INSERT",
        schema: "public",
        table: "chat_contador",
        filter: `contador_id=eq.${contadorId}`,
      }, (payload) => {
        const nova = payload.new as Msg;
        if (nova.usuario_id === uid || modo === "contador") {
          setMsgs((prev) => [...prev, nova]);
          scrollBottom();
        }
      })
      .subscribe();
    return () => { supabase.removeChannel(channel); };
  }, [contadorId, uid, modo]);

  useEffect(() => { scrollBottom(); }, [msgs]);

  const scrollBottom = () => {
    setTimeout(() => bottomRef.current?.scrollIntoView({ behavior: "smooth" }), 100);
  };

  const enviarMensagem = async () => {
    if (!texto.trim() || !user) return;
    setEnviando(true);
    const payload = {
      usuario_id: modo === "usuario" ? user.id : (uid || ""),
      contador_id: contadorId,
      mensagem: texto.trim(),
      remetente: modo,
    };
    const { error } = await (supabase as any).from("chat_contador").insert(payload);
    setEnviando(false);
    if (error) { toast.error("Erro ao enviar: " + error.message); return; }
    setTexto("");
  };

  const formatHora = (dt: string) => {
    return new Date(dt).toLocaleTimeString("pt-BR", { hour: "2-digit", minute: "2-digit" });
  };

  const formatData = (dt: string) => {
    return new Date(dt).toLocaleDateString("pt-BR", { day: "2-digit", month: "short" });
  };

  return (
    <Card className="flex flex-col h-[520px]">
      <CardHeader className="pb-3 border-b">
        <CardTitle className="flex items-center gap-2 text-base">
          <MessageCircle className="w-4 h-4 text-primary" />
          {modo === "usuario"
            ? `Chat com ${contador?.name || "Contador"}`
            : "Chat com Cliente"}
        </CardTitle>
        {contador?.empresa_contabil && (
          <CardDescription>{contador.empresa_contabil}</CardDescription>
        )}
      </CardHeader>

      <CardContent className="flex-1 overflow-y-auto p-4 space-y-3">
        {loading ? (
          <div className="flex justify-center py-8">
            <Loader2 className="w-6 h-6 animate-spin text-primary" />
          </div>
        ) : msgs.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-center">
            <MessageCircle className="w-12 h-12 text-muted-foreground mb-3" />
            <p className="text-muted-foreground text-sm">Nenhuma mensagem ainda.</p>
            <p className="text-xs text-muted-foreground mt-1">
              {modo === "usuario"
                ? "Apresente-se e descreva sua necessidade cont├íbil."
                : "Aguardando mensagem do cliente."}
            </p>
          </div>
        ) : (
          msgs.map((m) => {
            const isMe = m.remetente === modo;
            return (
              <div key={m.id} className={`flex ${isMe ? "justify-end" : "justify-start"}`}>
                <div className={`max-w-[75%] rounded-xl px-3 py-2 space-y-1 ${
                  isMe
                    ? "bg-primary text-primary-foreground rounded-br-sm"
                    : "bg-muted rounded-bl-sm"
                }`}>
                  <div className="flex items-center gap-2 mb-1">
                    {!isMe && (
                      <span className="text-xs font-medium opacity-70">
                        {m.remetente === "contador" ? (
                          <span className="flex items-center gap-1">
                            <UserCheck className="w-3 h-3" /> Contador
                          </span>
                        ) : (
                          <span className="flex items-center gap-1">
                            <User className="w-3 h-3" /> Cliente
                          </span>
                        )}
                      </span>
                    )}
                  </div>
                  <p className="text-sm leading-relaxed">{m.mensagem}</p>
                  <p className={`text-xs opacity-60 text-right`}>
                    {formatData(m.data_envio)} {formatHora(m.data_envio)}
                  </p>
                </div>
              </div>
            );
          })
        )}
        <div ref={bottomRef} />
      </CardContent>

      <div className="p-3 border-t flex gap-2">
        <Input
          placeholder="Digite sua mensagem..."
          value={texto}
          onChange={(e) => setTexto(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && !e.shiftKey && enviarMensagem()}
          disabled={enviando}
        />
        <Button variant="gold" size="icon" onClick={enviarMensagem} disabled={enviando || !texto.trim()}>
          {enviando ? <Loader2 className="w-4 h-4 animate-spin" /> : <Send className="w-4 h-4" />}
        </Button>
      </div>
    </Card>
  );
}

