export default MarketingEmpresarial;

import { useState, useEffect, useCallback } from "react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Switch } from "@/components/ui/switch";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "@/hooks/use-toast";
import { CalendarClock, Plus, Trash2 } from "lucide-react";

interface WeeklySchedulePanelProps {
  barbershopId: string;
}

interface Schedule {
  id: string;
  name: string;
  is_active: boolean;
  days_of_week: number[];
  send_time: string;
  channel: string;
  target_audience: string;
  message_template: string;
  use_ai: boolean;
}

const DAYS = [
  { value: 0, label: "Dom" },
  { value: 1, label: "Seg" },
  { value: 2, label: "Ter" },
  { value: 3, label: "Qua" },
  { value: 4, label: "Qui" },
  { value: 5, label: "Sex" },
  { value: 6, label: "S├íb" },
];

export function WeeklySchedulePanel({ barbershopId }: WeeklySchedulePanelProps) {
  const [schedules, setSchedules] = useState<Schedule[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState<Omit<Schedule, "id">>({
    name: "",
    is_active: true,
    days_of_week: [1, 2, 3, 4, 5],
    send_time: "09:00",
    channel: "whatsapp",
    target_audience: "all",
    message_template: "",
    use_ai: false,
  });

  useEffect(() => {
    loadSchedules();
  }, [barbershopId, loadSchedules]);

  const loadSchedules = useCallback(async () => {
    try {
      const { data } = await (supabase as any)
        .from("message_schedules")
        .select("*")
        .eq("barbershop_id", barbershopId)
        .order("created_at", { ascending: false });
      setSchedules(data || []);
    } catch (err) {
      console.error("Error loading schedules:", err);
    } finally {
      setLoading(false);
    }
  }, [barbershopId]);

  const saveSchedule = async () => {
    if (!form.name || !form.message_template) {
      toast({ title: "Preencha todos os campos obrigat├│rios", variant: "destructive" });
      return;
    }
    try {
      const { error } = await (supabase as any)
        .from("message_schedules")
        .insert({ barbershop_id: barbershopId, ...form });

      if (error) throw error;
      toast({ title: "Agendamento criado!" });
      setShowForm(false);
      setForm({ name: "", is_active: true, days_of_week: [1, 2, 3, 4, 5], send_time: "09:00", channel: "whatsapp", target_audience: "all", message_template: "", use_ai: false });
      loadSchedules();
    } catch (err: any) {
      toast({ title: "Erro", description: err.message, variant: "destructive" });
    }
  };

  const toggleSchedule = async (id: string, active: boolean) => {
    await (supabase as any).from("message_schedules").update({ is_active: active }).eq("id", id);
    loadSchedules();
  };

  const deleteSchedule = async (id: string) => {
    await (supabase as any).from("message_schedules").delete().eq("id", id);
    loadSchedules();
    toast({ title: "Agendamento removido" });
  };

  const toggleDay = (day: number) => {
    setForm(prev => ({
      ...prev,
      days_of_week: prev.days_of_week.includes(day)
        ? prev.days_of_week.filter(d => d !== day)
        : [...prev.days_of_week, day].sort(),
    }));
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <div>
          <h3 className="text-lg font-semibold flex items-center gap-2">
            <CalendarClock className="w-5 h-5 text-primary" />
            Ciclo Semanal de Mensagens
          </h3>
          <p className="text-sm text-muted-foreground">Automa├º├Áes que se repetem infinitamente toda semana</p>
        </div>
        <Button onClick={() => setShowForm(!showForm)} size="sm">
          <Plus className="w-4 h-4 mr-1" />Novo Ciclo
        </Button>
      </div>

      {showForm && (
        <Card>
          <CardContent className="p-4 space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                <Label>Nome</Label>
                <Input value={form.name} onChange={(e) => setForm(p => ({ ...p, name: e.target.value }))} placeholder="Ex: Lembrete semanal" />
              </div>
              <div className="space-y-1">
                <Label>Hor├írio de envio</Label>
                <Input type="time" value={form.send_time} onChange={(e) => setForm(p => ({ ...p, send_time: e.target.value }))} />
              </div>
            </div>

            <div className="space-y-1">
              <Label>Dias da semana</Label>
              <div className="flex gap-1">
                {DAYS.map(day => (
                  <button
                    key={day.value}
                    onClick={() => toggleDay(day.value)}
                    className={`px-3 py-1 rounded text-sm font-medium transition-colors ${
                      form.days_of_week.includes(day.value) ? "bg-primary text-primary-foreground" : "bg-muted text-muted-foreground"
                    }`}
                  >
                    {day.label}
                  </button>
                ))}
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                <Label>Canal</Label>
                <Select value={form.channel} onValueChange={(v) => setForm(p => ({ ...p, channel: v }))}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="whatsapp">WhatsApp</SelectItem>
                    <SelectItem value="sms">SMS</SelectItem>
                    <SelectItem value="notification">Notifica├º├úo Interna</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-1">
                <Label>P├║blico-alvo</Label>
                <Select value={form.target_audience} onValueChange={(v) => setForm(p => ({ ...p, target_audience: v }))}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">Todos os clientes</SelectItem>
                    <SelectItem value="active">Clientes ativos</SelectItem>
                    <SelectItem value="inactive">Clientes inativos</SelectItem>
                    <SelectItem value="vip">Clientes VIP</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>

            <div className="space-y-1">
              <Label>Mensagem</Label>
              <Textarea
                value={form.message_template}
                onChange={(e) => setForm(p => ({ ...p, message_template: e.target.value }))}
                placeholder="Use {nome} para personalizar. Ex: Ol├í {nome}, temos novidades!"
                rows={3}
              />
            </div>

            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Switch checked={form.use_ai} onCheckedChange={(v) => setForm(p => ({ ...p, use_ai: v }))} />
                <Label>Personalizar com IA</Label>
              </div>
              <div className="flex gap-2">
                <Button variant="outline" onClick={() => setShowForm(false)}>Cancelar</Button>
                <Button onClick={saveSchedule}>Salvar</Button>
              </div>
            </div>
          </CardContent>
        </Card>
      )}

      {loading ? (
        <p className="text-center text-muted-foreground py-4">Carregando...</p>
      ) : schedules.length === 0 ? (
        <Card><CardContent className="p-6 text-center text-muted-foreground">Nenhum ciclo configurado</CardContent></Card>
      ) : (
        <div className="space-y-2">
          {schedules.map(s => (
            <Card key={s.id}>
              <CardContent className="p-4 flex items-center justify-between">
                <div className="space-y-1">
                  <div className="flex items-center gap-2">
                    <span className="font-medium">{s.name}</span>
                    <Badge variant={s.is_active ? "default" : "secondary"}>{s.is_active ? "Ativo" : "Pausado"}</Badge>
                    <Badge variant="outline">{s.channel}</Badge>
                    {s.use_ai && <Badge variant="outline">­ƒñû IA</Badge>}
                  </div>
                  <p className="text-sm text-muted-foreground">
                    {s.days_of_week.map(d => DAYS.find(dd => dd.value === d)?.label).join(", ")} ├ás {s.send_time} ÔÇó {s.target_audience}
                  </p>
                </div>
                <div className="flex items-center gap-2">
                  <Switch checked={s.is_active} onCheckedChange={(v) => toggleSchedule(s.id, v)} />
                  <Button variant="ghost" size="icon" onClick={() => deleteSchedule(s.id)}>
                    <Trash2 className="w-4 h-4 text-destructive" />
                  </Button>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </div>
  );
}

import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { Bell, CheckCircle, XCircle, Clock, Loader2 } from "lucide-react";
import { toast } from "sonner";
import { useAuth } from "@/lib/auth";
import { supabase } from "@/integrations/supabase/client";
import { PostAppointmentNotificationsService } from "@/services/notifications/PostAppointmentNotifications";

interface Notification {
  id: string;
  appointment_id: string;
  notification_type: 'finalization_reminder' | 'cancellation_request';
  created_at: string;
  appointment?: {
    client_name: string;
    services?: {
      name: string;
    };
    scheduled_at: string;
  };
}

export const NotificationBell = () => {
  const { user } = useAuth();
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [unreadCount, setUnreadCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [isOpen, setIsOpen] = useState(false);

  const loadNotifications = async () => {
    if (!user) return;

    setLoading(true);
    try {
      const notificationsData = await PostAppointmentNotificationsService.getUnreadNotifications(user.id);
      
      // Buscar detalhes dos agendamentos
      const notificationsWithDetails = await Promise.all(
        notificationsData.map(async (notification) => {
          const { data: appointment } = await (supabase as any)
            .from("appointments")
            .select(`
              client_name,
              services(name),
              scheduled_at
            `)
            .eq("id", notification.appointment_id)
            .single();

          return {
            ...notification,
            appointment: appointment || undefined
          };
        })
      );

      setNotifications(notificationsWithDetails);
      setUnreadCount(notificationsWithDetails.length);
    } catch (error) {
      console.error("Erro ao carregar notifica├º├Áes:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (user) {
      const loadNotifications = async () => {
        if (!user) return;

        setLoading(true);
        try {
          const notificationsData = await PostAppointmentNotificationsService.getUnreadNotifications(user.id);
          
          // Buscar detalhes dos agendamentos
          const notificationsWithDetails = await Promise.all(
            notificationsData.map(async (notification) => {
              const { data: appointment } = await (supabase as any)
                .from("appointments")
                .select(`
                  client_name,
                  services(name),
                  scheduled_at
                `)
                .eq("id", notification.appointment_id)
                .single();

              return {
                ...notification,
                appointment: appointment || undefined
              };
            })
          );

          setNotifications(notificationsWithDetails);
          setUnreadCount(notificationsWithDetails.length);
        } catch (error) {
          console.error("Erro ao carregar notifica├º├Áes:", error);
        } finally {
          setLoading(false);
        }
      };
      loadNotifications();
      
      // Recarregar notifica├º├Áes a cada 30 segundos
      const interval = setInterval(loadNotifications, 30000);
      return () => clearInterval(interval);
    }
  }, [user]);

  const handleNotificationAction = async (
    notification: Notification,
    action: 'finalize' | 'cancel'
  ) => {
    const success = await PostAppointmentNotificationsService.processNotificationAction(
      notification.appointment_id,
      action,
      user?.id || ''
    );

    if (success) {
      // Remover notifica├º├úo da lista
      setNotifications(prev => prev.filter(n => n.id !== notification.id));
      setUnreadCount(prev => Math.max(0, prev - 1));
    }
  };

  const dismissNotification = async (notification: Notification) => {
    await PostAppointmentNotificationsService.acknowledgeNotification(
      notification.id,
      'dismissed'
    );
    
    setNotifications(prev => prev.filter(n => n.id !== notification.id));
    setUnreadCount(prev => Math.max(0, prev - 1));
  };

  const formatTimeAgo = (dateString: string) => {
    const date = new Date(dateString);
    const now = new Date();
    const diffMinutes = Math.floor((now.getTime() - date.getTime()) / (1000 * 60));
    
    if (diffMinutes < 1) return "agora";
    if (diffMinutes < 60) return `${diffMinutes} min atr├ís`;
    
    const diffHours = Math.floor(diffMinutes / 60);
    if (diffHours < 24) return `${diffHours} h atr├ís`;
    
    const diffDays = Math.floor(diffHours / 24);
    return `${diffDays} d atr├ís`;
  };

  return (
    <Popover open={isOpen} onOpenChange={setIsOpen}>
      <PopoverTrigger asChild>
        <Button variant="ghost" size="icon" className="relative">
          <Bell className="h-5 w-5" />
          {unreadCount > 0 && (
            <Badge 
              variant="destructive" 
              className="absolute -top-1 -right-1 h-5 w-5 rounded-full p-0 flex items-center justify-center text-xs"
            >
              {unreadCount > 9 ? '9+' : unreadCount}
            </Badge>
          )}
        </Button>
      </PopoverTrigger>
      
      <PopoverContent className="w-80 p-0" align="end">
        <div className="border-b px-4 py-3">
          <h3 className="font-semibold">Notifica├º├Áes</h3>
          {unreadCount > 0 && (
            <p className="text-sm text-muted-foreground">
              {unreadCount} n├úo lida{unreadCount > 1 ? 's' : ''}
            </p>
          )}
        </div>
        
        <div className="max-h-96 overflow-y-auto">
          {loading ? (
            <div className="flex justify-center py-8">
              <Loader2 className="h-6 w-6 animate-spin" />
            </div>
          ) : notifications.length === 0 ? (
            <div className="text-center py-8 text-muted-foreground">
              <Bell className="h-8 w-8 mx-auto mb-2 opacity-50" />
              <p className="text-sm">Nenhuma notifica├º├úo</p>
            </div>
          ) : (
            <div className="divide-y">
              {notifications.map((notification) => (
                <div key={notification.id} className="p-4 space-y-3">
                  <div className="flex items-start justify-between">
                    <div className="flex-1 space-y-1">
                      <div className="flex items-center gap-2">
                        <Clock className="h-4 w-4 text-blue-500" />
                        <span className="text-sm font-medium">
                          {notification.notification_type === 'finalization_reminder' 
                            ? 'Finalizar Atendimento' 
                            : 'Confirma├º├úo Necess├íria'
                          }
                        </span>
                      </div>
                      
                      {notification.appointment && (
                        <div className="text-sm text-muted-foreground">
                          <p><strong>Cliente:</strong> {notification.appointment.client_name}</p>
                          {notification.appointment.services && (
                            <p><strong>Servi├ºo:</strong> {notification.appointment.services.name}</p>
                          )}
                          <p className="text-xs">
                            {formatTimeAgo(notification.created_at)}
                          </p>
                        </div>
                      )}
                    </div>
                    
                    <Button
                      variant="ghost"
                      size="icon"
                      className="h-6 w-6"
                      onClick={() => dismissNotification(notification)}
                    >
                      <XCircle className="h-4 w-4" />
                    </Button>
                  </div>
                  
                  {notification.notification_type === 'finalization_reminder' && (
                    <div className="flex gap-2">
                      <Button
                        size="sm"
                        onClick={() => handleNotificationAction(notification, 'finalize')}
                        className="flex-1"
                      >
                        <CheckCircle className="h-3 w-3 mr-1" />
                        Finalizar
                      </Button>
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => handleNotificationAction(notification, 'cancel')}
                        className="flex-1"
                      >
                        <XCircle className="h-3 w-3 mr-1" />
                        Cancelar
                      </Button>
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
        
        {notifications.length > 0 && (
          <div className="border-t p-2">
            <Button
              variant="ghost"
              size="sm"
              className="w-full"
              onClick={() => {
                // Marcar todas como lidas
                notifications.forEach(notification => {
                  PostAppointmentNotificationsService.acknowledgeNotification(
                    notification.id,
                    'dismissed'
                  );
                });
                setNotifications([]);
                setUnreadCount(0);
              }}
            >
              Marcar todas como lidas
            </Button>
          </div>
        )}
      </PopoverContent>
    </Popover>
  );
};

import { useState } from "react";
import { useAuth } from "@/lib/auth";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Store, MapPin, Loader2, CheckCircle } from "lucide-react";
import { toast } from "sonner";
import { formatCpfCnpjBR, formatWhatsAppBR } from "@/lib/input-masks";
import logo from "@/assets/logo.png";

interface DonoOnboardingProps {
  onComplete: () => void;
}

const validateForm = (form: { name: string; address: string; cpf_cnpj: string }) => {
  const errors: Record<string, string> = {};
  if (!form.name || form.name.length < 2) {
    errors.name = "Nome da barbearia deve ter no m├¡nimo 2 caracteres";
  }
  if (!form.address || form.address.length < 5) {
    errors.address = "Endere├ºo deve ter no m├¡nimo 5 caracteres";
  }
  const cleanCpfCnpj = form.cpf_cnpj.replace(/\D/g, "");
  if (cleanCpfCnpj.length < 11) {
    errors.cpf_cnpj = "CPF/CNPJ inv├ílido";
  }
  return errors;
};

export function DonoOnboarding({ onComplete }: DonoOnboardingProps) {
  const { user, profile } = useAuth();
  const [saving, setSaving] = useState(false);
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [step, setStep] = useState(1);
  const [form, setForm] = useState({
    name: "",
    address: "",
    cpf_cnpj: profile?.cpf_cnpj || "",
    phone: profile?.whatsapp || "",
    description: "",
  });

  const validateAndSubmit = async () => {
    setErrors({});
    const validationErrors = validateForm(form);
    
    if (Object.keys(validationErrors).length > 0) {
      setErrors(validationErrors);
      return;
    }

    if (!user) return;

    setSaving(true);
    try {
      const baseSlug = form.name
        .toLowerCase()
        .normalize("NFD")
        .replace(/[\u0300-\u036f]/g, "")
        .replace(/[^a-z0-9]+/g, "-")
        .replace(/(^-|-$)/g, "") || `barbearia-${user.id.slice(0, 8)}`;

      const payload = {
        owner_user_id: user.id,
        name: form.name,
        address: form.address,
        phone: form.phone || null,
        description: form.description || null,
      };

      const { data: existingList, error: existingError } = await (supabase as any)
        .from("barbershops")
        .select("id, slug")
        .eq("owner_user_id", user.id)
        .order("created_at", { ascending: true })
        .limit(1);

      if (existingError) {
        toast.error("Erro ao validar cadastro existente: " + existingError.message);
        setSaving(false);
        return;
      }

      const existing = existingList?.[0];

      if (existing) {
        const { error: updateError } = await (supabase as any)
          .from("barbershops")
          .update({
            ...payload,
            slug: existing.slug || baseSlug,
          })
          .eq("id", existing.id);

        if (updateError) {
          toast.error("Erro ao atualizar barbearia: " + updateError.message);
          setSaving(false);
          return;
        }
      } else {
        let slugToUse = baseSlug;

        const insertOnce = async (slug: string) =>
          (supabase as any).from("barbershops").insert({
            ...payload,
            slug,
          });

        let { error: insertError } = await insertOnce(slugToUse);

        if (insertError?.message?.toLowerCase().includes("barbershops_slug_key")) {
          slugToUse = `${baseSlug}-${Math.random().toString(36).slice(2, 6)}`;
          const retry = await insertOnce(slugToUse);
          insertError = retry.error;
        }

        if (insertError) {
          toast.error("Erro ao cadastrar barbearia: " + insertError.message);
          setSaving(false);
          return;
        }
      }

      if (form.cpf_cnpj) {
        await (supabase as any)
          .from("profiles")
          .update({ cpf_cnpj: form.cpf_cnpj })
          .eq("user_id", user.id);
      }

      toast.success("Barbearia cadastrada com sucesso! ­ƒÄë");
      onComplete();
    } catch {
      toast.error("Erro inesperado. Tente novamente.");
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-background p-4">
      <div className="w-full max-w-lg">
        {/* Header */}
        <div className="text-center mb-8">
          <img src={logo} alt="Sal├úoCashBack" className="w-16 h-16 mx-auto mb-4" />
          <h1 className="font-display text-2xl font-bold">Configure sua Barbearia</h1>
          <p className="text-muted-foreground mt-2">
            Complete o cadastro para come├ºar a usar o sistema
          </p>
        </div>

        {/* Progress */}
        <div className="flex items-center justify-center gap-2 mb-8">
          {[1, 2].map((s) => (
            <div
              key={s}
              className={`flex items-center gap-2 ${s <= step ? "text-primary" : "text-muted-foreground"}`}
            >
              <div
                className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold border-2 transition-colors ${
                  s < step
                    ? "bg-primary text-primary-foreground border-primary"
                    : s === step
                    ? "border-primary text-primary"
                    : "border-muted-foreground/30"
                }`}
              >
                {s < step ? <CheckCircle className="w-4 h-4" /> : s}
              </div>
              {s < 2 && (
                <div className={`w-12 h-0.5 ${s < step ? "bg-primary" : "bg-muted"}`} />
              )}
            </div>
          ))}
        </div>

        {step === 1 && (
          <Card>
            <CardHeader>
              <div className="w-10 h-10 rounded-lg bg-primary/10 flex items-center justify-center mb-2">
                <Store className="w-5 h-5 text-primary" />
              </div>
              <CardTitle>Dados da Barbearia</CardTitle>
              <CardDescription>Informa├º├Áes b├ísicas do seu neg├│cio</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div>
                <label htmlFor="name" className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70">Nome da Barbearia *</label>
                <Input
                  id="name"
                  placeholder="Ex: Barbearia do Jo├úo"
                  value={form.name}
                  onChange={(e) => setForm({ ...form, name: e.target.value })}
                  className={`mt-1 ${errors.name ? "border-destructive" : ""}`}
                />
                {errors.name && <p className="text-xs text-destructive mt-1">{errors.name}</p>}
              </div>

              <div>
                <label htmlFor="description" className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70">Descri├º├úo (opcional)</label>
                <Input
                  id="description"
                  placeholder="Breve descri├º├úo do seu neg├│cio"
                  value={form.description}
                  onChange={(e) => setForm({ ...form, description: e.target.value })}
                  className="mt-1"
                />
              </div>

              <div>
                <label htmlFor="phone" className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70">Telefone/WhatsApp</label>
                <Input
                  id="phone"
                  placeholder="(00) 00000-0000"
                  value={form.phone}
                  onChange={(e) => setForm({ ...form, phone: formatWhatsAppBR(e.target.value) })}
                  className="mt-1"
                />
              </div>

              <Button
                variant="gold"
                className="w-full"
                onClick={() => {
                  if (!form.name || form.name.length < 2) {
                    setErrors({ name: "Nome ├® obrigat├│rio" });
                    return;
                  }
                  setErrors({});
                  setStep(2);
                }}
              >
                Pr├│ximo
              </Button>
            </CardContent>
          </Card>
        )}

        {step === 2 && (
          <Card>
            <CardHeader>
              <div className="w-10 h-10 rounded-lg bg-secondary/10 flex items-center justify-center mb-2">
                <MapPin className="w-5 h-5 text-secondary" />
              </div>
              <CardTitle>Endere├ºo e Documentos</CardTitle>
              <CardDescription>Informa├º├Áes fiscais e localiza├º├úo</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div>
                <label htmlFor="address" className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70">Endere├ºo Completo *</label>
                <Input
                  id="address"
                  placeholder="Rua, n├║mero, bairro, cidade - UF"
                  value={form.address}
                  onChange={(e) => setForm({ ...form, address: e.target.value })}
                  className={`mt-1 ${errors.address ? "border-destructive" : ""}`}
                />
                {errors.address && <p className="text-xs text-destructive mt-1">{errors.address}</p>}
              </div>

              <div>
                <label htmlFor="cpf_cnpj" className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70">CPF ou CNPJ *</label>
                <Input
                  id="cpf_cnpj"
                  placeholder="000.000.000-00 ou 00.000.000/0000-00"
                  value={form.cpf_cnpj}
                  onChange={(e) => setForm({ ...form, cpf_cnpj: formatCpfCnpjBR(e.target.value) })}
                  className={`mt-1 ${errors.cpf_cnpj ? "border-destructive" : ""}`}
                />
                {errors.cpf_cnpj && <p className="text-xs text-destructive mt-1">{errors.cpf_cnpj}</p>}
              </div>

              <div className="flex gap-2">
                <Button variant="outline" className="flex-1" onClick={() => setStep(1)}>
                  Voltar
                </Button>
                <Button
                  variant="gold"
                  className="flex-1"
                  onClick={validateAndSubmit}
                  disabled={saving}
                >
                  {saving && <Loader2 className="w-4 h-4 animate-spin mr-2" />}
                  {saving ? "Cadastrando..." : "Finalizar Cadastro"}
                </Button>
              </div>
            </CardContent>
          </Card>
        )}

        <p className="text-center text-xs text-muted-foreground mt-6">
          Voc├¬ poder├í alterar essas informa├º├Áes depois nas configura├º├Áes.
        </p>
      </div>
    </div>
  );
}

import { usePartnerCommissionSummary, usePartnerCommissions } from '@/hooks/usePartners';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Loader2, DollarSign, Clock, CheckCircle, TrendingUp } from 'lucide-react';
import { formatCurrency } from '@/lib/formatters';

interface CommissionsPanelProps {
  partnerId: string;
}

export default function CommissionsPanel({ partnerId }: CommissionsPanelProps) {
  const { data: summary, isLoading: summaryLoading } = usePartnerCommissionSummary(partnerId) as { data: any; isLoading: boolean };
  const { data: commissions, isLoading: commissionsLoading } = usePartnerCommissions(partnerId) as { data: any[]; isLoading: boolean };

  if (summaryLoading) {
    return (
      <div className="flex justify-center items-center py-12">
        <Loader2 className="w-8 h-8 animate-spin text-primary" />
      </div>
    );
  }

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'pending': return 'bg-yellow-500/10 text-yellow-700';
      case 'approved': return 'bg-blue-500/10 text-blue-700';
      case 'paid': return 'bg-green-500/10 text-green-700';
      default: return 'bg-gray-500/10 text-gray-700';
    }
  };

  const getStatusLabel = (status: string) => {
    switch (status) {
      case 'pending': return 'Pendente';
      case 'approved': return 'Aprovada';
      case 'paid': return 'Paga';
      default: return status;
    }
  };

  return (
    <div className="space-y-4">
      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
              <Clock className="w-4 h-4" />
              Pendentes
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{formatCurrency(summary?.pending_amount || 0)}</div>
            <p className="text-xs text-muted-foreground mt-1">
              {summary?.pending_count || 0} comiss├Áes
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
              <CheckCircle className="w-4 h-4" />
              Aprovadas
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{formatCurrency(summary?.approved_amount || 0)}</div>
            <p className="text-xs text-muted-foreground mt-1">
              {summary?.approved_count || 0} comiss├Áes
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
              <DollarSign className="w-4 h-4" />
              Pagas
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-green-600">{formatCurrency(summary?.paid_amount || 0)}</div>
            <p className="text-xs text-muted-foreground mt-1">
              {summary?.paid_count || 0} comiss├Áes
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
              <TrendingUp className="w-4 h-4" />
              Total
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{formatCurrency(summary?.total_amount || 0)}</div>
            <p className="text-xs text-muted-foreground mt-1">
              Todas as comiss├Áes
            </p>
          </CardContent>
        </Card>
      </div>

      {/* Commissions List */}
      <Card>
        <CardHeader>
          <CardTitle>Hist├│rico de Comiss├Áes</CardTitle>
          <CardDescription>
            ├Ültimas comiss├Áes geradas
          </CardDescription>
        </CardHeader>
        <CardContent>
          {commissionsLoading ? (
            <div className="flex justify-center py-8">
              <Loader2 className="w-6 h-6 animate-spin text-primary" />
            </div>
          ) : !commissions || commissions.length === 0 ? (
            <div className="text-center py-8 text-muted-foreground">
              Nenhuma comiss├úo registrada ainda
            </div>
          ) : (
            <div className="space-y-3">
              {commissions.map((commission: any) => (
                <div
                  key={commission.id}
                  className="flex items-center justify-between p-3 border rounded-lg hover:bg-muted/50 transition"
                >
                  <div className="flex-1">
                    <div className="flex items-center gap-2">
                      <p className="font-medium capitalize">
                        {commission.type.replace(/_/g, ' ')}
                      </p>
                      <Badge variant="outline" className={getStatusColor(commission.status)}>
                        {getStatusLabel(commission.status)}
                      </Badge>
                    </div>
                    <p className="text-sm text-muted-foreground mt-1">
                      {commission.description || 'Sem descri├º├úo'}
                    </p>
                  </div>
                  <div className="text-right">
                    <p className="font-bold text-lg">
                      {formatCurrency(commission.amount)}
                    </p>
                    <p className="text-xs text-muted-foreground">
                      {new Date(commission.created_at).toLocaleDateString('pt-BR')}
                    </p>
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

// Componente de formul├írio para criar/editar parceiros
// Integra├º├úo com estrutura existente

import { useState } from 'react';
import { useCreatePartner, usePartners } from '@/hooks/usePartners';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Loader2, UserPlus, CheckCircle, XCircle } from 'lucide-react';
import { toast } from 'sonner';

interface PartnerFormProps {
  onSuccess?: () => void;
  onCancel?: () => void;
  defaultValues?: {
    user_id?: string;
    type?: 'afiliado' | 'franqueado' | 'diretor';
    parent_id?: string | null;
  };
}

export default function PartnerForm({ 
  onSuccess, 
  onCancel, 
  defaultValues 
}: PartnerFormProps) {
  const { data: partners } = usePartners();
  const createPartner = useCreatePartner();
  
  const [formData, setFormData] = useState({
    user_id: defaultValues?.user_id || '',
    type: defaultValues?.type || 'afiliado' as 'afiliado' | 'franqueado' | 'diretor',
    parent_id: defaultValues?.parent_id || '',
  });

  const [errors, setErrors] = useState<Record<string, string>>({});

  const validateForm = () => {
    const newErrors: Record<string, string> = {};

    if (!formData.user_id.trim()) {
      newErrors.user_id = 'ID do usu├írio ├® obrigat├│rio';
    }

    if (!formData.type) {
      newErrors.type = 'Tipo de parceiro ├® obrigat├│rio';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    if (!validateForm()) {
      toast.error('Por favor, corrija os erros no formul├írio');
      return;
    }

    try {
      const partnerData = {
        user_id: formData.user_id.trim(),
        type: formData.type,
        parent_id: formData.parent_id || null,
      };

      await createPartner.mutateAsync(partnerData);
      
      toast.success('Parceiro criado com sucesso!', {
        icon: <CheckCircle className="w-5 h-5 text-green-500" />,
      });

      // Reset form
      setFormData({
        user_id: '',
        type: 'afiliado',
        parent_id: '',
      });
      setErrors({});

      if (onSuccess) onSuccess();
    } catch (error: any) {
      console.error('Erro ao criar parceiro:', error);
      
      let errorMessage = 'Erro ao criar parceiro';
      if (error?.message?.includes('duplicate key')) {
        errorMessage = 'Este usu├írio j├í ├® um parceiro';
      } else if (error?.message?.includes('foreign key')) {
        errorMessage = 'Usu├írio n├úo encontrado';
      }

      toast.error(errorMessage, {
        icon: <XCircle className="w-5 h-5 text-red-500" />,
      });
    }
  };

  const handleChange = (field: string, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    
    // Clear error for this field when user starts typing
    if (errors[field]) {
      setErrors(prev => ({ ...prev, [field]: '' }));
    }
  };

  const getTypeDescription = (type: string) => {
    switch (type) {
      case 'afiliado':
        return 'Indica clientes e ganha comiss├úo sobre vendas';
      case 'franqueado':
        return 'Gerencia uma unidade e ganha sobre faturamento';
      case 'diretor':
        return 'Coordena franqueados e ganha sobre rede';
      default:
        return '';
    }
  };

  const activePartners = partners?.filter(p => p.status === 'ativo') || [];

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <UserPlus className="w-5 h-5" />
          {defaultValues?.user_id ? 'Editar Parceiro' : 'Novo Parceiro'}
        </CardTitle>
      </CardHeader>
      <CardContent>
        <form onSubmit={handleSubmit} className="space-y-4">
          {/* User ID */}
          <div className="space-y-2">
            <Label htmlFor="user_id">
              ID do Usu├írio <span className="text-destructive">*</span>
            </Label>
            <Input
              id="user_id"
              placeholder="Digite o ID do usu├írio (UUID)"
              value={formData.user_id}
              onChange={(e) => handleChange('user_id', e.target.value)}
              className={errors.user_id ? 'border-destructive' : ''}
              disabled={!!defaultValues?.user_id}
            />
            {errors.user_id && (
              <p className="text-sm text-destructive">{errors.user_id}</p>
            )}
            <p className="text-xs text-muted-foreground">
              ID ├║nico do usu├írio no sistema (geralmente do auth.users)
            </p>
          </div>

          {/* Partner Type */}
          <div className="space-y-2">
            <Label htmlFor="type">
              Tipo de Parceiro <span className="text-destructive">*</span>
            </Label>
            <Select
              value={formData.type}
              onValueChange={(value: 'afiliado' | 'franqueado' | 'diretor') => 
                handleChange('type', value)
              }
            >
              <SelectTrigger className={errors.type ? 'border-destructive' : ''}>
                <SelectValue placeholder="Selecione o tipo" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="afiliado">
                  <div className="flex items-center gap-2">
                    <div className="w-2 h-2 rounded-full bg-green-500" />
                    <span>Afiliado</span>
                  </div>
                </SelectItem>
                <SelectItem value="franqueado">
                  <div className="flex items-center gap-2">
                    <div className="w-2 h-2 rounded-full bg-blue-500" />
                    <span>Franqueado</span>
                  </div>
                </SelectItem>
                <SelectItem value="diretor">
                  <div className="flex items-center gap-2">
                    <div className="w-2 h-2 rounded-full bg-purple-500" />
                    <span>Diretor</span>
                  </div>
                </SelectItem>
              </SelectContent>
            </Select>
            {errors.type && (
              <p className="text-sm text-destructive">{errors.type}</p>
            )}
            <p className="text-xs text-muted-foreground">
              {getTypeDescription(formData.type)}
            </p>
          </div>

          {/* Parent Partner (Optional) */}
          <div className="space-y-2">
            <Label htmlFor="parent_id">Parceiro Pai (Opcional)</Label>
            <Select
              value={formData.parent_id}
              onValueChange={(value) => handleChange('parent_id', value)}
            >
              <SelectTrigger>
                <SelectValue placeholder="Selecione o parceiro pai" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="">Nenhum (Parceiro raiz)</SelectItem>
                {activePartners.map(partner => (
                  <SelectItem key={partner.id} value={partner.id}>
                    <div className="flex items-center gap-2">
                      <span className="capitalize">{partner.type}</span>
                      <span className="text-muted-foreground text-xs">
                        - {partner.users?.name || 'Sem nome'}
                      </span>
                    </div>
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
            <p className="text-xs text-muted-foreground">
              Selecione o parceiro que indicou este novo parceiro
            </p>
          </div>

          {/* Form Actions */}
          <div className="flex gap-2 pt-4">
            <Button
              type="submit"
              disabled={createPartner.isPending}
              className="flex-1"
            >
              {createPartner.isPending ? (
                <>
                  <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                  Criando...
                </>
              ) : (
                <>
                  <UserPlus className="w-4 h-4 mr-2" />
                  {defaultValues?.user_id ? 'Atualizar' : 'Criar Parceiro'}
                </>
              )}
            </Button>

            {onCancel && (
              <Button
                type="button"
                variant="outline"
                onClick={onCancel}
                disabled={createPartner.isPending}
              >
                Cancelar
              </Button>
            )}
          </div>

          {/* Help Text */}
          <div className="pt-4 border-t">
            <p className="text-sm text-muted-foreground">
              <strong>Importante:</strong> O usu├írio deve existir no sistema antes de ser cadastrado como parceiro.
            </p>
            <p className="text-xs text-muted-foreground mt-1">
              Ap├│s a cria├º├úo, o parceiro aparecer├í na lista e poder├í come├ºar a indicar clientes.
            </p>
          </div>
        </form>
      </CardContent>
    </Card>
  );
}

import { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Loader2, Bell, Trash2, CheckCircle, AlertCircle, Gift, Users } from 'lucide-react';
import { toast } from 'sonner';
import { markNotificationAsRead, deleteNotification, markAllNotificationsAsRead } from '@/services/partnerNotificationService';

interface PartnerNotificationCenterProps {
  partnerId: string;
}

export default function PartnerNotificationCenter({ partnerId }: PartnerNotificationCenterProps) {
  const queryClient = useQueryClient();
  const [filter, setFilter] = useState<'all' | 'unread'>('unread');

  const { data: notifications, isLoading } = useQuery({
    queryKey: ['partner-notifications', partnerId, filter],
    queryFn: async () => {
      let query = (supabase as any)
        .from('partner_notifications')
        .select('*')
        .eq('partner_id', partnerId)
        .order('created_at', { ascending: false });

      if (filter === 'unread') {
        query = (query as any).eq('read', false);
      }

      const { data, error } = await query;
      if (error) throw error;
      return data || [];
    },
  });

  const markAsReadMutation = useMutation({
    mutationFn: markNotificationAsRead,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['partner-notifications'] });
      toast.success('Notifica├º├úo marcada como lida');
    },
  });

  const deleteMutation = useMutation({
    mutationFn: deleteNotification,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['partner-notifications'] });
      toast.success('Notifica├º├úo deletada');
    },
  });

  const markAllAsReadMutation = useMutation({
    mutationFn: () => markAllNotificationsAsRead(partnerId),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['partner-notifications'] });
      toast.success('Todas as notifica├º├Áes marcadas como lidas');
    },
  });

  const getIcon = (type: string) => {
    switch (type) {
      case 'commission_generated':
      case 'commission_approved':
      case 'commission_paid':
        return <Gift className="w-5 h-5 text-green-500" />;
      case 'new_referral':
      case 'referral_completed':
        return <Users className="w-5 h-5 text-blue-500" />;
      default:
        return <Bell className="w-5 h-5 text-gray-500" />;
    }
  };

  const getTypeLabel = (type: string) => {
    switch (type) {
      case 'commission_generated': return 'Comiss├úo Gerada';
      case 'commission_approved': return 'Comiss├úo Aprovada';
      case 'commission_paid': return 'Comiss├úo Paga';
      case 'new_referral': return 'Nova Indica├º├úo';
      case 'referral_completed': return 'Indica├º├úo Completada';
      default: return type;
    }
  };

  const unreadCount = notifications?.filter((n: any) => !n.read).length || 0;

  if (isLoading) {
    return (
      <div className="flex justify-center items-center py-12">
        <Loader2 className="w-8 h-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold">Notifica├º├Áes</h2>
          {unreadCount > 0 && (
            <p className="text-sm text-muted-foreground">
              {unreadCount} notifica├º├úo{unreadCount !== 1 ? 's' : ''} n├úo lida{unreadCount !== 1 ? 's' : ''}
            </p>
          )}
        </div>
        {unreadCount > 0 && (
          <Button
            variant="outline"
            size="sm"
            onClick={() => markAllAsReadMutation.mutate()}
            disabled={markAllAsReadMutation.isPending}
          >
            Marcar todas como lidas
          </Button>
        )}
      </div>

      {/* Filters */}
      <div className="flex gap-2">
        <Button
          variant={filter === 'all' ? 'default' : 'outline'}
          size="sm"
          onClick={() => setFilter('all')}
        >
          Todas
        </Button>
        <Button
          variant={filter === 'unread' ? 'default' : 'outline'}
          size="sm"
          onClick={() => setFilter('unread')}
        >
          N├úo lidas ({unreadCount})
        </Button>
      </div>

      {/* Notifications List */}
      <Card>
        <CardContent className="p-0">
          {!notifications || notifications.length === 0 ? (
            <div className="text-center py-12 text-muted-foreground">
              <Bell className="w-12 h-12 mx-auto mb-4 opacity-30" />
              <p>Nenhuma notifica├º├úo</p>
            </div>
          ) : (
            <div className="divide-y">
              {notifications.map((notification: any) => (
                <div
                  key={notification.id}
                  className={`p-4 hover:bg-muted/50 transition ${
                    !notification.read ? 'bg-blue-50/50' : ''
                  }`}
                >
                  <div className="flex items-start gap-3">
                    <div className="mt-1">
                      {getIcon(notification.type)}
                    </div>

                    <div className="flex-1">
                      <div className="flex items-center gap-2 mb-1">
                        <p className="font-semibold">
                          {notification.title}
                        </p>
                        {!notification.read && (
                          <Badge variant="default" className="text-xs">
                            Novo
                          </Badge>
                        )}
                      </div>

                      <p className="text-sm text-muted-foreground mb-2">
                        {notification.message}
                      </p>

                      <div className="flex items-center justify-between">
                        <p className="text-xs text-muted-foreground">
                          {new Date(notification.created_at).toLocaleDateString('pt-BR', {
                            year: 'numeric',
                            month: 'short',
                            day: 'numeric',
                            hour: '2-digit',
                            minute: '2-digit',
                          })}
                        </p>

                        <div className="flex gap-2">
                          {!notification.read && (
                            <Button
                              variant="ghost"
                              size="sm"
                              onClick={() => markAsReadMutation.mutate(notification.id)}
                              disabled={markAsReadMutation.isPending}
                            >
                              <CheckCircle className="w-4 h-4" />
                            </Button>
                          )}
                          <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => deleteMutation.mutate(notification.id)}
                            disabled={deleteMutation.isPending}
                          >
                            <Trash2 className="w-4 h-4" />
                          </Button>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

