import { useState, useEffect, useCallback } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { toast } from "sonner";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/lib/auth";
import { FinalizarAtendimentoModal } from "@/components/atendimento/FinalizarAtendimentoModal";
import {
  Calendar,
  Clock,
  User,
  Scissors,
  CheckCircle,
  XCircle,
  DollarSign,
  Loader2
} from "lucide-react";

interface Appointment {
  id: string;
  client_name: string;
  client_user_id?: string;
  service_id: string;
  professional_id: string;
  barbershop_id: string;
  scheduled_at: string;
  status: string;
  notes?: string;
  services?: {
    name: string;
    price: number;
    duration_minutes: number;
  };
  professionals?: {
    name: string;
    commission_percent: number;
  };
  barbershops?: {
    name: string;
  };
}

interface AgendaProfissionalProps {
  professionalId?: string;
}

export const AgendaProfissional = ({ professionalId }: AgendaProfissionalProps) => {
  const { user } = useAuth();
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedAppointment, setSelectedAppointment] = useState<Appointment | null>(null);
  const [showFinalizarModal, setShowFinalizarModal] = useState(false);
  const [filter, setFilter] = useState<"today" | "all">("today");

  const loadAppointments = useCallback(async () => {
    if (!user && !professionalId) return;

    setLoading(true);
    try {
      const query = (supabase as any)
        .from("appointments")
        .select(`
          *,
          services(name, price, duration_minutes),
          professionals(name, commission_percent),
          barbershops(name)
        `)
        .in("status", ["scheduled", "in_progress"])
        .order("scheduled_at", { ascending: true });

      if (professionalId) {
        query.eq("professional_id", professionalId);
      } else {
        query.eq("professional_id", user?.user_metadata?.professional_id);
      }

      const { data, error } = await query;

      if (error) throw error;

      let filteredData = data || [];
      
      if (filter === "today") {
        const today = new Date().toISOString().split('T')[0];
        filteredData = filteredData.filter(apt => 
          apt.scheduled_at.startsWith(today)
        );
      }

      setAppointments(filteredData);
    } catch (error: any) {
      console.error("Erro ao carregar agenda:", error);
      toast.error("Erro ao carregar agenda");
    } finally {
      setLoading(false);
    }
  }, [user, professionalId, filter]);

  useEffect(() => {
    loadAppointments();
  }, [user, professionalId, filter, loadAppointments]);

  const handleFinalizarAtendimento = (appointment: Appointment) => {
    setSelectedAppointment(appointment);
    setShowFinalizarModal(true);
  };

  const handleCancelarAtendimento = async (appointment: Appointment) => {
    try {
      const { error } = await (supabase as any)
        .from("appointments")
        .update({
          status: "cancelled",
          updated_at: new Date().toISOString()
        })
        .eq("id", appointment.id);

      if (error) throw error;

      toast.success("Atendimento cancelado");
      loadAppointments();
    } catch (error: any) {
      console.error("Erro ao cancelar atendimento:", error);
      toast.error("Erro ao cancelar atendimento");
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case "scheduled":
        return "bg-blue-100 text-blue-800";
      case "in_progress":
        return "bg-yellow-100 text-yellow-800";
      case "completed":
        return "bg-green-100 text-green-800";
      case "cancelled":
        return "bg-red-100 text-red-800";
      default:
        return "bg-gray-100 text-gray-800";
    }
  };

  const getStatusText = (status: string) => {
    switch (status) {
      case "scheduled":
        return "Agendado";
      case "in_progress":
        return "Em Andamento";
      case "completed":
        return "Conclu├¡do";
      case "cancelled":
        return "Cancelado";
      default:
        return status;
    }
  };

  const isPastAppointment = (scheduledAt: string) => {
    return new Date(scheduledAt) < new Date();
  };

  const isInProgressAppointment = (scheduledAt: string) => {
    const now = new Date();
    const appointmentTime = new Date(scheduledAt);
    const diffMinutes = (now.getTime() - appointmentTime.getTime()) / (1000 * 60);
    return diffMinutes >= -15 && diffMinutes <= 120; // 15min antes at├® 2h depois
  };

  if (loading) {
    return (
      <div className="flex justify-center py-12">
        <Loader2 className="w-8 h-8 animate-spin" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold flex items-center gap-2">
            <Calendar className="w-6 h-6" />
            Minha Agenda
          </h2>
          <p className="text-muted-foreground">
            {filter === "today" ? "Agendamentos de hoje" : "Todos os agendamentos"}
          </p>
        </div>
        
        <div className="flex gap-2">
          <Button
            variant={filter === "today" ? "default" : "outline"}
            size="sm"
            onClick={() => setFilter("today")}
          >
            Hoje
          </Button>
          <Button
            variant={filter === "all" ? "default" : "outline"}
            size="sm"
            onClick={() => setFilter("all")}
          >
            Todos
          </Button>
        </div>
      </div>

      {appointments.length === 0 ? (
        <Card>
          <CardContent className="py-12 text-center">
            <Calendar className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
            <p className="text-muted-foreground">
              {filter === "today" 
                ? "Nenhum atendimento agendado para hoje." 
                : "Nenhum atendimento agendado."
              }
            </p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-4">
          {appointments.map((appointment) => (
            <Card key={appointment.id} className="relative">
              <CardContent className="p-6">
                <div className="flex items-start justify-between">
                  <div className="space-y-2 flex-1">
                    <div className="flex items-center gap-2">
                      <User className="w-4 h-4 text-muted-foreground" />
                      <span className="font-semibold">{appointment.client_name}</span>
                      <Badge className={getStatusColor(appointment.status)}>
                        {getStatusText(appointment.status)}
                      </Badge>
                    </div>
                    
                    <div className="flex items-center gap-4 text-sm text-muted-foreground">
                      <div className="flex items-center gap-1">
                        <Scissors className="w-4 h-4" />
                        {appointment.services?.name || "Servi├ºo"}
                      </div>
                      <div className="flex items-center gap-1">
                        <Clock className="w-4 h-4" />
                        {new Date(appointment.scheduled_at).toLocaleTimeString('pt-BR', {
                          hour: '2-digit',
                          minute: '2-digit'
                        })}
                      </div>
                      <div className="flex items-center gap-1">
                        <DollarSign className="w-4 h-4" />
                        R$ {appointment.services?.price?.toFixed(2) || "0,00"}
                      </div>
                    </div>

                    {appointment.notes && (
                      <p className="text-sm text-muted-foreground mt-2">
                        <strong>Observa├º├Áes:</strong> {appointment.notes}
                      </p>
                    )}

                    {appointment.barbershops && (
                      <p className="text-sm text-muted-foreground">
                        <strong>Local:</strong> {appointment.barbershops.name}
                      </p>
                    )}
                  </div>

                  <div className="flex flex-col gap-2 ml-4">
                    {appointment.status === "scheduled" && isInProgressAppointment(appointment.scheduled_at) && (
                      <Button
                        size="sm"
                        onClick={() => handleFinalizarAtendimento(appointment)}
                        className="bg-green-600 hover:bg-green-700"
                      >
                        <CheckCircle className="w-4 h-4 mr-1" />
                        Iniciar
                      </Button>
                    )}
                    
                    {appointment.status === "scheduled" && isPastAppointment(appointment.scheduled_at) && (
                      <>
                        <Button
                          size="sm"
                          onClick={() => handleFinalizarAtendimento(appointment)}
                          className="bg-blue-600 hover:bg-blue-700"
                        >
                          <CheckCircle className="w-4 h-4 mr-1" />
                          Finalizar
                        </Button>
                        <Button
                          size="sm"
                          variant="destructive"
                          onClick={() => handleCancelarAtendimento(appointment)}
                        >
                          <XCircle className="w-4 h-4 mr-1" />
                          Cancelar
                        </Button>
                      </>
                    )}

                    {appointment.status === "in_progress" && (
                      <Button
                        size="sm"
                        onClick={() => handleFinalizarAtendimento(appointment)}
                        className="bg-green-600 hover:bg-green-700"
                      >
                        <CheckCircle className="w-4 h-4 mr-1" />
                        Finalizar
                      </Button>
                    )}
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      <FinalizarAtendimentoModal
        open={showFinalizarModal}
        onOpenChange={setShowFinalizarModal}
        appointment={selectedAppointment}
        onSuccess={() => {
          loadAppointments();
          setSelectedAppointment(null);
        }}
      />
    </div>
  );
};

import { useState, useEffect } from "react";
import { useAuth } from "@/lib/auth";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { CreditCard, Loader2, CheckCircle2, AlertCircle } from "lucide-react";
import { toast } from "sonner";
import { formatCpfCnpjBR } from "@/lib/input-masks";

interface ProfessionalBankData {
  name: string;
  cpf_cnpj: string;
  mobile_phone: string;
  pix_key: string;
  pix_key_type: string;
  asaas_wallet_id: string | null;
}

const PIX_KEY_TYPES = [
  { value: "cpf", label: "CPF/CNPJ" },
  { value: "email", label: "E-mail" },
  { value: "phone", label: "Telefone" },
  { value: "random", label: "Chave Aleat├│ria" },
];

const ContaBancariaPage = () => {
  const { user, profile } = useAuth();
  const [data, setData] = useState<ProfessionalBankData | null>(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [professionalId, setProfessionalId] = useState<string | null>(null);

  const [form, setForm] = useState({
    name: "",
    cpf_cnpj: "",
    mobile_phone: "",
    pix_key: "",
    pix_key_type: "cpf",
  });

  useEffect(() => {
    if (!user) return;
    (async () => {
      const { data: prof } = await (supabase as any)
        .from("professionals")
        .select("id, name, cpf_cnpj, whatsapp, pix_key, asaas_wallet_id")
        .eq("user_id", user.id)
        .maybeSingle();

      if (prof) {
        setProfessionalId(prof.id);
        const ph = (prof as any).whatsapp || "";
        const bankData: ProfessionalBankData = {
          name: prof.name || "",
          cpf_cnpj: prof.cpf_cnpj || "",
          mobile_phone: typeof ph === "string" ? ph.replace(/\D/g, "") : "",
          pix_key: prof.pix_key || "",
          pix_key_type: "cpf",
          asaas_wallet_id: prof.asaas_wallet_id,
        };
        setData(bankData);
        setForm({
          name: prof.name || profile?.name || "",
          cpf_cnpj: prof.cpf_cnpj || "",
          mobile_phone: bankData.mobile_phone,
          pix_key: prof.pix_key || "",
          pix_key_type: "cpf",
        });
      } else {
        setForm(f => ({ ...f, name: profile?.name || "" }));
      }
      setLoading(false);
    })();
  }, [user, profile]);

  const handleSave = async () => {
    if (!form.name.trim()) {
      toast.error("Nome completo ├® obrigat├│rio.");
      return;
    }
    if (!form.cpf_cnpj.replace(/\D/g, "")) {
      toast.error("CPF/CNPJ ├® obrigat├│rio para criar sua conta no gateway.");
      return;
    }
    if (!form.pix_key) {
      toast.error("Chave PIX ├® obrigat├│ria para receber pagamentos.");
      return;
    }
    const phoneDigits = form.mobile_phone.replace(/\D/g, "");
    if (phoneDigits.length < 10) {
      toast.error("Telefone/WhatsApp ├® obrigat├│rio para criar conta no gateway (formato: 11999990000).");
      return;
    }

    setSaving(true);

    // Save to professionals table
    const updatePayload: Record<string, string> = {
      name: form.name,
      cpf_cnpj: form.cpf_cnpj.replace(/\D/g, ""),
      pix_key: form.pix_key,
    };
    if (phoneDigits.length >= 10) (updatePayload as any).whatsapp = `+55${phoneDigits}`;

    const { error } = await (supabase as any)
      .from("professionals")
      .update(updatePayload)
      .eq("user_id", user!.id);

    if (error) {
      toast.error("Erro ao salvar: " + error.message);
      setSaving(false);
      return;
    }

    // Call edge function to create gateway account
    try {
      const { data: result, error: fnError } = await supabase.functions.invoke("process-payment", {
        body: {
          action: "create-professional-account",
          professional_id: professionalId,
          cpf_cnpj: form.cpf_cnpj.replace(/\D/g, ""),
          name: form.name,
          email: profile?.email,
          mobile_phone: phoneDigits.length >= 10 ? phoneDigits : undefined,
          pix_key: form.pix_key,
        },
      });

      if (fnError) throw new Error(fnError.message);

      setData({
        ...form,
        cpf_cnpj: form.cpf_cnpj.replace(/\D/g, ""),
        asaas_wallet_id: result?.wallet_id || data?.asaas_wallet_id || null,
      });

      toast.success("Dados salvos e conta criada no gateway!");
    } catch (e: any) {
      console.error("Gateway error:", e);
      setData({
        ...form,
        cpf_cnpj: form.cpf_cnpj.replace(/\D/g, ""),
        asaas_wallet_id: data?.asaas_wallet_id || null,
      });
      toast.success("Dados salvos! A conta no gateway ser├í criada automaticamente.");
    }

    setSaving(false);
  };

  if (loading) {
    return (
      <div className="flex justify-center py-12">
        <Loader2 className="w-8 h-8 animate-spin text-primary" />
      </div>
    );
  }

  if (!professionalId) {
    return (
      <div className="space-y-6">
        <h1 className="font-display text-2xl font-bold">Conta Banc├íria / PIX</h1>
        <Card className="border-destructive/30 bg-destructive/5">
          <CardContent className="py-8 text-center">
            <AlertCircle className="w-12 h-12 text-destructive mx-auto mb-4" />
            <p className="text-muted-foreground">Seu cadastro de profissional n├úo foi encontrado. Contate o dono da barbearia.</p>
          </CardContent>
        </Card>
      </div>
    );
  }

  const hasGatewayAccount = !!data?.asaas_wallet_id;
  const hasData = !!data?.cpf_cnpj;

  return (
    <div className="space-y-6">
      <h1 className="font-display text-2xl font-bold">Conta Banc├íria / PIX</h1>

      {/* Status card */}
      {hasGatewayAccount && (
      <Card className="border-primary/30 bg-primary/5">
          <CardContent className="py-4 flex items-center gap-3">
            <CheckCircle2 className="w-5 h-5 text-primary shrink-0" />
            <div>
              <p className="font-medium text-sm">Conta ativa no gateway</p>
              <p className="text-xs text-muted-foreground">Seus recebimentos cair├úo automaticamente via PIX.</p>
            </div>
          </CardContent>
        </Card>
      )}

      <Card className="border-primary/20">
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <CreditCard className="w-5 h-5" />
            Dados para Recebimento
          </CardTitle>
          <CardDescription>
            Preencha seu CPF/CNPJ e chave PIX. Sua conta no gateway de pagamentos ser├í criada automaticamente.
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="md:col-span-2">
              <Label>Nome Completo *</Label>
              <Input
                value={form.name}
                onChange={(e) => setForm({ ...form, name: e.target.value })}
                placeholder="Nome completo conforme documento"
                className="mt-1"
              />
              <p className="text-xs text-muted-foreground mt-1">Nome que aparecer├í na conta do gateway</p>
            </div>
            <div>
              <Label>Telefone / WhatsApp *</Label>
              <Input
                value={form.mobile_phone}
                onChange={(e) => setForm({ ...form, mobile_phone: e.target.value.replace(/\D/g, "").slice(0, 11) })}
                placeholder="11999990000"
                className="mt-1"
              />
              <p className="text-xs text-muted-foreground mt-1">Obrigat├│rio para API gateway</p>
            </div>
            <div>
              <Label>CPF/CNPJ *</Label>
              <Input
                value={formatCpfCnpjBR(form.cpf_cnpj)}
                onChange={(e) => setForm({ ...form, cpf_cnpj: e.target.value })}
                placeholder="000.000.000-00"
                className="mt-1"
              />
              <p className="text-xs text-muted-foreground mt-1">Necess├írio para criar sua conta no gateway</p>
            </div>
            <div>
              <Label>Tipo de Chave PIX</Label>
              <select
                className="flex h-11 w-full rounded-lg border border-input bg-muted/30 px-4 py-2 text-sm mt-1 transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary focus-visible:ring-offset-2"
                value={form.pix_key_type}
                onChange={(e) => setForm({ ...form, pix_key_type: e.target.value })}
              >
                {PIX_KEY_TYPES.map((t) => (
                  <option key={t.value} value={t.value}>{t.label}</option>
                ))}
              </select>
            </div>
            <div className="md:col-span-2">
              <Label>Chave PIX *</Label>
              <Input
                value={form.pix_key}
