          </Button>
        </CardContent>
      </Card>
    </div>
  );
};

export default ContaBancariaPage;

import { useState, useEffect, useCallback } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "@/hooks/use-toast";
import { Star, MessageCircle } from "lucide-react";

interface ClientReviewsPanelProps {
  barbershopId: string;
  canCreate?: boolean;
}

interface Review {
  id: string;
  rating: number;
  comment: string | null;
  created_at: string;
  is_public: boolean;
}

export function ClientReviewsPanel({ barbershopId, canCreate = false }: ClientReviewsPanelProps) {
  const [reviews, setReviews] = useState<Review[]>([]);
  const [loading, setLoading] = useState(true);
  const [newRating, setNewRating] = useState(5);
  const [newComment, setNewComment] = useState("");
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    loadReviews();
  }, [barbershopId, loadReviews]);

  const loadReviews = useCallback(async () => {
    try {
      const { data } = await (supabase as any)
        .from("client_reviews")
        .select("id, rating, comment, created_at, is_public")
        .eq("barbershop_id", barbershopId)
        .eq("is_public", true)
        .order("created_at", { ascending: false })
        .limit(50);

      setReviews(data || []);
    } catch (err) {
      console.error("Error loading reviews:", err);
    } finally {
      setLoading(false);
    }
  }, [barbershopId]);

  const submitReview = async () => {
    setSubmitting(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Fa├ºa login para avaliar");

      const { error } = await (supabase as any)
        .from("client_reviews")
        .insert({
          barbershop_id: barbershopId,
          client_user_id: user.id,
          rating: newRating,
          comment: newComment || null,
        });

      if (error) throw error;
      toast({ title: "Avalia├º├úo enviada!", description: "Obrigado pelo seu feedback." });
      setNewComment("");
      setNewRating(5);
      loadReviews();
    } catch (err: any) {
      toast({ title: "Erro", description: err.message, variant: "destructive" });
    } finally {
      setSubmitting(false);
    }
  };

  const avgRating = reviews.length > 0 ? (reviews.reduce((s, r) => s + r.rating, 0) / reviews.length).toFixed(1) : "0.0";

  return (
    <div className="space-y-4">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center justify-between">
            <span className="flex items-center gap-2"><Star className="w-5 h-5 text-yellow-500" />Avalia├º├Áes</span>
            <Badge variant="secondary">Ô¡É {avgRating} ({reviews.length})</Badge>
          </CardTitle>
        </CardHeader>
        <CardContent>
          {canCreate && (
            <div className="mb-6 p-4 border rounded-lg space-y-3">
              <div className="flex gap-1">
                {[1, 2, 3, 4, 5].map(star => (
                  <button key={star} onClick={() => setNewRating(star)} className="p-1">
                    <Star className={`w-6 h-6 ${star <= newRating ? "fill-yellow-500 text-yellow-500" : "text-muted-foreground"}`} />
                  </button>
                ))}
              </div>
              <Textarea value={newComment} onChange={(e) => setNewComment(e.target.value)} placeholder="Conte sua experi├¬ncia..." rows={2} />
              <Button onClick={submitReview} disabled={submitting} size="sm">
                {submitting ? "Enviando..." : "Enviar Avalia├º├úo"}
              </Button>
            </div>
          )}

          {loading ? (
            <p className="text-muted-foreground text-center py-4">Carregando...</p>
          ) : reviews.length === 0 ? (
            <p className="text-muted-foreground text-center py-4">Nenhuma avalia├º├úo ainda</p>
          ) : (
            <div className="space-y-3">
              {reviews.map(review => (
                <div key={review.id} className="p-3 border rounded-lg">
                  <div className="flex items-center gap-1 mb-1">
                    {[1, 2, 3, 4, 5].map(s => (
                      <Star key={s} className={`w-4 h-4 ${s <= review.rating ? "fill-yellow-500 text-yellow-500" : "text-muted-foreground"}`} />
                    ))}
                    <span className="text-xs text-muted-foreground ml-2">
                      {new Date(review.created_at).toLocaleDateString("pt-BR")}
                    </span>
                  </div>
                  {review.comment && <p className="text-sm">{review.comment}</p>}
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

import { useState, useEffect } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";
import { Loader2, Save, AlertCircle, CheckCircle } from "lucide-react";
import { toast } from "sonner";
import { useAuth } from "@/lib/auth";
import { getBookingPolicies, updateBookingPolicies } from "@/services/onboardingService";

interface BookingPolicies {
  deposit_required: boolean;
  deposit_percentage: number;
  cancellation_window_hours: number;
  no_show_fee_percentage: number;
  advance_booking_hours_min: number;
  advance_booking_hours_max: number;
  buffer_minutes_before: number;
  buffer_minutes_after: number;
  allow_recurring: boolean;
  max_instances_per_recurring: number;
  require_confirmation: boolean;
  auto_confirm_after_hours: number;
}

const DEFAULT_POLICIES: BookingPolicies = {
  deposit_required: false,
  deposit_percentage: 0,
  cancellation_window_hours: 24,
  no_show_fee_percentage: 0,
  advance_booking_hours_min: 1,
  advance_booking_hours_max: 720,
  buffer_minutes_before: 0,
  buffer_minutes_after: 0,
  allow_recurring: true,
  max_instances_per_recurring: 12,
  require_confirmation: true,
  auto_confirm_after_hours: 24,
};

export default function BookingPoliciesPanel() {
  const { barbershop } = useAuth();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [policies, setPolicies] = useState<BookingPolicies>(DEFAULT_POLICIES);
  const [hasChanges, setHasChanges] = useState(false);

  useEffect(() => {
    if (barbershop?.id) {
      const fetchPolicies = async () => {
        if (!barbershop?.id) return;
        setLoading(true);
        try {
          const result = await getBookingPolicies(barbershop.id);
          if (result.success && result.policies) {
            setPolicies({ ...DEFAULT_POLICIES, ...result.policies });
          }
        } catch (error) {
          console.error("Erro ao buscar pol├¡ticas:", error);
          toast.error("Erro ao carregar pol├¡ticas de agendamento.");
        } finally {
          setLoading(false);
        }
      };
      fetchPolicies();
    }
  }, [barbershop?.id]);

  const handleChange = (field: keyof BookingPolicies, value: any) => {
    setPolicies((prev) => ({ ...prev, [field]: value }));
    setHasChanges(true);
  };

  const handleSave = async () => {
    if (!barbershop?.id) return;
    setSaving(true);
    try {
      const result = await updateBookingPolicies(barbershop.id, policies);
      if (result.success) {
        toast.success("Pol├¡ticas salvas com sucesso!");
        setHasChanges(false);
      } else {
        toast.error("Erro ao salvar: " + result.error);
      }
    } catch (error) {
      console.error("Erro ao salvar pol├¡ticas:", error);
      toast.error("Erro ao salvar pol├¡ticas.");
    } finally {
      setSaving(false);
    }
  };

  if (loading) {
