                  </Label>
                  <Input
                    id="deposit_percentage"
                    type="number"
                    min={1}
                    max={100}
                    value={policies.deposit_percentage}
                    onChange={(e) => handleChange("deposit_percentage", parseInt(e.target.value) || 0)}
