const db = supabase as any;
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { toast } from "sonner";
import { Download, Loader2, Upload } from "lucide-react";

type Mode = "owner" | "accountant";

type AccountingDocument = {
  id: string;
  title: string;
  doc_type: string;
  status: string;
  created_at: string;
  is_company_document: boolean;
  barbershop_id: string | null;
};

export function AccountingDocumentsPanel({
  mode,
  barbershopId,
}: {
  mode: Mode;
  barbershopId?: string | null;
}) {
  const [loading, setLoading] = useState(true);
  const [docs, setDocs] = useState<AccountingDocument[]>([]);
  const [uploading, setUploading] = useState(false);

  const [title, setTitle] = useState("");
  const [isCompany, setIsCompany] = useState(true);
  const [file, setFile] = useState<File | null>(null);

  const canUpload = mode === "owner";

  const uploadContext = useMemo(() => {
    const isCompanyDocument = !!(isCompany && barbershopId);
    return {
      isCompanyDocument,
      barbershopId: isCompanyDocument ? barbershopId! : null,
    };
  }, [isCompany, barbershopId]);

  const fetchDocs = async () => {
    setLoading(true);
    const { data, error } = await db
      .from("accounting_documents")
      .select("id,title,doc_type,status,created_at,is_company_document,barbershop_id")
      .order("created_at", { ascending: false });

    setLoading(false);

    if (error) {
      toast.error(error.message);
      return;
    }

    setDocs((data || []) as AccountingDocument[]);
  };

  useEffect(() => {
    fetchDocs();
  }, []);

  const downloadDoc = async (docId: string) => {
    const { data, error } = await supabase.functions.invoke("accounting-docs", {
      body: { action: "download", document_id: docId },
    });

    if (error) {
      toast.error(error.message);
      return;
    }

    const signedUrl = (data as any)?.signed_url as string | undefined;
    if (!signedUrl) {
      toast.error("Falha ao gerar link de download.");
      return;
    }

    window.open(signedUrl, "_blank", "noopener,noreferrer");
  };

  const handleInitUpload = async () => {
    if (!canUpload) return;
    if (!title.trim()) return toast.error("Informe um t├¡tulo.");
    if (!file) return toast.error("Selecione um arquivo.");

    if (isCompany && !barbershopId) {
      return toast.error("Nenhuma barbearia encontrada para enviar documento da empresa.");
    }

    setUploading(true);

    const { data, error } = await supabase.functions.invoke("accounting-docs", {
      body: {
        action: "init_upload",
        title: title.trim(),
        doc_type: "other",
        is_company_document: uploadContext.isCompanyDocument,
        barbershop_id: uploadContext.barbershopId,
        filename: file.name,
        mime_type: file.type || null,
        file_size_bytes: file.size || null,
      },
    });

    if (error) {
      setUploading(false);
      toast.error(error.message);
      return;
    }

    const path = (data as any)?.path as string | undefined;
    const token = (data as any)?.token as string | undefined;
    if (!path || !token) {
      setUploading(false);
      toast.error("Falha ao iniciar upload.");
      return;
    }

    const { error: uploadErr } = await (supabase.storage as any)
      .from("accounting-docs")
      .uploadToSignedUrl(path, token, file);

    setUploading(false);

    if (uploadErr) {
      toast.error(uploadErr.message || "Erro ao enviar arquivo.");
      return;
    }

    toast.success("Documento enviado!");
    setTitle("");
    setFile(null);
    await fetchDocs();
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-display text-2xl font-bold">Documentos Cont├íbeis</h1>
        <p className="text-muted-foreground text-sm">
          Fa├ºa upload e acompanhe os documentos fiscais. O acesso ├® controlado por v├¡nculo e permiss├Áes.
        </p>
      </div>

      {canUpload && (
        <Card>
          <CardHeader>
            <CardTitle>Enviar documento</CardTitle>
            <CardDescription>O documento ficar├í dispon├¡vel para voc├¬ e para o contador (quando houver v├¡nculo ativo).</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="space-y-2">
              <Label>T├¡tulo</Label>
              <Input value={title} onChange={(e) => setTitle(e.target.value)} placeholder="Ex: Extrato banc├írio Mar├ºo" />
            </div>

            <div className="flex items-center justify-between gap-3 p-3 rounded-lg border border-border">
              <div className="min-w-0">
                <p className="text-sm font-medium">Documento da empresa</p>
                <p className="text-xs text-muted-foreground">Se desmarcar, o documento ser├í tratado como pessoal.</p>
              </div>
              <input
                type="checkbox"
                className="h-5 w-5"
                checked={isCompany}
                onChange={(e) => setIsCompany(e.target.checked)}
              />
            </div>

            <div className="space-y-2">
              <Label>Arquivo</Label>
              <Input type="file" onChange={(e) => setFile(e.target.files?.[0] || null)} />
            </div>

            <Button variant="gold" onClick={handleInitUpload} disabled={uploading} className="gap-2">
              {uploading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Upload className="w-4 h-4" />}
              Enviar
            </Button>
          </CardContent>
        </Card>
      )}

      <Card>
        <CardHeader>
          <CardTitle>Meus documentos</CardTitle>
          <CardDescription>Lista de documentos dispon├¡veis para sua conta.</CardDescription>
        </CardHeader>
        <CardContent>
          {loading ? (
            <div className="py-12 text-center text-muted-foreground">
              <Loader2 className="w-6 h-6 animate-spin mx-auto mb-3" />
              Carregando...
            </div>
          ) : docs.length === 0 ? (
            <div className="py-12 text-center text-muted-foreground">Nenhum documento encontrado.</div>
          ) : (
            <div className="space-y-3">
              {docs.map((d) => (
                <div key={d.id} className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3 p-3 rounded-lg border border-border">
                  <div className="min-w-0">
                    <p className="font-medium truncate">{d.title}</p>
                    <p className="text-xs text-muted-foreground">
                      {d.is_company_document ? "Empresa" : "Pessoal"} ÔÇó {d.status} ÔÇó {new Date(d.created_at).toLocaleString()}
                    </p>
                  </div>
                  <div className="flex items-center gap-2">
                    <Button variant="outline" size="sm" className="gap-2" onClick={() => downloadDoc(d.id)}>
                      <Download className="w-4 h-4" />
                      Baixar
                    </Button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

import { useEffect, useMemo, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
const db = supabase as any;
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { toast } from "sonner";
import { Loader2 } from "lucide-react";

type Mode = "owner" | "accountant";

type LinkRow = {
  id: string;
  barbershop_id: string;
  accountant_id: string;
  status: "pending" | "active" | "revoked";
  requested_at: string;
  accepted_at: string | null;
  revoked_at: string | null;
};

export function AccountingLinksPanel({
  mode,
  barbershopId,
}: {
  mode: Mode;
  barbershopId?: string | null;
}) {
  const [loading, setLoading] = useState(true);
  const [links, setLinks] = useState<LinkRow[]>([]);

  const [creating, setCreating] = useState(false);
  const [accountantEmail, setAccountantEmail] = useState("");

  const canCreate = mode === "owner";

  const title = useMemo(() => {
    return mode === "owner" ? "V├¡nculo com Contador" : "Empresas Vinculadas";
  }, [mode]);

  const description = useMemo(() => {
    return mode === "owner"
      ? "Solicite e gerencie o v├¡nculo com um contador. O contador s├│ acessa documentos da empresa ap├│s o v├¡nculo ficar ativo."
      : "Gerencie solicita├º├Áes de v├¡nculo de empresas (aceite para ativar acesso aos documentos).";
  }, [mode]);

  const fetchLinks = async () => {
    setLoading(true);

    let query = db
      .from("accountant_barbershop_links")
      .select("id, barbershop_id, accountant_id, status, requested_at, accepted_at, revoked_at")
      .order("requested_at", { ascending: false });

    if (mode === "owner") {
      if (barbershopId) {
        query = query.eq("barbershop_id", barbershopId);
      }
    }

    const { data, error } = await query;

    setLoading(false);

    if (error) {
      toast.error(error.message);
      return;
    }

    setLinks((data || []) as unknown as LinkRow[]);
  };

  useEffect(() => {
    fetchLinks();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [mode, barbershopId]);

  const createLink = async () => {
    if (!canCreate) return;
    if (!barbershopId) return toast.error("Nenhuma barbearia encontrada.");
    if (!accountantEmail.trim()) return toast.error("Informe o e-mail do contador.");

    setCreating(true);

    const { data: authData, error: authErr } = await supabase.auth.getUser();
    const currentUserId = authData?.user?.id || null;
    if (authErr || !currentUserId) {
      setCreating(false);
      toast.error("Sess├úo inv├ílida. Fa├ºa login novamente.");
      return;
    }

    const { data: accountantId, error: accErr } = await db.rpc("get_accountant_id_by_email", {
      _email: accountantEmail.trim(),
    });

    if (accErr) {
      setCreating(false);
      toast.error(accErr.message);
      return;
    }

    if (!accountantId) {
      setCreating(false);
      toast.error("Contador n├úo encontrado ou inativo.");
      return;
    }

    const { error: insErr } = await db.from("accountant_barbershop_links").insert({
      barbershop_id: barbershopId,
      accountant_id: accountantId,
      status: "pending",
      requested_by_user_id: currentUserId,
      requested_at: new Date().toISOString(),
    } as any);

    setCreating(false);

    if (insErr) {
      toast.error(insErr.message);
      return;
    }

    toast.success("Solicita├º├úo enviada ao contador!");
    setAccountantEmail("");
    await fetchLinks();
  };

  const acceptLink = async (linkId: string) => {
    const { error } = await db
      .from("accountant_barbershop_links")
      .update({ status: "active", accepted_at: new Date().toISOString() })
      .eq("id", linkId)
      .eq("status", "pending");

    if (error) {
      toast.error(error.message);
      return;
    }

    toast.success("V├¡nculo ativado!");
    await fetchLinks();
  };

  const revokeLink = async (linkId: string) => {
    const { error } = await db
      .from("accountant_barbershop_links")
      .update({ status: "revoked", revoked_at: new Date().toISOString() })
      .eq("id", linkId);

    if (error) {
      toast.error(error.message);
      return;
    }

    toast.success("V├¡nculo revogado.");
    await fetchLinks();
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-display text-2xl font-bold">{title}</h1>
        <p className="text-muted-foreground text-sm">{description}</p>
      </div>

      {canCreate && (
        <Card>
          <CardHeader>
            <CardTitle>Solicitar v├¡nculo</CardTitle>
            <CardDescription>Informe o e-mail do contador para enviar a solicita├º├úo.</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="space-y-2">
              <Label>E-mail do contador</Label>
              <Input value={accountantEmail} onChange={(e) => setAccountantEmail(e.target.value)} placeholder="contador@exemplo.com" />
            </div>
            <Button variant="gold" onClick={createLink} disabled={creating}>
              {creating ? <Loader2 className="w-4 h-4 animate-spin" /> : "Enviar solicita├º├úo"}
            </Button>
          </CardContent>
        </Card>
      )}

      <Card>
        <CardHeader>
          <CardTitle>V├¡nculos</CardTitle>
          <CardDescription>Status dos v├¡nculos.</CardDescription>
        </CardHeader>
        <CardContent>
          {loading ? (
            <div className="py-12 text-center text-muted-foreground">
              <Loader2 className="w-6 h-6 animate-spin mx-auto mb-3" />
              Carregando...
            </div>
          ) : links.length === 0 ? (
            <div className="py-12 text-center text-muted-foreground">Nenhum v├¡nculo encontrado.</div>
          ) : (
            <div className="space-y-3">
              {links.map((l) => (
                <div key={l.id} className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3 p-3 rounded-lg border border-border">
                  <div className="min-w-0">
                    <p className="font-medium truncate">{l.status === "active" ? "Ativo" : l.status === "pending" ? "Pendente" : "Revogado"}</p>
                    <p className="text-xs text-muted-foreground">
                      Solicita├º├úo: {new Date(l.requested_at).toLocaleString()}
                      {l.accepted_at ? ` ÔÇó Aceito: ${new Date(l.accepted_at).toLocaleString()}` : ""}
                      {l.revoked_at ? ` ÔÇó Revogado: ${new Date(l.revoked_at).toLocaleString()}` : ""}
                    </p>
                  </div>
                  <div className="flex items-center gap-2">
                    {mode === "accountant" && l.status === "pending" && (
                      <Button size="sm" variant="gold" onClick={() => acceptLink(l.id)}>Aceitar</Button>
                    )}
                    {l.status !== "revoked" && (
                      <Button size="sm" variant="outline" onClick={() => revokeLink(l.id)}>Revogar</Button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

import { useEffect, useMemo, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
const db = supabase as any;
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { toast } from "sonner";
import { Loader2, Send } from "lucide-react";
import { useAuth } from "@/lib/auth";

type Mode = "owner" | "accountant";

type MessageRow = {
  id: string;
  barbershop_id: string;
  accountant_id: string | null;
  sender_user_id: string;
  sender_role: string | null;
  body: string;
  created_at: string;
};

type LinkedBarbershop = {
  id: string;
  name: string | null;
};

export function AccountingMessagesPanel({
  mode,
  barbershopId,
}: {
  mode: Mode;
  barbershopId?: string | null;
}) {
  const { user } = useAuth();
  const [loading, setLoading] = useState(true);
  const [sending, setSending] = useState(false);
  const [messages, setMessages] = useState<MessageRow[]>([]);
  const [messageBody, setMessageBody] = useState("");

  const [linkedBarbershops, setLinkedBarbershops] = useState<LinkedBarbershop[]>([]);
  const [selectedBarbershopId, setSelectedBarbershopId] = useState<string | null>(barbershopId || null);

  const title = useMemo(() => {
    return "Mensagens Cont├íbeis";
  }, []);

  const description = useMemo(() => {
    return mode === "owner"
      ? "Converse com seu contador sobre documentos, guias e quest├Áes fiscais."
      : "Converse com as empresas vinculadas sobre documentos, guias e quest├Áes fiscais.";
  }, [mode]);

  const fetchLinkedBarbershops = async () => {
    if (mode !== "accountant") return;

    const { data: authData, error: authErr } = await supabase.auth.getUser();
    const currentUserId = authData?.user?.id || null;
    if (authErr || !currentUserId) {
      toast.error("Sess├úo inv├ílida. Fa├ºa login novamente.");
      return;
    }

    const { data: accountantRow, error: accountantErr } = await (supabase as any)
      .from("accountants")
      .select("id")
      .eq("user_id", currentUserId)
      .maybeSingle();

    if (accountantErr) {
      toast.error(accountantErr.message);
      return;
    }

    const accountantId = (accountantRow as any)?.id as string | undefined;
    if (!accountantId) {
      return;
    }

    const { data: linkRows, error: linksErr } = await db
      .from("accountant_barbershop_links")
      .select("barbershop_id, barbershops(name)")
      .eq("accountant_id", accountantId)
      .eq("status", "active")
      .order("requested_at", { ascending: false });

    if (linksErr) {
      toast.error(linksErr.message);
      return;
    }

    const mapped = (linkRows || []).map((r: any) => ({
      id: r.barbershop_id,
      name: r.barbershops?.name || null,
    }));

    setLinkedBarbershops(mapped);
    if (!selectedBarbershopId && mapped[0]?.id) {
      setSelectedBarbershopId(mapped[0].id);
    }
  };

  const fetchMessages = async () => {
    setLoading(true);

    const effectiveBarbershopId = mode === "owner" ? barbershopId : selectedBarbershopId;
    if (!effectiveBarbershopId) {
      setMessages([]);
      setLoading(false);
      return;
    }

    const { data, error } = await db
      .from("accounting_messages")
      .select("id,barbershop_id,accountant_id,sender_user_id,sender_role,body,created_at")
      .eq("barbershop_id", effectiveBarbershopId)
      .order("created_at", { ascending: true });

    setLoading(false);

    if (error) {
      toast.error(error.message);
      return;
    }

    setMessages((data || []) as any);
  };

  useEffect(() => {
    fetchLinkedBarbershops();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [mode]);

  useEffect(() => {
    if (mode === "owner") {
      setSelectedBarbershopId(barbershopId || null);
    }
  }, [mode, barbershopId]);

  useEffect(() => {
    fetchMessages();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [mode, barbershopId, selectedBarbershopId]);

  const sendMessage = async () => {
    if (!messageBody.trim()) {
      toast.error("Digite uma mensagem.");
      return;
    }

    const effectiveBarbershopId = mode === "owner" ? barbershopId : selectedBarbershopId;
    if (!effectiveBarbershopId) {
      toast.error("Selecione uma barbearia.");
      return;
    }

    if (!user?.id) {
      toast.error("Sess├úo inv├ílida. Fa├ºa login novamente.");
      return;
    }

    setSending(true);

    let accountantId: string | null = null;
    if (mode === "accountant") {
      const { data: accountantRow, error: accountantErr } = await (supabase as any)
        .from("accountants")
        .select("id")
        .eq("user_id", user.id)
        .maybeSingle();

      if (accountantErr || !accountantRow?.id) {
        setSending(false);
        toast.error("Contador n├úo encontrado.");
        return;
      }

      accountantId = accountantRow.id;
    }

    const payload: any = {
      barbershop_id: effectiveBarbershopId,
      accountant_id: accountantId,
      sender_user_id: user.id,
      body: messageBody.trim(),
      created_at: new Date().toISOString(),
    };

    const { error } = await db.from("accounting_messages").insert(payload as never);

    setSending(false);

    if (error) {
      toast.error(error.message);
      return;
    }

    setMessageBody("");
    await fetchMessages();
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-display text-2xl font-bold">{title}</h1>
        <p className="text-muted-foreground text-sm">{description}</p>
      </div>

      {mode === "accountant" && (
        <Card>
          <CardHeader>
            <CardTitle>Empresa</CardTitle>
            <CardDescription>Selecione uma empresa vinculada para visualizar as mensagens.</CardDescription>
          </CardHeader>
          <CardContent>
            <div className="space-y-2">
              <select
                className="w-full h-10 rounded-md border border-input bg-background px-3 text-sm"
                value={selectedBarbershopId || ""}
                onChange={(e) => setSelectedBarbershopId(e.target.value || null)}
              >
                <option value="">Selecione...</option>
                {linkedBarbershops.map((b) => (
                  <option key={b.id} value={b.id}>
                    {b.name || b.id}
                  </option>
                ))}
              </select>
            </div>
          </CardContent>
        </Card>
      )}

      <Card>
        <CardHeader>
          <CardTitle>Conversa</CardTitle>
          <CardDescription>Hist├│rico de mensagens trocadas.</CardDescription>
        </CardHeader>
        <CardContent>
          {loading ? (
            <div className="py-12 text-center text-muted-foreground">
              <Loader2 className="w-6 h-6 animate-spin mx-auto mb-3" />
              Carregando...
            </div>
          ) : messages.length === 0 ? (
            <div className="py-12 text-center text-muted-foreground">Nenhuma mensagem ainda.</div>
          ) : (
            <div className="space-y-3 max-h-96 overflow-y-auto">
              {messages.map((m) => {
                const isMine = m.sender_user_id === user?.id;
                return (
                  <div key={m.id} className={`flex ${isMine ? "justify-end" : "justify-start"}`}>
                    <div className={`max-w-[70%] rounded-lg p-3 ${isMine ? "bg-primary text-primary-foreground" : "bg-muted"}`}>
                      <p className="text-sm whitespace-pre-wrap break-words">{m.body}</p>
                      <p className={`text-xs mt-1 ${isMine ? "text-primary-foreground/70" : "text-muted-foreground"}`}>
                        {new Date(m.created_at).toLocaleString("pt-BR")}
                      </p>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle>Nova mensagem</CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <Textarea
            value={messageBody}
            onChange={(e) => setMessageBody(e.target.value)}
            placeholder="Digite sua mensagem..."
            rows={4}
          />
          <Button variant="gold" onClick={sendMessage} disabled={sending} className="gap-2">
            {sending ? <Loader2 className="w-4 h-4 animate-spin" /> : <Send className="w-4 h-4" />}
            Enviar
          </Button>
        </CardContent>
      </Card>
    </div>
  );
}

import { useEffect, useMemo, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
const db = supabase as any;
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { toast } from "sonner";
import { Loader2 } from "lucide-react";

type Mode = "owner" | "accountant";

type TaxGuideStatus = "draft" | "pending" | "paid" | "overdue" | "archived";

type TaxGuideRow = {
  id: string;
  barbershop_id: string;
  tax_type: string;
  reference_period: string | null;
  due_date: string | null;
  amount: number | null;
  status: TaxGuideStatus;
  guide_document_id: string | null;
  notes: string | null;
  created_at: string;
};

type LinkedBarbershop = {
  id: string;
  name: string | null;
};

export function AccountingTaxesPanel({
  mode,
  barbershopId,
}: {
  mode: Mode;
  barbershopId?: string | null;
}) {
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [guides, setGuides] = useState<TaxGuideRow[]>([]);

  const [linkedBarbershops, setLinkedBarbershops] = useState<LinkedBarbershop[]>([]);
  const [selectedBarbershopId, setSelectedBarbershopId] = useState<string | null>(barbershopId || null);

  const [taxType, setTaxType] = useState("das");
  const [referencePeriod, setReferencePeriod] = useState("");
  const [dueDate, setDueDate] = useState("");
  const [amount, setAmount] = useState("");
  const [status, setStatus] = useState<TaxGuideStatus>("pending");
  const [guideDocumentId, setGuideDocumentId] = useState("");
  const [notes, setNotes] = useState("");

  const title = useMemo(() => {
    return "Impostos & Guias";
  }, []);

  const description = useMemo(() => {
    return mode === "owner"
      ? "Cadastre e acompanhe guias (DAS, DARF, GPS, ISS etc.) vinculadas ├á sua barbearia."
      : "Cadastre e acompanhe guias (DAS, DARF, GPS, ISS etc.) de empresas com v├¡nculo ativo.";
  }, [mode]);

  const taxTypeOptions = useMemo(
    () => [
      { value: "das", label: "DAS" },
      { value: "darf", label: "DARF" },
      { value: "gps", label: "GPS" },
      { value: "iss", label: "ISS" },
      { value: "irpj", label: "IRPJ" },
      { value: "csll", label: "CSLL" },
      { value: "other", label: "Outro" },
    ],
    [],
  );

  const statusOptions = useMemo(
    () => [
      { value: "draft", label: "Rascunho" },
      { value: "pending", label: "Pendente" },
      { value: "paid", label: "Pago" },
      { value: "overdue", label: "Vencido" },
      { value: "archived", label: "Arquivado" },
    ],
    [],
  );

  const fetchLinkedBarbershops = async () => {
    if (mode !== "accountant") return;

    const { data: authData, error: authErr } = await supabase.auth.getUser();
    const currentUserId = authData?.user?.id || null;
    if (authErr || !currentUserId) {
      toast.error("Sess├úo inv├ílida. Fa├ºa login novamente.");
      return;
    }

    const { data: accountantRow, error: accountantErr } = await (supabase as any)
      .from("accountants")
      .select("id")
      .eq("user_id", currentUserId)
      .maybeSingle();

    if (accountantErr) {
      toast.error(accountantErr.message);
      return;
    }

    const accountantId = (accountantRow as any)?.id as string | undefined;
    if (!accountantId) {
      return;
    }

    const { data: linkRows, error: linksErr } = await db
      .from("accountant_barbershop_links")
      .select("barbershop_id, barbershops(name)")
      .eq("accountant_id", accountantId)
      .eq("status", "active")
      .order("requested_at", { ascending: false });

    if (linksErr) {
      toast.error(linksErr.message);
      return;
    }

    const mapped = (linkRows || []).map((r: any) => ({
      id: r.barbershop_id,
      name: r.barbershops?.name || null,
    }));

    setLinkedBarbershops(mapped);
    if (!selectedBarbershopId && mapped[0]?.id) {
      setSelectedBarbershopId(mapped[0].id);
    }
  };

  const fetchGuides = async () => {
    setLoading(true);

    const effectiveBarbershopId = mode === "owner" ? barbershopId : selectedBarbershopId;
    if (!effectiveBarbershopId) {
      setGuides([]);
      setLoading(false);
      return;
    }

    const { data, error } = await db
      .from("accounting_tax_guides")
      .select("id,barbershop_id,tax_type,reference_period,due_date,amount,status,guide_document_id,notes,created_at")
      .eq("barbershop_id", effectiveBarbershopId)
      .order("due_date", { ascending: true, nullsFirst: false });

    setLoading(false);

    if (error) {
      toast.error(error.message);
      return;
    }

    setGuides((data || []) as any);
  };

  useEffect(() => {
    fetchLinkedBarbershops();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [mode]);

  useEffect(() => {
    if (mode === "owner") {
      setSelectedBarbershopId(barbershopId || null);
    }
  }, [mode, barbershopId]);

  useEffect(() => {
    fetchGuides();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [mode, barbershopId, selectedBarbershopId]);

  const createGuide = async () => {
    const effectiveBarbershopId = mode === "owner" ? barbershopId : selectedBarbershopId;
    if (!effectiveBarbershopId) {
      toast.error("Selecione uma barbearia.");
      return;
    }

    setSaving(true);

    const { data: authData, error: authErr } = await supabase.auth.getUser();
    const currentUserId = authData?.user?.id || null;
    if (authErr || !currentUserId) {
      setSaving(false);
      toast.error("Sess├úo inv├ílida. Fa├ºa login novamente.");
      return;
    }

    const payload: any = {
      barbershop_id: effectiveBarbershopId,
      tax_type: taxType,
      reference_period: referencePeriod.trim() || null,
      due_date: dueDate || null,
      amount: amount ? Number(amount) : null,
      status,
      guide_document_id: guideDocumentId.trim() || null,
      notes: notes.trim() || null,
      created_by_user_id: currentUserId,
      updated_at: new Date().toISOString(),
    };

    const { error } = await db.from("accounting_tax_guides").insert(payload as never);

    setSaving(false);

    if (error) {
      toast.error(error.message);
      return;
    }

    toast.success("Guia cadastrada!");
    setReferencePeriod("");
    setDueDate("");
    setAmount("");
    setNotes("");
    setGuideDocumentId("");
    await fetchGuides();
  };

  const updateGuideStatus = async (id: string, next: TaxGuideStatus) => {
    setSaving(true);

    const { error } = await db
      .from("accounting_tax_guides")
      .update({ status: next, updated_at: new Date().toISOString() })
      .eq("id", id);

    setSaving(false);

    if (error) {
      toast.error(error.message);
      return;
    }

    setGuides(guides.map((g) => (g.id === id ? { ...g, status: next } : g)));
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-display text-2xl font-bold">{title}</h1>
        <p className="text-muted-foreground text-sm">{description}</p>
      </div>

      {mode === "accountant" && (
        <Card>
          <CardHeader>
            <CardTitle>Empresa</CardTitle>
            <CardDescription>Selecione uma empresa vinculada para visualizar as guias.</CardDescription>
          </CardHeader>
          <CardContent>
            <div className="space-y-2">
              <Label>Barbearia vinculada</Label>
              <select
                className="w-full h-10 rounded-md border border-input bg-background px-3 text-sm"
                value={selectedBarbershopId || ""}
                onChange={(e) => setSelectedBarbershopId(e.target.value || null)}
              >
                <option value="">Selecione...</option>
                {linkedBarbershops.map((b) => (
                  <option key={b.id} value={b.id}>
                    {b.name || b.id}
                  </option>
                ))}
              </select>
            </div>
          </CardContent>
        </Card>
      )}

      <Card>
        <CardHeader>
          <CardTitle>Nova guia</CardTitle>
          <CardDescription>Cadastre a guia para acompanhar vencimento e status.</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label>Tipo</Label>
              <select
                className="w-full h-10 rounded-md border border-input bg-background px-3 text-sm"
                value={taxType}
                onChange={(e) => setTaxType(e.target.value)}
              >
                {taxTypeOptions.map((o) => (
                  <option key={o.value} value={o.value}>
                    {o.label}
                  </option>
                ))}
              </select>
            </div>

            <div className="space-y-2">
              <Label>Compet├¬ncia (refer├¬ncia)</Label>
              <Input value={referencePeriod} onChange={(e) => setReferencePeriod(e.target.value)} placeholder="Ex: 2026-03" />
            </div>

            <div className="space-y-2">
              <Label>Vencimento</Label>
              <Input type="date" value={dueDate} onChange={(e) => setDueDate(e.target.value)} />
            </div>

            <div className="space-y-2">
              <Label>Valor (R$)</Label>
              <Input type="number" step="0.01" min="0" value={amount} onChange={(e) => setAmount(e.target.value)} placeholder="0,00" />
            </div>

            <div className="space-y-2">
              <Label>Status</Label>
              <select
                className="w-full h-10 rounded-md border border-input bg-background px-3 text-sm"
                value={status}
                onChange={(e) => setStatus(e.target.value as TaxGuideStatus)}
              >
                {statusOptions.map((o) => (
                  <option key={o.value} value={o.value}>
                    {o.label}
                  </option>
                ))}
              </select>
            </div>

            <div className="space-y-2">
              <Label>ID do documento (opcional)</Label>
              <Input value={guideDocumentId} onChange={(e) => setGuideDocumentId(e.target.value)} placeholder="Cole o ID do documento em Documentos Cont├íbeis" />
            </div>

            <div className="md:col-span-2 space-y-2">
              <Label>Observa├º├Áes</Label>
              <Textarea value={notes} onChange={(e) => setNotes(e.target.value)} placeholder="Ex: guia gerada pelo contador, aguarda pagamento..." />
            </div>
          </div>

          <Button variant="gold" onClick={createGuide} disabled={saving} className="gap-2">
            {saving && <Loader2 className="w-4 h-4 animate-spin" />}
            Cadastrar guia
          </Button>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle>Guias</CardTitle>
          <CardDescription>Lista de guias cadastradas.</CardDescription>
        </CardHeader>
        <CardContent>
          {loading ? (
            <div className="py-12 text-center text-muted-foreground">
              <Loader2 className="w-6 h-6 animate-spin mx-auto mb-3" />
              Carregando...
            </div>
          ) : guides.length === 0 ? (
            <div className="py-12 text-center text-muted-foreground">Nenhuma guia encontrada.</div>
          ) : (
            <div className="space-y-3">
              {guides.map((g) => (
                <div key={g.id} className="flex flex-col md:flex-row md:items-center md:justify-between gap-3 p-3 rounded-lg border border-border">
                  <div className="min-w-0">
                    <p className="font-medium truncate">
                      {(taxTypeOptions.find((o) => o.value === g.tax_type)?.label || g.tax_type).toUpperCase()} {g.reference_period ? `ÔÇó ${g.reference_period}` : ""}
                    </p>
                    <p className="text-xs text-muted-foreground">
                      Vencimento: {g.due_date ? new Date(g.due_date).toLocaleDateString("pt-BR") : "-"} ÔÇó Valor: {g.amount != null ? `R$ ${Number(g.amount).toFixed(2)}` : "-"}
                    </p>
                    <p className="text-xs text-muted-foreground">Status: {g.status}</p>
                  </div>

                  <div className="flex items-center gap-2">
                    <select
                      className="h-9 rounded-md border border-input bg-background px-2 text-sm"
                      value={g.status}
                      onChange={(e) => updateGuideStatus(g.id, e.target.value as TaxGuideStatus)}
                      disabled={saving}
                    >
                      {statusOptions.map((o) => (
                        <option key={o.value} value={o.value}>
                          {o.label}
                        </option>
                      ))}
                    </select>
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

import { useState, useEffect } from "react";
import { useAuth } from "@/lib/auth";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { CreditCard, Loader2, CheckCircle2, Building2, Save } from "lucide-react";
import { toast } from "sonner";
import { formatCpfCnpjBR } from "@/lib/input-masks";

const PIX_KEY_TYPES = [
  { value: "cpf", label: "CPF/CNPJ" },
  { value: "email", label: "E-mail" },
  { value: "phone", label: "Telefone" },
  { value: "random", label: "Chave Aleat├│ria" },
];

const DadosBancariosPage = () => {
  const { user, profile } = useAuth();
  const [barbershop, setBarbershop] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  const [form, setForm] = useState({
    name: "",
    cpf_cnpj: "",
    mobile_phone: "",
    pix_key: "",
    pix_key_type: "cpf",
  });

  useEffect(() => {
    if (!user) return;
    Promise.all([
      (supabase as any).from("barbershops").select("id, name, asaas_customer_id, asaas_wallet_id").eq("owner_user_id", user.id).limit(1).maybeSingle(),
      (supabase as any).from("profiles").select("name, cpf_cnpj, whatsapp, pix_key, bank_info").eq("user_id", user.id).maybeSingle(),
    ]).then(([shop, prof]) => {
      setBarbershop(shop.data);
      const w = (prof.data as any)?.whatsapp || "";
      setForm({
        name: prof.data?.name || profile?.name || "",
        cpf_cnpj: prof.data?.cpf_cnpj || "",
        mobile_phone: typeof w === "string" ? w.replace(/\D/g, "") : "",
        pix_key: prof.data?.pix_key || "",
        pix_key_type: "cpf",
      });
      setLoading(false);
    });
  }, [user, profile]);

  const handleSave = async () => {
    if (!form.name.trim()) {
      toast.error("Nome completo ├® obrigat├│rio.");
      return;
    }
    if (!form.cpf_cnpj.replace(/\D/g, "")) {
      toast.error("CPF/CNPJ ├® obrigat├│rio para criar sua conta no gateway.");
      return;
    }
    if (!form.pix_key) {
      toast.error("Chave PIX ├® obrigat├│ria para receber pagamentos.");
      return;
    }
    const phoneDigits = form.mobile_phone.replace(/\D/g, "");
    if (phoneDigits.length < 10) {
      toast.error("Telefone/WhatsApp ├® obrigat├│rio para criar conta no gateway (formato: 11999990000).");
      return;
    }

    setSaving(true);

    const cleanCpfCnpj = form.cpf_cnpj.replace(/\D/g, "");

    // Update profile
    const { error: profileError } = await (supabase as any)
      .from("profiles")
      .update({
        name: form.name,
        cpf_cnpj: cleanCpfCnpj,
        whatsapp: phoneDigits ? `+55${phoneDigits}` : null,
        pix_key: form.pix_key,
      })
      .eq("user_id", user!.id);

    if (profileError) {
      toast.error("Erro ao salvar perfil: " + profileError.message);
      setSaving(false);
      return;
    }

    // If has barbershop, try to create gateway account
    if (barbershop?.id) {
      try {
        const { data: result, error: fnError } = await supabase.functions.invoke("process-payment", {
          body: {
            action: "create-barbershop-account",
            barbershop_id: barbershop.id,
            cpf_cnpj: cleanCpfCnpj,
            name: form.name,
            email: profile?.email,
            mobile_phone: phoneDigits,
            pix_key: form.pix_key,
          },
        });

        if (fnError) throw new Error(fnError.message);
        toast.success("Dados salvos e conta criada no gateway!");
      } catch (e: any) {
        console.error("Gateway error:", e);
        toast.success("Dados salvos! A conta no gateway ser├í criada automaticamente.");
      }
    } else {
      toast.success("Dados banc├írios salvos com sucesso!");
    }

    setSaving(false);
  };

  if (loading) {
    return (
      <div className="flex justify-center py-12">
        <Loader2 className="w-8 h-8 animate-spin text-primary" />
      </div>
    );
  }

  const hasGateway = !!barbershop?.asaas_customer_id;
  const hasData = !!form.cpf_cnpj;

  return (
    <div className="space-y-6">
      <h1 className="font-display text-2xl font-bold">Dados Banc├írios</h1>
      <p className="text-muted-foreground text-sm">
        Preencha seus dados para criar sua conta no gateway de pagamentos automaticamente.
      </p>

      {/* Gateway status */}
      <Card className={hasGateway ? "border-primary/30 bg-primary/5" : "border-muted"}>
        <CardContent className="py-4 flex items-center gap-3">
          {hasGateway ? (
            <>
              <CheckCircle2 className="w-5 h-5 text-primary shrink-0" />
              <div>
                <p className="font-medium text-sm">Conta ativa no gateway de pagamentos</p>
                <p className="text-xs text-muted-foreground">Recebimentos via PIX est├úo habilitados.</p>
              </div>
            </>
          ) : (
            <>
              <Building2 className="w-5 h-5 text-muted-foreground shrink-0" />
              <div>
                <p className="font-medium text-sm">Conta no gateway pendente</p>
                <p className="text-xs text-muted-foreground">Preencha os dados abaixo para criar automaticamente.</p>
              </div>
            </>
          )}
        </CardContent>
      </Card>

      {/* Editable form */}
      <Card className="border-primary/20">
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <CreditCard className="w-5 h-5" />
            Dados para Recebimento
          </CardTitle>
          <CardDescription>
            Seus dados s├úo necess├írios para criar sua conta no gateway e receber pagamentos via PIX.
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="md:col-span-2">
              <Label>Nome Completo *</Label>
              <Input
                value={form.name}
                onChange={(e) => setForm({ ...form, name: e.target.value })}
                placeholder="Nome completo conforme documento"
                className="mt-1"
              />
              <p className="text-xs text-muted-foreground mt-1">Nome que aparecer├í na conta do gateway</p>
            </div>
            <div>
              <Label>Telefone / WhatsApp *</Label>
              <Input
                value={form.mobile_phone}
                onChange={(e) => setForm({ ...form, mobile_phone: e.target.value.replace(/\D/g, "").slice(0, 11) })}
                placeholder="11999990000"
                className="mt-1"
              />
              <p className="text-xs text-muted-foreground mt-1">Obrigat├│rio para API gateway. DDD + n├║mero.</p>
            </div>
            <div>
              <Label>CPF ou CNPJ *</Label>
              <Input
                value={formatCpfCnpjBR(form.cpf_cnpj)}
                onChange={(e) => setForm({ ...form, cpf_cnpj: e.target.value })}
                placeholder="000.000.000-00"
                className="mt-1"
              />
              <p className="text-xs text-muted-foreground mt-1">Necess├írio para criar sua conta no gateway</p>
            </div>
            <div>
              <Label>Tipo de Chave PIX</Label>
              <select
                className="flex h-11 w-full rounded-lg border border-input bg-muted/30 px-4 py-2 text-sm mt-1 transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary focus-visible:ring-offset-2"
                value={form.pix_key_type}
                onChange={(e) => setForm({ ...form, pix_key_type: e.target.value })}
              >
                {PIX_KEY_TYPES.map((t) => (
                  <option key={t.value} value={t.value}>{t.label}</option>
                ))}
              </select>
            </div>
            <div className="md:col-span-2">
              <Label>Chave PIX *</Label>
              <Input
                value={form.pix_key}
                onChange={(e) => setForm({ ...form, pix_key: e.target.value })}
                placeholder="Sua chave PIX para receber pagamentos"
                className="mt-1"
              />
              <p className="text-xs text-muted-foreground mt-1">Seus ganhos ser├úo enviados para esta chave</p>
            </div>
          </div>

          <Button variant="gold" onClick={handleSave} disabled={saving} className="w-full sm:w-auto">
            {saving ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <Save className="w-4 h-4 mr-2" />}
            {saving ? "Salvando..." : hasData ? "Atualizar Dados" : "Salvar e Criar Conta"}
          </Button>
        </CardContent>
      </Card>

      {/* Gateway IDs (read-only) */}
      {hasGateway && (
        <Card>
          <CardHeader>
            <CardTitle className="text-sm">IDs do Gateway</CardTitle>
            <CardDescription>Refer├¬ncias internas (somente leitura)</CardDescription>
          </CardHeader>
          <CardContent>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
              <InfoField label="Customer ID" value={barbershop.asaas_customer_id} mono />
              <InfoField label="Wallet ID" value={barbershop.asaas_wallet_id} mono />
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
};

function InfoField({ label, value, mono }: { label: string; value?: string | null; mono?: boolean }) {
  return (
    <div className="p-3 bg-muted rounded-lg">
      <p className="text-xs text-muted-foreground">{label}</p>
      <p className={`font-medium ${mono ? "font-mono text-xs" : ""}`}>{value || "-"}</p>
    </div>
  );
}

export default DadosBancariosPage;

import { useRef, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { uploadImage } from "@/lib/upload-image";
import { Camera, Loader2, User } from "lucide-react";
import { toast } from "sonner";

interface ProfilePhotoUploadProps {
  userId: string;
  avatarUrl: string | null;
  onUpdate: (url: string | null) => void;
  size?: "sm" | "md" | "lg";
}

const sizes = { sm: "w-12 h-12", md: "w-16 h-16", lg: "w-24 h-24" };

export function ProfilePhotoUpload({ userId, avatarUrl, onUpdate, size = "md" }: ProfilePhotoUploadProps) {
  const [uploading, setUploading] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  const handleChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setUploading(true);
    const url = await uploadImage(file, "avatars", userId.slice(0, 8));
    setUploading(false);
    if (url) {
      const { error } = await (supabase as any).from("profiles").update({ avatar_url: url }).eq("user_id", userId);
      if (error) { toast.error("Erro ao salvar foto."); return; }
      onUpdate(url);
      toast.success("Foto atualizada!");
    } else {
      toast.error("Erro ao enviar imagem.");
    }
  };

  return (
    <div className="relative group">
      <div className={`${sizes[size]} rounded-full overflow-hidden bg-primary/10 flex items-center justify-center border-2 border-border`}>
        {avatarUrl ? (
          <img src={avatarUrl} alt="Avatar" className="w-full h-full object-cover" />
        ) : (
          <User className={`${size === "sm" ? "w-6 h-6" : size === "md" ? "w-8 h-8" : "w-12 h-12"} text-primary`} />
        )}
      </div>
      <input ref={inputRef} type="file" accept="image/*" className="hidden" onChange={handleChange} />
      <button
        type="button"
        onClick={() => inputRef.current?.click()}
        disabled={uploading}
        className="absolute bottom-0 right-0 p-1.5 rounded-full bg-primary text-primary-foreground shadow hover:bg-primary/90 transition-opacity opacity-0 group-hover:opacity-100 disabled:opacity-70"
      >
        {uploading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Camera className="w-4 h-4" />}
      </button>
    </div>
  );
}

