    { key: "annual_revenue", label: "Faturamento Bruto Anual (R$)", placeholder: "Ex: 360.000,00", required: true },
    { key: "employees_count", label: "N┬║ de Funcion├írios", placeholder: "Ex: 3" },
    { key: "tax_regime", label: "Regime Tribut├írio", type: "select", placeholder: "", options: [
      { value: "simples", label: "Simples Nacional" },
      { value: "lucro_presumido", label: "Lucro Presumido" },
