    { key: "year", label: "Ano-Calend├írio", placeholder: "Ex: 2025", required: true },
    { key: "income_sources", label: "Fontes de Renda", placeholder: "Ex: Sal├írio, Aut├┤nomo, Aluguel, etc.", type: "textarea" },
    { key: "dependents", label: "N┬║ de Dependentes", placeholder: "Ex: 2" },
    { key: "has_assets", label: "Possui Bens (im├│vel, ve├¡culo)?", type: "select", placeholder: "", options: [
      { value: "no", label: "N├úo" },
      { value: "yes", label: "Sim" },
    ] },
    { key: "had_investments", label: "Teve Investimentos?", type: "select", placeholder: "", options: [
      { value: "no", label: "N├úo" },
      { value: "yes", label: "Sim" },
    ] },
  ],
  cnpj_migration: [
    { key: "cpf", label: "CPF Atual", placeholder: "000.000.000-00", required: true },
    { key: "full_name", label: "Nome Completo", placeholder: "Nome conforme RG", required: true },
    { key: "target_type", label: "Migrar Para", type: "select", placeholder: "", options: [
      { value: "mei", label: "MEI - Microempreendedor Individual" },
      { value: "me", label: "ME - Microempresa" },
    ], required: true },
    { key: "activity", label: "Atividade Principal (CNAE)", placeholder: "Ex: 9602-5/01 - Cabeleireiros" },
    { key: "monthly_revenue", label: "Faturamento Mensal Estimado (R$)", placeholder: "Ex: 5.000,00" },
    { key: "address", label: "Endere├ºo Comercial", placeholder: "Rua, n├║mero, bairro, cidade/UF" },
  ],
  cnpj_closing: [
    { key: "cnpj", label: "CNPJ a Encerrar", placeholder: "00.000.000/0001-00", required: true },
    { key: "company_name", label: "Raz├úo Social", placeholder: "Nome da empresa" },
    { key: "reason", label: "Motivo do Encerramento", type: "textarea", placeholder: "Ex: Encerramento das atividades, mudan├ºa de regime, etc." },
    { key: "has_debts", label: "Possui D├®bitos Fiscais?", type: "select", placeholder: "", options: [
      { value: "no", label: "N├úo" },
      { value: "yes", label: "Sim" },
      { value: "nao_sei", label: "N├úo sei" },
    ] },
  ],
  other: [
    { key: "description", label: "Descreva o Servi├ºo", type: "textarea", placeholder: "Detalhe o que precisa para o contador avaliar", required: true },
  ],
};

function parseRequiredFields(rf: any[]): DynamicField[] {
  if (!Array.isArray(rf)) return [];
  return rf.map((f: any) => ({
    key: f.key || "",
    label: f.label || f.key || "",
    placeholder: f.placeholder || "",
    type: (f.type || "text") as "text" | "select" | "textarea",
    options: f.options,
    required: !!f.required,
  })).filter(f => f.key);
}

export default function SolicitarServicoFiscalPage() {
  const { user, getPrimaryRole } = useAuth();
  const [requests, setRequests] = useState<any[]>([]);
  const [services, setServices] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [saving, setSaving] = useState(false);
  const [serviceType, setServiceType] = useState("cnpj_opening");
  const [fields, setFields] = useState<Record<string, string>>({});
  const [notes, setNotes] = useState("");
  const [requestAsCompany, setRequestAsCompany] = useState(false);
  const [barbershopId, setBarbershopId] = useState<string | null>(null);
  const [allowMatching, setAllowMatching] = useState(true);

  useEffect(() => {
    db.from("fiscal_service_types").select("service_type, label, price, required_fields").eq("status", "approved").eq("is_active", true).then(({ data }: any) => {
      setServices(data || []);
    });
  }, []);

  const serviceMap = Object.fromEntries((services || []).map(s => [s.service_type, s]));
  const SERVICE_LABELS = Object.fromEntries(services.length ? services.map(s => [s.service_type, s.label]) : Object.entries(SERVICE_LABELS_FALLBACK));
  const getFieldsForType = (type: string) => {
    const s = serviceMap[type];
    if (s?.required_fields) {
      const parsed = parseRequiredFields(s.required_fields);
      if (parsed.length) return parsed;
    }
    return SERVICE_FIELDS_FALLBACK[type] || [];
  };
  const getPriceForType = (type: string) => {
    const s = serviceMap[type];
    return s ? Number(s.price) : 0;
  };

  const fetchRequests = useCallback(async () => {
    if (!user) return;
    const { data } = await (supabase as any)
      .from("fiscal_service_requests")
      .select("*")
      .eq("client_user_id", user.id)
      .order("created_at", { ascending: false });
    setRequests(data || []);
    setLoading(false);
  }, [user]);

  useEffect(() => { fetchRequests(); }, [user, fetchRequests]);

  const primaryRole = getPrimaryRole();
  const canRequestAsCompany = primaryRole === "dono";

  useEffect(() => {
    if (!user) return;
    if (!canRequestAsCompany) {
      setRequestAsCompany(false);
      setBarbershopId(null);
      return;
    }

    supabase
      .from("barbershops")
      .select("id")
      .eq("owner_user_id", user.id)
      .order("created_at", { ascending: true })
      .limit(1)
      .maybeSingle()
      .then(({ data }) => {
        setBarbershopId(data?.id || null);
      });
  }, [user, canRequestAsCompany]);

  const openForm = (type: string) => {
    setServiceType(type);
    setFields({});
    setNotes("");
    setAllowMatching(true);
    setShowForm(true);
  };

  const handleSubmit = async () => {
    if (!user) return;

    // Validate required fields
    const requiredFields = getFieldsForType(serviceType).filter(f => f.required);
    const missing = requiredFields.filter(f => !fields[f.key]?.trim());
    if (missing.length > 0) {
      toast.error(`Preencha: ${missing.map(f => f.label).join(", ")}`);
      return;
    }

    setSaving(true);

    // Build description with all fields for the accountant
    const dynamicFields = getFieldsForType(serviceType);
    const descriptionParts = dynamicFields
      .filter(f => fields[f.key]?.trim())
      .map(f => {
        let val = fields[f.key];
        if (f.type === "select" && f.options) {
          const opt = f.options.find(o => o.value === val);
          if (opt) val = opt.label;
        }
        return `${f.label}: ${val}`;
      });
    if (notes.trim()) descriptionParts.push(`Observa├º├Áes: ${notes}`);

    const description = descriptionParts.join("\n");

    const requestedByRole = (primaryRole || "cliente");

    if (requestAsCompany) {
      if (!canRequestAsCompany) {
        toast.error("Apenas o dono pode solicitar servi├ºos em nome da empresa.");
        return;
      }
      if (!barbershopId) {
        toast.error("Nenhuma barbearia encontrada para sua conta. Conclua o cadastro da barbearia.");
        return;
      }
    }

    const { error } = await (supabase as any).from("fiscal_service_requests").insert({
      client_user_id: user.id,
      requested_by_user_id: user.id,
      requested_by_role: requestedByRole,
      is_company_request: requestAsCompany,
      barbershop_id: requestAsCompany ? barbershopId : null,
      allow_accountant_matching: allowMatching,
      service_type: serviceType,
      description,
    } as any);
    setSaving(false);
    if (error) { toast.error("Erro: " + error.message); return; }
    toast.success("Pedido enviado ao contador com todos os dados!");
    setShowForm(false);
    setFields({});
    setNotes("");
    setRequestAsCompany(false);
    fetchRequests();
  };

  const currentFields = getFieldsForType(serviceType);

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3">
        <div>
          <h1 className="font-display text-2xl font-bold">Servi├ºos Cont├íbeis</h1>
          <p className="text-muted-foreground text-sm">Solicite abertura de CNPJ, declara├º├Áes e mais</p>
        </div>
        <Button variant="gold" onClick={() => openForm("cnpj_opening")} className="w-full sm:w-auto">
          <ClipboardList className="w-4 h-4 mr-2" />Solicitar
        </Button>
      </div>

      {showForm && (
        <Card className="border-primary/20 bg-primary/5">
          <CardHeader>
            <CardTitle className="text-lg">Novo Pedido ÔÇö {SERVICE_LABELS[serviceType] || SERVICE_LABELS_FALLBACK[serviceType]}</CardTitle>
            <CardDescription>Preencha os dados para o contador processar seu pedido</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            {canRequestAsCompany && (
              <div className="p-3 rounded-lg bg-background border border-border">
                <div className="flex items-center justify-between gap-3">
                  <div className="min-w-0">
                    <p className="text-sm font-medium">Pedido em nome da empresa</p>
                    <p className="text-xs text-muted-foreground">
                      Marque para enviar este pedido como barbearia (dono). O contador s├│ ter├í acesso aos dados da empresa com autoriza├º├úo.
                    </p>
                  </div>
                  <input
                    type="checkbox"
                    className="h-5 w-5"
                    checked={requestAsCompany}
                    onChange={(e) => setRequestAsCompany(e.target.checked)}
                  />
                </div>
              </div>
            )}

            <div className="p-3 rounded-lg bg-background border border-border">
              <div className="flex items-center justify-between gap-3">
                <div className="min-w-0">
                  <p className="text-sm font-medium">Permitir que um contador aceite seu pedido</p>
                  <p className="text-xs text-muted-foreground">
                    Se desmarcar, o pedido s├│ ser├í vis├¡vel para o contador ap├│s atribui├º├úo (por voc├¬ ou Super Admin).
                  </p>
                </div>
                <input
                  type="checkbox"
                  className="h-5 w-5"
                  checked={allowMatching}
                  onChange={(e) => setAllowMatching(e.target.checked)}
                />
              </div>
            </div>

            {/* Service type selector */}
            <div>
              <Label>Tipo de Servi├ºo</Label>
              <select
                className="flex h-11 w-full rounded-lg border border-input bg-muted/30 px-4 py-2 text-sm mt-1 transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary focus-visible:ring-offset-2"
                value={serviceType}
                onChange={(e) => { setServiceType(e.target.value); setFields({}); }}
              >
                {Object.entries(SERVICE_LABELS).map(([k, v]) => (
                  <option key={k} value={k}>{String(v)}</option>
                ))}
              </select>
            </div>

            {/* Dynamic fields */}
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {currentFields.map((field) => (
                <div key={field.key} className={field.type === "textarea" ? "sm:col-span-2" : ""}>
                  <Label>
                    {field.label}
                    {field.required && <span className="text-destructive ml-1">*</span>}
                  </Label>
                  {field.type === "select" ? (
                    <select
                      className="flex h-11 w-full rounded-lg border border-input bg-muted/30 px-4 py-2 text-sm mt-1"
                      value={fields[field.key] || ""}
                      onChange={(e) => setFields({ ...fields, [field.key]: e.target.value })}
                    >
                      <option value="">Selecione...</option>
                      {field.options?.map(opt => (
                        <option key={opt.value} value={opt.value}>{opt.label}</option>
                      ))}
                    </select>
                  ) : field.type === "textarea" ? (
                    <Textarea
                      className="mt-1 min-h-[80px]"
                      placeholder={field.placeholder}
                      value={fields[field.key] || ""}
                      onChange={(e) => setFields({ ...fields, [field.key]: e.target.value })}
                    />
                  ) : (
                    <Input
                      className="mt-1"
                      placeholder={field.placeholder}
                      value={fields[field.key] || ""}
                      onChange={(e) => setFields({ ...fields, [field.key]: e.target.value })}
                    />
                  )}
                </div>
              ))}
            </div>

            {/* Extra notes */}
            {serviceType !== "other" && (
              <div>
                <Label>Observa├º├Áes Adicionais</Label>
                <Textarea
                  className="mt-1 min-h-[60px]"
                  placeholder="Informa├º├Áes extras que ajudem o contador..."
                  value={notes}
                  onChange={(e) => setNotes(e.target.value)}
                />
              </div>
            )}

            <div className="flex flex-col sm:flex-row gap-2">
              <Button variant="gold" onClick={handleSubmit} disabled={saving} className="w-full sm:w-auto">
                {saving ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : null}
                {saving ? "Enviando..." : "Enviar Pedido"}
              </Button>
              <Button variant="outline" onClick={() => setShowForm(false)} className="w-full sm:w-auto">Cancelar</Button>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Available services grid - mobile friendly */}
      <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
        {[
          { key: "cnpj_opening", icon: "­ƒÅó", desc: "Abrir MEI ou ME" },
          { key: "mei_declaration", icon: "­ƒôï", desc: "DASN-SIMEI anual" },
          { key: "me_declaration", icon: "­ƒôè", desc: "Declara├º├úo ME" },
          { key: "income_tax", icon: "­ƒÆ░", desc: "Declara├º├úo IRPF" },
          { key: "cnpj_migration", icon: "­ƒöä", desc: "CPF ÔåÆ CNPJ" },
          { key: "cnpj_closing", icon: "­ƒÜ½", desc: "Encerrar CNPJ" },
          { key: "other", icon: "­ƒôØ", desc: "Outros servi├ºos" },
        ].map((s) => (
          <button
            key={s.key}
            onClick={() => openForm(s.key)}
            className="p-3 rounded-xl border border-border bg-card text-center hover:border-primary/50 hover:bg-primary/5 transition-colors active:scale-95"
          >
            <span className="text-2xl block mb-1">{s.icon}</span>
            <p className="text-xs font-medium leading-tight">{SERVICE_LABELS[s.key] || SERVICE_LABELS_FALLBACK[s.key]}</p>
            <p className="text-[10px] text-muted-foreground mt-0.5">{s.desc}</p>
            {getPriceForType(s.key) > 0 && <p className="text-xs font-bold text-primary mt-1">R$ {getPriceForType(s.key).toFixed(2)}</p>}
          </button>
        ))}
      </div>

      {/* Requests list */}
      {loading ? (
        <div className="flex justify-center py-8"><Loader2 className="w-8 h-8 animate-spin text-primary" /></div>
      ) : requests.length === 0 ? (
        <Card>
          <CardContent className="py-12 text-center">
            <FileText className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
            <p className="text-muted-foreground">Nenhum pedido realizado.</p>
            <p className="text-sm text-muted-foreground mt-1">Solicite seu primeiro servi├ºo cont├íbil acima!</p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-3">
          <h2 className="font-semibold text-sm text-muted-foreground uppercase tracking-wide">Meus Pedidos</h2>
          {requests.map((r) => {
            const sc = STATUS_CONFIG[r.status] || STATUS_CONFIG.pending;
            return (
              <Card key={r.id}>
                <CardContent className="p-4">
                  <div className="flex justify-between items-start gap-2">
                    <div className="min-w-0 flex-1">
                      <p className="font-semibold text-sm">{SERVICE_LABELS[r.service_type] || r.service_type}</p>
                      {r.description && (
                        <p className="text-xs text-muted-foreground mt-1 whitespace-pre-line line-clamp-3">{r.description}</p>
                      )}
                      <p className="text-xs text-muted-foreground mt-1">
                        {new Date(r.created_at).toLocaleDateString("pt-BR")}
                      </p>
                      {r.notes && (
                        <p className="text-xs text-primary mt-1 italic">Resposta: {r.notes}</p>
                      )}
                    </div>
                    <span className={`text-xs px-2 py-1 rounded-full shrink-0 ${sc.color}`}>{sc.label}</span>
                  </div>
                </CardContent>
              </Card>
            );
          })}
        </div>
      )}
    </div>
  );
}

// @ts-nocheck
import { useState, useEffect, useRef, useCallback } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { toast } from "sonner";
import { MessageCircle, Send, Loader2, UserCheck, User, Users } from "lucide-react";
import { useAuth } from "@/lib/auth";

interface Message {
  id: string;
  usuario_id: string;
  contador_id: string;
  mensagem: string;
  remetente: string;
  lido: boolean;
  data_envio: string;
  created_at: string;
  user_type?: string;
}

interface ContadorInfo {
  id: string;
  name: string;
  email: string;
  empresa_contabil: string | null;
  cidade: string | null;
  estado: string | null;
  aceita_novos_clientes: boolean;
}

interface UserInfo {
  id: string;
  email: string;
  name?: string;
}

type ChatMode = "usuario" | "contador" | "superadmin";

export function UniversalChatPanel({ 
  mode, 
  contadorId, 
  usuarioId,
  userType = "barbershop" 
}: {
  mode: ChatMode;
  contadorId?: string;
  usuarioId?: string;
  userType?: "barbershop" | "profissional" | "afiliado";
}) {
  const { user } = useAuth();
  const [messages, setMessages] = useState<Message[]>([]);
  const [contador, setContador] = useState<ContadorInfo | null>(null);
  const [usuario, setUsuario] = useState<UserInfo | null>(null);
  const [messageText, setMessageText] = useState("");
  const [loading, setLoading] = useState(true);
  const [sending, setSending] = useState(false);
  const [contadores, setContadores] = useState<ContadorInfo[]>([]);
  const [usuarios, setUsuarios] = useState<UserInfo[]>([]);
  const [selectedContadorId, setSelectedContadorId] = useState<string>(contadorId || "");
  const [selectedUsuarioId, setSelectedUsuarioId] = useState<string>(usuarioId || "");
  const bottomRef = useRef<HTMLDivElement>(null);

  const currentUserId = user?.id;
  const effectiveContadorId = mode === "contador" ? 
    (contadores.find(c => c.id === selectedContadorId)?.id || "") : 
    selectedContadorId;
  const effectiveUsuarioId = mode === "usuario" ? 
    currentUserId : 
    selectedUsuarioId;

  // Carregar mensagens
  const loadMessages = useCallback(async () => {
    if (!effectiveContadorId || !effectiveUsuarioId) {
      setMessages([]);
      setLoading(false);
      return;
    }

    setLoading(true);
    try {
      const query = (supabase as any)
        .from("chat_contador")
        .select("*")
        .eq("contador_id", effectiveContadorId)
        .eq("usuario_id", effectiveUsuarioId)
        .order("data_envio", { ascending: true });

      const { data, error } = await query;
      
      if (error) throw error;
      setMessages(data || []);

      // Marcar mensagens como lidas (se for contador)
      if (mode === "contador") {
        await (supabase as any)
          .from("chat_contador")
          .update({ lido: true })
          .eq("contador_id", effectiveContadorId)
          .eq("usuario_id", effectiveUsuarioId)
          .eq("remetente", "usuario");
      }
    } catch (error) {
      console.error("Erro ao carregar mensagens:", error);
      toast.error("Erro ao carregar mensagens");
    } finally {
      setLoading(false);
    }
  }, [effectiveContadorId, effectiveUsuarioId, mode]);

  // Enviar mensagem
  const sendMessage = async () => {
    if (!messageText.trim() || !effectiveContadorId || !effectiveUsuarioId || !currentUserId) {
      toast.error("Preencha todos os campos");
      return;
    }

    setSending(true);
    try {
      const payload = {
        usuario_id: effectiveUsuarioId,
        contador_id: effectiveContadorId,
        mensagem: messageText.trim(),
        remetente: mode === "contador" ? "contador" : "usuario",
        user_type: userType
      };

      const { error } = await (supabase as any).from("chat_contador").insert(payload);
      
      if (error) throw error;
      
      setMessageText("");
      toast.success("Mensagem enviada");
      await loadMessages();
    } catch (error) {
      console.error("Erro ao enviar mensagem:", error);
      toast.error("Erro ao enviar mensagem");
    } finally {
      setSending(false);
    }
  };

  // Configurar subscription em tempo real
  useEffect(() => {
    if (!effectiveContadorId || !effectiveUsuarioId) return;

    const channel = supabase
      .channel(`chat_${effectiveContadorId}_${effectiveUsuarioId}`)
      .on("postgres_changes", {
        event: "*",
        schema: "public",
        table: "chat_contador",
        filter: `contador_id=eq.${effectiveContadorId}&usuario_id=eq.${effectiveUsuarioId}`,
      }, (payload) => {
        if (payload.eventType === "INSERT") {
          setMessages(prev => [...prev, payload.new as Message]);
          setTimeout(() => bottomRef.current?.scrollIntoView({ behavior: "smooth" }), 100);
        } else if (payload.eventType === "UPDATE") {
          setMessages(prev => 
            prev.map(msg => msg.id === payload.new.id ? payload.new as Message : msg)
          );
        }
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [effectiveContadorId, effectiveUsuarioId]);

  // Carregar dados iniciais
  useEffect(() => {
    const loadContadores = async () => {
      try {
        const { data, error } = await (supabase as any)
          .from("accountants")
          .select("id, name, email, empresa_contabil, cidade, estado, aceita_novos_clientes")
          .eq("is_active", true)
          .eq("status_verificado", "verified")
          .order("name");

        if (error) throw error;
        setContadores(data || []);
        
        if (!selectedContadorId && data && data.length > 0) {
          setSelectedContadorId(data[0].id);
        }
      } catch (error) {
        console.error("Erro ao carregar contadores:", error);
        toast.error("Erro ao carregar lista de contadores");
      }
    };
    const loadUsuarios = async () => {
      if (mode !== "contador") return;
      
      try {
        const { data, error } = await (supabase as any)
          .from("recent_chat_messages")
          .select("usuario_id, usuario_email, usuario_name")
          .eq("contador_id", effectiveContadorId)
          .neq("usuario_id", currentUserId)
          .distinct();

        if (error) throw error;
        
        const usuariosUnicos = data?.map(u => ({
          id: u.usuario_id,
          email: u.usuario_email,
          name: u.usuario_name || u.usuario_email
        })) || [];
        
        setUsuarios(usuariosUnicos);
        
        if (!selectedUsuarioId && usuariosUnicos.length > 0) {
          setSelectedUsuarioId(usuariosUnicos[0].id);
        }
      } catch (error) {
        console.error("Erro ao carregar usu├írios:", error);
      }
    };
    if (mode === "usuario" || mode === "superadmin") {
      loadContadores();
    } else if (mode === "contador" && effectiveContadorId) {
      loadUsuarios();
    }
  }, [mode, effectiveContadorId, currentUserId, selectedContadorId, selectedUsuarioId]);

  useEffect(() => {
    const loadContadorInfo = async () => {
      if (!effectiveContadorId) return;
      
      try {
        const { data, error } = await (supabase as any)
          .from("accountants")
          .select("id, name, email, empresa_contabil, cidade, estado, aceita_novos_clientes")
          .eq("id", effectiveContadorId)
          .single();

        if (error) throw error;
        setContador(data);
      } catch (error) {
        console.error("Erro ao carregar info do contador:", error);
      }
    };
    loadContadorInfo();
  }, [effectiveContadorId]);

  useEffect(() => {
    const loadUsuarioInfo = async () => {
      if (!effectiveUsuarioId) return;
      
      try {
        const { data, error } = await supabase.auth.admin.getUserById(effectiveUsuarioId);
        if (error) throw error;
        
        if (data.user) {
          setUsuario({
            id: data.user.id,
            email: data.user.email || "",
            name: data.user.user_metadata?.name || data.user.email
          });
        }
      } catch (error) {
        console.error("Erro ao carregar info do usu├írio:", error);
      }
    };
    loadUsuarioInfo();
  }, [effectiveUsuarioId]);

  useEffect(() => {
    if (effectiveContadorId && effectiveUsuarioId) {
      loadMessages();
    }
  }, [effectiveContadorId, effectiveUsuarioId, loadMessages]);

  const formatTime = (dateString: string) => {
    return new Date(dateString).toLocaleTimeString("pt-BR", { 
      hour: "2-digit", 
      minute: "2-digit" 
    });
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString("pt-BR", { 
      day: "2-digit", 
      month: "short" 
    });
  };

  const getChatTitle = () => {
    if (mode === "usuario") {
      return `Chat com ${contador?.name || "Contador"}`;
    } else if (mode === "contador") {
      return `Chat com ${usuario?.name || "Cliente"}`;
    } else {
      return "Chat Cont├íbil";
    }
  };

  const getChatDescription = () => {
    if (mode === "usuario" && contador?.empresa_contabil) {
      return contador.empresa_contabil;
    } else if (mode === "contador" && usuario?.email) {
      return usuario.email;
    } else if (contador?.cidade && contador?.estado) {
      return `${contador.cidade} - ${contador.estado}`;
    }
    return "";
  };

  return (
    <Card className="flex flex-col h-[600px]">
      <CardHeader className="pb-3 border-b">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <MessageCircle className="w-4 h-4 text-primary" />
            <CardTitle className="text-base">{getChatTitle()}</CardTitle>
          </div>
          {(mode === "usuario" || mode === "superadmin") && (
            <Select value={selectedContadorId} onValueChange={setSelectedContadorId}>
              <SelectTrigger className="w-[200px]">
                <SelectValue placeholder="Selecione um contador" />
              </SelectTrigger>
              <SelectContent>
                {contadores.map((c) => (
                  <SelectItem key={c.id} value={c.id}>
                    {c.name} - {c.cidade}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          )}
          {mode === "contador" && (
            <Select value={selectedUsuarioId} onValueChange={setSelectedUsuarioId}>
              <SelectTrigger className="w-[200px]">
                <SelectValue placeholder="Selecione um cliente" />
              </SelectTrigger>
              <SelectContent>
                {usuarios.map((u) => (
                  <SelectItem key={u.id} value={u.id}>
                    {u.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          )}
        </div>
        {getChatDescription() && (
          <CardDescription>{getChatDescription()}</CardDescription>
        )}
      </CardHeader>

      <CardContent className="flex-1 overflow-y-auto p-4 space-y-3">
        {loading ? (
          <div className="flex justify-center py-8">
            <Loader2 className="w-6 h-6 animate-spin text-primary" />
          </div>
        ) : messages.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-center">
            <MessageCircle className="w-12 h-12 text-muted-foreground mb-3" />
            <p className="text-muted-foreground text-sm">Nenhuma mensagem ainda.</p>
            <p className="text-xs text-muted-foreground mt-1">
              {mode === "usuario" || mode === "superadmin"
                ? "Apresente-se e descreva sua necessidade cont├íbil."
                : "Aguardando mensagem do cliente."}
            </p>
          </div>
        ) : (
          messages.map((message) => {
            const isMe = 
              (mode === "usuario" && message.remetente === "usuario") ||
              (mode === "contador" && message.remetente === "contador") ||
              (mode === "superadmin" && message.usuario_id === currentUserId);

            return (
              <div key={message.id} className={`flex ${isMe ? "justify-end" : "justify-start"}`}>
                <div className={`max-w-[75%] rounded-xl px-3 py-2 space-y-1 ${
                  isMe
                    ? "bg-primary text-primary-foreground rounded-br-sm"
                    : "bg-muted rounded-bl-sm"
                }`}>
                  <div className="flex items-center gap-2 mb-1">
                    {!isMe && (
                      <span className="text-xs font-medium opacity-70">
                        {message.remetente === "contador" ? (
                          <span className="flex items-center gap-1">
                            <UserCheck className="w-3 h-3" /> Contador
                          </span>
                        ) : (
                          <span className="flex items-center gap-1">
                            <User className="w-3 h-3" /> Cliente
                          </span>
                        )}
                      </span>
                    )}
                  </div>
                  <p className="text-sm leading-relaxed whitespace-pre-wrap break-words">
                    {message.mensagem}
                  </p>
                  <p className={`text-xs opacity-60 text-right`}>
                    {formatDate(message.data_envio)} {formatTime(message.data_envio)}
                  </p>
                </div>
              </div>
            );
          })
        )}
        <div ref={bottomRef} />
      </CardContent>

      <div className="p-3 border-t flex gap-2">
        <Input
          placeholder="Digite sua mensagem..."
          value={messageText}
          onChange={(e) => setMessageText(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && !e.shiftKey && sendMessage()}
          disabled={sending || !effectiveContadorId || !effectiveUsuarioId}
        />
        <Button 
          variant="gold" 
          size="icon" 
          onClick={sendMessage} 
          disabled={sending || !messageText.trim() || !effectiveContadorId || !effectiveUsuarioId}
        >
          {sending ? <Loader2 className="w-4 h-4 animate-spin" /> : <Send className="w-4 h-4" />}
        </Button>
      </div>
    </Card>
  );
}

export default UniversalChatPanel;

import { useState, useMemo } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Slider } from "@/components/ui/slider";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { 
  TrendingUp, 
  Users, 
  Building2, 
  Percent,
  ArrowRight,
  Info,
  Rocket
} from "lucide-react";
import { useTranslation } from "react-i18next";
import { useNiche } from "@/hooks/useNiche";
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";

interface SimulatorProps {
  variant: 'afiliado' | 'barbearia';
  onCTA?: () => void;
}

// Internal factors (not shown to user)
const INTERNAL_FACTORS = {
  directFactor: 0.08, // Hidden commission factor
  indirectFactor: 0.03, // Sub-affiliate factor
};

const EarningsSimulator = ({ variant, onCTA }: SimulatorProps) => {
  // Affiliate inputs
  const [barbershops, setBarbershops] = useState(5);
  const [ticketMedio, setTicketMedio] = useState(500);
  const [adesaoPercent, setAdesaoPercent] = useState(60);
  const [subAfiliados, setSubAfiliados] = useState(2);
  const [producaoSubAfiliado, setProducaoSubAfiliado] = useState(300);
  const [crescimentoMensal, setCrescimentoMensal] = useState(10);

  // Barbershop inputs
  const [clientesAtivos, setClientesAtivos] = useState(100);
  const [ticketServico, setTicketServico] = useState(50);
  const [indicacoesMes, setIndicacoesMes] = useState(10);
  const [cashbackRate, setCashbackRate] = useState(5);

  const calculations = useMemo(() => {
    if (variant === 'afiliado') {
      const receitaDireta = barbershops * ticketMedio * INTERNAL_FACTORS.directFactor * (adesaoPercent / 100);
      const receitaIndireta = subAfiliados * producaoSubAfiliado * INTERNAL_FACTORS.indirectFactor;
      const ganhoMensal = receitaDireta + receitaIndireta;
      
      const projecao6Meses = ganhoMensal * Math.pow(1 + crescimentoMensal / 100, 6);
      const projecao12Meses = ganhoMensal * Math.pow(1 + crescimentoMensal / 100, 12);

      return {
        receitaDireta,
        receitaIndireta,
        ganhoMensal,
        projecao6Meses,
        projecao12Meses,
        barbershopsAtivos: barbershops,
        subAfiliadosAtivos: subAfiliados
      };
    } else {
      // Barbershop variant
      const faturamentoBase = clientesAtivos * ticketServico;
      const faturamentoIndicacoes = indicacoesMes * ticketServico * 0.8;
      const cashbackDistribuido = faturamentoBase * (cashbackRate / 100);
      const faturamentoTotal = faturamentoBase + faturamentoIndicacoes;
      
      const projecao6Meses = faturamentoTotal * Math.pow(1 + crescimentoMensal / 100, 6);
      const projecao12Meses = faturamentoTotal * Math.pow(1 + crescimentoMensal / 100, 12);

      return {
        receitaDireta: faturamentoBase,
        receitaIndireta: faturamentoIndicacoes,
        ganhoMensal: faturamentoTotal,
        projecao6Meses,
        projecao12Meses,
        cashbackDistribuido,
        clientesAtivos,
        indicacoesMes
      };
    }
  }, [
    variant, barbershops, ticketMedio, adesaoPercent, subAfiliados, 
    producaoSubAfiliado, crescimentoMensal, clientesAtivos, ticketServico,
    indicacoesMes, cashbackRate
  ]);

  const { t, i18n } = useTranslation();
  const { currentNiche } = useNiche();
  const nLabel = typeof currentNiche === 'object' && currentNiche !== null ? (currentNiche as any).label || 'Neg├│cio' : (currentNiche || 'Neg├│cio');

  const formatCurrency = (value: number) => {
    return new Intl.NumberFormat(i18n.language === 'en' ? 'en-US' : (i18n.language === 'es' ? 'es-ES' : 'pt-BR'), {
      style: 'currency',
      currency: i18n.language === 'en' ? 'USD' : (i18n.language === 'es' ? 'EUR' : 'BRL'),
      minimumFractionDigits: 0,
      maximumFractionDigits: 0
    }).format(value);
  };

  return (
    <TooltipProvider>
      <div className="w-full max-w-6xl mx-auto">
        {/* Header */}
        <div className="text-center mb-10">
          <h2 className="font-display text-3xl sm:text-4xl font-bold mb-4">
            {variant === 'afiliado' 
              ? t(`simulator_growth_title_${nLabel}`, { defaultValue: t("simulator_growth_title") })
              : t(`simulator_earnings_title_${nLabel}`, { defaultValue: t("simulator_earnings_title") })
            }
          </h2>
          <p className="text-muted-foreground text-lg max-w-2xl mx-auto">
            {t("simulator_description")}
          </p>
        </div>

        <Card className="bg-gradient-card border-border/50 shadow-card">
          <CardContent className="p-8">
            <div className="grid lg:grid-cols-2 gap-10">
              {/* Left Column - Inputs */}
              <div className="space-y-6">
                <h3 className="font-display text-xl font-semibold flex items-center gap-2 mb-6">
                  <Rocket className="w-5 h-5 text-primary" />
                  {t("simulator_adjust_values")}
                </h3>

                {variant === 'afiliado' ? (
                  <>
                    {/* Barbershops Input */}
                    <div className="space-y-3">
                      <div className="flex items-center justify-between">
                        <span className="text-sm font-medium leading-none flex items-center gap-2">
                          <Building2 className="w-4 h-4 text-muted-foreground" />
                          {t(`simulator_barbershops_${nLabel}`, { defaultValue: t("simulator_units") })}
                          <Tooltip>
                            <TooltipTrigger>
                              <Info className="w-4 h-4 text-muted-foreground" />
                            </TooltipTrigger>
                            <TooltipContent>
                              <p className="max-w-xs">Este valor ├® apenas uma simula├º├úo para ajudar no planejamento.</p>
                            </TooltipContent>
                          </Tooltip>
                        </span>
                        <Input
                          type="number"
                          value={barbershops}
                          onChange={(e) => setBarbershops(Number(e.target.value) || 0)}
                          className="w-20 text-center"
                        />
                      </div>
                      <Slider
                        value={[barbershops]}
                        onValueChange={([v]) => setBarbershops(v)}
                        max={50}
                        step={1}
                      />
                    </div>

                    {/* Ticket M├®dio */}
                    <div className="space-y-3">
                      <div className="flex items-center justify-between">
                        <span className="text-sm font-medium leading-none flex items-center gap-2">
                          {t("simulator_avg_ticket")} (R$)
                          <Tooltip>
                            <TooltipTrigger>
                              <Info className="w-4 h-4 text-muted-foreground" />
                            </TooltipTrigger>
                            <TooltipContent>
                              <p className="max-w-xs">Valor m├®dio mensal por barbearia ativa.</p>
                            </TooltipContent>
                          </Tooltip>
                        </span>
                        <span className="font-semibold text-primary">{formatCurrency(ticketMedio)}</span>
                      </div>
                      <Slider
                        value={[ticketMedio]}
                        onValueChange={([v]) => setTicketMedio(v)}
                        min={200}
                        max={2000}
                        step={50}
                      />
                    </div>

                    {/* Ades├úo */}
                    <div className="space-y-3">
                      <div className="flex items-center justify-between">
                        <span className="text-sm font-medium leading-none flex items-center gap-2">
                          <Percent className="w-4 h-4 text-muted-foreground" />
                          {t("simulator_adoption_rate")}
                        </span>
                        <span className="font-semibold text-primary">{adesaoPercent}%</span>
                      </div>
                      <Slider
                        value={[adesaoPercent]}
                        onValueChange={([v]) => setAdesaoPercent(v)}
                        min={20}
                        max={100}
                        step={5}
                      />
                    </div>

                    {/* Sub-afiliados */}
                    <div className="space-y-3">
                      <div className="flex items-center justify-between">
                        <span className="text-sm font-medium leading-none flex items-center gap-2">
                          <Users className="w-4 h-4 text-muted-foreground" />
                          {t("simulator_subaffiliates")}
                        </span>
                        <Input
                          type="number"
                          value={subAfiliados}
                          onChange={(e) => setSubAfiliados(Number(e.target.value) || 0)}
                          className="w-20 text-center"
                        />
                      </div>
                      <Slider
                        value={[subAfiliados]}
                        onValueChange={([v]) => setSubAfiliados(v)}
                        max={20}
                        step={1}
                      />
                    </div>

                    {/* Produ├º├úo Sub-afiliado */}
                    <div className="space-y-3">
                      <div className="flex items-center justify-between">
                        <span className="text-sm font-medium leading-none">{t("simulator_subaffiliate_avg")}</span>
                        <span className="font-semibold text-primary">{formatCurrency(producaoSubAfiliado)}</span>
                      </div>
                      <Slider
                        value={[producaoSubAfiliado]}
                        onValueChange={([v]) => setProducaoSubAfiliado(v)}
                        min={100}
                        max={1000}
                        step={50}
                      />
                    </div>
                  </>
                ) : (
                  <>
                    {/* Clientes Ativos */}
                    <div className="space-y-3">
                      <div className="flex items-center justify-between">
                        <span className="text-sm font-medium leading-none flex items-center gap-2">
                          <Users className="w-4 h-4 text-muted-foreground" />
                          {t("simulator_active_customers")}
                        </span>
                        <Input
                          type="number"
                          value={clientesAtivos}
                          onChange={(e) => setClientesAtivos(Number(e.target.value) || 0)}
                          className="w-20 text-center"
                        />
                      </div>
                      <Slider
                        value={[clientesAtivos]}
                        onValueChange={([v]) => setClientesAtivos(v)}
                        max={500}
                        step={10}
                      />
                    </div>

                    {/* Ticket Servi├ºo */}
                    <div className="space-y-3">
                      <div className="flex items-center justify-between">
                        <span className="text-sm font-medium leading-none">{t("simulator_service_ticket")}</span>
                        <span className="font-semibold text-primary">{formatCurrency(ticketServico)}</span>
                      </div>
                      <Slider
                        value={[ticketServico]}
                        onValueChange={([v]) => setTicketServico(v)}
                        min={20}
                        max={150}
                        step={5}
                      />
                    </div>

                    {/* Indica├º├Áes */}
                    <div className="space-y-3">
                      <div className="flex items-center justify-between">
                        <span className="text-sm font-medium leading-none flex items-center gap-2">
                          {t("simulator_referrals")}
                        </span>
                        <Input
                          type="number"
                          value={indicacoesMes}
                          onChange={(e) => setIndicacoesMes(Number(e.target.value) || 0)}
                          className="w-20 text-center"
                        />
                      </div>
                      <Slider
                        value={[indicacoesMes]}
                        onValueChange={([v]) => setIndicacoesMes(v)}
                        max={50}
                        step={1}
                      />
                    </div>

                    {/* Cashback Rate */}
                    <div className="space-y-3">
                      <div className="flex items-center justify-between">
                        <span className="text-sm font-medium leading-none flex items-center gap-2">
                          <Percent className="w-4 h-4 text-muted-foreground" />
                          {t("simulator_cashback_rate")}
                        </span>
                        <span className="font-semibold text-primary">{cashbackRate}%</span>
                      </div>
                      <Slider
                        value={[cashbackRate]}
                        onValueChange={([v]) => setCashbackRate(v)}
                        min={1}
                        max={10}
                        step={0.5}
                      />
                    </div>
                  </>
                )}

                {/* Crescimento Mensal (both variants) */}
                <div className="space-y-3">
                  <div className="flex items-center justify-between">
                    <span className="text-sm font-medium leading-none flex items-center gap-2">
                      <TrendingUp className="w-4 h-4 text-muted-foreground" />
                      {t("simulator_growth_est")}
                    </span>
                    <span className="font-semibold text-primary">{crescimentoMensal}%</span>
                  </div>
                  <Slider
                    value={[crescimentoMensal]}
                    onValueChange={([v]) => setCrescimentoMensal(v)}
                    min={0}
                    max={30}
                    step={1}
                  />
                </div>
              </div>

              {/* Right Column - Results */}
              <div className="space-y-6">
                <h3 className="font-display text-xl font-semibold flex items-center gap-2 mb-6">
                  <TrendingUp className="w-5 h-5 text-primary" />
                  Resultados Estimados
                </h3>

                {/* Main Result */}
                <Card className="bg-primary/10 border-primary/30">
                  <CardContent className="p-6 text-center">
                    <p className="text-sm text-muted-foreground mb-2">Ganho Mensal Estimado</p>
                    <p className="text-4xl sm:text-5xl font-display font-bold text-gradient-gold">
                      {formatCurrency(calculations.ganhoMensal)}
                    </p>
                  </CardContent>
                </Card>

                {/* Breakdown Cards */}
                <div className="grid grid-cols-2 gap-4">
                  <Card className="bg-muted/30 border-border/50">
                    <CardContent className="p-4 text-center">
                      <p className="text-xs text-muted-foreground mb-1">
                        {variant === 'afiliado' ? 'Receita Direta' : 'Faturamento Base'}
                      </p>
                      <p className="text-xl font-bold text-foreground">
                        {formatCurrency(calculations.receitaDireta)}
                      </p>
                    </CardContent>
                  </Card>
                  <Card className="bg-muted/30 border-border/50">
                    <CardContent className="p-4 text-center">
                      <p className="text-xs text-muted-foreground mb-1">
                        {variant === 'afiliado' ? 'Receita Indireta' : 'Via Indica├º├Áes'}
                      </p>
                      <p className="text-xl font-bold text-foreground">
                        {formatCurrency(calculations.receitaIndireta)}
                      </p>
                    </CardContent>
                  </Card>
                </div>

                {/* Projections Table */}
                <Card className="bg-muted/20 border-border/50">
                  <CardHeader className="pb-2">
                    <CardTitle className="text-base">Proje├º├Áes de Crescimento</CardTitle>
                  </CardHeader>
                  <CardContent>
                    <Table>
                      <TableHeader>
                        <TableRow>
                          <TableHead>Per├¡odo</TableHead>
                          <TableHead className="text-right">Estimativa</TableHead>
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        <TableRow>
                          <TableCell>Atual</TableCell>
                          <TableCell className="text-right font-semibold">
                            {formatCurrency(calculations.ganhoMensal)}
                          </TableCell>
                        </TableRow>
                        <TableRow>
                          <TableCell>Em 6 meses</TableCell>
                          <TableCell className="text-right font-semibold text-primary">
                            {formatCurrency(calculations.projecao6Meses)}
                          </TableCell>
                        </TableRow>
                        <TableRow>
                          <TableCell>Em 12 meses</TableCell>
                          <TableCell className="text-right font-semibold text-primary">
                            {formatCurrency(calculations.projecao12Meses)}
                          </TableCell>
                        </TableRow>
                      </TableBody>
                    </Table>
                  </CardContent>
                </Card>

                {/* Growth Visualization */}
                <div className="flex items-end justify-around h-32 px-4">
                  <div className="flex flex-col items-center">
                    <div 
                      className="w-16 bg-muted rounded-t transition-all duration-500"
                      style={{ height: '30%' }}
                    />
                    <span className="text-xs text-muted-foreground mt-2">Atual</span>
                  </div>
                  <div className="flex flex-col items-center">
                    <div 
                      className="w-16 bg-primary/60 rounded-t transition-all duration-500"
                      style={{ height: `${Math.min(60, 30 * (calculations.projecao6Meses / calculations.ganhoMensal))}%` }}
                    />
                    <span className="text-xs text-muted-foreground mt-2">6 meses</span>
                  </div>
