import { toast } from "sonner";
import { waitlistManager, type WaitlistEntry, type AgendaIntelligenceSettings } from "@/services/waitlist/WaitlistManager";
import { useAuth } from "@/lib/auth";
import {
  Users,
  Clock,
  Calendar,
  AlertCircle,
  CheckCircle,
  XCircle,
  MessageSquare,
  Loader2,
  ArrowRight,
  User,
  Phone
} from "lucide-react";

interface ProfessionalWaitlistPanelProps {
  barbershopId: string;
  professionalId?: string;
}

export const ProfessionalWaitlistPanel = ({ barbershopId, professionalId }: ProfessionalWaitlistPanelProps) => {
  const { user } = useAuth();
  const [settings, setSettings] = useState<AgendaIntelligenceSettings | null>(null);
  const [waitlist, setWaitlist] = useState<WaitlistEntry[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);
  const [showOfferDialog, setShowOfferDialog] = useState(false);
  const [selectedClient, setSelectedClient] = useState<WaitlistEntry | null>(null);
  const [offeringSlot, setOfferingSlot] = useState(false);

  // Estado do formul├írio de oferta manual
  const [offerForm, setOfferForm] = useState({
    date: new Date().toISOString().split('T')[0],
    time: "",
    professional_id: professionalId || "",
    notes: "",
  });

  useEffect(() => {
    loadData();
  }, [barbershopId, professionalId, selectedDate, loadData]);

  const loadData = useCallback(async () => {
    try {
      setLoading(true);
      
      const [settingsData, waitlistData] = await Promise.all([
        waitlistManager.getAgendaSettings(barbershopId),
        waitlistManager.getWaitlist(barbershopId, {
          date: selectedDate,
          professionalId: professionalId,
          status: "waiting",
        }),
      ]);

      setSettings(settingsData);
      setWaitlist(waitlistData);
    } catch (error) {
      console.error("[PROFESSIONAL_WAITLIST] Error loading data:", error);
      toast.error("Erro ao carregar dados da fila");
    } finally {
      setLoading(false);
    }
  }, [barbershopId, selectedDate, professionalId]);

  const handleOfferSlot = async (client: WaitlistEntry) => {
    if (!offerForm.time) {
      toast.error("Selecione um hor├írio para oferecer");
      return;
    }

    setOfferingSlot(true);
    
    try {
      const result = await waitlistManager.processSlotRelease(
        barbershopId,
        offerForm.date,
        offerForm.time,
        offerForm.professional_id || null,
        client.service_id
      );

      if (result.processed) {
        toast.success("Oferta enviada com sucesso!");
        setShowOfferDialog(false);
        setSelectedClient(null);
        setOfferForm({
          date: new Date().toISOString().split('T')[0],
          time: "",
          professional_id: professionalId || "",
          notes: "",
        });
        await loadData(); // Recarregar fila
      } else {
        toast.error("Erro ao enviar oferta");
      }
    } catch (error) {
      console.error("[PROFESSIONAL_WAITLIST] Error offering slot:", error);
      toast.error("Erro ao enviar oferta");
    } finally {
      setOfferingSlot(false);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case "waiting":
        return "default";
      case "offered":
        return "secondary";
      case "accepted":
        return "default";
      case "declined":
        return "destructive";
      case "expired":
        return "outline";
      default:
        return "secondary";
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case "waiting":
        return <Users className="w-4 h-4" />;
      case "offered":
        return <MessageSquare className="w-4 h-4" />;
      case "accepted":
        return <CheckCircle className="w-4 h-4" />;
      case "declined":
        return <XCircle className="w-4 h-4" />;
      case "expired":
        return <Clock className="w-4 h-4" />;
      default:
        return <AlertCircle className="w-4 h-4" />;
    }
  };

  const getStatusText = (status: string) => {
    switch (status) {
      case "waiting":
        return "Aguardando";
      case "offered":
        return "Oferta enviada";
      case "accepted":
        return "Aceito";
      case "declined":
        return "Recusado";
      case "expired":
        return "Expirado";
      default:
        return status;
    }
  };

  const getPreferenceIcon = (accepts: { other: boolean; nearby: boolean; any: boolean }) => {
    if (accepts.any) return <Calendar className="w-4 h-4 text-green-600" />;
    if (accepts.nearby) return <Clock className="w-4 h-4 text-blue-600" />;
    if (accepts.other) return <Users className="w-4 h-4 text-orange-600" />;
    return <User className="w-4 h-4 text-purple-600" />;
  };

  const getPreferenceText = (accepts: { other: boolean; nearby: boolean; any: boolean }) => {
    if (accepts.any) return "Aceita qualquer hor├írio";
    if (accepts.nearby) return "Aceita hor├írio pr├│ximo";
    if (accepts.other) return "Aceita outro profissional";
    return "Apenas profissional escolhido";
  };

  if (!settings) {
    return (
      <Card>
        <CardContent className="text-center py-12">
          <AlertCircle className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
          <p className="text-muted-foreground">Configura├º├Áes n├úo encontradas</p>
        </CardContent>
      </Card>
    );
  }

  // Verificar se profissional tem permiss├úo para ver fila
  if (!settings.allow_professionals_view_queue) {
    return (
      <Card>
        <CardContent className="text-center py-12">
          <AlertCircle className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
          <h3 className="text-lg font-medium mb-2">Acesso Restrito</h3>
          <p className="text-muted-foreground">
            Voc├¬ n├úo tem permiss├úo para visualizar a fila de espera.
            Entre em contato com o dono da barbearia para solicitar acesso.
          </p>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold flex items-center gap-2">
            <Users className="w-6 h-6 text-primary" />
            Fila de Espera
          </h2>
          <p className="text-muted-foreground">
            Gerencie clientes aguardando por hor├írios dispon├¡veis
          </p>
        </div>
        {settings.allow_professionals_offer_slots && (
          <Button onClick={() => setShowOfferDialog(true)}>
            <MessageSquare className="w-4 h-4 mr-2" />
            Oferecer Vaga
          </Button>
        )}
      </div>

      <Tabs defaultValue="waiting" className="space-y-6">
        <TabsList>
          <TabsTrigger value="waiting">Aguardando ({waitlist.filter(w => w.status === 'waiting').length})</TabsTrigger>
          <TabsTrigger value="offered">Ofertas Enviadas ({waitlist.filter(w => w.status === 'offered').length})</TabsTrigger>
          <TabsTrigger value="history">Hist├│rico</TabsTrigger>
        </TabsList>

        {/* Filtro por data */}
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2">
            <Label>Data:</Label>
            <input
              type="date"
              value={selectedDate}
              onChange={(e) => setSelectedDate(e.target.value)}
              className="px-3 py-2 border rounded-md"
            />
          </div>
          <Button variant="outline" size="sm" onClick={loadData}>
            Atualizar
          </Button>
        </div>

        {/* Aba: Aguardando */}
        <TabsContent value="waiting" className="space-y-4">
          {loading ? (
            <div className="flex items-center justify-center py-12">
              <Loader2 className="w-8 h-8 animate-spin text-primary" />
            </div>
          ) : waitlist.filter(w => w.status === 'waiting').length === 0 ? (
            <Card>
              <CardContent className="text-center py-12">
                <Users className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
                <h3 className="text-lg font-medium mb-2">Nenhum cliente aguardando</h3>
                <p className="text-muted-foreground">
                  N├úo h├í clientes na fila de espera para esta data.
                </p>
              </CardContent>
            </Card>
          ) : (
            <div className="space-y-4">
              {waitlist
                .filter(w => w.status === 'waiting')
                .sort((a, b) => a.position_in_queue - b.position_in_queue)
                .map((client) => (
                  <Card key={client.id}>
                    <CardContent className="p-4">
                      <div className="flex items-start justify-between">
                        <div className="space-y-2 flex-1">
                          <div className="flex items-center gap-2">
                            <Badge variant="outline">#{client.position_in_queue}</Badge>
                            <h4 className="font-medium">{client.clients?.name}</h4>
                            {client.clients?.whatsapp && (
                              <a
                                href={`https://wa.me/${client.clients.whatsapp.replace(/\D/g, '')}`}
                                target="_blank"
                                rel="noopener noreferrer"
                                className="text-green-600 hover:text-green-700"
                              >
                                <Phone className="w-4 h-4" />
                              </a>
                            )}
                          </div>
                          
                          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm">
                            <div>
                              <span className="text-muted-foreground">Hor├írio desejado:</span>
                              <p className="font-medium">{client.desired_time}</p>
                            </div>
                            <div>
                              <span className="text-muted-foreground">Servi├ºo:</span>
                              <p className="font-medium">{client.services?.name}</p>
                            </div>
                            <div>
                              <span className="text-muted-foreground">Profissional:</span>
                              <p className="font-medium">
                                {client.professionals?.name || 'Sem prefer├¬ncia'}
                              </p>
                            </div>
                            <div>
                              <span className="text-muted-foreground">Prefer├¬ncia:</span>
                              <div className="flex items-center gap-1">
                                {getPreferenceIcon({
                                  other: client.accepts_other_professional,
                                  nearby: client.accepts_nearby_time,
                                  any: client.accepts_any_time,
                                })}
                                <span className="text-xs">
                                  {getPreferenceText({
                                    other: client.accepts_other_professional,
                                    nearby: client.accepts_nearby_time,
                                    any: client.accepts_any_time,
                                  })}
                                </span>
                              </div>
                            </div>
                          </div>

                          {client.notes && (
                            <div className="p-2 bg-muted/50 rounded text-sm">
                              <span className="text-muted-foreground">Observa├º├Áes:</span>
                              <p>{client.notes}</p>
                            </div>
                          )}

                          <div className="text-xs text-muted-foreground">
                            Entrou na fila: {new Date(client.created_at).toLocaleString('pt-BR')}
                          </div>
                        </div>

                        {settings.allow_professionals_offer_slots && (
                          <div className="flex gap-2">
                            <Button
                              size="sm"
                              onClick={() => {
                                setSelectedClient(client);
                                setOfferForm({
                                  ...offerForm,
                                  date: client.desired_date,
                                  professional_id: client.professional_preferred_id || professionalId || "",
                                });
                                setShowOfferDialog(true);
                              }}
                            >
                              <MessageSquare className="w-4 h-4 mr-2" />
                              Oferecer
                            </Button>
                          </div>
                        )}
                      </div>
                    </CardContent>
                  </Card>
                ))}
            </div>
          )}
        </TabsContent>

        {/* Aba: Ofertas Enviadas */}
        <TabsContent value="offered" className="space-y-4">
          {waitlist.filter(w => w.status === 'offered').length === 0 ? (
            <Card>
              <CardContent className="text-center py-12">
                <MessageSquare className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
                <h3 className="text-lg font-medium mb-2">Nenhuma oferta enviada</h3>
                <p className="text-muted-foreground">
                  N├úo h├í ofertas pendentes de resposta.
                </p>
              </CardContent>
            </Card>
          ) : (
            <div className="space-y-4">
              {waitlist
                .filter(w => w.status === 'offered')
                .map((client) => (
                  <Card key={client.id}>
                    <CardContent className="p-4">
                      <div className="flex items-start justify-between">
                        <div className="space-y-2 flex-1">
                          <div className="flex items-center gap-2">
                            <Badge variant="secondary" className="flex items-center gap-1">
                              {getStatusIcon(client.status)}
                              {getStatusText(client.status)}
                            </Badge>
                            <h4 className="font-medium">{client.clients?.name}</h4>
                          </div>
                          
                          <div className="text-sm">
                            <span className="text-muted-foreground">Oferta enviada:</span>
                            <p>{new Date(client.offered_at!).toLocaleString('pt-BR')}</p>
                          </div>

                          <div className="text-sm">
                            <span className="text-muted-foreground">Prazo de resposta:</span>
                            <p>{new Date(client.response_deadline!).toLocaleString('pt-BR')}</p>
                          </div>

                          {client.notes && (
                            <div className="p-2 bg-muted/50 rounded text-sm">
                              <span className="text-muted-foreground">Observa├º├Áes:</span>
                              <p>{client.notes}</p>
                            </div>
                          )}
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                ))}
            </div>
          )}
        </TabsContent>

        {/* Aba: Hist├│rico */}
        <TabsContent value="history" className="space-y-4">
          {waitlist.filter(w => ['accepted', 'declined', 'expired'].includes(w.status)).length === 0 ? (
            <Card>
              <CardContent className="text-center py-12">
                <Calendar className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
                <h3 className="text-lg font-medium mb-2">Nenhum hist├│rico</h3>
                <p className="text-muted-foreground">
                  N├úo h├í hist├│rico de ofertas para esta data.
                </p>
              </CardContent>
            </Card>
          ) : (
            <div className="space-y-4">
              {waitlist
                .filter(w => ['accepted', 'declined', 'expired'].includes(w.status))
                .map((client) => (
                  <Card key={client.id} className="opacity-75">
                    <CardContent className="p-4">
                      <div className="flex items-start justify-between">
                        <div className="space-y-2 flex-1">
                          <div className="flex items-center gap-2">
                            <Badge variant={getStatusColor(client.status)} className="flex items-center gap-1">
                              {getStatusIcon(client.status)}
                              {getStatusText(client.status)}
                            </Badge>
                            <h4 className="font-medium">{client.clients?.name}</h4>
                          </div>
                          
                          <div className="text-sm">
                            <span className="text-muted-foreground">Respondido:</span>
                            <p>
                              {client.responded_at 
                                ? new Date(client.responded_at).toLocaleString('pt-BR')
                                : 'N├úo respondido'
                              }
                            </p>
                          </div>
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                ))}
            </div>
          )}
        </TabsContent>
      </Tabs>

      {/* Dialog de oferta manual */}
      <Dialog open={showOfferDialog} onOpenChange={setShowOfferDialog}>
        <DialogContent className="sm:max-w-[500px]">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <MessageSquare className="w-5 h-5 text-primary" />
              Oferecer Hor├írio
            </DialogTitle>
          </DialogHeader>

          {selectedClient && (
            <div className="space-y-6">
              {/* Informa├º├Áes do cliente */}
              <div className="p-4 bg-muted/50 rounded-lg space-y-2">
                <h4 className="font-medium">Cliente selecionado:</h4>
                <div className="grid grid-cols-2 gap-2 text-sm">
                  <div>
                    <span className="text-muted-foreground">Nome:</span>
                    <p className="font-medium">{selectedClient.clients?.name}</p>
                  </div>
                  <div>
                    <span className="text-muted-foreground">Posi├º├úo:</span>
                    <p className="font-medium">#{selectedClient.position_in_queue}</p>
                  </div>
                  <div>
                    <span className="text-muted-foreground">Hor├írio desejado:</span>
                    <p className="font-medium">{selectedClient.desired_time}</p>
                  </div>
                  <div>
                    <span className="text-muted-foreground">Servi├ºo:</span>
                    <p className="font-medium">{selectedClient.services?.name}</p>
                  </div>
                </div>
              </div>

              {/* Formul├írio de oferta */}
              <div className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label>Data</Label>
                    <input
                      type="date"
                      value={offerForm.date}
                      onChange={(e) => setOfferForm({ ...offerForm, date: e.target.value })}
                      className="w-full px-3 py-2 border rounded-md"
                    />
                  </div>
                  <div className="space-y-2">
                    <Label>Hor├írio</Label>
                    <input
                      type="time"
                      value={offerForm.time}
                      onChange={(e) => setOfferForm({ ...offerForm, time: e.target.value })}
                      className="w-full px-3 py-2 border rounded-md"
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <Label>Profissional</Label>
                  <Select
                    value={offerForm.professional_id}
                    onValueChange={(value) => setOfferForm({ ...offerForm, professional_id: value })}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Selecione um profissional" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="">Sem prefer├¬ncia</SelectItem>
                      {/* Aqui viria a lista de profissionais da barbearia */}
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label>Mensagem (opcional)</Label>
                  <Textarea
                    placeholder="Alguma informa├º├úo adicional sobre o hor├írio oferecido?"
                    value={offerForm.notes}
                    onChange={(e) => setOfferForm({ ...offerForm, notes: e.target.value })}
                    rows={3}
                  />
                </div>
              </div>

              <div className="flex gap-2">
                <Button variant="outline" onClick={() => setShowOfferDialog(false)} className="flex-1">
                  Cancelar
                </Button>
                <Button 
                  onClick={() => handleOfferSlot(selectedClient)} 
                  disabled={offeringSlot || !offerForm.time}
                  className="flex-1"
                >
                  {offeringSlot ? (
                    <>
                      <Loader2 className="w-4 h-4 animate-spin mr-2" />
                      Enviando...
                    </>
                  ) : (
                    <>
                      <ArrowRight className="w-4 h-4 mr-2" />
                      Enviar Oferta
                    </>
                  )}
                </Button>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
};

import { useState, useEffect, useCallback } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { useToast } from '@/hooks/use-toast';
import { Download, RefreshCw, BarChart3, TrendingUp, MessageSquare, Users, PieChart } from 'lucide-react';
import {
  getReportSummary,
  getDailyUsage,
  getTopRecipients,
  getMessageUsage,
  exportMessageUsage,
  MessageUsage,
  MessageReportSummary,
  DailyUsage,
} from '@/services/messageReportService';
import { supabase } from '@/integrations/supabase/client';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart as RePieChart, Pie, Cell, Legend } from 'recharts';

interface MessageReportsPanelProps {
  barbershopId: string;
}

const COLORS = ['#22c55e', '#3b82f6', '#f59e0b', '#ef4444', '#8b5cf6'];

export function MessageReportsPanel({ barbershopId }: MessageReportsPanelProps) {
  const { toast } = useToast();
  const [summary, setSummary] = useState<MessageReportSummary | null>(null);
  const [dailyUsage, setDailyUsage] = useState<DailyUsage[]>([]);
  const [topRecipients, setTopRecipients] = useState<{ phone: string; count: number; last_sent: string }[]>([]);
  const [usageData, setUsageData] = useState<MessageUsage[]>([]);
  const [loading, setLoading] = useState(true);
  const [totalCount, setTotalCount] = useState(0);
  const [page, setPage] = useState(0);
  const [filters, setFilters] = useState({
    startDate: new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    endDate: new Date().toISOString().split('T')[0],
    messageType: 'all',
  });
  const [exportLoading, setExportLoading] = useState(false);
  const [selectedMessage, setSelectedMessage] = useState<MessageUsage | null>(null);

  const loadData = useCallback(async () => {
    setLoading(true);
    try {
      const start = new Date(filters.startDate);
      const end = new Date(filters.endDate);
      end.setHours(23, 59, 59, 999);

      const [sum, daily, top, usage] = await Promise.all([
        getReportSummary(barbershopId, start, end),
        getDailyUsage(barbershopId, 30),
        getTopRecipients(barbershopId, 10),
        getMessageUsage(barbershopId, {
          startDate: start,
          endDate: end,
          messageType: filters.messageType !== 'all' ? filters.messageType : undefined,
          limit: 20,
          offset: page * 20,
        }),
      ]);

      setSummary(sum);
      setDailyUsage(daily);
      setTopRecipients(top);
      setUsageData(usage.data);
      setTotalCount(usage.total);
    } catch (error) {
      console.error('Erro ao carregar dados:', error);
      toast({ title: 'Erro', description: 'Falha ao carregar relat├│rios', variant: 'destructive' });
    } finally {
      setLoading(false);
    }
  }, [barbershopId, filters, toast, page]);

  useEffect(() => {
    loadData();
  }, [loadData]);

  const handleExport = async () => {
    setExportLoading(true);
    try {
      const start = new Date(filters.startDate);
      const end = new Date(filters.endDate);
      end.setHours(23, 59, 59, 999);

      const csv = await exportMessageUsage(barbershopId, start, end);

      if (csv) {
        const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = `relatorio-mensagens-${filters.startDate}-${filters.endDate}.csv`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);
        toast({ title: 'Exporta├º├úo conclu├¡da!' });
      } else {
        toast({ title: 'Erro', description: 'Falha ao gerar CSV', variant: 'destructive' });
      }
    } catch (error) {
      toast({ title: 'Erro', description: 'Falha ao exportar dados', variant: 'destructive' });
    } finally {
      setExportLoading(false);
    }
  };

  const getTypeLabel = (type: string) => {
    const labels: Record<string, string> = {
      notification: 'Notifica├º├úo',
      marketing: 'Marketing',
      automation: 'Automa├º├úo',
      reminder: 'Lembrete',
      confirmation: 'Confirma├º├úo',
    };
    return labels[type] || type;
  };

  const pieChartData = summary
    ? Object.entries(summary.by_type).map(([name, data]) => ({
        name: getTypeLabel(name),
        value: data.count,
      }))
    : [];

  if (loading) {
    return (
      <div className="flex items-center justify-center p-8">
        <RefreshCw className="w-8 h-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold">Relat├│rios de Mensagens</h2>
          <p className="text-muted-foreground">Acompanhe o envio de mensagens e custos</p>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" onClick={handleExport} disabled={exportLoading}>
            <Download className="w-4 h-4 mr-2" /> Exportar CSV
          </Button>
          <Button variant="outline" onClick={loadData}>
            <RefreshCw className="w-4 h-4 mr-2" /> Atualizar
          </Button>
        </div>
      </div>

      <div className="grid gap-4 md:grid-cols-4">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Total Enviadas</CardTitle>
            <MessageSquare className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{summary?.total_sent || 0}</div>
            <p className="text-xs text-muted-foreground">mensagens enviadas</p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Custo Total</CardTitle>
            <TrendingUp className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">R$ {summary?.total_cost.toFixed(2) || '0.00'}</div>
            <p className="text-xs text-muted-foreground">total gasto</p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Custo Dono</CardTitle>
            <BarChart3 className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">R$ {summary?.owner_cost.toFixed(2) || '0.00'}</div>
            <p className="text-xs text-muted-foreground">custo do sal├úo</p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Custo Profissionais</CardTitle>
            <Users className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">R$ {summary?.professional_cost.toFixed(2) || '0.00'}</div>
            <p className="text-xs text-muted-foreground">dividido com profis.</p>
          </CardContent>
        </Card>
      </div>

      <div className="grid gap-4 md:grid-cols-3">
        <Card>
          <CardHeader>
            <CardTitle className="text-base">Taxa de Sucesso</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-4xl font-bold text-green-600">{summary?.success_rate || 0}%</div>
            <p className="text-sm text-muted-foreground">mensagens entregues</p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader>
            <CardTitle className="text-base">Per├¡odo</CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-lg font-semibold">{filters.startDate} at├® {filters.endDate}</p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader>
            <CardTitle className="text-base">Filtros</CardTitle>
          </CardHeader>
          <CardContent className="space-y-2">
            <div className="flex gap-2">
              <Input
                type="date"
                value={filters.startDate}
                onChange={(e) => setFilters({ ...filters, startDate: e.target.value })}
                className="w-full"
              />
              <Input
                type="date"
                value={filters.endDate}
                onChange={(e) => setFilters({ ...filters, endDate: e.target.value })}
                className="w-full"
              />
            </div>
            <Select value={filters.messageType} onValueChange={(v) => setFilters({ ...filters, messageType: v })}>
              <SelectTrigger>
                <SelectValue placeholder="Tipo de mensagem" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">Todos os tipos</SelectItem>
                <SelectItem value="notification">Notifica├º├úo</SelectItem>
                <SelectItem value="marketing">Marketing</SelectItem>
                <SelectItem value="automation">Automa├º├úo</SelectItem>
                <SelectItem value="reminder">Lembrete</SelectItem>
                <SelectItem value="confirmation">Confirma├º├úo</SelectItem>
              </SelectContent>
            </Select>
          </CardContent>
        </Card>
      </div>

      <Tabs defaultValue="overview">
        <TabsList>
          <TabsTrigger value="overview">Vis├úo Geral</TabsTrigger>
          <TabsTrigger value="daily">Uso Di├írio</TabsTrigger>
          <TabsTrigger value="recipients">Principais Destinat├írios</TabsTrigger>
          <TabsTrigger value="details">Detalhamento</TabsTrigger>
        </TabsList>

        <TabsContent value="overview">
          <div className="grid gap-4 md:grid-cols-2">
            <Card>
              <CardHeader>
                <CardTitle>Mensagens por Tipo</CardTitle>
              </CardHeader>
              <CardContent>
                {pieChartData.length > 0 ? (
                  <ResponsiveContainer width="100%" height={250}>
                    <RePieChart>
                      <Pie
                        data={pieChartData}
                        cx="50%"
                        cy="50%"
                        labelLine={false}
                        label={({ name, percent }) => `${name} (${(percent * 100).toFixed(0)}%)`}
                        outerRadius={80}
                        fill="#8884d8"
                        dataKey="value"
                      >
                        {pieChartData.map((_, index) => (
                          <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                        ))}
                      </Pie>
                      <Legend />
                    </RePieChart>
                  </ResponsiveContainer>
                ) : (
                  <p className="text-center text-muted-foreground py-8">Sem dados dispon├¡veis</p>
                )}
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle>Custos por Tipo</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-4">
                  {Object.entries(summary?.by_type || {}).map(([type, data], index) => (
                    <div key={type} className="flex items-center justify-between">
                      <div className="flex items-center gap-2">
                        <div className={`w-3 h-3 rounded-full`} style={{ backgroundColor: COLORS[index % COLORS.length] }} />
                        <span className="text-sm">{getTypeLabel(type)}</span>
                      </div>
                      <div className="text-right">
                        <p className="font-semibold">R$ {(data as any).cost.toFixed(2)}</p>
                        <p className="text-xs text-muted-foreground">{(data as any).count} msgs</p>
                      </div>
                    </div>
                  ))}
                </div>
              </CardContent>
            </Card>
          </div>
        </TabsContent>

        <TabsContent value="daily">
          <Card>
            <CardHeader>
              <CardTitle>Uso Di├írio de Mensagens</CardTitle>
            </CardHeader>
            <CardContent>
              {dailyUsage.length > 0 ? (
                <ResponsiveContainer width="100%" height={300}>
                  <LineChart data={dailyUsage}>
                    <CartesianGrid strokeDasharray="3 3" />
                    <XAxis dataKey="date" tick={{ fontSize: 12 }} />
                    <YAxis yAxisId="left" />
                    <YAxis yAxisId="right" orientation="right" />
                    <Tooltip />
                    <Legend />
                    <Line yAxisId="left" type="monotone" dataKey="messages_sent" stroke="#22c55e" name="Mensagens" />
                    <Line yAxisId="right" type="monotone" dataKey="total_cost" stroke="#3b82f6" name="Custo (R$)" />
                  </LineChart>
                </ResponsiveContainer>
              ) : (
                <p className="text-center text-muted-foreground py-8">Sem dados dispon├¡veis</p>
              )}
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="recipients">
          <Card>
            <CardHeader>
              <CardTitle>Principais Destinat├írios</CardTitle>
              <CardDescription>Clientes que mais receberam mensagens</CardDescription>
            </CardHeader>
            <CardContent>
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Telefone</TableHead>
                    <TableHead>Mensagens Recebidas</TableHead>
                    <TableHead>├Ültima Mensagem</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {topRecipients.length === 0 ? (
                    <TableRow>
                      <TableCell colSpan={3} className="text-center py-8 text-muted-foreground">
                        Nenhum dado dispon├¡vel
                      </TableCell>
                    </TableRow>
                  ) : (
                    topRecipients.map((recipient) => (
                      <TableRow key={recipient.phone}>
                        <TableCell className="font-mono">{recipient.phone}</TableCell>
                        <TableCell>
                          <Badge variant="secondary">{recipient.count}</Badge>
                        </TableCell>
                        <TableCell>{new Date(recipient.last_sent).toLocaleString('pt-BR')}</TableCell>
                      </TableRow>
                    ))
                  )}
                </TableBody>
              </Table>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="details">
          <Card>
            <CardHeader>
              <CardTitle>Detalhamento de Mensagens</CardTitle>
            </CardHeader>
            <CardContent>
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Data</TableHead>
                    <TableHead>Telefone</TableHead>
                    <TableHead>Tipo</TableHead>
                    <TableHead>Custo Total</TableHead>
                    <TableHead>Custo Dono</TableHead>
                    <TableHead>Custo Prof.</TableHead>
                    <TableHead>Status</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {usageData.length === 0 ? (
                    <TableRow>
                      <TableCell colSpan={7} className="text-center py-8 text-muted-foreground">
                        Nenhuma mensagem registrada
                      </TableCell>
                    </TableRow>
                  ) : (
                    usageData.map((msg) => (
                      <TableRow key={msg.id} className="cursor-pointer" onClick={() => setSelectedMessage(msg)}>
                        <TableCell className="text-sm">{new Date(msg.created_at).toLocaleString('pt-BR')}</TableCell>
                        <TableCell className="font-mono text-sm">{msg.recipient_phone}</TableCell>
                        <TableCell>
                          <Badge variant="outline">{getTypeLabel(msg.message_type)}</Badge>
                        </TableCell>
                        <TableCell>R$ {msg.total_cost.toFixed(4)}</TableCell>
                        <TableCell>R$ {msg.owner_cost_share.toFixed(4)}</TableCell>
                        <TableCell>R$ {msg.professional_cost_share.toFixed(4)}</TableCell>
                        <TableCell>
                          <Badge
                            variant={msg.twilio_status === 'delivered' ? 'default' : msg.twilio_status === 'failed' ? 'destructive' : 'secondary'}
                          >
                            {msg.twilio_status || 'pending'}
                          </Badge>
                        </TableCell>
                      </TableRow>
                    ))
                  )}
                </TableBody>
              </Table>
              <div className="flex items-center justify-between mt-4">
                <p className="text-sm text-muted-foreground">
                  Mostrando {usageData.length} de {totalCount} mensagens
                </p>
                <div className="flex gap-2">
                  <Button variant="outline" size="sm" onClick={() => setPage(Math.max(0, page - 1))} disabled={page === 0}>
                    Anterior
                  </Button>
                  <Button variant="outline" size="sm" onClick={() => setPage(page + 1)} disabled={usageData.length < 20}>
                    Pr├│xima
                  </Button>
                </div>
              </div>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>

      <Dialog open={!!selectedMessage} onOpenChange={() => setSelectedMessage(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Detalhes da Mensagem</DialogTitle>
          </DialogHeader>
          {selectedMessage && (
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label className="text-xs text-muted-foreground">Data/Hora</Label>
                  <p>{new Date(selectedMessage.created_at).toLocaleString('pt-BR')}</p>
                </div>
                <div>
                  <Label className="text-xs text-muted-foreground">Status Twilio</Label>
                  <p>{selectedMessage.twilio_status || 'Pendente'}</p>
                </div>
                <div>
                  <Label className="text-xs text-muted-foreground">Destinat├írio</Label>
                  <p className="font-mono">{selectedMessage.recipient_phone}</p>
                </div>
                <div>
                  <Label className="text-xs text-muted-foreground">Tipo</Label>
                  <p>{getTypeLabel(selectedMessage.message_type)}</p>
                </div>
              </div>
              {selectedMessage.message_content && (
                <div>
                  <Label className="text-xs text-muted-foreground">Conte├║do</Label>
                  <p className="p-3 bg-muted rounded-lg mt-1">{selectedMessage.message_content}</p>
                </div>
              )}
              <div className="grid grid-cols-3 gap-4">
                <div className="p-3 bg-muted rounded-lg">
                  <Label className="text-xs text-muted-foreground">Custo Total</Label>
                  <p className="text-lg font-bold">R$ {selectedMessage.total_cost.toFixed(4)}</p>
                </div>
                <div className="p-3 bg-muted rounded-lg">
                  <Label className="text-xs text-muted-foreground">Custo Dono</Label>
                  <p className="text-lg font-bold">R$ {selectedMessage.owner_cost_share.toFixed(4)}</p>
                </div>
                <div className="p-3 bg-muted rounded-lg">
                  <Label className="text-xs text-muted-foreground">Custo Prof.</Label>
                  <p className="text-lg font-bold">R$ {selectedMessage.professional_cost_share.toFixed(4)}</p>
                </div>
              </div>
              {selectedMessage.twilio_message_sid && (
                <div>
                  <Label className="text-xs text-muted-foreground">Twilio SID</Label>
                  <p className="font-mono text-sm">{selectedMessage.twilio_message_sid}</p>
                </div>
              )}
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { useToast } from '@/hooks/use-toast';
import { CheckCircle, XCircle, Phone, MessageSquare, Settings, Plus, RefreshCw, Trash2, Crown } from 'lucide-react';
import {
  getWhatsAppAccounts,
  registerWhatsAppAccount,
  verifyPhoneNumber,
  resendVerificationCode,
  setPrimaryAccount,
  deleteWhatsAppAccount,
  updateAccountCredentials,
  WhatsAppAccount,
  AccountWithProfessional,
} from '@/services/whatsappAccountService';
import { getWhatsAppAccountsWithProfessional } from '@/services/whatsappAccountService';
import { supabase } from '@/integrations/supabase/client';

interface WhatsAppAccountsPanelProps {
  barbershopId: string;
}

export function WhatsAppAccountsPanel({ barbershopId }: WhatsAppAccountsPanelProps) {
  const { toast } = useToast();
  const [accounts, setAccounts] = useState<AccountWithProfessional[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddDialog, setShowAddDialog] = useState(false);
  const [showVerifyDialog, setShowVerifyDialog] = useState(false);
  const [showCredentialsDialog, setShowCredentialsDialog] = useState(false);
  const [selectedAccount, setSelectedAccount] = useState<WhatsAppAccount | null>(null);
  const [professionals, setProfessionals] = useState<{ id: string; name: string }[]>([]);

  const [newAccount, setNewAccount] = useState({
    phone_number: '',
    professional_id: '',
    nickname: '',
  });

  const [verificationCode, setVerificationCode] = useState('');
  const [credentials, setCredentials] = useState({
    twilio_sid: '',
    twilio_auth_token: '',
    twilio_messaging_service_sid: '',
  });

  const loadAccounts = useCallback(async () => {
    setLoading(true);
    try {
      const data = await getWhatsAppAccountsWithProfessional(barbershopId);
      setAccounts(data);
    } catch (error) {
      console.error('Erro ao carregar contas:', error);
      toast({ title: 'Erro', description: 'Falha ao carregar contas WhatsApp', variant: 'destructive' });
    } finally {
      setLoading(false);
    }
  }, [barbershopId, toast]);

  const loadProfessionals = useCallback(async () => {
    try {
      const { data } = await (supabase as any)
        .from('professionals')
        .select('id, name')
        .eq('barbershop_id', barbershopId)
        .eq('is_active', true);

      setProfessionals(data || []);
    } catch (error) {
      console.error('Erro ao carregar profissionais:', error);
    }
  }, [barbershopId]);

  useEffect(() => {
    loadAccounts();
    loadProfessionals();
  }, [loadAccounts, loadProfessionals]);

  const handleAddAccount = async () => {
    if (!newAccount.phone_number) {
      toast({ title: 'Erro', description: 'Informe o n├║mero de WhatsApp', variant: 'destructive' });
      return;
    }

    try {
      const result = await registerWhatsAppAccount({
        barbershop_id: barbershopId,
        professional_id: newAccount.professional_id || undefined,
        phone_number: newAccount.phone_number,
        nickname: newAccount.nickname || undefined,
      });

      if (result.success) {
        toast({ title: 'Conta cadastrada', description: 'C├│digo de verifica├º├úo enviado!' });
        setSelectedAccount(result.account!);
        setShowAddDialog(false);
        setShowVerifyDialog(true);
        setNewAccount({ phone_number: '', professional_id: '', nickname: '' });
        loadAccounts();
      } else {
        toast({ title: 'Erro', description: result.error, variant: 'destructive' });
      }
    } catch (error) {
      toast({ title: 'Erro', description: 'Falha ao cadastrar conta', variant: 'destructive' });
    }
  };

  const handleVerify = async () => {
    if (!selectedAccount || !verificationCode) return;

    try {
      const result = await verifyPhoneNumber({
        account_id: selectedAccount.id,
        code: verificationCode,
        twilio_sid: credentials.twilio_sid || undefined,
        twilio_auth_token: credentials.twilio_auth_token || undefined,
      });

      if (result.success) {
        toast({ title: 'Verificado!', description: 'N├║mero de WhatsApp verificado com sucesso!' });
        setShowVerifyDialog(false);
        setShowCredentialsDialog(true);
        loadAccounts();
      } else {
        toast({ title: 'Erro', description: result.message, variant: 'destructive' });
      }
    } catch (error) {
      toast({ title: 'Erro', description: 'Falha na verifica├º├úo', variant: 'destructive' });
    }
  };

  const handleResendCode = async () => {
    if (!selectedAccount) return;

    const result = await resendVerificationCode(selectedAccount.id);
    if (result.success) {
      toast({ title: 'C├│digo reenviado', description: 'Verifique seu WhatsApp' });
    } else {
      toast({ title: 'Erro', description: result.message, variant: 'destructive' });
    }
  };

  const handleSaveCredentials = async () => {
    if (!selectedAccount) return;

    try {
      const success = await updateAccountCredentials({
        accountId: selectedAccount.id,
        twilio_sid: credentials.twilio_sid,
        twilio_auth_token: credentials.twilio_auth_token,
        twilio_messaging_service_sid: credentials.twilio_messaging_service_sid,
      });

      if (success) {
        toast({ title: 'Credenciais salvas', description: 'Configura├º├úo do Twilio conclu├¡da!' });
        setShowCredentialsDialog(false);
        setCredentials({ twilio_sid: '', twilio_auth_token: '', twilio_messaging_service_sid: '' });
        loadAccounts();
      } else {
        toast({ title: 'Erro', description: 'Falha ao salvar credenciais', variant: 'destructive' });
      }
    } catch (error) {
      toast({ title: 'Erro', description: 'Falha ao salvar credenciais', variant: 'destructive' });
    }
  };

  const handleSetPrimary = async (accountId: string) => {
    const success = await setPrimaryAccount(accountId, barbershopId);
    if (success) {
      toast({ title: 'Conta principal definida' });
      loadAccounts();
    } else {
      toast({ title: 'Erro', description: 'Falha ao definir conta principal', variant: 'destructive' });
    }
  };

  const handleDelete = async (accountId: string) => {
    if (!confirm('Tem certeza que deseja remover esta conta?')) return;

    const success = await deleteWhatsAppAccount(accountId);
    if (success) {
      toast({ title: 'Conta removida' });
      loadAccounts();
    } else {
      toast({ title: 'Erro', description: 'Falha ao remover conta', variant: 'destructive' });
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center p-8">
        <RefreshCw className="w-8 h-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold">Contas WhatsApp</h2>
          <p className="text-muted-foreground">Gerencie os n├║meros de WhatsApp para envio de mensagens</p>
        </div>
        <Dialog open={showAddDialog} onOpenChange={setShowAddDialog}>
          <DialogTrigger asChild>
            <Button><Plus className="w-4 h-4 mr-2" /> Adicionar N├║mero</Button>
          </DialogTrigger>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>Cadastrar N├║mero de WhatsApp</DialogTitle>
              <DialogDescription>Cadastre o n├║mero que ser├í usado para enviar mensagens aos clientes</DialogDescription>
            </DialogHeader>
            <div className="space-y-4 py-4">
              <div className="space-y-2">
                <Label>N├║mero de WhatsApp</Label>
                <Input
                  placeholder="+55 11 99999-9999"
                  value={newAccount.phone_number}
                  onChange={(e) => setNewAccount({ ...newAccount, phone_number: e.target.value })}
                />
              </div>
              <div className="space-y-2">
                <Label>Profissional Vinculado (opcional)</Label>
                <Select onValueChange={(v) => setNewAccount({ ...newAccount, professional_id: v })}>
                  <SelectTrigger>
                    <SelectValue placeholder="Selecione um profissional" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="">Nenhum / Conta do Sal├úo</SelectItem>
                    {professionals.map((p) => (
                      <SelectItem key={p.id} value={p.id}>{p.name}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label>Apelido (opcional)</Label>
                <Input
                  placeholder="Ex: WhatsApp Principal"
                  value={newAccount.nickname}
                  onChange={(e) => setNewAccount({ ...newAccount, nickname: e.target.value })}
                />
              </div>
            </div>
            <DialogFooter>
              <Button variant="outline" onClick={() => setShowAddDialog(false)}>Cancelar</Button>
              <Button onClick={handleAddAccount}>Cadastrar</Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>

      <Tabs defaultValue="accounts">
        <TabsList>
          <TabsTrigger value="accounts">Contas Cadastradas</TabsTrigger>
