// @ts-nocheck
import { createContext, useContext, useEffect, useState, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/lib/auth';
import { toast } from 'sonner';

interface Subscription {
  id: string;
  user_id: string;
  plan_id: string;
  status: 'active' | 'pending' | 'cancelled' | 'expired';
  starts_at: string;
  ends_at: string;
  trial_used: boolean;
  subscription_plans: {
    name: string;
    price: number;
    duration_months: number;
  };
}

interface SubscriptionContextType {
  subscription: Subscription | null;
  loading: boolean;
  isActive: boolean;
  isExpired: boolean;
  daysUntilExpiry: number;
  canAccessPremium: boolean;
  refreshSubscription: () => void;
}

const SubscriptionContext = createContext<SubscriptionContextType | undefined>(undefined);

export function SubscriptionProvider({ children }: { children: React.ReactNode }) {
  const { user } = useAuth();
  const [subscription, setSubscription] = useState<Subscription | null>(null);
  const [loading, setLoading] = useState(true);

  const fetchSubscription = useCallback(async () => {
    if (!user) {
      setSubscription(null);
      setLoading(false);
      return;
    }

    try {
      const { data, error } = await (supabase as any)
        .from('user_subscriptions')
        .select(`
          *,
          subscription_plans(name, price, duration_months)
        `)
        .eq('user_id', user.id)
        .eq('status', 'active')
        .gte('ends_at', new Date().toISOString())
        .single();

      if (error && error.code !== 'PGRST116') {
        console.error('Erro ao buscar assinatura:', error);
      }

      setSubscription(data);
    } catch (error) {
      console.error('Erro inesperado:', error);
    } finally {
      setLoading(false);
    }
  }, [user]);

  useEffect(() => {
    fetchSubscription();
  }, [fetchSubscription]);

  const isActive = subscription?.status === 'active' && new Date(subscription.ends_at) > new Date();
  const isExpired = subscription ? new Date(subscription.ends_at) < new Date() : false;
  const daysUntilExpiry = subscription ? Math.ceil((new Date(subscription.ends_at).getTime() - new Date().getTime()) / (1000 * 60 * 60 * 24)) : 0;
  const canAccessPremium = isActive || !subscription; // Sem assinatura = trial

  const value = {
    subscription,
    loading,
    isActive,
    isExpired,
    daysUntilExpiry,
    canAccessPremium,
    refreshSubscription: fetchSubscription
  };

  return (
    <SubscriptionContext.Provider value={value}>
      {children}
    </SubscriptionContext.Provider>
  );
}

export function useSubscription() {
  const context = useContext(SubscriptionContext);
  if (context === undefined) {
    throw new Error('useSubscription must be used within a SubscriptionProvider');
  }
  return context;
}

// Middleware para prote├º├úo de rotas
export function requireSubscription<T extends Record<string, any>>(
  Component: React.ComponentType<T>,
  options: { allowTrial?: boolean; redirectTo?: string } = {}
) {
  return function SubscriptionProtectedComponent(props: T) {
    const { canAccessPremium, subscription, loading } = useSubscription();
    const { user } = useAuth();

    if (loading) {
      return (
        <div className="flex items-center justify-center min-h-screen">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
        </div>
      );
    }

    if (!user) {
      window.location.href = '/login';
      return null;
    }

    if (!canAccessPremium) {
      if (options.redirectTo) {
        window.location.href = options.redirectTo;
        return null;
      }

      return (
        <div className="flex items-center justify-center min-h-screen">
          <div className="text-center p-8">
            <h2 className="text-2xl font-bold mb-4">Assinatura Necess├íria</h2>
            <p className="text-muted-foreground mb-6">
              Voc├¬ precisa de uma assinatura ativa para acessar esta funcionalidade.
            </p>
            <button
              onClick={() => window.location.href = '/pricing'}
              className="px-6 py-2 bg-primary text-white rounded-lg hover:bg-primary/90"
            >
              Ver Planos
            </button>
          </div>
        </div>
      );
    }

    return <Component {...props} />;
  };
}

/**
 * Hook para gerenciar configura├º├Áes de integra├º├úo
 */

import { useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useToast } from "@/hooks/use-toast";
import type { Environment, ServiceName } from "@/lib/integrations/api-config";

interface IntegrationSetting {
  id: string;
  service_name: string;
  environment: string;
  api_key_hash: string | null;
  webhook_secret_hash: string | null;
  base_url: string | null;
  from_email: string | null;
  is_active: boolean;
  created_at: string;
  updated_at: string;
}

interface AppEnvironment {
  current_env: Environment;
  updated_at: string;
}

export function useIntegrationSettings() {
  const [settings, setSettings] = useState<IntegrationSetting[]>([]);
  const [appEnvironment, setAppEnvironment] = useState<AppEnvironment | null>(null);
  const [loading, setLoading] = useState(true);
  const { toast } = useToast();

  // Carregar configura├º├Áes
  const fetchSettings = async () => {
    setLoading(true);
    try {
      // Carregar ambiente
      const { data: envData, error: envError } = await (supabase as any)
        .from('app_environment')
        .select('*')
        .limit(1)
        .maybeSingle();

      if (envError) throw envError;
      
      if (envData) {
        setAppEnvironment({
          current_env: envData.current_env as Environment,
          updated_at: envData.updated_at,
        });
      }

      // Carregar settings
      const { data: settingsData, error: settingsError } = await (supabase as any)
        .from('integration_settings')
        .select('*')
        .order('service_name');

      if (settingsError) throw settingsError;
      setSettings(settingsData as IntegrationSetting[] || []);
    } catch (error) {
      console.error('Failed to load integration settings:', error);
      toast({
        title: "Erro",
        description: "N├úo foi poss├¡vel carregar as configura├º├Áes de integra├º├úo.",
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchSettings();
  }, []);

  // Alternar ambiente global
  const switchEnvironment = async (env: Environment) => {
    try {
      const { error } = await (supabase as any)
        .from('app_environment')
        .update({ current_env: env, updated_at: new Date().toISOString() })
        .neq('id', '00000000-0000-0000-0000-000000000000');

      if (error) throw error;

      setAppEnvironment((prev) => prev ? { ...prev, current_env: env } : null);
      
      toast({
        title: "Ambiente alterado",
        description: `Ambiente alterado para ${env === 'sandbox' ? 'Teste (Sandbox)' : 'Produ├º├úo'}`,
      });

      return true;
    } catch (error) {
      console.error('Failed to switch environment:', error);
      toast({
        title: "Erro",
        description: "N├úo foi poss├¡vel alterar o ambiente.",
        variant: "destructive",
      });
      return false;
    }
  };

  // Salvar ou atualizar configura├º├úo
  const saveSettings = async (
    service: ServiceName,
    environment: Environment,
    config: {
      apiKey?: string;
      webhookSecret?: string;
      baseUrl?: string;
      fromEmail?: string;
      isActive: boolean;
    }
  ) => {
    const sha256Hex = async (value: string) => {
      const bytes = new TextEncoder().encode(value);
      const digest = await crypto.subtle.digest("SHA-256", bytes);
      return Array.from(new Uint8Array(digest))
        .map((b) => b.toString(16).padStart(2, "0"))
        .join("");
    };

    try {
      // Verificar se j├í existe
      const existing = settings.find(
        (s) => s.service_name === service && s.environment === environment
      );

      // IMPORTANTE: n├úo persistimos chaves em texto puro no frontend.
      const payload = {
        service_name: service,
        environment,
        api_key_hash: config.apiKey ? await sha256Hex(config.apiKey) : null,
        webhook_secret_hash: config.webhookSecret ? await sha256Hex(config.webhookSecret) : null,
        base_url: config.baseUrl || null,
        from_email: config.fromEmail || null,
        is_active: config.isActive,
      };

      if (existing) {
        const { error } = await (supabase as any)
          .from('integration_settings')
          .update(payload)
          .eq('id', existing.id);

        if (error) throw error;
      } else {
        const { error } = await (supabase as any)
          .from('integration_settings')
          .insert(payload);

        if (error) throw error;
      }

      await fetchSettings();

      toast({
        title: "Configura├º├úo salva",
        description: `${service.toUpperCase()} (${environment}) foi atualizado com sucesso.`,
      });

      return true;
    } catch (error) {
      console.error('Failed to save settings:', error);
      toast({
        title: "Erro",
        description: "N├úo foi poss├¡vel salvar as configura├º├Áes.",
        variant: "destructive",
      });
      return false;
    }
  };

  // Toggle ativo/inativo
  const toggleServiceActive = async (id: string, isActive: boolean) => {
    try {
      const { error } = await (supabase as any)
        .from('integration_settings')
        .update({ is_active: isActive })
        .eq('id', id);

      if (error) throw error;

      setSettings((prev) =>
        prev.map((s) => (s.id === id ? { ...s, is_active: isActive } : s))
      );

      return true;
    } catch (error) {
      console.error('Failed to toggle service:', error);
      return false;
    }
  };

  return {
    settings,
    appEnvironment,
    loading,
    switchEnvironment,
    saveSettings,
    toggleServiceActive,
    refresh: fetchSettings,
  };
}

import { useState, useEffect } from "react";
import { useAuth } from "@/lib/auth";
import { supabase } from "@/integrations/supabase/client";

interface Barbershop {
  id: string;
  name: string;
  slug: string | null;
  address: string | null;
  phone: string | null;
  description: string | null;
  logo_url: string | null;
  is_active: boolean | null;
  owner_user_id: string;
  cashback_percentage: number | null;
  subscription_status: string | null;
  subscription_ends_at: string | null;
  affiliate_commission_pct: number | null;
  affiliate_auto_pay: boolean | null;
  affiliate_reward_type: string | null;
  asaas_customer_id: string | null;
  asaas_wallet_id: string | null;
  automation_schedule: any;
  sector: string | null;
  created_at: string;
  updated_at: string;
}

export function useBarbershop() {
  const { user } = useAuth();
  const [barbershop, setBarbershop] = useState<Barbershop | null>(null);
  const [loading, setLoading] = useState(true);

  const fetchBarbershop = async () => {
    if (!user) {
      setLoading(false);
      return;
    }

    setLoading(true);
    const { data, error } = await (supabase as any)
      .from("barbershops")
      .select("*")
      .eq("owner_user_id", user.id)
      .order("created_at", { ascending: true })
      .limit(1)
      .maybeSingle();

    if (!error && data) {
      setBarbershop(data as Barbershop);
    }
    setLoading(false);
  };

  useEffect(() => {
    fetchBarbershop();
  }, [user]);

  const updateBarbershop = async (updates: Partial<Barbershop>) => {
    if (!barbershop?.id) return { success: false, error: 'Barbearia n├úo encontrada' };

    setLoading(true);
    try {
      const { error } = await (supabase as any)
        .from("barbershops")
        .update(updates)
        .eq("id", barbershop.id);

      if (error) throw error;
      
      setBarbershop((prev) => prev ? { ...prev, ...updates } : null);
      return { success: true };
    } catch (error: any) {
      console.error('Erro ao atualizar barbearia:', error);
      return { success: false, error: error.message };
    } finally {
      setLoading(false);
    }
  };

  return { barbershop, loading, refetch: fetchBarbershop, updateBarbershop };
}

