/**
 * Hook para chat com IA aprimorada
 */
export function useAIChat(clientId?: string) {
  const [messages, setMessages] = useState<Array<{
    id: string;
    text: string;
    sender: 'user' | 'ai';
    timestamp: Date;
    personalized?: boolean;
  }>>([]);
  
  const { processMessage, isProcessing } = useEnhancedAI(clientId);
  const { data: history } = useAIHistory(clientId);
  
  // Carregar hist├│rico quando dispon├¡vel
  useEffect(() => {
    if (history && history.length > 0) {
      const historyMessages = history.map(item => ({
        id: item.id,
        text: item.message,
        sender: 'user' as const,
        timestamp: new Date(item.created_at),
      }));
      setMessages(historyMessages.slice(0, 10));
    }
  }, [history]);
  
  const sendMessage = useCallback(async (text: string) => {
    if (!text.trim() || !clientId) return;
    
    // Adicionar mensagem do usu├írio
    const userMessage = {
      id: Date.now().toString(),
      text,
      sender: 'user' as const,
      timestamp: new Date(),
    };
    
    setMessages(prev => [...prev, userMessage]);
    
    try {
      // Processar com IA
      const response = await processMessage(text);
      
      // Adicionar resposta da IA
      const aiMessage = {
        id: (Date.now() + 1).toString(),
        text: response.message,
        sender: 'ai' as const,
        timestamp: new Date(),
        personalized: response.personalized,
      };
      
      setMessages(prev => [...prev, aiMessage]);
      
      return response;
    } catch (error) {
      console.error('Erro ao processar mensagem:', error);
      
      // Mensagem de erro
      const errorMessage = {
        id: (Date.now() + 1).toString(),
        text: 'Desculpe, ocorreu um erro ao processar sua mensagem. Tente novamente.',
        sender: 'ai' as const,
        timestamp: new Date(),
        personalized: false,
      };
      
      setMessages(prev => [...prev, errorMessage]);
      
      throw error;
    }
  }, [clientId, processMessage]);
  
  const clearChat = useCallback(() => {
    setMessages([]);
  }, []);
  
  return {
    messages,
    sendMessage,
    clearChat,
    isProcessing,
    hasHistory: history && history.length > 0,
  };
}

