// @ts-nocheck
import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';

interface Plan {
  id: string;
  name: string;
  duration_months: number;
  price: number;
  asaas_checkout_id: string | null;
  is_active: boolean;
  sort_order: number;
}

export function useSubscriptionPlans() {
  const [plans, setPlans] = useState<Plan[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchPlans();
  }, []);

  const fetchPlans = async () => {
    try {
      const { data, error } = await (supabase as any)
        .from('subscription_plans')
        .select('*')
        .eq('is_active', true)
        .order('sort_order', { ascending: true });

      if (error) {
        console.error('Erro ao buscar planos:', error);
        toast.error('Erro ao carregar planos');
        return;
      }

      setPlans(data || []);
    } catch (error) {
      console.error('Erro inesperado:', error);
      toast.error('Erro ao carregar planos');
    } finally {
      setLoading(false);
    }
  };

  const createSubscription = async (planId: string, userId: string) => {
    try {
      const plan = plans.find(p => p.id === planId);
      if (!plan) {
        toast.error('Plano n├úo encontrado');
        return null;
      }

      // Se plano trial, criar assinatura gratuita
      if (plan.duration_months === 0) {
        const { data, error } = await (supabase as any)
          .from('user_subscriptions')
          .insert({
            user_id: userId,
            plan_id: planId,
            status: 'active',
            starts_at: new Date().toISOString(),
            ends_at: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString(), // 7 dias
            trial_used: true
          })
          .select()
          .single();

        if (error) {
          console.error('Erro ao criar assinatura trial:', error);
          toast.error('Erro ao ativar plano trial');
          return null;
        }

        toast.success('Plano trial ativado com sucesso!');
        return data;
      }

      // Para planos pagos, redirecionar para checkout ASAAS
      if (plan.asaas_checkout_id) {
        // Criar assinatura pendente
        const { data: subscription, error: subError } = await (supabase as any)
          .from('user_subscriptions')
          .insert({
            user_id: userId,
            plan_id: planId,
            status: 'pending',
            trial_used: false
          })
          .select()
          .single();

        if (subError) {
          console.error('Erro ao criar assinatura pendente:', subError);
          toast.error('Erro ao iniciar assinatura');
          return null;
        }

        // Redirecionar para checkout ASAAS
        const checkoutUrl = `https://checkout.asaas.com/checkout/${plan.asaas_checkout_id}`;
        window.open(checkoutUrl, '_blank');
        
        return subscription;
      }

      toast.error('Plano n├úo dispon├¡vel para compra');
      return null;
    } catch (error) {
      console.error('Erro ao criar assinatura:', error);
      toast.error('Erro ao processar assinatura');
      return null;
    }
  };

  const checkSubscriptionStatus = async (userId: string) => {
    try {
      const { data, error } = await (supabase as any)
        .from('user_subscriptions')
        .select(`
          *,
          subscription_plans(name, price, duration_months)
        `)
        .eq('user_id', userId)
        .eq('status', 'active')
        .gte('ends_at', new Date().toISOString())
        .single();

      if (error && error.code !== 'PGRST116') {
        console.error('Erro ao verificar assinatura:', error);
        return null;
      }

      return data;
    } catch (error) {
      console.error('Erro inesperado:', error);
      return null;
    }
  };

  return {
    plans,
    loading,
    createSubscription,
    checkSubscriptionStatus,
    refetch: fetchPlans
  };
}

/**
 * Hook customizado para carregar dados do Supabase com tratamento de erro
 * Evita telas brancas e fornece feedback ao usu├írio
 */

import { useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { handleSupabaseError, retrySupabaseQuery } from "@/lib/supabase-error-handler";
import { toast } from "sonner";

interface UseSupabaseDataOptions {
  showError?: boolean;
  retryCount?: number;
  fallbackData?: any;
}

export const useSupabaseData = <T>(
  queryFn: () => Promise<{ data: T | null; error: any }>,
  dependencies: any[] = [],
  options: UseSupabaseDataOptions = {}
) => {
  const { showError = true, retryCount = 2, fallbackData = null } = options;
  const [data, setData] = useState<T | null>(fallbackData);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let isMounted = true;

    const fetchData = async () => {
      try {
        setLoading(true);
        setError(null);

        const result = await retrySupabaseQuery(queryFn, retryCount);

        if (!isMounted) return;

        if (result.error) {
          const errorMessage = handleSupabaseError(result.error);
          setError(errorMessage);
          if (showError) {
            toast.error(errorMessage);
          }
          setData(fallbackData);
        } else {
          setData(result.data || fallbackData);
        }
      } catch (err: any) {
        if (!isMounted) return;
        const errorMessage = handleSupabaseError(err);
        setError(errorMessage);
        if (showError) {
          toast.error(errorMessage);
        }
        setData(fallbackData);
      } finally {
        if (isMounted) {
          setLoading(false);
        }
      }
    };

    fetchData();

    return () => {
      isMounted = false;
    };
  }, dependencies);

  return { data, loading, error, refetch: () => {} };
};

/**
 * Hook para opera├º├Áes de escrita (insert, update, delete)
 */
export const useSupabaseMutation = () => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const mutate = async (
    mutationFn: () => Promise<{ data: any; error: any }>,
    options: { onSuccess?: () => void; onError?: (err: string) => void } = {}
  ) => {
    try {
      setLoading(true);
      setError(null);

      const result = await mutationFn();

      if (result.error) {
        const errorMessage = handleSupabaseError(result.error);
        setError(errorMessage);
        toast.error(errorMessage);
        options.onError?.(errorMessage);
        return null;
      }

      toast.success("Opera├º├úo realizada com sucesso!");
      options.onSuccess?.();
      return result.data;
    } catch (err: any) {
      const errorMessage = handleSupabaseError(err);
      setError(errorMessage);
      toast.error(errorMessage);
      options.onError?.(errorMessage);
      return null;
    } finally {
      setLoading(false);
    }
  };

  return { mutate, loading, error };
};

