/**
 * activityTracker.ts
 * Registra atividade do usu├írio e detecta inatividade para remarketing
 * Usa tabela notifications como log (sem criar tabela nova)
 */
import { supabase } from "@/integrations/supabase/client";

export type InactivityTrigger = "1d" | "3d" | "7d";

/**
 * Registra uma a├º├úo do usu├írio (silencioso, n├úo bloqueia UI)
 */
export async function trackActivity(userId: string, action: string): Promise<void> {
  try {
    await (supabase as any).from("notifications").insert({
      user_id: userId,
      title: "activity",
      message: action,
      type: "info",
      read: true,
    });
  } catch {
    // silencioso
  }
}

/**
 * Retorna quantos dias desde a ├║ltima atividade do usu├írio
 */
export async function getDaysSinceLastActivity(userId: string): Promise<number> {
  try {
    const { data } = await (supabase as any)
      .from("notifications")
      .select("created_at")
      .eq("user_id", userId)
      .order("created_at", { ascending: false })
      .limit(1)
      .maybeSingle();

    if (!data) return 999;
    const diff = Date.now() - new Date(data.created_at).getTime();
    return Math.floor(diff / (1000 * 60 * 60 * 24));
  } catch {
    return 999;
  }
}

/**
 * Retorna o trigger de inatividade (1d, 3d, 7d) ou null se ativo
 */
export async function getInactivityTrigger(userId: string): Promise<InactivityTrigger | null> {
  const days = await getDaysSinceLastActivity(userId);
  if (days >= 7) return "7d";
  if (days >= 3) return "3d";
  if (days >= 1) return "1d";
  return null;
}

/**
 * Pixel Adapter - Client-side + Server-side tracking
 * Super Admin define quais eventos disparam pixel
 */

import { supabase } from "@/integrations/supabase/client";
import type { PixelAdapter, PixelTrackRequest, PixelEvent } from "./types";

interface ActivePixel {
  pixel_type: string;
  pixel_id: string;
  events_json: unknown[];
}

class PixelAdapterImpl implements PixelAdapter {
  private pixels: ActivePixel[] = [];
  private loaded = false;

  private async loadPixels() {
    if (this.loaded) return;
    try {
      // Load platform-level pixels (public-facing, loaded without auth)
      const { data } = await (supabase as any)
        .from("pixel_configurations")
        .select("platform, pixel_id, events, is_active")
        .eq("is_active", true)
        .eq("is_global", true);

      if (data) {
        this.pixels = data.map((p) => ({
          pixel_type: p.platform,
          pixel_id: p.pixel_id,
          events_json: (p.events as unknown[]) || [],
        }));
      }
    } catch {
      // Silent fail - pixels are non-critical
    }
    this.loaded = true;
  }

  track(request: PixelTrackRequest): void {
    this.loadPixels().then(() => {
      for (const pixel of this.pixels) {
        const events = pixel.events_json as string[];
        if (events.length > 0 && !events.includes(request.event)) continue;

        switch (pixel.pixel_type) {
          case "meta":
            this.trackMeta(pixel.pixel_id, request);
            break;
          case "google":
          case "ga4":
            this.trackGA4(pixel.pixel_id, request);
            break;
          case "tiktok":
            this.trackTikTok(pixel.pixel_id, request);
            break;
        }
      }
