/**
 * Tratamento centralizado de erros do Supabase
 * Evita telas brancas e fornece feedback ao usu├írio
 */

export interface SupabaseError {
  code?: string;
  message: string;
  details?: string;
  hint?: string;
}

export const handleSupabaseError = (error: any): string => {
  if (!error) return "Erro desconhecido";

  // Erro de conex├úo
  if (error.message?.includes("Failed to fetch")) {
    return "Erro de conex├úo. Verifique sua internet.";
  }

  // Erro de autentica├º├úo
  if (error.status === 401 || error.message?.includes("unauthorized")) {
    return "Sess├úo expirada. Fa├ºa login novamente.";
  }

  // Erro de permiss├úo
  if (error.status === 403 || error.message?.includes("permission denied")) {
    return "Voc├¬ n├úo tem permiss├úo para acessar isso.";
  }

  // Erro de tabela n├úo encontrada
  if (error.code === "PGRST116" || error.message?.includes("relation does not exist")) {
    return "Recurso n├úo dispon├¡vel. Contate o suporte.";
  }

  // Erro de constraint (chave estrangeira, unique, etc)
  if (error.code?.startsWith("23")) {
    if (error.message?.includes("unique")) {
      return "Este registro j├í existe.";
    }
    if (error.message?.includes("foreign key")) {
      return "Refer├¬ncia inv├ílida. Verifique os dados.";
    }
    return "Erro de valida├º├úo dos dados.";
  }

  // Erro gen├®rico
  return error.message || "Erro ao processar requisi├º├úo";
};

/**
 * Wrapper seguro para queries do Supabase
 * Retorna dados ou array vazio em caso de erro
 */
export const safeSupabaseQuery = async <T>(
  query: Promise<{ data: T | null; error: any }>,
  fallback: T = [] as any
): Promise<T> => {
  try {
    const { data, error } = await query;
    if (error) {
      console.error("Supabase Error:", error);
      return fallback;
    }
    return data || fallback;
  } catch (err) {
    console.error("Query Error:", err);
    return fallback;
  }
};

/**
 * Validar se tabela existe antes de fazer query
 */
export const tableExists = async (supabase: any, tableName: string): Promise<boolean> => {
  try {
    const { error } = await (supabase as any)
      .from(tableName)
      .select("1")
      .limit(1);
    
    // Se erro ├® "relation does not exist", tabela n├úo existe
    if (error?.code === "PGRST116") {
      return false;
    }
    
    return true;
  } catch {
    return false;
  }
};

/**
 * Retry logic para queries que podem falhar temporariamente
 */
export const retrySupabaseQuery = async <T>(
  queryFn: () => Promise<{ data: T | null; error: any }>,
  maxRetries: number = 3,
  delayMs: number = 1000
): Promise<{ data: T | null; error: any }> => {
  let lastError: any;

  for (let i = 0; i < maxRetries; i++) {
    try {
      const result = await queryFn();
      if (!result.error) {
        return result;
      }
      lastError = result.error;

      // N├úo retry em erros de permiss├úo ou autentica├º├úo
      if (result.error?.status === 401 || result.error?.status === 403) {
        return result;
      }

      // Aguarda antes de retry
      if (i < maxRetries - 1) {
        await new Promise(resolve => setTimeout(resolve, delayMs * (i + 1)));
      }
    } catch (err) {
      lastError = err;
    }
  }

  return { data: null, error: lastError };
};

