// ==================== AUTOMA├ç├âO DE CAMPANHAS ====================

export async function runBirthdayCampaign(barbershopId: string, discount: number = 15): Promise<{ sent: number }> {
  const profiles = await getClientProfiles(barbershopId);
  const today = new Date();
  const todayStr = `${String(today.getMonth() + 1).padStart(2, '0')}-${String(today.getDate()).padStart(2, '0')}`;

  const birthdayClients = profiles.filter(p => {
    if (!p.birthday) return false;
    const bday = p.birthday.substring(5); // MM-DD
    return bday === todayStr;
  });

  if (birthdayClients.length === 0) return { sent: 0 };

  const template = CAMPAIGN_TEMPLATES.birthday;
  let sent = 0;

  for (const client of birthdayClients) {
    await enqueueJob({
      type: 'send_whatsapp',
      payload: {
        phone: client.phone,
        message: template.message
          .replace('{{name}}', client.name)
          .replace('{{discount}}', String(discount)),
      },
      priority: 'normal',
    });
    sent++;
  }

  return { sent };
}

export async function runReactivationCampaign(barbershopId: string, params: {
  min_days_inactive: number;
  discount: number;
  channel: NotificationChannel;
}): Promise<{ sent: number }> {
  const profiles = await getClientProfiles(barbershopId);
  const inactiveClients = segmentClients(profiles, {
    status: ['inactive', 'at_risk'],
    last_visit_days_ago: { min: params.min_days_inactive },
  });

  if (inactiveClients.length === 0) return { sent: 0 };

  const template = CAMPAIGN_TEMPLATES.reactivation;
  const result = await sendBulkNotification({
    barbershop_id: barbershopId,
    channel: params.channel,
    trigger: 'reactivation',
    title: template.title,
    body: template.message
      .replace('{{discount}}', String(params.discount)),
    target: inactiveClients.map(c => c.user_id),
  });

  return { sent: result.sent };
}

export async function runEmptySlotsCampaign(barbershopId: string, discount: number = 20): Promise<{ sent: number }> {
  // Verificar slots vazios para hoje
  const today = new Date().toISOString().split('T')[0];
  const now = new Date().getHours();

  const { data: appointments } = await (supabase as any)
    .from('appointments')
    .select('scheduled_at')
    .eq('barbershop_id', barbershopId)
    .gte('scheduled_at', `${today}T${String(now).padStart(2, '0')}:00:00`)
    .lte('scheduled_at', `${today}T20:00:00`)
    .in('status', ['scheduled', 'confirmed']);

  const { data: professionals } = await (supabase as any)
    .from('professionals')
    .select('id')
    .eq('barbershop_id', barbershopId)
    .eq('is_active', true);

  const totalProfsCount = (professionals || []).length;
  const remainingHours = 20 - now;
  const slotsPerHour = 2; // 30 min each
  const totalPossibleSlots = totalProfsCount * remainingHours * slotsPerHour;
  const bookedSlots = (appointments || []).length;
  const emptyRate = totalPossibleSlots > 0 ? ((totalPossibleSlots - bookedSlots) / totalPossibleSlots) * 100 : 0;

  // S├│ dispara se mais de 60% da agenda est├í vazia
  if (emptyRate < 60) return { sent: 0 };

  const profiles = await getClientProfiles(barbershopId);
  const activeClients = segmentClients(profiles, { status: ['active', 'at_risk'] });

  const result = await sendBulkNotification({
    barbershop_id: barbershopId,
    channel: 'whatsapp',
    trigger: 'promotion',
    title: CAMPAIGN_TEMPLATES.empty_slots.title,
    body: CAMPAIGN_TEMPLATES.empty_slots.message.replace('{{discount}}', String(discount)),
    target: activeClients.slice(0, 50).map(c => c.user_id),
  });

  return { sent: result.sent };
}

// ==================== SCHEDULER DE AUTOMA├ç├òES ====================

export async function runAllAutomations(barbershopId: string): Promise<{
  birthday: number;
  reactivation: number;
  empty_slots: number;
}> {
  const [birthday, reactivation, emptySlots] = await Promise.all([
    runBirthdayCampaign(barbershopId),
    runReactivationCampaign(barbershopId, { min_days_inactive: 30, discount: 15, channel: 'whatsapp' }),
    runEmptySlotsCampaign(barbershopId),
  ]);

  return {
    birthday: birthday.sent,
    reactivation: reactivation.sent,
    empty_slots: emptySlots.sent,
  };
}

/**
 * M├│dulo Notifica├º├Áes Multicanal ÔÇö Tipos + Service
 * WhatsApp, Push, Email, SMS
 */

import { supabase } from '@/integrations/supabase/client';
import { enqueueJob } from '@/modules/queue';

// ==================== TIPOS ====================

export type NotificationChannel = 'whatsapp' | 'push' | 'email' | 'sms';
export type NotificationTrigger = 
  | 'appointment_reminder'
  | 'appointment_confirmed'
  | 'appointment_cancelled'
  | 'payment_received'
  | 'cashback_earned'
  | 'birthday'
  | 'reactivation'
  | 'promotion'
  | 'waitlist_available'
  | 'custom';

export interface NotificationTemplate {
  id: string;
  trigger: NotificationTrigger;
  channel: NotificationChannel;
  title_template: string;
  body_template: string;
  variables: string[];
  enabled: boolean;
  barbershop_id?: string;
}

export interface NotificationPayload {
  user_id?: string;
  phone?: string;
  email?: string;
  channel: NotificationChannel;
  trigger: NotificationTrigger;
  title: string;
  body: string;
  data?: Record<string, unknown>;
  scheduled_for?: string;
}

// ==================== TEMPLATE ENGINE ====================

export function renderTemplate(template: string, vars: Record<string, string>): string {
  return Object.entries(vars).reduce(
    (text, [key, value]) => text.replace(new RegExp(`{{${key}}}`, 'g'), value),
    template
  );
}

// ==================== ENVIO ====================

export async function sendNotification(payload: NotificationPayload): Promise<{ success: boolean; error?: string }> {
  try {
    // Enfileira na queue para processamento ass├¡ncrono
    const result = await enqueueJob({
      type: payload.channel === 'whatsapp' ? 'send_whatsapp' 
            : payload.channel === 'email' ? 'send_email' 
            : payload.channel === 'sms' ? 'send_sms' 
            : 'send_notification',
      payload: {
        ...payload,
        sent_via: 'notification_service',
      },
      priority: payload.trigger === 'appointment_reminder' ? 'high' : 'normal',
      scheduled_for: payload.scheduled_for,
    });

    // Registrar na tabela de notifica├º├Áes
    if (payload.user_id) {
      await (supabase as any).from('notifications').insert({
        user_id: payload.user_id,
        title: payload.title,
        message: payload.body,
        type: payload.trigger,
        read: false,
      });
    }

    return { success: result.success, error: result.error };
  } catch (err: any) {
    return { success: false, error: err.message };
  }
}

// ==================== ENVIO EM MASSA ====================

export async function sendBulkNotification(params: {
  barbershop_id: string;
  channel: NotificationChannel;
  trigger: NotificationTrigger;
  title: string;
  body: string;
  target: 'all_clients' | 'vip' | 'inactive' | 'birthday_today' | string[];
}): Promise<{ sent: number; failed: number }> {
  let userIds: string[] = [];

  if (Array.isArray(params.target)) {
    userIds = params.target;
  } else {
    // Buscar clientes pelo filtro
    let query = (supabase as any)
      .from('appointments')
      .select('client_user_id')
      .eq('barbershop_id', params.barbershop_id)
      .not('client_user_id', 'is', null);

    if (params.target === 'inactive') {
      const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString();
      query = query.lt('scheduled_at', thirtyDaysAgo);
    }

    const { data } = await query;
    userIds = [...new Set((data || []).map((d: any) => d.client_user_id).filter(Boolean))] as string[];
  }

  let sent = 0, failed = 0;

  for (const userId of userIds) {
    const result = await sendNotification({
      user_id: userId,
      channel: params.channel,
      trigger: params.trigger,
      title: params.title,
      body: params.body,
    });
    result.success ? sent++ : failed++;
  }

  return { sent, failed };
}

// ==================== LEMBRETES AUTOM├üTICOS ====================

export async function scheduleAppointmentReminders(barbershopId: string): Promise<number> {
  const tomorrow = new Date();
  tomorrow.setDate(tomorrow.getDate() + 1);
  const tomorrowStr = tomorrow.toISOString().split('T')[0];

  const { data: appointments } = await (supabase as any)
    .from('appointments')
    .select('id, client_user_id, client_name, scheduled_at, service_id')
    .eq('barbershop_id', barbershopId)
    .gte('scheduled_at', `${tomorrowStr}T00:00:00`)
    .lte('scheduled_at', `${tomorrowStr}T23:59:59`)
    .in('status', ['scheduled', 'confirmed']);

  if (!appointments?.length) return 0;

  let count = 0;
  for (const appt of appointments) {
    const time = new Date(appt.scheduled_at).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
    await sendNotification({
      user_id: appt.client_user_id,
      channel: 'push',
      trigger: 'appointment_reminder',
      title: '­ƒôà Lembrete de Agendamento',
      body: `Ol├í ${appt.client_name || ''}! Lembrete: seu agendamento ├® amanh├ú ├ás ${time}.`,
    });
    count++;
  }

  return count;
}

