import { useState, useEffect, useCallback } from "react";
import { useNavigate, Link } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { ArrowLeft, Loader2, Shield, Mail, CheckCircle, AlertTriangle, Eye, EyeOff } from "lucide-react";
import { toast } from "sonner";
import { useAuth, getDashboardForRole } from "@/lib/auth";
import { supabase } from "@/integrations/supabase/client";
import { z } from "zod";

const emailSchema = z.object({
  email: z.string().email("E-mail inv├ílido"),
});

const AdminLoginPage = () => {
  const navigate = useNavigate();
  const { user, signIn, signInWithMagicLink, getPrimaryRole, roles, loading: authLoading, authResolved } = useAuth();
  
  const [loading, setLoading] = useState(false);
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [emailSent, setEmailSent] = useState(false);
  const [error, setError] = useState("");
  const [unauthorized, setUnauthorized] = useState(false);
  const [loginMode, setLoginMode] = useState<"password" | "magiclink">("password");

  // Redirect if already logged in AND roles loaded
  useEffect(() => {
    if (user && authResolved && roles.length > 0) {
      const role = getPrimaryRole();
      if (role) {
        navigate(getDashboardForRole(role), { replace: true });
      }
    }
  }, [user, authResolved, roles, navigate, getPrimaryRole]);

  // Failsafe: release loading state when auth resolves
  useEffect(() => {
    if (loading && user && authResolved && roles.length > 0) {
      setLoading(false);
    }
  }, [loading, user, authResolved, roles]);

  const checkAuthorization = useCallback(async (emailToCheck: string): Promise<boolean> => {
    try {
      const { data, error } = await (supabase as any).rpc("is_authorized_admin_email", {
        _email: emailToCheck,
      });
      if (error) return false;
      return !!data;
    } catch {
      return false;
    }
  }, []);

  const handlePasswordLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setError("");
    setUnauthorized(false);
    
    const emailValue = email.trim();
    const passwordValue = password;
    
    if (!emailValue || !emailValue.includes("@")) {
      setError("E-mail inv├ílido");
      return;
    }

    if (!passwordValue) {
      setError("Senha obrigat├│ria");
      return;
    }
    
    setLoading(true);

    try {
      const isAuthorized = await checkAuthorization(emailValue);
      
      if (!isAuthorized) {
        setUnauthorized(true);
        setLoading(false);
        return;
      }

      const { error: signInError } = await signIn(emailValue, passwordValue);
      
      if (signInError) {
        const msg = signInError.message || "";
        if (msg.toLowerCase().includes("invalid login credentials")) {
          toast.error("Credenciais inv├ílidas. Verifique e-mail e senha.");
        } else if (msg.toLowerCase().includes("email not confirmed")) {
          toast.error("Confirme seu e-mail antes de entrar.");
        } else {
          toast.error("Erro ao fazer login. Tente novamente.");
        }
        setLoading(false);
        return;
      }
      
      toast.success("Acesso autorizado!");
      // Failsafe: release loading after timeout if redirect doesn't happen
      setTimeout(() => setLoading(false), 5000);
      return;
    } catch (err) {
      toast.error("Ocorreu um erro. Tente novamente.");
      setLoading(false);
    }
  };

  const handleMagicLink = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setUnauthorized(false);
    
    const emailValue = email.trim();
    
    try {
      emailSchema.parse({ email: emailValue });
    } catch (err) {
      if (err instanceof z.ZodError) {
        setError(err.errors[0].message);
        return;
      }
    }
    
    setLoading(true);

    try {
      const isAuthorized = await checkAuthorization(emailValue);
      
      if (!isAuthorized) {
        setUnauthorized(true);
        setLoading(false);
        return;
      }

      const { error } = await signInWithMagicLink(emailValue, "/super-admin2026ok");
      
      if (error) {
        toast.error(error.message || "Erro ao enviar link de acesso");
        setLoading(false);
        return;
      }
      
      setEmailSent(true);
      toast.success("Link de acesso enviado!");
    } catch (err) {
      toast.error("Ocorreu um erro. Tente novamente.");
    } finally {
      setLoading(false);
    }
  };

  if (!authResolved && authLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-background">
        <Loader2 className="w-8 h-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-4 bg-background">
      <div className="w-full max-w-md">
        <Link 
          to="/" 
          className="inline-flex items-center gap-2 text-muted-foreground hover:text-foreground transition-colors mb-8"
        >
          <ArrowLeft className="w-4 h-4" />
          Voltar
        </Link>

        <div className="bg-card border border-destructive/20 rounded-2xl p-8 shadow-lg">
          <div className="flex items-center gap-3 mb-8">
            <div className="w-12 h-12 rounded-xl bg-destructive/10 flex items-center justify-center">
              <Shield className="w-6 h-6 text-destructive" />
            </div>
            <div>
              <h2 className="font-display font-bold text-lg">Super Admin</h2>
              <p className="text-xs text-muted-foreground">Acesso Restrito</p>
            </div>
          </div>

          {emailSent ? (
            <div className="text-center space-y-4">
              <div className="w-16 h-16 rounded-full bg-green-500/10 flex items-center justify-center mx-auto">
                <CheckCircle className="w-8 h-8 text-green-500" />
              </div>
              <h1 className="font-display text-2xl font-bold">Verifique seu e-mail</h1>
              <p className="text-muted-foreground">
                Enviamos um link de acesso para <strong>{email}</strong>.
                Clique no link para entrar no painel administrativo.
              </p>
              <Button 
                variant="outline" 
                className="w-full mt-4"
                onClick={() => { setEmailSent(false); setEmail(""); }}
              >
                Usar outro e-mail
              </Button>
            </div>
          ) : (
            <>
              <h1 className="font-display text-2xl font-bold mb-2">├ürea Administrativa</h1>
              <p className="text-muted-foreground mb-4">
                Acesso exclusivo para administradores autorizados.
              </p>

              {/* Mode toggle */}
              <div className="flex gap-1 p-1 bg-muted rounded-lg mb-6">
                <button
                  type="button"
                  onClick={() => { setLoginMode("password"); setError(""); setUnauthorized(false); }}
                  className={`flex-1 py-1.5 px-3 rounded-md text-sm font-medium transition-all ${
                    loginMode === "password" ? "bg-card shadow text-foreground" : "text-muted-foreground hover:text-foreground"
                  }`}
                >
                  Email + Senha
                </button>
                <button
                  type="button"
                  onClick={() => { setLoginMode("magiclink"); setError(""); setUnauthorized(false); }}
                  className={`flex-1 py-1.5 px-3 rounded-md text-sm font-medium transition-all ${
                    loginMode === "magiclink" ? "bg-card shadow text-foreground" : "text-muted-foreground hover:text-foreground"
                  }`}
                >
                  Magic Link
                </button>
              </div>

              {unauthorized && (
                <div className="p-4 bg-destructive/10 border border-destructive/20 rounded-lg mb-4 flex items-start gap-3">
                  <AlertTriangle className="w-5 h-5 text-destructive flex-shrink-0 mt-0.5" />
                  <div>
                    <p className="font-medium text-sm">Acesso Negado</p>
                    <p className="text-xs text-muted-foreground mt-1">
                      Este e-mail n├úo est├í autorizado a acessar o painel administrativo.
                    </p>
                  </div>
                </div>
              )}


              {loginMode === "password" ? (
                <form onSubmit={handlePasswordLogin} className="space-y-4">
                  <div>
                    <Label htmlFor="email">E-mail Autorizado</Label>
                    <div className="relative mt-1">
                      <Input
                        id="email"
                        type="email"
                        placeholder="admin@salao.app"
                        value={email}
                        onChange={(e) => { setEmail(e.target.value); setUnauthorized(false); setError(""); }}
                        className={`pl-10 ${error || unauthorized ? "border-destructive" : ""}`}
                      />
                      <Mail className="w-4 h-4 text-muted-foreground absolute left-3 top-1/2 -translate-y-1/2" />
                    </div>
                    {error && <p className="text-xs text-destructive mt-1">{error}</p>}
                  </div>

                  <div>
                    <Label htmlFor="password">Senha</Label>
                    <div className="relative mt-1">
                      <Input
                        id="password"
                        type={showPassword ? "text" : "password"}
                        placeholder="ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        className="pr-10"
                      />
                      <button
                        type="button"
                        onClick={() => setShowPassword(!showPassword)}
                        className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                      >
                        {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                      </button>
                    </div>
                  </div>

                  <Button 
                    type="submit" 
                    variant="destructive" 
                    className="w-full" 
                    size="lg"
                    disabled={loading}
                  >
                    {loading && <Loader2 className="w-4 h-4 animate-spin mr-2" />}
                    Entrar
                  </Button>
                </form>
              ) : (
                <form onSubmit={handleMagicLink} className="space-y-4">
                  <div>
                    <Label htmlFor="email-magic">E-mail Autorizado</Label>
                    <div className="relative mt-1">
                      <Input
                        id="email-magic"
                        type="email"
                        placeholder="admin@salao.app"
                        value={email}
                        onChange={(e) => { setEmail(e.target.value); setUnauthorized(false); setError(""); }}
                        className={`pl-10 ${error || unauthorized ? "border-destructive" : ""}`}
                      />
                      <Mail className="w-4 h-4 text-muted-foreground absolute left-3 top-1/2 -translate-y-1/2" />
                    </div>
                    {error && <p className="text-xs text-destructive mt-1">{error}</p>}
                  </div>

                  <Button 
                    type="submit" 
                    variant="destructive" 
                    className="w-full" 
                    size="lg"
                    disabled={loading}
                  >
                    {loading && <Loader2 className="w-4 h-4 animate-spin mr-2" />}
                    Enviar Link de Acesso
                  </Button>
                </form>
              )}

              <p className="text-xs text-muted-foreground text-center mt-6">
                Login seguro via autentica├º├úo multi-fator.
              </p>
            </>
          )}
        </div>
      </div>
    </div>
  );
};

