// ============ CONTA BANC├üRIA CONTADOR ============
const ContaBancariaPage = () => {
  const { user, profile } = useAuth();
  const [bankInfo, setBankInfo] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [editing, setEditing] = useState(false);
  const [saving, setSaving] = useState(false);
  const [form, setForm] = useState({
    bank_name: "",
    agency: "",
    account: "",
    account_type: "corrente",
    cpf_cnpj: "",
    pix_key: "",
    pix_key_type: "cpf",
  });

  useEffect(() => {
    if (!user) return;
    supabase
      .from("profiles")
      .select("bank_info, pix_key, cpf_cnpj")
      .eq("user_id", user.id)
      .maybeSingle()
      .then(({ data }) => {
        if (data?.bank_info) {
          setBankInfo(data.bank_info);
          setForm({
            ...(data.bank_info as any),
            pix_key: data.pix_key || "",
            cpf_cnpj: data.cpf_cnpj || "",
          });
        } else
          setForm((f) => ({
            ...f,
            pix_key: data?.pix_key || "",
            cpf_cnpj: data?.cpf_cnpj || "",
          }));
        setLoading(false);
      });
  }, [user]);

  const handleSave = async () => {
    if (!form.cpf_cnpj || !form.pix_key) {
      toast.error("CPF/CNPJ e chave PIX s├úo obrigat├│rios.");
      return;
    }
    setSaving(true);
    const bankData = {
      bank_name: form.bank_name,
      agency: form.agency,
      account: form.account,
      account_type: form.account_type,
      pix_key_type: form.pix_key_type,
    };
    const { error } = await (supabase as any)
      .from("profiles")
      .update({
        bank_info: bankData,
        pix_key: form.pix_key,
        cpf_cnpj: form.cpf_cnpj,
      })
      .eq("user_id", user!.id);
    if (error) {
      toast.error("Erro: " + error.message);
      setSaving(false);
      return;
    }
    // Create wallet on gateway
    try {
      await supabase.functions.invoke("process-payment", {
        body: {
          action: "create-wallet",
          user_id: user!.id,
          cpf_cnpj: form.cpf_cnpj,
          name: profile?.name,
          pix_key: form.pix_key,
        },
      });
      toast.success("Conta banc├íria salva e carteira criada no gateway!");
    } catch {
      toast.success(
        "Conta banc├íria salva! Carteira ser├í criada automaticamente.",
      );
    }
    setSaving(false);
    setBankInfo(bankData);
    setEditing(false);
  };

  if (loading)
    return (
      <div className="flex justify-center py-12">
        <Loader2 className="w-8 h-8 animate-spin text-primary" />
      </div>
    );

  return (
    <div className="space-y-6">
      <h1 className="font-display text-2xl font-bold">Conta Banc├íria / PIX</h1>
      <Card className="border-primary/20 bg-primary/5">
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <CreditCard className="w-5 h-5" />
            Dados para Recebimento
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          {!editing && bankInfo ? (
            <>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                <div className="p-3 bg-muted rounded-lg">
                  <p className="text-xs text-muted-foreground">Banco</p>
                  <p className="font-medium">{bankInfo.bank_name || "-"}</p>
                </div>
                <div className="p-3 bg-muted rounded-lg">
                  <p className="text-xs text-muted-foreground">Ag├¬ncia</p>
                  <p className="font-medium">{bankInfo.agency || "-"}</p>
                </div>
                <div className="p-3 bg-muted rounded-lg">
                  <p className="text-xs text-muted-foreground">Conta</p>
                  <p className="font-medium">{bankInfo.account || "-"}</p>
                </div>
                <div className="p-3 bg-muted rounded-lg">
                  <p className="text-xs text-muted-foreground">Chave PIX</p>
                  <p className="font-medium">{form.pix_key || "-"}</p>
                </div>
              </div>
              <Button variant="gold" onClick={() => setEditing(true)}>
                Editar Dados
              </Button>
            </>
          ) : (
            <>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                <div>
                  <Label>CPF/CNPJ *</Label>
                  <Input
                    value={form.cpf_cnpj}
                    onChange={(e) =>
                      setForm({
                        ...form,
                        cpf_cnpj: formatCpfCnpjBR(e.target.value),
                      })
                    }
                    placeholder="000.000.000-00"
                    className="mt-1"
                  />
                </div>
                <div>
                  <Label>Chave PIX *</Label>
                  <Input
                    value={form.pix_key}
                    onChange={(e) =>
                      setForm({ ...form, pix_key: e.target.value })
                    }
                    placeholder="Chave PIX"
                    className="mt-1"
                  />
                </div>
                <div>
                  <Label>Banco</Label>
                  <Input
                    value={form.bank_name}
                    onChange={(e) =>
                      setForm({ ...form, bank_name: e.target.value })
                    }
                    placeholder="Nome do banco"
                    className="mt-1"
                  />
                </div>
                <div>
                  <Label>Ag├¬ncia</Label>
                  <Input
                    value={form.agency}
                    onChange={(e) =>
                      setForm({ ...form, agency: e.target.value })
                    }
                    className="mt-1"
                  />
                </div>
                <div>
                  <Label>Conta</Label>
                  <Input
                    value={form.account}
                    onChange={(e) =>
                      setForm({ ...form, account: e.target.value })
                    }
                    className="mt-1"
                  />
                </div>
              </div>
              <div className="flex gap-2">
                <Button variant="gold" onClick={handleSave} disabled={saving}>
                  {saving ? "Salvando..." : "Salvar"}
                </Button>
                {bankInfo && (
                  <Button variant="ghost" onClick={() => setEditing(false)}>
                    Cancelar
                  </Button>
                )}
              </div>
            </>
          )}
        </CardContent>
      </Card>
    </div>
  );
};

