                </label>
                <p className="font-medium">{profile?.whatsapp || "-"}</p>
              </div>
              <Button
                variant="outline"
                className="w-full"
                onClick={() => setEditing(true)}
              >
                Editar Perfil
              </Button>
            </>
          )}
        </CardContent>
      </Card>
    </div>
  );
};

