const AutomacaoFiscalContadorPage = () => {
  const { user } = useAuth();
  const [linkedBarbershops, setLinkedBarbershops] = useState<
    { id: string; name: string | null }[]
  >([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!user) return;
    (async () => {
      const { data: acc } = await (supabase as any)
        .from("accountants")
        .select("id")
        .eq("user_id", user.id)
        .maybeSingle();
      if (!acc?.id) {
        setLoading(false);
        return;
      }
      const { data: links } = await db
        .from("accountant_barbershop_links")
        .select("barbershop_id, barbershops(name)")
        .eq("accountant_id", acc.id)
        .eq("status", "active");
      const mapped = (links || []).map((r: any) => ({
        id: r.barbershop_id,
        name: r.barbershops?.name || null,
      }));
      setLinkedBarbershops(mapped);
      if (mapped[0]?.id) setSelectedId(mapped[0].id);
      setLoading(false);
    })();
  }, [user]);

  if (loading)
    return (
      <div className="flex justify-center py-12">
        <Loader2 className="w-8 h-8 animate-spin text-primary" />
      </div>
    );

  return (
    <div className="space-y-6">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <BarChart3 className="w-5 h-5" /> Automa├º├úo Fiscal
          </CardTitle>
          <CardDescription>
            Selecione uma empresa vinculada para acessar a automa├º├úo fiscal
            completa.
          </CardDescription>
        </CardHeader>
        <CardContent>
          {linkedBarbershops.length === 0 ? (
            <p className="text-muted-foreground text-sm">
              Nenhuma empresa vinculada. Crie v├¡nculos primeiro.
            </p>
          ) : (
            <div className="space-y-2">
              <Label>Empresa</Label>
              <select
                className="w-full h-10 rounded-md border border-input bg-background px-3 text-sm"
                value={selectedId || ""}
                onChange={(e) => setSelectedId(e.target.value || null)}
              >
                <option value="">Selecione...</option>
                {linkedBarbershops.map((b) => (
                  <option key={b.id} value={b.id}>
                    {b.name || b.id}
                  </option>
                ))}
              </select>
            </div>
          )}
        </CardContent>
      </Card>

      {selectedId && (
        <FiscalAutomationPanel barbershopId={selectedId} mode="accountant" />
      )}
    </div>
  );
