// ============ AGENDAMENTOS ============

const AgendamentosPage = () => {
  const { barbershop } = useBarbershop();
  const { services } = useServices(barbershop?.id);
  const { professionals } = useProfessionals(barbershop?.id);
  const { appointments, refetch } = useAppointments(barbershop?.id);
  const [showForm, setShowForm] = useState(false);
  const [saving, setSaving] = useState(false);
  const [form, setForm] = useState({
    client_name: "",
    client_whatsapp: "",
    service_id: "",
    professional_id: "",
    scheduled_at: "",
    notes: "",
  });

  const handleCreate = async () => {
    if (
      !form.client_name ||
      !form.service_id ||
      !form.professional_id ||
      !form.scheduled_at
    ) {
      toast.error("Preencha todos os campos obrigat├│rios.");
      return;
    }
    if (!barbershop) return;
    setSaving(true);
    const { error } = await (supabase as any).from("appointments").insert({
      barbershop_id: barbershop.id,
      client_name: form.client_name,
      client_whatsapp: form.client_whatsapp || null,
      service_id: form.service_id,
      professional_id: form.professional_id,
      scheduled_at: new Date(form.scheduled_at).toISOString(),
      notes: form.notes || null,
      status: "scheduled",
    });
    setSaving(false);
    if (error) {
      toast.error("Erro: " + error.message);
      return;
    }
    toast.success("Agendamento criado!");
    setShowForm(false);
    setForm({
      client_name: "",
      client_whatsapp: "",
      service_id: "",
      professional_id: "",
      scheduled_at: "",
      notes: "",
    });
    refetch();
  };

  const updateStatus = async (id: string, status: string) => {
    const { error } = await (supabase as any)
      .from("appointments")
      .update({ status })
      .eq("id", id);
    if (error) {
      toast.error("Erro: " + error.message);
      return;
    }
    toast.success(`Status: "${status}"`);
    refetch();
  };

  const statusLabel: Record<string, string> = {
    scheduled: "Agendado",
    confirmed: "Confirmado",
    completed: "Conclu├¡do",
    canceled: "Cancelado",
  };
  const statusColor: Record<string, string> = {
    scheduled: "bg-blue-500/10 text-blue-600",
    confirmed: "bg-primary/10 text-primary",
    completed: "bg-green-500/10 text-green-600",
    canceled: "bg-destructive/10 text-destructive",
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="font-display text-2xl font-bold">Agendamentos</h1>
        <Button variant="gold" onClick={() => setShowForm(!showForm)}>
          <Plus className="w-4 h-4 mr-2" />
          Novo
        </Button>
      </div>
      {showForm && (
        <Card className="border-primary/30">
          <CardHeader>
            <CardTitle>Novo Agendamento</CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <Label>Nome do Cliente *</Label>
                <Input
                  placeholder="Nome"
                  value={form.client_name}
                  onChange={(e) =>
                    setForm({ ...form, client_name: e.target.value })
                  }
                  className="mt-1"
                />
              </div>
              <div>
                <Label>WhatsApp</Label>
                <Input
                  placeholder="(11) 99999-0000"
                  value={form.client_whatsapp}
                  onChange={(e) =>
                    setForm({
                      ...form,
                      client_whatsapp: formatWhatsAppBR(e.target.value),
                    })
                  }
                  className="mt-1"
                />
              </div>
              <div>
                <Label>Servi├ºo *</Label>
                <select
                  className="w-full mt-1 h-10 rounded-md border border-input bg-background px-3 text-sm"
                  value={form.service_id}
                  onChange={(e) =>
                    setForm({ ...form, service_id: e.target.value })
                  }
                >
                  <option value="">Selecione</option>
                  {services.map((s) => (
                    <option key={s.id} value={s.id}>
                      {s.name} - R$ {Number(s.price).toFixed(2)}
                    </option>
                  ))}
                </select>
              </div>
              <div>
                <Label>Profissional *</Label>
                <select
                  className="w-full mt-1 h-10 rounded-md border border-input bg-background px-3 text-sm"
                  value={form.professional_id}
                  onChange={(e) =>
                    setForm({ ...form, professional_id: e.target.value })
                  }
                >
                  <option value="">Selecione</option>
                  {professionals.map((p) => (
                    <option key={p.id} value={p.id}>
                      {p.name}
                    </option>
                  ))}
                </select>
              </div>
              <div>
                <Label>Data e Hora *</Label>
                <Input
                  type="datetime-local"
                  value={form.scheduled_at}
