// ============ RECEBER PAGAMENTO R├üPIDO ============

const ReceberPagamentoRapido = ({ barbershopId }: { barbershopId: string }) => {
  const [open, setOpen] = useState(false);
  const [valor, setValor] = useState("");
  const [descricao, setDescricao] = useState("");
  const [loading, setLoading] = useState(false);
  const [pixData, setPixData] = useState<{
    qr_code?: string;
    copy_paste?: string;
    payment_link?: string;
    payment_id?: string;
  } | null>(null);
  const [nfcSupported] = useState(() => isPaymentRequestSupported());
  const [nfcLoading, setNfcLoading] = useState(false);

  // Vincular a devedor
  const [vincularDevedor, setVincularDevedor] = useState(false);
  const [devedorSelecionado, setDevedorSelecionado] = useState<string>("");
  const [devedores, setDevedores] = useState<any[]>([]);

  useEffect(() => {
    if (open && barbershopId) {
      supabase
        .from("debts")
        .select("*")
        .eq("barbershop_id", barbershopId)
        .eq("status", "pending")
        .order("client_name")
        .then(({ data }) => setDevedores(data || []));
    }
  }, [open, barbershopId]);

  const handleGerar = async () => {
    const amount = Number(valor);
    if (!amount || amount <= 0) {
      toast.error("Informe um valor v├ílido.");
      return;
    }
    setLoading(true);
    setPixData(null);

    const devedorInfo =
      vincularDevedor && devedorSelecionado
        ? devedores.find((d) => d.id === devedorSelecionado)
        : null;

    try {
      const { data, error } = await supabase.functions.invoke(
        "process-payment",
        {
          body: {
            action: "charge",
            amount,
            description: devedorInfo
              ? `Pagamento d├¡vida: ${devedorInfo.client_name}`
              : descricao || "Recebimento r├ípido",
            billing_type: "PIX",
            external_reference:
              devedorInfo?.id || `quick-${barbershopId}-${Date.now()}`,
          },
        },
      );
      if (error) throw error;
      setPixData({
        qr_code: data?.pix_qr_code || data?.qrCode,
        copy_paste: data?.pix_copy_paste || data?.copyPaste,
        payment_link: data?.payment_link || data?.invoiceUrl,
        payment_id: data?.payment_id,
      });
      toast.success("Cobran├ºa gerada com sucesso!");
    } catch {
      toast.error("Erro ao gerar cobran├ºa. Tente novamente.");
    } finally {
      setLoading(false);
    }
  };

  const handleCopy = (text: string) => {
    navigator.clipboard?.writeText(text);
    toast.success("Copiado para a ├írea de transfer├¬ncia!");
  };

  const handleMarcarPago = async () => {
    if (!vincularDevedor || !devedorSelecionado) return;

    const devedorInfo = devedores.find((d) => d.id === devedorSelecionado);
    const valorPago = Number(valor);
    const valorDivida = Number(devedorInfo?.amount || 0);

    try {
      if (valorPago >= valorDivida) {
        // Paga toda a d├¡vida
        await (supabase as any)
          .from("debts")
          .update({
            status: "paid",
            paid_at: new Date().toISOString(),
          })
          .eq("id", devedorSelecionado);
        toast.success(`D├¡vida de ${devedorInfo.client_name} quitada!`);
      } else {
        // Abate parcial
        const novoValor = valorDivida - valorPago;
        await (supabase as any)
          .from("debts")
          .update({
            amount: novoValor,
            description: `${devedorInfo.description || "Fiado"} (abatido R$ ${valorPago.toFixed(2)})`,
          })
          .eq("id", devedorSelecionado);
        toast.success(
          `Abatido R$ ${valorPago.toFixed(2)} da d├¡vida de ${devedorInfo.client_name}. Restante: R$ ${novoValor.toFixed(2)}`,
        );
      }

      // Reset
      setPixData(null);
      setValor("");
      setDescricao("");
      setVincularDevedor(false);
      setDevedorSelecionado("");
      setOpen(false);
    } catch {
      toast.error("Erro ao marcar como pago.");
    }
  };

  return (
    <div className="space-y-6">
      <h1 className="font-display text-2xl font-bold">Financeiro</h1>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <Card className="bg-gradient-card border-primary/20">
          <CardHeader>
            <CardDescription>Recebido</CardDescription>
            <CardTitle className="text-3xl text-gradient-gold">
              R$ {totalReceived.toFixed(2)}
            </CardTitle>
          </CardHeader>
          <CardContent>
            <Button
              variant="gold"
              size="sm"
              className="w-full"
              onClick={() => toast.info("Saque via PIX em breve!")}
            >
              Sacar via PIX
            </Button>
          </CardContent>
        </Card>
        <Card>
          <CardHeader>
            <CardDescription>Pendente</CardDescription>
            <CardTitle className="text-2xl">
              R$ {totalPending.toFixed(2)}
            </CardTitle>
          </CardHeader>
        </Card>
        <Card>
          <CardHeader>
            <CardDescription>Faturamento do M├¬s</CardDescription>
            <CardTitle className="text-2xl">
              R$ {(totalReceived + totalPending).toFixed(2)}
            </CardTitle>
          </CardHeader>
        </Card>
      </div>

      {/* REPASSE DE COMISS├òES */}
      <Card className="border-secondary/20">
        <CardHeader>
          <div className="flex items-center justify-between">
            <div>
              <CardTitle className="flex items-center gap-2">
                <Repeat className="w-5 h-5" />
                Repasse de Comiss├Áes
              </CardTitle>
              <CardDescription>
                Repasse autom├ítico ou manual para profissionais
              </CardDescription>
            </div>
            <Button
              variant={showPayout ? "outline" : "gold"}
              size="sm"
              onClick={() => setShowPayout(!showPayout)}
            >
              {showPayout ? "Fechar" : "Gerenciar Repasses"}
            </Button>
          </div>
        </CardHeader>
        {showPayout && (
          <CardContent className="space-y-4">
            <div className="flex gap-2 mb-4">
              <Button
                variant={payoutMode === "manual" ? "gold" : "outline"}
                size="sm"
                onClick={() => setPayoutMode("manual")}
              >
