const AcaoEntreAmigosPage = () => {
  const { barbershop } = useBarbershop();
  const [raffles, setRaffles] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAdd, setShowAdd] = useState(false);
  const [form, setForm] = useState({
    name: "",
    description: "",
    ticket_price: "10",
    credit_award: "50",
    max_tickets: "100",
    image_url: "",
  });
  const [uploadingImg, setUploadingImg] = useState(false);
  const raffleFileRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (barbershop?.id) {
      supabase
        .from("raffles")
        .select("*")
        .eq("barbershop_id", barbershop.id)
        .order("created_at", { ascending: false })
        .then(({ data }) => {
          setRaffles(data || []);
          setLoading(false);
        });
    }
  }, [barbershop?.id]);

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setUploadingImg(true);
    const url = await uploadImage(file, "raffles", barbershop?.id?.slice(0, 8));
    setUploadingImg(false);
    if (url) setForm((f) => ({ ...f, image_url: url }));
    else toast.error("Erro ao enviar imagem.");
  };

  const handleCreate = async () => {
    if (!form.name || !barbershop?.id) return toast.error("Preencha o nome");
    const { data, error } = await (supabase as any)
      .from("raffles")
      .insert([
        {
          barbershop_id: barbershop.id,
          name: form.name,
          description: form.description,
          ticket_price: Number(form.ticket_price),
          credit_award: Number(form.credit_award),
          max_tickets: Number(form.max_tickets),
          image_url: form.image_url || null,
        },
      ])
      .select();
    if (error) toast.error(error.message);
    else {
      setRaffles([...(data as any[]), ...raffles]);
      setShowAdd(false);
      setForm({ ...form, image_url: "" });
      toast.success("A├º├úo entre Amigos criada!");
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h1 className="font-display text-2xl font-bold">A├º├úo entre Amigos</h1>
