                      else
                        toast.info(`${data?.length || 0} bilhetes vendidos.`);
                    }}
                  >
                    Bilhetes
                  </Button>
                  <Button
                    variant="destructive"
                    size="sm"
                    disabled={r.status !== "open"}
                    onClick={async () => {
                      if (
                        !confirm(
                          "Deseja realizar o sorteio agora? O pr├¬mio ser├í creditado automaticamente.",
                        )
                      )
                        return;
                      const { data, error } = await (supabase as any).rpc(
                        "draw_raffle_winner",
                        { _raffle_id: r.id },
                      );
                      if (error) toast.error(error.message);
                      else
                        toast.success(
                          `Sorteio realizado! Vencedor: ${data.winner_name}`,
                        );
                      setRaffles((current) =>
                        current.map((item) =>
                          item.id === r.id
                            ? { ...item, status: "closed" }
                            : item,
                        ),
                      );
                    }}
                  >
                    Sortear
                  </Button>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </div>
  );
};

// ============ PIXELS ============

const PixelsPage = () => {
  const { barbershop } = useBarbershop();
  const [configs, setConfigs] = useState<any[]>([]);
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState({ platform: "meta", pixel_id: "" });
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    if (!barbershop?.id) return;
    supabase
      .from("pixel_configurations")
      .select("*")
      .eq("barbershop_id", barbershop.id)
      .then(({ data }) => setConfigs(data || []));
  }, [barbershop?.id]);

  const handleSave = async () => {
    if (!form.pixel_id || !barbershop?.id) {
      toast.error("Preencha o ID do pixel.");
      return;
    }
    setSaving(true);
    const { error } = await (supabase as any).from("pixel_configurations").insert({
      barbershop_id: barbershop.id,
      platform: form.platform,
      pixel_id: form.pixel_id,
      events: ["signup", "booking_created", "booking_paid"],
      is_active: true,
    });
    setSaving(false);
    if (error) {
      toast.error("Erro: " + error.message);
      return;
    }
    toast.success("Pixel configurado!");
    setShowForm(false);
    setForm({ platform: "meta", pixel_id: "" });
    supabase
      .from("pixel_configurations")
      .select("*")
      .eq("barbershop_id", barbershop.id)
      .then(({ data }) => setConfigs(data || []));
  };

  const togglePixel = async (id: string, active: boolean) => {
    await (supabase as any)
      .from("pixel_configurations")
      .update({ is_active: !active })
      .eq("id", id);
    supabase
      .from("pixel_configurations")
      .select("*")
      .eq("barbershop_id", barbershop?.id)
      .then(({ data }) => setConfigs(data || []));
    toast.success(active ? "Pixel desativado" : "Pixel ativado");
  };

  const platforms = [
    {
      key: "meta",
      name: "Meta Pixel",
      icon: "­ƒôÿ",
      desc: "Facebook e Instagram",
    },
    {
      key: "google",
      name: "Google Ads",
      icon: "­ƒöì",
      desc: "Google Tag Manager",
    },
    { key: "tiktok", name: "TikTok Pixel", icon: "­ƒÄÁ", desc: "TikTok Ads" },
    {
      key: "ga4",
      name: "Google Analytics 4",
      icon: "­ƒôè",
      desc: "GA4 Measurement ID",
    },
  ];

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="font-display text-2xl font-bold">Pixels & Marketing</h1>
        <Button variant="gold" onClick={() => setShowForm(!showForm)}>
          <Plus className="w-4 h-4 mr-2" />
          Adicionar Pixel
        </Button>
      </div>

      {showForm && (
        <Card className="border-primary/30">
          <CardHeader>
            <CardTitle>Novo Pixel</CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <div>
              <Label>Plataforma</Label>
              <select
                className="w-full mt-1 h-10 rounded-md border border-input bg-background px-3 text-sm"
                value={form.platform}
                onChange={(e) => setForm({ ...form, platform: e.target.value })}
              >
                {platforms.map((p) => (
                  <option key={p.key} value={p.key}>
                    {p.name}
                  </option>
                ))}
              </select>
            </div>
            <div>
              <Label>ID do Pixel *</Label>
              <Input
                placeholder="Ex: 123456789"
                value={form.pixel_id}
                onChange={(e) => setForm({ ...form, pixel_id: e.target.value })}
                className="mt-1"
              />
            </div>
            <div className="flex gap-2">
              <Button variant="gold" onClick={handleSave} disabled={saving}>
                {saving ? "Salvando..." : "Salvar"}
              </Button>
              <Button variant="outline" onClick={() => setShowForm(false)}>
                Cancelar
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      {configs.length > 0 && (
        <div className="space-y-3">
          {configs.map((c) => {
            const plat = platforms.find((p) => p.key === c.platform);
            return (
              <Card key={c.id}>
                <CardContent className="p-4 flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <span className="text-2xl">{plat?.icon || "­ƒôª"}</span>
                    <div>
                      <p className="font-semibold">
                        {plat?.name || c.platform}
                      </p>
                      <p className="text-sm text-muted-foreground">
                        ID: {c.pixel_id}
                      </p>
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <Switch
                      checked={c.is_active}
                      onCheckedChange={() => togglePixel(c.id, c.is_active)}
                    />
                    <span
                      className={`text-xs ${c.is_active ? "text-green-600" : "text-muted-foreground"}`}
                    >
                      {c.is_active ? "Ativo" : "Inativo"}
                    </span>
                  </div>
                </CardContent>
              </Card>
            );
          })}
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {platforms
          .filter((p) => !configs.some((c) => c.platform === p.key))
          .map((p) => (
            <Card key={p.key}>
              <CardHeader>
                <div className="text-2xl mb-1">{p.icon}</div>
                <CardTitle className="text-lg">{p.name}</CardTitle>
                <CardDescription>{p.desc}</CardDescription>
              </CardHeader>
              <CardContent>
                <Button
                  variant="outline"
                  className="w-full"
                  onClick={() => {
                    setForm({ platform: p.key, pixel_id: "" });
                    setShowForm(true);
                  }}
                >
                  Configurar
                </Button>
              </CardContent>
            </Card>
          ))}
      </div>
    </div>
  );
};

// ============ SUPORTE (chat real) ============

const SuportePage = () => {
  const { user } = useAuth();
  const [chats, setChats] = useState<any[]>([]);
  const [activeChat, setActiveChat] = useState<any>(null);
  const [messages, setMessages] = useState<any[]>([]);
  const [newMsg, setNewMsg] = useState("");
  const [sending, setSending] = useState(false);

  useEffect(() => {
    if (!user) return;
    supabase
      .from("support_chats")
      .select("*")
      .eq("user_id", user.id)
      .order("updated_at", { ascending: false })
      .then(({ data }) => {
        setChats(data || []);
        if (data && data.length > 0) {
          setActiveChat(data[0]);
          loadMessages(data[0].id);
        }
      });
  }, [user]);

  const loadMessages = async (chatId: string) => {
    const { data } = await (supabase as any)
      .from("support_messages")
      .select("*")
      .eq("chat_id", chatId)
      .order("created_at", { ascending: true });
    setMessages(data || []);
  };

  const startNewChat = async () => {
    if (!user) return;
    const { data, error } = await (supabase as any)
      .from("support_chats")
      .insert({ user_id: user.id })
      .select()
      .single();
    if (error) {
      toast.error("Erro ao iniciar chat.");
      return;
    }
    setActiveChat(data);
    setChats([data, ...chats]);
    setMessages([]);
  };

  const sendMessage = async () => {
    if (!newMsg.trim() || !activeChat || !user) return;
    setSending(true);
    const { error } = await (supabase as any).from("support_messages").insert({
      chat_id: activeChat.id,
      sender_id: user.id,
      message: newMsg.trim(),
      is_from_support: false,
    });
    setSending(false);
    if (error) {
      toast.error("Erro ao enviar.");
      return;
    }
    setNewMsg("");
    loadMessages(activeChat.id);
  };

  return (
    <div className="space-y-6">
      <h1 className="font-display text-2xl font-bold">Suporte</h1>
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <div>
              <CardTitle>Chat com Suporte</CardTitle>
              <CardDescription>
                Envie suas d├║vidas e receba ajuda
              </CardDescription>
            </div>
            <Button variant="gold" size="sm" onClick={startNewChat}>
              Novo Chat
            </Button>
          </div>
        </CardHeader>
        <CardContent className="space-y-4">
          {chats.length === 0 ? (
            <p className="text-sm text-muted-foreground text-center py-8">
              Nenhum chat iniciado. Clique em "Novo Chat" para come├ºar.
            </p>
          ) : (
            <>
              <div className="flex gap-2 overflow-x-auto pb-2">
                {chats.map((chat) => (
                  <Button
                    key={chat.id}
                    variant={activeChat?.id === chat.id ? "gold" : "outline"}
                    size="sm"
                    onClick={() => {
                      setActiveChat(chat);
                      loadMessages(chat.id);
                    }}
                  >
                    Chat #{chat.id.slice(0, 6)}
                  </Button>
                ))}
              </div>
              {activeChat && (
                <>
                  <div className="border rounded-lg p-4 h-64 overflow-y-auto space-y-2">
                    {messages.map((msg) => (
                      <div
                        key={msg.id}
                        className={`p-2 rounded-lg max-w-[80%] ${msg.is_from_support ? "bg-primary/10 mr-auto" : "bg-muted ml-auto"}`}
                      >
                        <p className="text-sm">{msg.message}</p>
                        <p className="text-[10px] text-muted-foreground mt-1">
                          {new Date(msg.created_at).toLocaleString("pt-BR")}
                        </p>
                      </div>
                    ))}
                  </div>
                  <div className="flex gap-2">
                    <Input
                      placeholder="Digite sua mensagem..."
                      value={newMsg}
                      onChange={(e) => setNewMsg(e.target.value)}
                      onKeyDown={(e) => e.key === "Enter" && sendMessage()}
                    />
                    <Button
                      variant="gold"
                      onClick={sendMessage}
                      disabled={sending}
                    >
                      Enviar
                    </Button>
                  </div>
                </>
              )}
            </>
          )}
        </CardContent>
      </Card>
    </div>
  );
};

