// ============ SUPORTE ADMIN ============
const SuporteAdminPage = () => {
  const { user } = useAuth();
  const [chats, setChats] = useState<any[]>([]);
  const [activeChat, setActiveChat] = useState<any>(null);
  const [messages, setMessages] = useState<any[]>([]);
  const [newMsg, setNewMsg] = useState("");
  const [sending, setSending] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    supabase
      .from("support_chats")
      .select("*, profiles:user_id(name, email, whatsapp)")
      .order("updated_at", { ascending: false })
      .then(({ data }) => {
        setChats(data || []);
        setLoading(false);
      });
  }, []);

  const loadMessages = async (chatId: string) => {
    const { data } = await (supabase as any)
      .from("support_messages")
      .select("*")
      .eq("chat_id", chatId)
      .order("created_at", { ascending: true });
    setMessages(data || []);
  };

  const selectChat = (chat: any) => {
    setActiveChat(chat);
    loadMessages(chat.id);
  };

  const sendMessage = async () => {
    if (!newMsg.trim() || !activeChat || !user) return;
    setSending(true);
    const { error } = await (supabase as any)
      .from("support_messages")
      .insert({
        chat_id: activeChat.id,
        sender_id: user.id,
        message: newMsg.trim(),
        is_from_support: true,
      });
    setSending(false);
    if (error) {
      toast.error("Erro: " + error.message);
      return;
    }
    setNewMsg("");
    loadMessages(activeChat.id);
  };

  const updateStatus = async (chatId: string, status: string) => {
    await (supabase as any)
      .from("support_chats")
      .update({ status, assigned_to: user?.id })
      .eq("id", chatId);
    toast.success(`Chat ${status}`);
    supabase
      .from("support_chats")
      .select("*, profiles:user_id(name, email, whatsapp)")
      .order("updated_at", { ascending: false })
      .then(({ data }) => setChats(data || []));
  };

  return (
    <div className="space-y-6">
      <h1 className="font-display text-2xl font-bold">Suporte - Atendimento</h1>
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="space-y-2">
          <h2 className="font-semibold text-sm text-muted-foreground uppercase">
            Chamados ({chats.length})
          </h2>
          {loading ? (
            <Loader2 className="w-6 h-6 animate-spin mx-auto" />
          ) : chats.length === 0 ? (
            <Card>
              <CardContent className="py-8 text-center text-muted-foreground text-sm">
                Nenhum chamado.
              </CardContent>
            </Card>
          ) : (
            chats.map((c) => (
              <Card
                key={c.id}
                className={`cursor-pointer hover:border-primary transition-colors ${activeChat?.id === c.id ? "border-primary bg-primary/5" : ""}`}
                onClick={() => selectChat(c)}
              >
                <CardContent className="p-3">
                  <div className="flex justify-between items-center">
                    <div>
                      <p className="font-medium text-sm">
                        {(c as any).profiles?.name || "Usu├írio"}
                      </p>
                      <p className="text-xs text-muted-foreground">
                        {(c as any).profiles?.whatsapp ||
                          (c as any).profiles?.email ||
                          ""}
                      </p>
                    </div>
                    <span
                      className={`text-[10px] px-2 py-0.5 rounded-full ${c.status === "open" ? "bg-destructive/10 text-destructive" : c.status === "in_progress" ? "bg-primary/10 text-primary" : "bg-success/10 text-success"}`}
                    >
                      {c.status === "open"
                        ? "Aberto"
                        : c.status === "in_progress"
                          ? "Em Atendimento"
                          : "Fechado"}
                    </span>
                  </div>
                </CardContent>
              </Card>
            ))
          )}
        </div>
        <div className="lg:col-span-2">
          {!activeChat ? (
            <Card>
              <CardContent className="py-12 text-center">
                <MessageCircle className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
                <p className="text-muted-foreground">Selecione um chat.</p>
              </CardContent>
            </Card>
          ) : (
            <Card>
              <CardHeader className="border-b py-3">
                <div className="flex items-center justify-between">
                  <div>
                    <CardTitle className="text-sm">
                      {(activeChat as any).profiles?.name}
                    </CardTitle>
                    <CardDescription className="text-xs">
                      {(activeChat as any).profiles?.whatsapp ||
                        (activeChat as any).profiles?.email}
                    </CardDescription>
                  </div>
                  <div className="flex gap-2">
                    {activeChat.status === "open" && (
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() =>
                          updateStatus(activeChat.id, "in_progress")
                        }
                      >
                        Assumir
                      </Button>
                    )}
                    {activeChat.status !== "closed" && (
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => updateStatus(activeChat.id, "closed")}
                      >
                        Fechar
                      </Button>
                    )}
                  </div>
                </div>
              </CardHeader>
              <CardContent className="p-0">
                <div className="h-80 overflow-y-auto p-4 space-y-3">
                  {messages.length === 0 ? (
                    <p className="text-center text-sm text-muted-foreground py-8">
                      Nenhuma mensagem.
                    </p>
                  ) : (
                    messages.map((m) => (
                      <div
                        key={m.id}
                        className={`flex ${m.is_from_support ? "justify-end" : "justify-start"}`}
                      >
                        <div
                          className={`max-w-[70%] rounded-lg px-3 py-2 text-sm ${m.is_from_support ? "bg-secondary text-secondary-foreground" : "bg-muted text-foreground"}`}
                        >
                          {m.message}
                          <p className="text-[10px] opacity-60 mt-1">
                            {new Date(m.created_at).toLocaleTimeString(
                              "pt-BR",
                              { hour: "2-digit", minute: "2-digit" },
                            )}
                          </p>
                        </div>
                      </div>
                    ))
                  )}
                </div>
                <div className="p-4 border-t flex gap-2">
                  <Input
                    placeholder="Responder..."
                    value={newMsg}
                    onChange={(e) => setNewMsg(e.target.value)}
                    onKeyDown={(e) => e.key === "Enter" && sendMessage()}
                  />
                  <Button
                    variant="gold"
                    onClick={sendMessage}
                    disabled={sending}
                  >
                    Enviar
                  </Button>
                </div>
              </CardContent>
            </Card>
          )}
        </div>
      </div>
    </div>
  );
};

// ============ NOTIFICA├ç├òES ADMIN ============
const NotificacoesAdminPage = () => {
  const [target, setTarget] = useState<
    "all" | "donos" | "profissionais" | "clientes"
  >("all");
  const [title, setTitle] = useState("");
  const [message, setMessage] = useState("");
  const [sending, setSending] = useState(false);
  const [channel, setChannel] = useState<"app" | "sms" | "whatsapp">("app");

  const handleSend = async () => {
    if (!title || !message) {
      toast.error("Preencha t├¡tulo e mensagem.");
      return;
    }
    setSending(true);
    let roleFilter: string | null = null;
    if (target === "donos") roleFilter = "dono";
    else if (target === "profissionais") roleFilter = "profissional";
    else if (target === "clientes") roleFilter = "cliente";

    let userIds: string[] = [];
    if (roleFilter) {
      const { data } = await (supabase as any)
        .from("user_roles")
        .select("user_id")
        .eq("role", roleFilter as any);
      userIds = data?.map((r) => r.user_id) || [];
    } else {
      const { data } = await (supabase as any).from("profiles").select("user_id");
      userIds = data?.map((r) => r.user_id) || [];
    }

    if (userIds.length === 0) {
      toast.error("Nenhum usu├írio encontrado.");
      setSending(false);
      return;
    }

    const notifications = userIds.map((uid) => ({
      user_id: uid,
      title,
      message,
      type: "info" as const,
      priority: "normal" as const,
    }));
    await (supabase as any).from("notifications").insert(notifications);

    if (channel === "sms" || channel === "whatsapp") {
      const { data: profiles } = await (supabase as any)
        .from("profiles")
        .select("whatsapp")
        .in("user_id", userIds);
      const phones = profiles?.map((p) => p.whatsapp).filter(Boolean) || [];
      let sent = 0;
      for (const phone of phones) {
        try {
          await supabase.functions.invoke("send-sms", {
            body: {
              action: channel === "whatsapp" ? "whatsapp" : "sms",
              to: phone,
              body: `${title}: ${message}`,
            },
          });
          sent++;
        } catch {}
      }
      toast.success(
        `${sent} ${channel.toUpperCase()} + ${userIds.length} notifica├º├Áes!`,
      );
    } else {
      toast.success(`Notifica├º├úo para ${userIds.length} usu├írio(s)!`);
    }
    setSending(false);
    setTitle("");
    setMessage("");
  };

  return (
    <div className="space-y-6">
      <h1 className="font-display text-2xl font-bold">Enviar Notifica├º├úo</h1>
      <Card>
        <CardHeader>
          <CardTitle>Destinat├írios</CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex flex-wrap gap-2">
            {(["all", "donos", "profissionais", "clientes"] as const).map(
              (t) => (
                <Button
                  key={t}
                  variant={target === t ? "gold" : "outline"}
                  size="sm"
                  onClick={() => setTarget(t)}
                >
                  {t === "all"
                    ? "Todos"
                    : t === "donos"
                      ? "Donos"
                      : t === "profissionais"
                        ? "Profissionais"
                        : "Clientes"}
                </Button>
              ),
            )}
          </div>
          <div>
            <Label>Canal</Label>
            <div className="flex flex-wrap gap-2 mt-1">
              {[
                { key: "app" as const, label: "­ƒô▒ App" },
                { key: "sms" as const, label: "­ƒÆ¼ SMS" },
                { key: "whatsapp" as const, label: "­ƒô▓ WhatsApp" },
              ].map((c) => (
                <Button
                  key={c.key}
                  variant={channel === c.key ? "gold" : "outline"}
                  size="sm"
                  onClick={() => setChannel(c.key)}
                >
                  {c.label}
                </Button>
              ))}
            </div>
          </div>
          <div>
            <Label>T├¡tulo *</Label>
            <Input
              placeholder="T├¡tulo"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              className="mt-1"
            />
          </div>
          <div>
            <Label>Mensagem *</Label>
            <Input
              placeholder="Mensagem..."
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              className="mt-1"
            />
          </div>
          <Button variant="gold" onClick={handleSend} disabled={sending}>
            <Send className="w-4 h-4 mr-2" />
            {sending ? "Enviando..." : "Enviar"}
          </Button>
        </CardContent>
      </Card>
    </div>
  );
};

