// N├¡veis de afiliados baseados em indica├º├Áes
const AFFILIATE_LEVELS = [
  { min: 0,    max: 50,   label: "Explorador",            color: "bg-slate-100 text-slate-700" },
  { min: 51,   max: 100,  label: "Vision├írio",            color: "bg-blue-100 text-blue-700" },
  { min: 101,  max: 200,  label: "Estrategista Vision├írio", color: "bg-purple-100 text-purple-700" },
  { min: 201,  max: 400,  label: "L├¡der Supremo",         color: "bg-orange-100 text-orange-700" },
  { min: 401,  max: 700,  label: "Imperador L├¡der",       color: "bg-red-100 text-red-700" },
  { min: 701,  max: 1000, label: "S├│cio PLM",             color: "bg-yellow-100 text-yellow-800" },
];

function getAffiliateLevel(totalReferrals: number) {
  return AFFILIATE_LEVELS.find(l => totalReferrals >= l.min && totalReferrals <= l.max) || AFFILIATE_LEVELS[0];
}

const AfiliadosPage = () => {
  const { user } = useAuth();
  const [affiliates, setAffiliates] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [editingAffiliate, setEditingAffiliate] = useState<any>(null);
  const [commissions, setCommissions] = useState({
    first: 60,
    recurring: 20,
    saas_tax: 10,
  });
  const [inviteLink, setInviteLink] = useState("");
  const [creating, setCreating] = useState(false);

  useEffect(() => {
    supabase
      .from("affiliates")
      .select("*, profiles:user_id(name, email)")
      .then(({ data }) => {
        setAffiliates(data || []);
        setLoading(false);
      });
  }, []);

  const generateInviteLink = async () => {
    setCreating(true);
    const { data, error } = await (supabase as any)
      .from("affiliate_invites" as any)
      .insert([
        {
          affiliate_type: "afiliado_saas",
          commission_first: commissions.first,
          commission_recurring: commissions.recurring,
          commission_saas_tax: commissions.saas_tax,
          created_by: user?.id,
        },
      ])
      .select()
      .single();
    setCreating(false);
    if (error) {
      toast.error(error.message);
      return;
    }
    const code = (data as any).invite_code;
    const link = `${window.location.origin}/cadastro?ref=${code}&type=afiliado`;
    setInviteLink(link);
    toast.success("Link de convite gerado!");
  };

  const copyLink = () => {
    navigator.clipboard.writeText(inviteLink);
    toast.success("Link copiado!");
  };

  const saveCommission = async () => {
    if (!editingAffiliate) return;
    const { error } = await (supabase as any)
      .from("affiliates")
      .update({
        commission_first: commissions.first,
        commission_recurring: commissions.recurring,
        commission_saas_tax: commissions.saas_tax,
      })
      .eq("id", editingAffiliate.id);
    if (error) toast.error(error.message);
    else {
      toast.success("Comiss├úo atualizada!");
      setAffiliates(
        affiliates.map((a) =>
          a.id === editingAffiliate.id ? { ...a, ...commissions } : a,
        ),
      );
      setEditingAffiliate(null);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center flex-wrap gap-2">
        <h1 className="font-display text-2xl font-bold">Afiliados</h1>
        <Button variant="gold" onClick={generateInviteLink} disabled={creating}>
          <LinkIcon className="w-4 h-4 mr-2" />
          {creating ? "..." : "Gerar Link de Convite"}
        </Button>
      </div>

      {inviteLink && (
        <Card className="border-primary/20 bg-primary/5">
          <CardContent className="p-4">
            <Label className="text-sm font-medium">
              Link de Convite de Afiliado
            </Label>
            <div className="flex gap-2 mt-2">
              <Input value={inviteLink} readOnly className="text-xs" />
              <Button variant="outline" size="sm" onClick={copyLink}>
                <Copy className="w-4 h-4" />
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      {editingAffiliate && (
        <Card className="border-primary/20 bg-primary/5">
          <CardHeader>
            <CardTitle className="text-sm">
              Editar Comiss├úo: {(editingAffiliate as any).profiles?.name}
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-3">
            <div className="grid grid-cols-3 gap-3">
              <div>
                <Label className="text-xs">1┬¬ Mensalidade (%)</Label>
                <Input
                  type="number"
                  value={commissions.first}
                  onChange={(e) =>
                    setCommissions({ ...commissions, first: +e.target.value })
                  }
                />
              </div>
              <div>
                <Label className="text-xs">Recorrente (%)</Label>
                <Input
                  type="number"
                  value={commissions.recurring}
                  onChange={(e) =>
                    setCommissions({
                      ...commissions,
                      recurring: +e.target.value,
                    })
                  }
                />
              </div>
              <div>
                <Label className="text-xs">Taxa SaaS (%)</Label>
                <Input
                  type="number"
                  value={commissions.saas_tax}
                  onChange={(e) =>
                    setCommissions({
                      ...commissions,
                      saas_tax: +e.target.value,
                    })
                  }
                />
              </div>
            </div>
            <div className="flex gap-2">
              <Button variant="gold" onClick={saveCommission}>
                Salvar
              </Button>
              <Button variant="ghost" onClick={() => setEditingAffiliate(null)}>
                Cancelar
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      {loading ? (
        <Loader2 className="w-6 h-6 animate-spin mx-auto" />
      ) : affiliates.length === 0 ? (
        <Card>
          <CardContent className="py-12 text-center">
            <Users className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
            <p className="text-muted-foreground">Nenhum afiliado.</p>
          </CardContent>
        </Card>
      ) : (
        affiliates.map((a) => (
          <Card key={a.id}>
            <CardContent className="p-4 flex items-center gap-4">
              <Users className="w-5 h-5 text-primary" />
              <div className="flex-1">
                <p className="font-semibold">
                  {(a as any).profiles?.name || "Afiliado"}
                </p>
                <p className="text-sm text-muted-foreground">
                  C├│digo: {a.referral_code} ÔÇó {a.commission_first}% /{" "}
                  {a.commission_recurring}% / {a.commission_saas_tax}%
                </p>
              </div>
              <span className={`text-xs px-2 py-1 rounded-full font-medium ${getAffiliateLevel(a.total_referrals || 0).color}`}>
                {getAffiliateLevel(a.total_referrals || 0).label}
              </span>
              <span className="text-xs bg-success/10 text-success px-2 py-1 rounded-full">
                {a.type}
              </span>
              <Button
                variant="outline"
                size="sm"
                onClick={() => {
                  setEditingAffiliate(a);
                  setCommissions({
                    first: a.commission_first || 60,
                    recurring: a.commission_recurring || 20,
                    saas_tax: a.commission_saas_tax || 10,
                  });
                }}
              >
                <Edit className="w-4 h-4 mr-1" />
                Comiss├úo
              </Button>
              <Button
                variant={a.blocked ? "destructive" : "outline"}
                size="sm"
                onClick={async () => {
                  const newBlocked = !a.blocked;
                  const { error } = await (supabase as any)
                    .from("affiliates")
                    .update({ blocked: newBlocked } as any)
                    .eq("id", a.id);
                  if (error) toast.error(error.message);
                  else {
                    toast.success(newBlocked ? "Afiliado bloqueado" : "Afiliado desbloqueado");
                    setAffiliates(affiliates.map(af => af.id === a.id ? { ...af, blocked: newBlocked } : af));
                  }
                }}
              >
                {a.blocked ? <><ShieldOff className="w-4 h-4 mr-1" />Desbloquear</> : <><Shield className="w-4 h-4 mr-1" />Bloquear</>}
              </Button>
            </CardContent>
          </Card>
        ))
      )}
    </div>
  );
};

