// ============ SERVI├çOS CONT├üBEIS (aprovar altera├º├Áes do contador) ============
const ServicosContabeisAdminPage = () => {
  const { user } = useAuth();
  type FiscalServiceType = {
    id: string;
    service_type: string;
    label: string;
    description: string | null;
    price: number;
    required_fields: unknown;
    status: "pending" | "approved" | "rejected";
    proposed_price: number | null;
    proposed_required_fields: unknown;
    proposed_description: string | null;
  };
  const [services, setServices] = useState<FiscalServiceType[]>([]);
  const [loading, setLoading] = useState(true);

  const fetchServices = () => {
    supabase
      .from("fiscal_service_types")
      .select("*")
      .order("service_type")
      .then(({ data }) => {
        setServices((data || []) as unknown as FiscalServiceType[]);
        setLoading(false);
      });
  };

  useEffect(() => {
    fetchServices();
  }, []);

  const approveOrReject = async (id: string, approved: boolean) => {
    const s = services.find((x) => x.id === id);
    if (!s || s.status !== "pending") return;
    const update = approved
      ? {
          status: "approved",
          price: s.proposed_price,
          required_fields: s.proposed_required_fields || s.required_fields,
          description: s.proposed_description ?? s.description ?? null,
          approved_by: user?.id,
          approved_at: new Date().toISOString(),
          proposed_price: null,
          proposed_required_fields: null,
          proposed_description: null,
          proposed_by: null,
          proposed_at: null,
          updated_at: new Date().toISOString(),
        }
      : {
          status: "rejected",
          proposed_price: null,
          proposed_required_fields: null,
          proposed_by: null,
          proposed_at: null,
          updated_at: new Date().toISOString(),
        };
    const { error } = await (supabase as any)
      .from("fiscal_service_types")
      .update(update as any)
      .eq("id", id);
    if (error) {
      toast.error(error.message);
      return;
    }
    toast.success(
      approved
        ? "Altera├º├úo aprovada e dispon├¡vel para usu├írios."
        : "Altera├º├úo rejeitada.",
    );
    fetchServices();
  };

  const pending = services.filter((s) => s.status === "pending");

  return (
    <div className="space-y-6">
      <h1 className="font-display text-2xl font-bold">Servi├ºos Cont├íbeis</h1>
      <p className="text-muted-foreground text-sm">
        Aprove ou rejeite altera├º├Áes de pre├ºo e dados requerentes enviadas pelo
        contador.
      </p>

      {pending.length > 0 && (
        <Card className="border-amber-500/50 bg-amber-500/5">
          <CardHeader>
            <CardTitle>Pendentes de Aprova├º├úo</CardTitle>
            <CardDescription>
              Altera├º├Áes do contador aguardando sua autoriza├º├úo
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-3">
            {pending.map((s) => (
              <div
                key={s.id}
                className="flex flex-col md:flex-row md:items-center justify-between gap-4 p-4 border rounded-lg bg-background"
              >
                <div>
                  <p className="font-semibold">{s.label}</p>
                  <p className="text-xs text-muted-foreground">
                    C├│digo: {s.service_type}
                  </p>
                  {(s.proposed_description || s.description) && (
                    <p className="text-sm text-muted-foreground mt-1 whitespace-pre-line line-clamp-3">
                      {s.proposed_description || s.description}
                    </p>
                  )}
                  <p className="text-sm text-muted-foreground mt-1">
