            Edite valores, nomes e links de checkout dos planos
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-3">
          {loadingPlans ? (
            <Loader2 className="w-6 h-6 animate-spin mx-auto" />
          ) : plans.length === 0 ? (
            <p className="text-sm text-muted-foreground">
              Nenhum plano cadastrado.
