          ) : (
            plans.map((p) => (
              <div
                key={p.id}
                className="flex items-center gap-3 p-3 rounded-lg border border-border"
              >
                <div className="flex-1">
                  <p className="font-semibold">{p.name}</p>
                  <p className="text-sm text-muted-foreground">
                    {p.duration_months === 0
                      ? "Gr├ítis"
                      : `${p.duration_months} m├¬s(es)`}{" "}
                    ÔÇó R$ {Number(p.price).toFixed(2)}
                  </p>
                  {p.asaas_checkout_id && (
                    <p className="text-xs text-muted-foreground">
                      Checkout: {p.asaas_checkout_id}
                    </p>
                  )}
                </div>
                <div className="flex items-center gap-2">
                  <span
                    className={`text-xs px-2 py-1 rounded-full ${p.is_active ? "bg-success/10 text-success" : "bg-muted text-muted-foreground"}`}
                  >
                    {p.is_active ? "Ativo" : "Inativo"}
                  </span>
                  <span
                    className={`text-xs px-2 py-1 rounded-full ${p.show_on_landing ? "bg-blue-100 text-blue-800" : "bg-gray-100 text-gray-800"}`}
                  >
                    {p.show_on_landing ? (
                      <>
                        <Globe className="w-3 h-3 inline mr-1" />
                        Landing
                      </>
                    ) : (
                      <>
                        <EyeOff className="w-3 h-3 inline mr-1" />
                        Oculto
                      </>
                    )}
                  </span>
                </div>
                <div className="flex gap-1">
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => setEditingPlan({ ...p })}
                  >
                    <Edit className="w-4 h-4" />
                  </Button>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() =>
                      togglePlanVisibility(p.id, !p.show_on_landing)
                    }
                    className={
                      p.show_on_landing
                        ? "text-orange-600 hover:bg-orange-50"
                        : "text-blue-600 hover:bg-blue-50"
                    }
                  >
                    {p.show_on_landing ? (
                      <EyeOff className="w-4 h-4" />
                    ) : (
                      <Globe className="w-4 h-4" />
                    )}
                  </Button>
                </div>
              </div>
            ))
          )}
        </CardContent>
      </Card>

      {editingPlan && (
        <Card className="border-primary/20 bg-primary/5">
          <CardHeader>
            <CardTitle className="text-sm">
              Editar Plano: {editingPlan.name}
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-3">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
              <div>
                <Label>Nome</Label>
                <Input
                  value={editingPlan.name}
                  onChange={(e) =>
                    setEditingPlan({ ...editingPlan, name: e.target.value })
                  }
                  className="mt-1"
                />
              </div>
              <div>
                <Label>Pre├ºo (R$)</Label>
                <Input
                  type="number"
                  step="0.01"
                  value={editingPlan.price}
                  onChange={(e) =>
                    setEditingPlan({ ...editingPlan, price: +e.target.value })
                  }
                  className="mt-1"
                />
              </div>
              <div>
                <Label>Dura├º├úo (meses)</Label>
                <Input
                  type="number"
                  value={editingPlan.duration_months}
                  onChange={(e) =>
                    setEditingPlan({
                      ...editingPlan,
                      duration_months: +e.target.value,
                    })
                  }
                  className="mt-1"
                />
              </div>
              <div>
                <Label>ASAAS Checkout ID</Label>
                <Input
                  value={editingPlan.asaas_checkout_id || ""}
                  onChange={(e) =>
                    setEditingPlan({
                      ...editingPlan,
                      asaas_checkout_id: e.target.value,
                    })
                  }
                  className="mt-1"
                />
              </div>
            </div>
            <div className="flex items-center gap-3">
              <label className="flex items-center gap-2 text-sm cursor-pointer">
                <input
                  type="checkbox"
                  checked={editingPlan.is_active}
                  onChange={(e) =>
                    setEditingPlan({
                      ...editingPlan,
                      is_active: e.target.checked,
                    })
                  }
                  className="rounded"
                />
                Plano Ativo
              </label>
              <label className="flex items-center gap-2 text-sm cursor-pointer">
                <input
                  type="checkbox"
                  checked={editingPlan.show_on_landing || false}
                  onChange={(e) =>
                    setEditingPlan({
                      ...editingPlan,
                      show_on_landing: e.target.checked,
                    })
                  }
                  className="rounded"
                />
                Mostrar na Landing Page
              </label>
            </div>
            <div className="flex gap-2">
              <Button variant="gold" onClick={savePlan}>
                Salvar
              </Button>
              <Button variant="ghost" onClick={() => setEditingPlan(null)}>
                Cancelar
              </Button>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
};

