const LandingVisibilidadePage = () => {
  const [visibility, setVisibility] = useState<Record<string, boolean>>({});
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    supabase
      .from("integration_settings")
      .select("*")
      .eq("service_name", "landing_visibility")
      .eq("environment", "production")
      .maybeSingle()
      .then(({ data }: any) => {
        if (data?.config) {
          setVisibility(data.config as Record<string, boolean>);
        } else {
          const defaults: Record<string, boolean> = {};
          LANDING_SECTIONS.forEach((s) => {
            defaults[s.key] = true;
          });
          setVisibility(defaults);
        }
        setLoading(false);
      });
  }, []);

  const toggle = (key: string) => {
    setVisibility((prev) => ({ ...prev, [key]: !prev[key] }));
  };

  const handleSave = async () => {
    setSaving(true);
    const { error } = await (supabase as any)
      .from("integration_settings")
      .upsert(
        {
          service_name: "landing_visibility",
          environment: "production",
          config: visibility,
          is_active: true,
        },
        { onConflict: "service_name,environment" },
      );
    setSaving(false);
    if (error) {
      toast.error("Erro ao salvar: " + error.message);
      return;
    }
    toast.success("Visibilidade da landing page salva!");
  };

  if (loading)
    return (
      <div className="flex justify-center py-12">
        <Loader2 className="w-8 h-8 animate-spin text-primary" />
      </div>
    );

  const activeCount = Object.values(visibility).filter(Boolean).length;

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <h1 className="font-display text-2xl font-bold">
            Visibilidade da Landing Page
          </h1>
          <p className="text-muted-foreground text-sm">
            Controle quais se├º├Áes aparecem para afiliados, pain├®is e visitantes
          </p>
        </div>
        <Button variant="gold" onClick={handleSave} disabled={saving}>
          {saving ? (
            <Loader2 className="w-4 h-4 animate-spin mr-2" />
          ) : (
            <Eye className="w-4 h-4 mr-2" />
          )}
          {saving ? "Salvando..." : "Salvar Configura├º├úo"}
        </Button>
      </div>

      <Card className="border-primary/20 bg-primary/5">
        <CardContent className="py-3 flex items-center gap-3">
          <Activity className="w-5 h-5 text-primary" />
          <p className="text-sm">
            {activeCount} de {LANDING_SECTIONS.length} se├º├Áes vis├¡veis na
            landing page
          </p>
        </CardContent>
      </Card>

      <div className="grid gap-3">
        {LANDING_SECTIONS.map((section) => (
          <Card
            key={section.key}
            className={`transition-all ${visibility[section.key] ? "border-primary/30" : "border-border opacity-60"}`}
          >
            <CardContent className="p-4 flex items-center justify-between gap-4">
              <div className="flex-1">
                <p className="font-medium">{section.label}</p>
                <p className="text-xs text-muted-foreground">{section.desc}</p>
              </div>
              <div className="flex items-center gap-3">
                <span
                  className={`text-xs px-2 py-0.5 rounded-full ${visibility[section.key] ? "bg-success/10 text-success" : "bg-muted text-muted-foreground"}`}
                >
                  {visibility[section.key] ? "Vis├¡vel" : "Oculto"}
                </span>
                <Switch
                  checked={!!visibility[section.key]}
                  onCheckedChange={() => toggle(section.key)}
                />
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="text-base">
            Links R├ípidos ÔÇö Se├º├Áes de Painel
          </CardTitle>
          <CardDescription>
            Configure quais CTAs aparecem para cada tipo de usu├írio
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-3">
          {[
            { key: "cta_afiliado", label: 'Bot├úo "Seja Afiliado" no header' },
            { key: "cta_dono", label: 'Bot├úo "Abrir Barbearia" no hero' },
            {
              key: "cta_cliente",
              label: 'Bot├úo "Agendar Agora" para clientes',
            },
            { key: "banner_vitrine", label: "Banner de vitrine dos produtos" },
          ].map((item) => (
            <div
              key={item.key}
              className="flex items-center justify-between p-3 border rounded-lg"
            >
              <p className="text-sm">{item.label}</p>
              <div className="flex items-center gap-2">
                <span
                  className={`text-xs px-2 py-0.5 rounded-full ${visibility[item.key] !== false ? "bg-success/10 text-success" : "bg-muted text-muted-foreground"}`}
                >
                  {visibility[item.key] !== false ? "Ativo" : "Inativo"}
                </span>
                <Switch
                  checked={visibility[item.key] !== false}
                  onCheckedChange={() => toggle(item.key)}
                />
              </div>
            </div>
          ))}
        </CardContent>
      </Card>
    </div>
  );
};

export default SuperAdminDashboard;

import { useState, useEffect } from "react";
import { useNavigate, Link } from "react-router-dom";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { 
  ArrowLeft, 
  Eye, 
  EyeOff, 
  Loader2, 
  User, 
  Scissors, 
  Store, 
  Sparkles, 
  Mail, 
  Globe, 
  ChevronDown, 
  Check 
} from "lucide-react";
import { toast } from "sonner";
import { useAuth, AppRole, getDashboardForRole } from "@/lib/auth";
import { formatCpfCnpjBR, formatWhatsAppBR } from "@/lib/input-masks";
import logo from "@/assets/logo.png";
import { z } from "zod";
import { motion, AnimatePresence } from "framer-motion";
import { useTranslation } from "react-i18next";
import { LanguageSelector } from "@/components/layout/LanguageSelector";

type UserType = "cliente" | "dono";
type LoginType = "cliente" | "profissional" | "dono";

const loginSchema = z.object({
  identifier: z.string().min(5, "Campo obrigat├│rio"),
  password: z.string().min(6, "Senha deve ter no m├¡nimo 6 caracteres"),
});

const signupSchema = z.object({
  name: z.string().min(2, "Nome deve ter no m├¡nimo 2 caracteres").max(100),
  whatsapp: z.string().min(10, "WhatsApp inv├ílido"),
  email: z.string().email("E-mail inv├ílido").optional().or(z.literal("")),
  password: z.string().min(6, "Senha deve ter no m├¡nimo 6 caracteres"),
  cpfCnpj: z.string().optional(),
  pix: z.string().optional(),
});

const LoginPage = () => {
  const { t, i18n } = useTranslation("common");
  const navigate = useNavigate();
  const {
    user, signUp, signIn, signInWithWhatsApp,
    getPrimaryRole, roles, loading: authLoading,
    authResolved, sendPasswordResetEmail
  } = useAuth();

  const [mode, setMode] = useState<"login" | "signup">("login");
  const [userType, setUserType] = useState<UserType>("cliente");
  const [loginType, setLoginType] = useState<LoginType>("cliente");
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState<Record<string, string>>({});

  const [formData, setFormData] = useState({
    name: "",
    whatsapp: "",
    email: "",
    password: "",
    cpfCnpj: "",
    pix: ""
  });

  // Redirect if already logged in AND roles loaded
  useEffect(() => {
    if (!user || !authResolved) return;
    
    const role = getPrimaryRole();
    if (!role) return;

    // Check if user selected a plan from pricing
    const selectedPlan = localStorage.getItem("selected_plan");
    if (selectedPlan && role === "dono") {
      try {
        const plan = JSON.parse(selectedPlan);
        localStorage.removeItem("selected_plan");
        if (plan.checkoutUrl) {
          window.location.href = plan.checkoutUrl;
          return;
        }
      } catch { /* ignore */ }
    }
    localStorage.removeItem("selected_plan");

    const dashboardUrl = role ? getDashboardForRole(role) : "/app";
    if (dashboardUrl) {
      navigate(dashboardUrl, { replace: true });
    }
  }, [user, authResolved, roles, getPrimaryRole, navigate]);

  // Failsafe: libera bot├úo assim que auth/roles resolverem
  useEffect(() => {
    if (loading && user && authResolved) {
      setLoading(false);
    }
  }, [loading, user, authResolved, roles]);

  const isBusinessUser = userType === "dono";

  const validateForm = () => {
    setErrors({});

    try {
      if (mode === "login") {
        loginSchema.parse({
          identifier: loginType === "cliente" ? formData.whatsapp : formData.email,
          password: formData.password,
        });
      } else {
        const dataToValidate: Record<string, string> = {
          name: formData.name,
          whatsapp: formData.whatsapp,
          password: formData.password,
        };

        if (isBusinessUser) {
          dataToValidate.email = formData.email;
        }

        signupSchema.parse(dataToValidate);
      }
      return true;
    } catch (err) {
      if (err instanceof z.ZodError) {
        const newErrors: Record<string, string> = {};
        err.errors.forEach((e) => {
          if (e.path[0]) {
            newErrors[e.path[0] as string] = e.message;
          }
        });
        setErrors(newErrors);
      }
      return false;
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!validateForm()) return;

    setLoading(true);

    try {
      if (mode === "login") {
        let result;

        if (loginType === "cliente") {
          result = await signInWithWhatsApp(formData.whatsapp, formData.password);
        } else {
          result = await signIn(formData.email, formData.password);
        }

        if (result.error) {
          const msg = result.error.message || "Erro ao fazer login";
          if (msg.toLowerCase().includes("email not confirmed")) {
            toast.error(t("auth.error_email_confirmed"));
          } else if (msg.toLowerCase().includes("invalid login credentials")) {
            toast.error(t("auth.error_invalid_credentials"));
          } else {
            toast.error(t("auth.error_generic"));
          }
          setLoading(false);
          return;
        }

        toast.success(t("auth.login_success"));
        setTimeout(() => setLoading(false), 3000);
        return;
      } else {
        const email = isBusinessUser
          ? formData.email
          : `${formData.whatsapp.replace(/\D/g, '')}@salao.app`;

        const { error } = await signUp(email, formData.password, {
          name: formData.name,
          whatsapp: formData.whatsapp,
          role: userType as AppRole,
          cpf_cnpj: isBusinessUser ? formData.cpfCnpj : undefined,
          pix_key: isBusinessUser ? formData.pix : undefined,
        });

        if (error) {
          if (error.message.includes("already registered")) {
            toast.error(t("auth.error_already_registered"));
          } else {
            toast.error(t("auth.error_signup_generic"));
          }
          setLoading(false);
          return;
        }

        if (isBusinessUser) {
          toast.success(t("auth.signup_success_business"));
          // Redirect to onboarding page for business users
          navigate("/onboarding", { replace: true });
        } else {
          toast.success(t("auth.signup_success_client"));
          setMode("login");
        }
        setLoginType(userType === "dono" ? "dono" : "cliente");
        return;
      }
    } catch (err) {
      toast.error(t("auth.error_generic"));
      setLoading(false);
    }
  };

  const loginTypes: { value: LoginType; label: string; icon: React.ElementType }[] = [
    { value: "cliente", label: t("auth.role_client_short"), icon: User },
    { value: "profissional", label: t("auth.role_professional_short"), icon: Scissors },
    { value: "dono", label: t("auth.role_business_owner_short"), icon: Store },
  ];

  return (
    <div className="min-h-screen flex flex-col lg:flex-row bg-[#020617] animate-in fade-in duration-700">
      {/* Left Side - Form */}
      <motion.div 
        initial={{ opacity: 0, x: -20 }}
        animate={{ opacity: 1, x: 0 }}
        transition={{ duration: 0.6, ease: "easeOut" }}
        className="flex-1 flex flex-col justify-center px-4 py-12 lg:px-12 z-10 relative overflow-y-auto"
      >
        <div className="w-full max-w-md mx-auto">
          {/* Back Button & Language Switcher */}
          <div className="flex items-center justify-between mb-8">
            <Link
              to="/"
              className="inline-flex items-center gap-2 transition-all hover:text-gold group text-slate-400"
            >
              <ArrowLeft className="w-4 h-4 transition-transform group-hover:-translate-x-1" />
              {t("auth.back_to_site")}
            </Link>

            <LanguageSelector />
          </div>

          {/* Logo */}
          <div className="flex items-center gap-3 mb-8">
            <motion.img 
              src={logo} 
              alt="Sal├úoCashBack" 
              className="w-12 h-12"
              whileHover={{ rotate: 360, transition: { duration: 0.8 } }}
            />
            <span className="font-display font-bold text-2xl bg-gradient-to-r from-[#D4AF37] via-[#f7e48b] to-[#D4AF37] bg-clip-text text-transparent">
              Sal├úoCashBack
            </span>
          </div>

          {/* Title */}
          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.1 }}
          >
            <h1 className="font-display text-3xl font-bold mb-2 text-slate-50">
              {mode === "login" ? t("auth.login_title") : t("auth.register_title")}
            </h1>
            <p className="mb-8 text-slate-400">
              {mode === "login"
                ? t("auth.login_subtitle")
                : t("auth.register_subtitle")}
            </p>
          </motion.div>

          {/* Mode Toggle */}
          <div className="flex gap-2 p-1 rounded-xl mb-8 bg-[#1e293b]/50 border border-slate-800 backdrop-blur-sm">
            <button
              type="button"
              onClick={() => setMode("login")}
              className={`flex-1 py-3 px-4 rounded-lg text-sm font-bold transition-all duration-300 ${mode === "login"
                ? "bg-gradient-to-r from-[#D4AF37] to-[#B8860B] text-[#020617] shadow-lg shadow-gold/20 scale-[1.02]"
                : "text-slate-400 hover:text-slate-200"
                }`}
            >
              {t("auth.sign_in")}
            </button>
            <button
              type="button"
              onClick={() => setMode("signup")}
              className={`flex-1 py-3 px-4 rounded-lg text-sm font-bold transition-all duration-300 ${mode === "signup"
                ? "bg-gradient-to-r from-[#D4AF37] to-[#B8860B] text-[#020617] shadow-lg shadow-gold/20 scale-[1.02]"
                : "text-slate-400 hover:text-slate-200"
                }`}
            >
              {t("auth.sign_up")}
            </button>
          </div>

          <AnimatePresence mode="wait">
            <motion.div
              key={`${mode}-${userType}-${loginType}`}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -10 }}
              transition={{ duration: 0.3 }}
            >
              {/* Login Type Selection (only for login) */}
              {mode === "login" && (
                <div className="mb-8">
                  <Label className="mb-4 block text-slate-400 text-sm font-medium">{t("auth.login_type_label")}</Label>
                  <div className="grid grid-cols-3 gap-3">
                    {loginTypes.map((type) => (
                      <button
                        key={type.value}
                        type="button"
                        onClick={() => setLoginType(type.value)}
                        className={`p-3 rounded-xl text-center transition-all duration-300 border ${
                          loginType === type.value 
                            ? "bg-gold/10 border-gold/40 shadow-gold/20 shadow-lg scale-105" 
                            : "bg-[#0f172a] border-slate-800 hover:border-slate-700"
                        }`}
                      >
                        <type.icon className={`w-5 h-5 mx-auto mb-2 transition-colors ${
                          loginType === type.value ? "text-gold" : "text-slate-500"
                        }`} />
                        <span className={`text-[11px] font-bold block transition-colors ${
                          loginType === type.value ? "text-gold" : "text-slate-500"
                        }`}>
                          {type.label}
                        </span>
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {/* User Type Selection (only for signup) */}
              {mode === "signup" && (
                <div className="mb-8">
                  <Label className="mb-4 block text-slate-400 text-sm font-medium">{t("auth.signup_type_label")}</Label>
                  <div className="grid grid-cols-2 gap-4">
                    <button
                      type="button"
                      onClick={() => setUserType("cliente")}
                      className={`flex-1 flex flex-col items-center gap-4 p-5 rounded-2xl border-2 transition-all duration-300 ${userType === "cliente"
                        ? "border-gold bg-gold/5 shadow-[0_0_20px_rgba(212,175,55,0.1)] scale-[1.02]"
                        : "border-slate-800 bg-[#0f172a] hover:border-gold/30 hover:bg-gold/5"
                        }`}
                    >
                      <div className={`p-3 rounded-full ${userType === "cliente" ? "bg-gold text-[#020617]" : "bg-slate-800 text-slate-500"
                        }`}>
                        <User className="w-6 h-6" />
                      </div>
                      <div className="text-center">
                        <span className={`block text-sm font-bold ${userType === "cliente" ? "text-gold" : "text-slate-300"
                          }`}>
                          {t("auth.role_client")}
                        </span>
                      </div>
                    </button>

                    <button
                      type="button"
                      onClick={() => setUserType("dono")}
                      className={`flex-1 flex flex-col items-center gap-4 p-5 rounded-2xl border-2 transition-all duration-300 ${userType === "dono"
                        ? "border-gold bg-gold/5 shadow-[0_0_20px_rgba(212,175,55,0.1)] scale-[1.02]"
                        : "border-slate-800 bg-[#0f172a] hover:border-gold/30 hover:bg-gold/5"
                        }`}
                    >
                      <div className={`p-3 rounded-full ${userType === "dono" ? "bg-gold text-[#020617]" : "bg-slate-800 text-slate-500"
                        }`}>
                        <Store className="w-6 h-6" />
                      </div>
                      <div className="text-center">
                        <span className={`block text-sm font-bold ${userType === "dono" ? "text-gold" : "text-slate-300"
                          }`}>
                          {t("auth.role_business_owner")}
                        </span>
                      </div>
                    </button>
                  </div>
                  <p className="text-[11px] mt-4 text-slate-500 italic text-center">
                    {t("auth.signup_disclaimer")}
                  </p>
                </div>
              )}

              {/* Form */}
              <form onSubmit={handleSubmit} className="space-y-5">
                {mode === "signup" && (
                  <div className="space-y-2">
                    <Label htmlFor="name" className="text-slate-300 ml-1 text-sm font-medium">{t("auth.name_label")}</Label>
                    <div className="relative group">
                      <User className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 group-focus-within:text-gold transition-colors" />
                      <Input
                        id="name"
                        type="text"
                        placeholder={t("auth.name_placeholder")}
                        value={formData.name}
                        onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                        className="pl-11 bg-[#0f172a] border-slate-800 focus:border-gold/50 transition-all h-13 rounded-xl text-slate-200"
                        autoComplete="name"
                      />
                    </div>
                    {errors.name && <p className="text-xs text-red-500 mt-1 ml-1">{errors.name}</p>}
                  </div>
                )}

                {/* WhatsApp */}
                {(mode === "signup" || loginType === "cliente") && (
                  <div className="space-y-2">
                    <Label htmlFor="whatsapp" className="text-slate-300 ml-1 text-sm font-medium">WhatsApp</Label>
                    <div className="relative group">
                      <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-gold transition-colors">
                        <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413z"/></svg>
                      </div>
                      <Input
                        id="whatsapp"
                        type="tel"
                        placeholder="(00) 00000-0000"
                        value={formData.whatsapp}
                        onChange={(e) => setFormData({ ...formData, whatsapp: formatWhatsAppBR(e.target.value) })}
                        className="pl-11 bg-[#0f172a] border-slate-800 focus:border-gold/50 transition-all h-13 rounded-xl text-slate-200"
                        autoComplete="tel"
                      />
                    </div>
                    {(errors.whatsapp || errors.identifier) && (
                      <p className="text-xs text-red-500 mt-1 ml-1">{errors.whatsapp || errors.identifier}</p>
                    )}
                  </div>
                )}

                {/* Email */}
                {((mode === "signup" && isBusinessUser) || (mode === "login" && loginType !== "cliente")) && (
                  <div className="space-y-2">
                    <Label htmlFor="email" className="text-slate-300 ml-1 text-sm font-medium">{t("auth.email_label")}</Label>
                    <div className="relative group">
                      <Mail className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 group-focus-within:text-gold transition-colors" />
                      <Input
                        id="email"
                        type="email"
                        placeholder={t("auth.email_placeholder")}
                        value={formData.email}
                        onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                        className="pl-11 bg-[#0f172a] border-slate-800 focus:border-gold/50 transition-all h-13 rounded-xl text-slate-200"
                        autoComplete="email"
                      />
                    </div>
                    {(errors.email || errors.identifier) && (
                      <p className="text-xs text-red-500 mt-1 ml-1">{errors.email || errors.identifier}</p>
                    )}
                  </div>
                )}

                {/* CPF/CNPJ */}
                {mode === "signup" && isBusinessUser && (
                  <div className="space-y-2">
                    <Label htmlFor="cpfCnpj" className="text-slate-300 ml-1 text-sm font-medium">{t("auth.cpf_cnpj_label")}</Label>
                    <Input
                      id="cpfCnpj"
                      type="text"
                      placeholder="000.000.000-00"
                      value={formData.cpfCnpj}
                      onChange={(e) => setFormData({ ...formData, cpfCnpj: formatCpfCnpjBR(e.target.value) })}
                      className="bg-[#0f172a] border-slate-800 focus:border-gold/50 transition-all h-13 rounded-xl text-slate-200"
                      autoComplete="off"
                    />
                  </div>
                )}

                {/* PIX */}
                {mode === "signup" && isBusinessUser && (
                  <div className="space-y-2">
                    <Label htmlFor="pix" className="text-slate-300 ml-1 text-sm font-medium">{t("auth.pix_label")}</Label>
                    <Input
                      id="pix"
                      type="text"
                      placeholder={t("auth.pix_placeholder")}
                      value={formData.pix}
                      onChange={(e) => setFormData({ ...formData, pix: e.target.value })}
                      className="bg-[#0f172a] border-slate-800 focus:border-gold/50 transition-all h-13 rounded-xl text-slate-200"
                      autoComplete="off"
                    />
                  </div>
                )}

                {/* Password */}
                <div className="space-y-2">
                  <Label htmlFor="password" className="text-slate-300 ml-1 text-sm font-medium">{t("auth.password_label")}</Label>
                  <div className="relative group">
                    <Input
                      id="password"
                      type={showPassword ? "text" : "password"}
                      placeholder="ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó"
                      value={formData.password}
                      onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                      className="px-11 bg-[#0f172a] border-slate-800 focus:border-gold/50 transition-all h-13 rounded-xl text-slate-200"
                      autoComplete={mode === "login" ? "current-password" : "new-password"}
                    />
                    <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-gold transition-colors">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"/></svg>
                    </div>
                    <button
                      type="button"
                      onClick={() => setShowPassword(!showPassword)}
                      className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 hover:text-slate-300 transition-colors"
                    >
                      {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                    </button>
                  </div>
                  {errors.password && <p className="text-xs text-red-500 mt-1 ml-1">{errors.password}</p>}
                </div>

                {/* Forgot Password (login only) */}
                {mode === "login" && (
                  <div className="text-right">
                    <button
                      type="button"
                      className="text-xs text-gold hover:text-white transition-colors font-medium"
                      onClick={async () => {
                        const identifier = loginType === "cliente" ? formData.whatsapp : formData.email;
                        let targetEmail = "";

                        if (loginType === "cliente") {
                          if (!formData.whatsapp || formData.whatsapp.length < 10) {
                            toast.error(t("auth.error_whatsapp_required"));
                            return;
                          }
                          setLoading(true);
                          const norm = formData.whatsapp.replace(/\D/g, '');
                          const { data } = await (supabase as any).rpc("get_email_by_whatsapp", { _whatsapp: norm });
                          setLoading(false);
                          if (!data) {
                            toast.error(t("auth.error_account_not_found"));
                            return;
                          }
                          targetEmail = data;
                        } else {
                          if (!formData.email || !formData.email.includes("@")) {
                            toast.error(t("auth.error_email_required"));
                            return;
                          }
                          targetEmail = formData.email;
                        }

                        if (targetEmail) {
                          const { error } = await sendPasswordResetEmail(targetEmail);
                          if (error) {
                            toast.error(t("auth.error_reset_email") + error.message);
                          } else {
                            toast.success(t("auth.reset_email_sent"));
                          }
                        }
                      }}
                      disabled={loading}
                    >
                      {t("auth.forgot_password")}
                    </button>
                  </div>
                )}

                {/* Submit Button */}
                <Button
                  type="submit"
                  className="w-full h-13 mt-4 bg-gradient-to-r from-[#D4AF37] via-[#f7e48b] to-[#D4AF37] text-[#020617] font-black text-base rounded-xl shadow-[0_0_20px_rgba(212,175,55,0.2)] hover:shadow-[0_0_30px_rgba(212,175,55,0.4)] transition-all duration-300 border-none group"
                  disabled={loading}
                >
                  {loading ? (
                    <div className="flex items-center gap-2">
                      <Loader2 className="w-5 h-5 animate-spin" />
                      {t("processing")}
                    </div>
                  ) : (
                    <div className="flex items-center justify-center gap-2">
                       {mode === "login" ? t("auth.sign_in") : t("auth.sign_up")}
                       <Sparkles className="w-4 h-4 opacity-0 group-hover:opacity-100 transition-opacity" />
                    </div>
                  )}
                </Button>
              </form>
            </motion.div>
          </AnimatePresence>

          {/* Info for business users */}
          {mode === "signup" && isBusinessUser && (
            <motion.div 
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              className="mt-6 p-4 rounded-2xl bg-white/5 border border-white/10 backdrop-blur-sm"
            >
              <p className="text-[11px] text-center text-slate-500 leading-relaxed">
                {t("auth.asaas_redirect_info")}{" "}
                <a
                  href="https://www.asaas.com/r/4095742a-0dd1-4fb7-b9ce-61431bb4f632"
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-gold font-bold underline hover:text-white transition-colors"
                >
                  Asaas
                </a>
              </p>
            </motion.div>
          )}

          {/* Affiliate Link */}
          <div className="mt-8 pt-6 text-center border-t border-slate-800">
            <Link
              to="/afiliado-saas/login"
              className="text-xs text-slate-500 hover:text-slate-300 transition-colors inline-flex items-center gap-1"
            >
              {t("auth.want_to_be_affiliate")}{" "}
              <span className="text-gold font-bold underline">{t("auth.click_here")}</span>
            </Link>
          </div>
        </div>
      </motion.div>

      {/* Right Side - Premium Visual Marketing */}
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ duration: 1, delay: 0.2 }}
        className="hidden lg:flex flex-1 relative bg-[#020617] items-center justify-center p-12 overflow-hidden border-l border-slate-800"
      >
        {/* Background Atmosphere */}
        <div className="absolute inset-0 z-0">
          <div className="absolute top-0 right-0 w-[80%] h-[80%] bg-gold/10 rounded-full blur-[140px] opacity-40 animate-pulse" />
          <div className="absolute bottom-0 left-0 w-[60%] h-[60%] bg-blue-500/5 rounded-full blur-[120px] opacity-30" />
          <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-[0.05]" />
          
          {/* Subtle grid pattern */}
          <div className="absolute inset-0 bg-[linear-gradient(to_right,#80808012_1px,transparent_1px),linear-gradient(to_bottom,#80808012_1px,transparent_1px)] bg-[size:40px_40px]" />
        </div>

        <div className="max-w-xl text-center relative z-10">
          <motion.div
            initial={{ scale: 0.9, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            transition={{ delay: 0.4 }}
            className="inline-flex items-center gap-3 px-5 py-2 rounded-full border border-gold/20 bg-gold/5 text-gold text-[10px] font-black uppercase tracking-[0.3em] mb-12 backdrop-blur-md"
          >
            <Sparkles className="w-3 h-3 animate-pulse" />
            {t("auth.visual_badge")}
          </motion.div>

          <motion.h2 
            initial={{ y: 20, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            transition={{ delay: 0.5 }}
            className="font-display text-5xl xl:text-7xl font-black mb-8 text-slate-50 leading-[1.1] tracking-tight"
          >
            {t("auth.visual_title")} <br />
            <span className="bg-gradient-to-r from-[#D4AF37] via-[#f7e48b] to-[#D4AF37] bg-clip-text text-transparent italic">
               {t("auth.visual_title_highlight")}
            </span>
          </motion.h2>
          
          <motion.p 
            initial={{ y: 20, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            transition={{ delay: 0.6 }}
            className="text-lg xl:text-xl text-slate-400 mb-16 leading-relaxed font-medium"
          >
            {t("auth.visual_subtitle")} <br />
            <span className="text-gold underline decoration-gold/30 underline-offset-8">{t("auth.visual_description")}</span>
          </motion.p>

          {/* Stats cards */}
          <motion.div 
            initial={{ y: 30, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            transition={{ delay: 0.7 }}
            className="grid grid-cols-3 gap-6 pt-16 border-t border-slate-800"
          >
            {[
              { value: "500+", label: t("auth.stat_partners") },
              { value: "40%", label: t("auth.stat_revenue") },
              { value: "100%", label: t("auth.stat_digital") },
            ].map(({ value, label }) => (
              <div key={label} className="text-center group p-4 rounded-2xl transition-all hover:bg-white/5 border border-transparent hover:border-white/10">
                <div className="text-3xl font-display font-black bg-gradient-to-r from-[#D4AF37] to-[#B8860B] bg-clip-text text-transparent mb-2 group-hover:scale-110 transition-transform">{value}</div>
                <div className="text-[9px] font-black uppercase tracking-[0.2em] text-slate-500 leading-tight">{label}</div>
              </div>
            ))}
          </motion.div>
        </div>

        {/* Security badge at bottom right */}
        <motion.div 
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 1 }}
          className="absolute bottom-12 right-12 flex items-center gap-3 bg-[#0f172a]/50 backdrop-blur-xl px-5 py-2.5 rounded-full border border-slate-800 shadow-2xl"
        >
          <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_10px_rgba(16,185,129,0.5)]" />
          <span className="text-[10px] uppercase tracking-[0.2em] font-black text-slate-400">{t("auth.security_title")}</span>
        </motion.div>
      </motion.div>
    </div>
  );
};

export default LoginPage;

import { useState, useEffect } from "react";
import { Link, useNavigate } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { CreditCard, ShieldCheck, ArrowLeft, Loader2, CheckCircle2 } from "lucide-react";
import { toast } from "sonner";
import logo from "@/assets/logo.png";

const PaymentSimulationPage = () => {
    const navigate = useNavigate();
    const [loading, setLoading] = useState(false);
    const [success, setSuccess] = useState(false);
    const [selectedPlan, setSelectedPlan] = useState<any>(null);

    useEffect(() => {
        const plan = localStorage.getItem("selected_plan");
        if (plan) {
            setSelectedPlan(JSON.parse(plan));
        }
    }, []);

    const handleSimulatePayment = () => {
        setLoading(true);
        // Simular processamento (ASAAS)
        setTimeout(() => {
            setLoading(false);
            setSuccess(true);
            toast.success("Pagamento aprovado com sucesso! (SIMULA├ç├âO)");

            // Armazenar flag de pagamento para o onboarding/auth
            localStorage.setItem("simulation_paid", "true");

            // Redirecionar ap├│s 3 segundos
            setTimeout(() => {
                navigate("/login");
            }, 3000);
        }, 2000);
    };

    if (success) {
        return (
            <div className="min-h-screen bg-background flex items-center justify-center p-4">
                <Card className="max-w-md w-full text-center py-8">
                    <CardContent className="space-y-4">
                        <div className="w-16 h-16 bg-success/10 rounded-full flex items-center justify-center mx-auto mb-4">
                            <CheckCircle2 className="w-10 h-10 text-success" />
                        </div>
                        <CardTitle className="text-2xl font-bold">Pagamento Confirmado!</CardTitle>
                        <CardDescription className="text-lg">
                            Sua assinatura do plano <strong>{selectedPlan?.name || "Premium"}</strong> foi ativada com sucesso.
                        </CardDescription>
                        <div className="pt-8">
                            <p className="text-muted-foreground text-sm flex items-center justify-center gap-2">
                                <Loader2 className="w-4 h-4 animate-spin" />
                                Redirecionando para o login...
                            </p>
                        </div>
                    </CardContent>
                </Card>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-background flex flex-col items-center justify-center p-4 relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-1 bg-gradient-gold" />

            <Link to="/" className="mb-8 flex items-center gap-2">
                <img src={logo} alt="Logo" className="w-10 h-10" />
                <span className="font-display font-bold text-xl text-gradient-gold">Sal├úoCashBack</span>
            </Link>

            <Card className="max-w-lg w-full shadow-2xl border-primary/20 bg-gradient-card">
                <CardHeader className="border-b border-border/50 pb-6">
                    <div className="flex items-center justify-between">
                        <div>
                            <CardTitle>Checkout Seguro</CardTitle>
                            <CardDescription>Ambiente de Simula├º├úo de Pagamento (Ambiente de Teste)</CardDescription>
                        </div>
                        <ShieldCheck className="text-primary w-8 h-8" />
                    </div>
                </CardHeader>

                <CardContent className="pt-6 space-y-6">
                    {/* Plan Summary */}
                    <div className="p-4 rounded-xl bg-primary/5 border border-primary/10 mb-6">
                        <div className="flex justify-between items-center">
                            <div>
                                <p className="text-sm text-muted-foreground">Plano Selecionado</p>
                                <p className="text-lg font-bold">{selectedPlan?.name || "Mensal"}</p>
                            </div>
                            <div className="text-right">
                                <p className="text-sm text-muted-foreground">Valor</p>
                                <p className="text-lg font-bold text-gradient-gold">R$ {selectedPlan?.price || "19,90"}</p>
                            </div>
                        </div>
                    </div>

                    <div className="space-y-4">
                        <div className="grid gap-2">
                            <Label htmlFor="card-name">Nome no Cart├úo</Label>
                            <Input id="card-name" placeholder="TESTE USER" defaultValue="TESTE USER" />
                        </div>

                        <div className="grid gap-2 text-center text-xs text-muted-foreground bg-muted p-3 rounded-lg border border-dashed border-border">
                            ESTA ├ë UMA TELA DE TESTE. N├âO INSIRA DADOS REAIS DE CART├âO.
                        </div>

                        <div className="grid gap-2">
                            <Label htmlFor="card-number">N├║mero do Cart├úo</Label>
                            <div className="relative">
                                <Input id="card-number" placeholder="4444 4444 4444 4444" defaultValue="4444 4444 4444 4444" />
                                <CreditCard className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="grid gap-2">
                                <Label htmlFor="expiry">Validade</Label>
                                <Input id="expiry" placeholder="12/29" defaultValue="12/29" />
                            </div>
                            <div className="grid gap-2">
                                <Label htmlFor="cvv">CVV</Label>
                                <Input id="cvv" placeholder="123" defaultValue="123" />
                            </div>
                        </div>
                    </div>

                    <div className="pt-4 flex items-center justify-center gap-2 text-xs text-muted-foreground">
                        <ShieldCheck className="w-4 h-4 text-success" />
                        Processado via <span className="font-bold">ASAAS Gateway</span> em modo Sandbox
                    </div>
                </CardContent>

                <CardFooter className="flex flex-col gap-3 pt-6 border-t border-border/50">
                    <Button
                        variant="gold"
                        className="w-full h-12 text-lg font-bold shadow-gold"
                        onClick={handleSimulatePayment}
                        disabled={loading}
                    >
                        {loading ? (
                            <>
                                <Loader2 className="mr-2 h-5 w-5 animate-spin" />
                                Processando...
                            </>
                        ) : (
                            "Confirmar Pagamento Simulado"
                        )}
                    </Button>
                    <Button
                        variant="ghost"
                        className="w-full text-muted-foreground"
                        onClick={() => navigate("/")}
                        disabled={loading}
                    >
                        <ArrowLeft className="mr-2 h-4 w-4" />
                        Voltar para a Home
                    </Button>
                </CardFooter>
            </Card>
        </div>
    );
};

export default PaymentSimulationPage;

/**
 * VitrinePage ÔÇô Vitrine p├║blica da barbearia
 * Rota: /v/:barbershopId
 * Exibe produtos e a├º├Áes entre amigos com bot├úo "Agendar Agora"
 */

import { useEffect, useState } from "react";
import { useParams, Link } from "react-router-dom";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Loader2, Package, Gift, Calendar, Star, MapPin, Phone } from "lucide-react";
import logo from "@/assets/logo.png";

type Barbershop = {
  id: string;
  name: string | null;
  address: string | null;
  phone: string | null;
  description: string | null;
};

type Product = {
  id: string;
  name: string;
  sell_price: number;
  quantity: number;
};

type Raffle = {
  id: string;
  name: string;
  description: string | null;
  ticket_price: number;
  credit_award: number;
  status: string;
};

export default function VitrinePage() {
  const { barbershopId } = useParams<{ barbershopId: string }>();
  const [barbershop, setBarbershop] = useState<Barbershop | null>(null);
  const [products, setProducts] = useState<Product[]>([]);
  const [raffles, setRaffles] = useState<Raffle[]>([]);
  const [loading, setLoading] = useState(true);
  const [notFound, setNotFound] = useState(false);

  useEffect(() => {
    if (!barbershopId) { setNotFound(true); setLoading(false); return; }
    (async () => {
      const { data: shop } = await (supabase as any)
        .from("barbershops")
        .select("id, name, address, phone, description")
        .eq("id", barbershopId)
        .maybeSingle();

      if (!shop) { setNotFound(true); setLoading(false); return; }
      setBarbershop(shop as Barbershop);

      const [prodsRes, rafflesRes] = await Promise.all([
        (supabase as any).from("stock_items").select("id, name, sell_price, quantity").eq("barbershop_id", barbershopId).eq("is_active", true).order("name"),
        (supabase as any).from("raffles").select("id, name, description, ticket_price, credit_award, status").eq("barbershop_id", barbershopId).eq("status", "open").order("created_at", { ascending: false }),
      ]);

      setProducts((prodsRes.data || []) as Product[]);
      setRaffles((rafflesRes.data || []) as Raffle[]);
      setLoading(false);
    })();
  }, [barbershopId]);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-background">
        <Loader2 className="w-10 h-10 animate-spin text-primary" />
      </div>
    );
  }

  if (notFound || !barbershop) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-background gap-4">
        <img src={logo} alt="Logo" className="w-16 h-16" />
        <h1 className="text-2xl font-bold">Barbearia n├úo encontrada</h1>
        <Link to="/"><Button variant="outline">Voltar ao in├¡cio</Button></Link>
      </div>
    );
  }

  const bookingUrl = `/app`;

  return (
    <div className="min-h-screen bg-background">
      {/* Header */}
      <header className="bg-card border-b border-border sticky top-0 z-10 shadow-sm">
        <div className="max-w-4xl mx-auto px-4 py-3 flex items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <img src={logo} alt="Logo" className="w-8 h-8" />
            <div>
              <h1 className="font-display font-bold text-lg leading-tight">{barbershop.name}</h1>
              {barbershop.address && (
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <MapPin className="w-3 h-3" />{barbershop.address}
                </p>
              )}
            </div>
          </div>
          <a href={bookingUrl}>
            <Button variant="gold" className="shrink-0 gap-2">
              <Calendar className="w-4 h-4" />
              Agendar Agora
            </Button>
          </a>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 py-8 space-y-10">
        {/* Hero CTA */}
        <div className="rounded-2xl bg-gradient-to-br from-primary/10 to-primary/5 border border-primary/20 p-6 text-center space-y-3">
          {barbershop.description && (
            <p className="text-muted-foreground">{barbershop.description}</p>
          )}
          <div className="flex flex-col sm:flex-row gap-3 justify-center">
            <a href={bookingUrl}>
              <Button variant="gold" size="lg" className="gap-2 w-full sm:w-auto">
                <Calendar className="w-5 h-5" />
                Agendar Agora
              </Button>
            </a>
            {barbershop.phone && (
              <a href={`https://wa.me/55${barbershop.phone.replace(/\D/g, "")}`} target="_blank" rel="noopener noreferrer">
                <Button variant="outline" size="lg" className="gap-2 w-full sm:w-auto">
                  <Phone className="w-5 h-5" />
                  Chamar no WhatsApp
                </Button>
              </a>
            )}
          </div>
        </div>

        {/* Produtos */}
        {products.length > 0 && (
          <section>
            <div className="flex items-center gap-2 mb-4">
              <Package className="w-5 h-5 text-primary" />
              <h2 className="font-display text-xl font-bold">Produtos</h2>
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4">
              {products.map(p => (
                <Card key={p.id} className="overflow-hidden hover:shadow-md transition-shadow">
                  <div className="aspect-square bg-muted flex items-center justify-center overflow-hidden">
                    <Package className="w-10 h-10 text-muted-foreground" />
                  </div>
                  <CardContent className="p-3">
                    <p className="font-semibold text-sm leading-tight">{p.name}</p>
                    <p className="text-primary font-bold mt-1">R$ {Number(p.sell_price).toFixed(2)}</p>
                    {p.quantity > 0 && (
                      <p className="text-xs text-muted-foreground">Em estoque: {p.quantity}</p>
                    )}
                  </CardContent>
                </Card>
              ))}
            </div>
          </section>
        )}

        {/* A├º├úo entre Amigos */}
        {raffles.length > 0 && (
          <section>
            <div className="flex items-center gap-2 mb-4">
              <Gift className="w-5 h-5 text-primary" />
              <h2 className="font-display text-xl font-bold">A├º├úo entre Amigos</h2>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {raffles.map(r => (
                <Card key={r.id} className="overflow-hidden hover:shadow-md transition-shadow">
                  <div className="h-32 bg-muted overflow-hidden">
                    <div className="w-full h-full flex items-center justify-center">
                      <Gift className="w-12 h-12 text-muted-foreground" />
                    </div>
                  </div>
                  <CardContent className="p-4">
                    <h3 className="font-bold">{r.name}</h3>
                    {r.description && <p className="text-sm text-muted-foreground mt-1">{r.description}</p>}
                    <div className="flex items-center justify-between mt-3">
                      <div>
                        <p className="text-xs text-muted-foreground">Bilhete</p>
                        <p className="font-bold text-primary">R$ {Number(r.ticket_price).toFixed(2)}</p>
                      </div>
                      <div className="text-right">
                        <p className="text-xs text-muted-foreground">Pr├¬mio</p>
                        <p className="font-bold flex items-center gap-1"><Star className="w-3 h-3 text-yellow-500" />R$ {Number(r.credit_award).toFixed(2)}</p>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          </section>
        )}

        {/* CTA final */}
        <div className="text-center py-6 border-t border-border">
          <p className="text-muted-foreground mb-4">Pronto para um novo visual?</p>
          <a href={bookingUrl}>
            <Button variant="gold" size="lg" className="gap-2">
              <Calendar className="w-5 h-5" />
              Agendar Agora
            </Button>
          </a>
          <p className="text-xs text-muted-foreground mt-4">
            Powered by <a href="/" className="text-primary hover:underline">Sal├úo Cashback</a>
          </p>
        </div>
      </main>
    </div>
  );
}

