/**
 * Detectar inten├º├úo da mensagem (simplificado)
 */
export function detectIntent(message: string): string {
  const msg = message.toLowerCase();
  
  if (msg.includes('hor├írio') || msg.includes('horario') || msg.includes('agenda')) {
    return 'check_schedule';
  }
  if (msg.includes('pre├ºo') || msg.includes('valor') || msg.includes('quanto custa')) {
    return 'check_price';
  }
  if (msg.includes('agendar') || msg.includes('marcar') || msg.includes('marca├º├úo')) {
    return 'schedule_appointment';
  }
  if (msg.includes('cancelar') || msg.includes('desmarcar')) {
    return 'cancel_appointment';
  }
  if (msg.includes('servi├ºo') || msg.includes('servico') || msg.includes('corte') || msg.includes('barba')) {
    return 'service_info';
  }
  if (msg.includes('ola') || msg.includes('oi') || msg.includes('ol├í') || msg.includes('bom dia') || msg.includes('boa tarde') || msg.includes('boa noite')) {
    return 'greeting';
  }
  
  return 'general_inquiry';
}

