export interface AISuggestion {
  message: string;
  action?: 'suggest_time' | 'list_services' | 'create_appointment';
  data?: any;
}

/**
 * Processa mensagem do cliente e retorna resposta inteligente
 */
export async function processarMensagem(
  cliente: any, 
  mensagem: string
): Promise<AISuggestion> {
  const msg = mensagem.toLowerCase();
  
  // ­ƒöì Detectar inten├º├úo
  if (msg.includes('horario') || msg.includes('agenda') || msg.includes('dispon├¡vel')) {
    const sugestao = await sugerirHorario(cliente);
    return {
      message: sugestao,
      action: 'suggest_time',
    };
  }
  
  if (msg.includes('pre├ºo') || msg.includes('valor') || msg.includes('quanto custa')) {
    const servicos = await listarServicos();
    return {
      message: servicos,
      action: 'list_services',
    };
  }
  
  if (msg.includes('agendar') || msg.includes('marcar') || msg.includes('reservar')) {
    const resultado = await criarAgendamento(cliente);
    return {
      message: resultado.message,
      action: 'create_appointment',
      data: resultado.data,
    };
  }
  
  if (msg.includes('ola') || msg.includes('oi') || msg.includes('bom dia') || msg.includes('boa tarde')) {
    return {
      message: `Ol├í ${cliente.name || 'cliente'}! ­ƒÿè Como posso te ajudar? Posso ajudar com:\nÔÇó Agendamentos\nÔÇó Valores dos servi├ºos\nÔÇó Informa├º├Áes sobre hor├írios`,
    };
  }
  
  // Resposta padr├úo
  return {
    message: "Posso te ajudar com agendamentos, valores dos servi├ºos ou informa├º├Áes sobre hor├írios dispon├¡veis. O que voc├¬ precisa? ­ƒÿè",
  };
}

/**
 * Sugere hor├írio dispon├¡vel baseado no perfil do cliente
 */
async function sugerirHorario(cliente: any): Promise<string> {
  try {
    // Buscar hor├írios dispon├¡veis para hoje e amanh├ú
    const hoje = new Date();
    const amanha = new Date();
    amanha.setDate(amanha.getDate() + 1);
    
    const { data: horarios, error } = await (supabase as any)
      .from('appointments')
      .select('*')
      .gte('scheduled_at', hoje.toISOString())
      .lte('scheduled_at', amanha.toISOString())
      .eq('status', 'scheduled')
      .order('scheduled_at', { ascending: true });

    if (error) {
      console.error('Erro ao buscar hor├írios:', error);
      return "Desculpe, estou com problemas para verificar os hor├írios. Tente novamente mais tarde. ­ƒÿó";
    }

    const livre = horarios?.find((a: any) => a.status === 'scheduled');
    
    if (!livre) {
      // Se n├úo tem hor├írio hoje/amanh├ú, sugerir para depois
      return "Hoje e amanh├ú est├úo cheios ­ƒÿó. Gostaria que eu verifique para depois de amanh├ú?";
    }

    const dataHora = new Date(livre.scheduled_at);
    const dataFormatada = dataHora.toLocaleDateString('pt-BR');
    const horaFormatada = dataHora.toLocaleTimeString('pt-BR', { 
      hour: '2-digit', 
      minute: '2-digit' 
    });

    return `Encontrei um hor├írio dispon├¡vel! ­ƒôà\n\n­ƒôà Data: ${dataFormatada}\nÔÅ░ Hora: ${horaFormatada}\n\nDeseja confirmar este hor├írio?`;
  } catch (error) {
    console.error('Erro na sugest├úo de hor├írio:', error);
    return "Desculpe, estou com problemas para verificar os hor├írios. Tente novamente mais tarde. ­ƒÿó";
  }
}

