      })
      .eq('is_resolved', false)
      .lt('created_at', cutoffDate.toISOString());

    if (error) throw error;
    return count || 0;
  } catch (error) {
    console.error('Erro ao resolver alertas antigos:', error);
    return 0;
  }
}

