export function generateReactivationMessage(client: InactiveClient): string {
  const messages = [
    `­ƒæï Ol├í ${client.name}! Sentimos sua falta! Faz ${client.days_inactive} dias que voc├¬ n├úo vem. Que tal agendar um retorno? ­ƒÆê`,
