/**
 * Enviar mensagem de reativa├º├úo via WhatsApp
 */
export async function sendReactivationMessage(
  client: InactiveClient,
  customMessage?: string
): Promise<{ success: boolean; messageId?: string }> {
  try {
    const message = customMessage || generateReactivationMessage(client);

    // Enviar via WhatsApp
    const result = await sendWhatsAppMessage(client.whatsapp, message);

    if (result.success) {
      // Salvar na mem├│ria da IA
      await saveConversation(
        client.user_id,
        'reactivation_message_sent',
        message,
        'reactivation_campaign',
        {
          client_id: client.id,
          days_inactive: client.days_inactive,
          timestamp: new Date().toISOString(),
        }
      );

      // Registrar no banco de dados
      await (supabase as any).from('reactivation_campaigns_log').insert({
        client_id: client.id,
        message: message,
        status: 'sent',
        sent_at: new Date().toISOString(),
      });
    }

    return result;
  } catch (error) {
    console.error('Erro ao enviar mensagem de reativa├º├úo:', error);
    return { success: false };
  }
}

/**
 * Executar campanha de reativa├º├úo
 */
export async function runReactivationCampaign(
  daysInactive: number = 15,
  limit: number = 50
): Promise<{
  total: number;
  sent: number;
  failed: number;
}> {
  try {
    const inactiveClients = await getInactiveClients(daysInactive, limit);
    
    let sent = 0;
    let failed = 0;

    for (const client of inactiveClients) {
      const result = await sendReactivationMessage(client);
      
      if (result.success) {
        sent++;
      } else {
        failed++;
      }

      // Delay para n├úo sobrecarregar a API
      await new Promise(resolve => setTimeout(resolve, 1000));
    }

    return {
      total: inactiveClients.length,
      sent,
      failed,
    };
  } catch (error) {
    console.error('Erro ao executar campanha de reativa├º├úo:', error);
    return { total: 0, sent: 0, failed: 0 };
  }
}

/**
 * Agendar campanha de reativa├º├úo autom├ítica
 */
export async function scheduleReactivationCampaign(
  daysInactive: number = 15,
  intervalHours: number = 24
): Promise<void> {
  try {
    // Executar imediatamente
    await runReactivationCampaign(daysInactive);

    // Agendar para executar periodicamente
    setInterval(async () => {
      await runReactivationCampaign(daysInactive);
    }, intervalHours * 60 * 60 * 1000);

    console.log(`Ô£à Campanha de reativa├º├úo agendada a cada ${intervalHours} horas`);
  } catch (error) {
    console.error('Erro ao agendar campanha de reativa├º├úo:', error);
  }
}

