/**
 * Buscar clientes por frequ├¬ncia
 */
export async function getClientsByFrequency(
  barbershopId: string,
  minVisits: number,
  maxVisits: number = 100
): Promise<Client[]> {
  try {
    const { data: appointments, error: appointmentsError } = await (supabase as any)
      .from('appointments')
      .select('client_user_id')
      .eq('barbershop_id', barbershopId);

    if (appointmentsError) {
      console.error('Erro ao buscar clientes:', appointmentsError);
      return [];
    }

    // Contar visitas por cliente
    const clientVisits: Record<string, number> = {};
    appointments?.forEach((a: any) => {
      const clientId = a.client_user_id;
      if (clientId) {
        clientVisits[clientId] = (clientVisits[clientId] || 0) + 1;
      }
    });

    // Filtrar por faixa de visitas
    const filteredClientIds = Object.entries(clientVisits)
      .filter(([, visits]) => visits >= minVisits && visits <= maxVisits)
      .map(([clientId]) => clientId);

    if (filteredClientIds.length === 0) {
      return [];
    }

    const { data, error } = await (supabase as any)
      .from('profiles')
      .select('*')
      .eq('barbershop_id', barbershopId)
      .in('user_id', filteredClientIds);

    if (error) {
      console.error('Erro ao buscar clientes:', error);
      return [];
    }

    return data || [];
  } catch (error) {
    console.error('Erro ao buscar clientes:', error);
    return [];
  }
}

// Servi├ºo de Comiss├úo Multin├¡vel
// Integra├º├úo com estrutura existente (partners, commissions, commission_rules)

import { supabase } from "@/integrations/supabase/client";

export interface CommissionDistribution {
  partner_id: string;
  amount: number;
  percentage: number;
  type: 'adesao' | 'recorrente';
  level: number;
}

/**
 * Distribuir comiss├úo multin├¡vel
 * Quando um pagamento ├® feito, percorre a hierarquia e distribui comiss├Áes
 */
export async function distribuirComissaoMultinivel(
  valor: number,
  partnerId: string,
  sourceUserId: string,
  type: 'adesao' | 'recorrente' = 'adesao'
): Promise<CommissionDistribution[]> {
  try {
    const distribuicoes: CommissionDistribution[] = [];
    let parceiro = await getPartner(partnerId);
    let nivel = 0;

    while (parceiro) {
      // Buscar regra de comiss├úo para este parceiro
      const regra = await getCommissionRule(parceiro, nivel);
      
      if (regra) {
        // Verificar se j├í existe comiss├úo para esta transa├º├úo
        const existe = await alreadyHasCommission(
          parceiro.id, 
          sourceUserId, 
          type
        );

        if (!existe) {
          const valorComissao = valor * (regra.commission_percent / 100);
          
          // Criar comiss├úo
          const { data: comissao, error } = await (supabase as any)
            .from('commissions')
            .insert({
              partner_id: parceiro.id,
              source_user_id: sourceUserId,
              amount: valorComissao,
              type: type,
              status: 'pendente',
            })
            .select()
            .single();

          if (error) {
            console.error('Erro ao criar comiss├úo:', error);
          } else {
            distribuicoes.push({
              partner_id: parceiro.id,
              amount: valorComissao,
              percentage: regra.commission_percent,
              type: type,
              level: nivel,
            });
          }
        }
      }

      // Subir na hierarquia
      if (parceiro.parent_id) {
        parceiro = await getPartner(parceiro.parent_id);
        nivel++;
      } else {
        parceiro = null;
      }
    }

    return distribuicoes;
  } catch (error) {
    console.error('Erro ao distribuir comiss├úo:', error);
    return [];
  }
}

