/**
 * Processar pagamento e distribuir comiss├Áes
 */
export async function processarPagamento(
  barbershopId: string,
  clientId: string,
  valor: number,
  partnerId: string
): Promise<{ success: boolean; distribuicoes: CommissionDistribution[] }> {
  try {
    // Validar dados
    if (!partnerId || valor <= 0) {
      return { success: false, distribuicoes: [] };
    }

    // Criar pagamento
    const { data: pagamento, error: pagError } = await (supabase as any)
      .from('payments')
      .insert({
        barbershop_id: barbershopId,
        client_id: clientId,
        amount: valor,
        method: 'pix',
        status: 'paid',
      })
      .select()
      .single();

    if (pagError) {
      console.error('Erro ao criar pagamento:', pagError);
      return { success: false, distribuicoes: [] };
    }

    // Distribuir comiss├Áes
    const distribuicoes = await distribuirComissaoMultinivel(
      valor,
      partnerId,
      clientId,
      'adesao'
    );

    return { success: true, distribuicoes };
  } catch (error) {
    console.error('Erro ao processar pagamento:', error);
    return { success: false, distribuicoes: [] };
  }
}

