  // Testar Webhooks
  static async testWebhooks(): Promise<IntegrationTest> {
    const test: IntegrationTest = {
      id: 'webhooks',
      name: 'Webhooks Configurados',
      type: 'webhook',
      status: 'running'
    };

    try {
      const startTime = Date.now();

      // Buscar webhooks ativos
      const { data: webhooks, error: webhooksError } = await (supabase as any)
        .from('webhook_configs')
        .select('*')
        .eq('is_active', true);

      if (webhooksError) {
        throw new Error('Erro ao buscar webhooks');
      }

      // Testar cada webhook
      const results = [];
      for (const webhook of webhooks || []) {
        try {
          const { data: testResult } = await (supabase as any).rpc('test_webhook', {
            p_webhook_config_id: webhook.id
          });

          if (testResult && testResult.length > 0) {
            results.push({
              service: webhook.service_name,
              success: testResult[0].success,
              status_code: testResult[0].status_code,
              duration: testResult[0].duration_ms
            });
          }
        } catch (error) {
          results.push({
            service: webhook.service_name,
            success: false,
            error: error.message
          });
        }
      }

      test.status = 'success';
      test.result = {
        total_webhooks: webhooks?.length || 0,
        tested_webhooks: results.length,
        results
      };
      test.duration = Date.now() - startTime;

      toast.success('Webhooks testados com sucesso!');
    } catch (error: any) {
      test.status = 'error';
      test.error = error.message;
      
      toast.error(`Erro nos webhooks: ${error.message}`);
    }

    return test;
  }

  // Executar todos os testes
  static async runAllTests(): Promise<IntegrationTest[]> {
    this.tests = [];

    const tests = [
      this.testPaymentGateway(),
      this.testSMS(),
      this.testEmail(),
      this.testWebhooks()
    ];

    const results = await Promise.all(tests);
    this.tests = results;

    return results;
  }

  // Obter status dos testes
  static getTestResults(): IntegrationTest[] {
    return this.tests;
  }

  // Limpar resultados
  static clearResults(): void {
    this.tests = [];
  }

  // Verificar se todos os testes passaram
  static allTestsPassed(): boolean {
    return this.tests.every(test => test.status === 'success');
  }

  // Obter resumo dos testes
  static getTestSummary(): {
    total: number;
    passed: number;
    failed: number;
    pending: number;
  } {
    const total = this.tests.length;
    const passed = this.tests.filter(t => t.status === 'success').length;
    const failed = this.tests.filter(t => t.status === 'error').length;
    const pending = this.tests.filter(t => t.status === 'pending').length;

    return { total, passed, failed, pending };
  }
}

// Job Queue Service
// Gerenciamento de fila de processamento de mensagens

import { supabase } from '@/integrations/supabase/client';

export type JobType = 'envio_mensagem' | 'reenvio' | 'alerta' | 'verificacao' | 'backup';
export type JobStatus = 'pendente' | 'processando' | 'completo' | 'falhou' | 'cancelado';

export interface Job {
  id: string;
  job_type: JobType;
  job_priority?: number;
  priority?: number;
  payload: Record<string, any>;
  status: JobStatus;
  attempts: number;
  max_attempts: number;
  error_message?: string;
  scheduled_for?: string;
  started_at?: string;
  completed_at?: string;
  created_at: string;
  updated_at?: string;
  [key: string]: any;
}

export interface JobResult {
  success: boolean;
  jobId?: string;
  error?: string;
}

export async function addJob(
  jobType: JobType,
  payload: Record<string, any>,
  priority: number = 0,
  scheduledFor?: Date
): Promise<JobResult> {
  try {
    const { data, error } = await (supabase as any)
      .rpc('add_job_to_queue', {
        p_job_type: jobType,
        p_payload: payload,
        p_priority: priority,
        p_scheduled_for: scheduledFor?.toISOString(),
      })
      .single();

    if (error) throw error;
    return { success: true, jobId: (data as any)?.id || String(data) };
  } catch (error: any) {
    console.error('Erro ao adicionar job:', error);
    return { success: false, error: error.message };
  }
}

export async function addMessageJob(params: {
  barbershopId: string;
  whatsappNumberId: string;
  recipientPhone: string;
  messageContent: string;
  messageType: string;
  professionalId?: string;
  campaignId?: string;
  priority?: number;
}): Promise<JobResult> {
  return addJob(
    'envio_mensagem',
    {
      type: 'send_message',
      ...params,
    },
    params.priority || 0
  );
}

export async function addReenvioJob(params: {
  originalJobId: string;
  reason: string;
  priority?: number;
}): Promise<JobResult> {
  return addJob(
    'reenvio',
    {
      type: 'reenvio',
      ...params,
    },
    params.priority || 5
  );
}

export async function addAlertJob(params: {
  alertType: string;
  barbershopId: string;
  whatsappNumberId: string;
  severity: 'low' | 'medium' | 'high' | 'critical';
  message: string;
  suggestedAction?: string;
}): Promise<JobResult> {
  return addJob(
    'alerta',
    {
      type: 'alert',
      ...params,
    },
    10
  );
}

export async function getJob(jobId: string): Promise<Job | null> {
  try {
    const { data, error } = await (supabase as any)
      .from('job_queue')
      .select('*')
      .eq('id', jobId)
      .single();

    if (error) return null;
    return data;
  } catch {
    return null;
  }
}

export async function getJobsByStatus(
