export async function getCashbackBalance(membershipId: string): Promise<number> {
  try {
    const transactions = await getTransactions(membershipId);

    const earned = transactions
      .filter(t => t.transaction_type === 'cashback_earned')
      .reduce((sum, t) => sum + t.amount, 0);

    const spent = transactions
      .filter(t => ['cashback_redeemed', 'refund'].includes(t.transaction_type))
      .reduce((sum, t) => sum + t.amount, 0);

    return earned - spent;
  } catch (error) {
    console.error('Erro ao calcular saldo:', error);
    return 0;
  }
}

export async function addCashback(params: {
  membership_id: string;
  amount: number;
  description: string;
  order_id?: string;
}): Promise<boolean> {
  try {
    // Buscar saldo atual
    const balance = await getCashbackBalance(params.membership_id);
    const newBalance = balance + params.amount;

    // Registrar transa├º├úo
    const { error } = await (supabase as any)
      .from('membership_transactions')
      .insert({
        membership_id: params.membership_id,
        transaction_type: 'cashback_earned',
        amount: params.amount,
        balance_after: newBalance,
        description: params.description,
      });

    if (error) throw error;

    // Atualizar total no membership
    await (supabase as any)
      .from('memberships')
      .update({ total_cashback_earned: newBalance })
      .eq('id', params.membership_id);

    return true;
  } catch (error) {
    console.error('Erro ao adicionar cashback:', error);
    return false;
  }
}

export async function redeemCashback(params: {
  membership_id: string;
  amount: number;
  description: string;
}): Promise<{ success: boolean; error?: string }> {
  try {
    const balance = await getCashbackBalance(params.membership_id);

    if (params.amount > balance) {
      return { success: false, error: 'Saldo insuficiente de cashback' };
    }

    const newBalance = balance - params.amount;

    const { error } = await (supabase as any)
      .from('membership_transactions')
      .insert({
        membership_id: params.membership_id,
        transaction_type: 'cashback_redeemed',
        amount: params.amount,
        balance_after: newBalance,
        description: params.description,
      });

    if (error) throw error;
    return { success: true };
  } catch (error: any) {
    return { success: false, error: error.message };
  }
}

export async function useReferralCode(referralCode: string, newUserId: string): Promise<{ success: boolean; bonus?: number; error?: string }> {
  try {
    const { data: referrer, error: referrerError } = await (supabase as any)
      .from('memberships')
      .select('*')
      .eq('referral_code', referralCode)
      .eq('status', 'active')
      .single();

    if (referrerError || !referrer) {
      return { success: false, error: 'C├│digo de indica├º├úo inv├ílido' };
    }

    const { data: plan } = await (supabase as any)
      .from('membership_plans')
      .select('cashback_percentage')
      .eq('id', referrer.plan_id)
      .single();

    const bonus = plan?.cashback_percentage || 10;

    await (supabase as any).from('membership_referrals').insert({
      referrer_membership_id: referrer.id,
      referred_user_id: newUserId,
      referral_code_used: referralCode,
      bonus_awarded: bonus,
    });

    await (supabase as any)
      .from('memberships')
      .update({ referral_count: referrer.referral_count + 1 })
      .eq('id', referrer.id);

    await addCashback({
      membership_id: referrer.id,
      amount: bonus,
      description: `B├┤nus por indicar amigo`,
    });

    return { success: true, bonus };
  } catch (error: any) {
