import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

export interface PostAppointmentNotification {
  id: string;
  appointment_id: string;
  professional_id: string;
  notification_type: 'finalization_reminder' | 'cancellation_request';
  sent_at: string | null;
  acknowledged_at: string | null;
  action_taken: string | null;
  created_at: string;
  updated_at: string;
}

export class PostAppointmentNotificationsService {
  // Verificar agendamentos que precisam de notifica├º├úo
  static async checkAppointmentsNeedingNotification(): Promise<void> {
    try {
      const now = new Date();
      const thirtyMinutesAgo = new Date(now.getTime() - 30 * 60 * 1000);
      
      // Buscar agendamentos que terminaram h├í 30 minutos e ainda n├úo foram notificados
      const { data: appointments, error } = await (supabase as any)
        .from("appointments")
        .select(`
          id,
          professional_id,
          scheduled_at,
          services(duration_minutes),
          professionals!inner(
            id,
            name,
            user_id
          )
        `)
        .eq("status", "scheduled")
        .lt("scheduled_at", thirtyMinutesAgo.toISOString())
        .is("post_appointment_notifications.appointment_id", null);

      if (error) {
        console.error("Erro ao buscar agendamentos para notifica├º├úo:", error);
        return;
      }

      // Criar notifica├º├Áes para cada agendamento
      for (const appointment of appointments || []) {
        await this.createNotification(appointment.id, appointment.professional_id, "finalization_reminder");
        
        // Enviar notifica├º├úo push/web se dispon├¡vel
        await this.sendNotificationToProfessional(
          appointment.professionals.user_id,
          "Lembrete de Finaliza├º├úo",
          "Seu atendimento recentemente terminou. Deseja finalizar ou marcar como cancelado?",
          {
            type: "post_appointment",
            appointment_id: appointment.id,
            actions: ["finalize", "cancel"]
          }
        );
      }
    } catch (error) {
      console.error("Erro ao verificar notifica├º├Áes p├│s-atendimento:", error);
    }
  }

  // Criar notifica├º├úo no banco
  static async createNotification(
    appointmentId: string,
    professionalId: string,
    type: 'finalization_reminder' | 'cancellation_request'
  ): Promise<string | null> {
    try {
      const { data, error } = await (supabase as any).rpc('create_post_appointment_notification', {
        p_appointment_id: appointmentId,
        p_professional_id: professionalId,
        p_notification_type: type
      });

      if (error) {
        console.error("Erro ao criar notifica├º├úo:", error);
        return null;
      }

      // Marcar como enviada
      await (supabase as any)
        .from("post_appointment_notifications")
        .update({ sent_at: new Date().toISOString() })
        .eq("id", data);

      return data;
    } catch (error) {
      console.error("Erro ao criar notifica├º├úo:", error);
      return null;
    }
  }

  // Enviar notifica├º├úo para o profissional (simulado - integrar com servi├ºo real)
  static async sendNotificationToProfessional(
    userId: string,
    title: string,
    body: string,
