  ): Promise<void> {
    try {
      // Simular envio de notifica├º├úo
      // Na implementa├º├úo real, integrar com Firebase Cloud Messaging, OneSignal, etc.
      console.log("Notifica├º├úo enviada:", {
        userId,
        title,
        body,
        data,
        timestamp: new Date().toISOString()
      });

      // Poderia tamb├®m enviar por WhatsApp se integrado com Twilio
      // await this.sendWhatsAppNotification(userId, title, body);
    } catch (error) {
      console.error("Erro ao enviar notifica├º├úo:", error);
    }
  }

  // Buscar notifica├º├Áes n├úo lidas do profissional
  static async getUnreadNotifications(professionalId: string): Promise<PostAppointmentNotification[]> {
    try {
      const { data, error } = await (supabase as any)
        .from("post_appointment_notifications")
        .select("*")
        .eq("professional_id", professionalId)
        .is("acknowledged_at", null)
        .order("created_at", { ascending: false });

      if (error) {
        console.error("Erro ao buscar notifica├º├Áes:", error);
        return [];
      }

      return data || [];
    } catch (error) {
      console.error("Erro ao buscar notifica├º├Áes:", error);
      return [];
    }
  }

  // Marcar notifica├º├úo como lida e registrar a├º├úo
  static async acknowledgeNotification(
    notificationId: string,
    action: 'finalized' | 'cancelled' | 'dismissed'
  ): Promise<void> {
    try {
      await (supabase as any)
        .from("post_appointment_notifications")
        .update({
          acknowledged_at: new Date().toISOString(),
          action_taken: action
        })
        .eq("id", notificationId);
    } catch (error) {
      console.error("Erro ao marcar notifica├º├úo como lida:", error);
    }
  }

  // Processar a├º├úo da notifica├º├úo (finalizar ou cancelar atendimento)
  static async processNotificationAction(
    appointmentId: string,
    action: 'finalize' | 'cancel',
    professionalId: string
  ): Promise<boolean> {
    try {
      if (action === 'finalize') {
        // Atualizar status para em_andamento
        const { error } = await (supabase as any)
          .from("appointments")
          .update({
            status: "in_progress",
            updated_at: new Date().toISOString()
          })
          .eq("id", appointmentId)
          .eq("professional_id", professionalId);

        if (error) throw error;

        toast.success("Atendimento marcado como em andamento");
      } else if (action === 'cancel') {
        // Atualizar status para cancelado
        const { error } = await (supabase as any)
          .from("appointments")
          .update({
            status: "cancelled",
            updated_at: new Date().toISOString()
          })
          .eq("id", appointmentId)
          .eq("professional_id", professionalId);

        if (error) throw error;

        toast.success("Atendimento cancelado");
      }

      // Marcar notifica├º├úo correspondente como processada
      const { data: notifications } = await (supabase as any)
        .from("post_appointment_notifications")
        .select("id")
        .eq("appointment_id", appointmentId)
        .eq("professional_id", professionalId)
        .is("acknowledged_at", null);

      if (notifications && notifications.length > 0) {
        await this.acknowledgeNotification(
          notifications[0].id,
          action === 'finalize' ? 'finalized' : 'cancelled'
        );
      }

      return true;
    } catch (error: any) {
      console.error("Erro ao processar a├º├úo:", error);
      toast.error(error.message || "Erro ao processar a├º├úo");
      return false;
    }
  }

  // Iniciar verifica├º├úo autom├ítica de notifica├º├Áes
  static startNotificationChecker(): void {
    // Verificar a cada 5 minutos
    setInterval(() => {
      this.checkAppointmentsNeedingNotification();
    }, 5 * 60 * 1000);

    // Verificar imediatamente ao iniciar
    this.checkAppointmentsNeedingNotification();
  }

  // Enviar notifica├º├úo por WhatsApp (opcional)
  static async sendWhatsAppNotification(
    userId: string,
    title: string,
    message: string
  ): Promise<void> {
    try {
      // Buscar dados do usu├írio
      const { data: profile } = await (supabase as any)
        .from("profiles")
        .select("whatsapp, name")
        .eq("id", userId)
        .single();

      if (profile?.whatsapp) {
        // Integrar com API do Twilio ou similar
        const { error } = await (supabase as any).functions.invoke('send-whatsapp', {
          body: {
            to: profile.whatsapp,
            message: `Ol├í ${profile.name}, ${title}: ${message}`
          }
        });

        if (error) {
          console.error("Erro ao enviar WhatsApp:", error);
        }
      }
    } catch (error) {
      console.error("Erro ao enviar notifica├º├úo WhatsApp:", error);
    }
  }
}

