      `)
      .order('created_at', { ascending: false });

    if (error) {
      // Se a tabela n├úo existir, retorna array vazio (sem quebrar)
      if (error.code === '42P01') {
        console.warn('Tabela partners n├úo existe ainda. Retornando array vazio.');
        return [];
      }
      throw error;
    }

    return data || [];
