  /**
   * Verificar conflitos de hor├írio para agendamento recorrente
   */
  static async checkRecurringConflicts(
    barbershopId: string,
    professionalId: string,
    day: number,
    time: string,
    excludeAppointmentId?: string
  ): Promise<{ hasConflicts: boolean; conflicts: any[] }> {
    try {
      // Buscar agendamentos existentes no mesmo dia/hor├írio
      let query = (supabase as any)
        .from('appointments')
        .select(`
          *,
          services(name),
          professionals(name)
        `)
        .eq('barbershop_id', barbershopId)
        .eq('professional_id', professionalId)
        .eq('recurring_day', day)
        .eq('recurring_time', time)
        .in('status', ['scheduled', 'confirmed'])
        .neq('auto_generated', true);

      if (excludeAppointmentId) {
        query = query.neq('id', excludeAppointmentId);
      }

      const { data, error } = await query;

      if (error) {
        console.error('Erro ao verificar conflitos:', error);
        return { hasConflicts: false, conflicts: [] };
      }

      return { 
        hasConflicts: (data?.length || 0) > 0, 
        conflicts: data || [] 
      };
    } catch (error) {
      console.error('Erro inesperado ao verificar conflitos:', error);
      return { hasConflicts: false, conflicts: [] };
    }
  }

