// Fun├º├Áes utilit├írias
export const RECURRING_TYPES = {
  weekly: { label: 'Semanal', description: 'Toda semana no mesmo dia e hor├írio' },
  biweekly: { label: 'Quinzenal', description: 'A cada 2 semanas no mesmo dia e hor├írio' },
  monthly: { label: 'Mensal', description: 'Todo m├¬s no mesmo dia e hor├írio' }
} as const;

export const WEEKDAYS = {
  1: 'Domingo',
  2: 'Segunda-feira',
  3: 'Ter├ºa-feira',
  4: 'Quarta-feira',
  5: 'Quinta-feira',
  6: 'Sexta-feira',
  7: 'S├íbado'
} as const;

export function formatRecurringDescription(appointment: RecurringAppointment): string {
  if (!appointment.is_recurring) return 'Agendamento ├║nico';

  const type = RECURRING_TYPES[appointment.recurring_type!]?.label || 'Recorrente';
  const day = WEEKDAYS[appointment.recurring_day!] || '';
  const time = appointment.recurring_time || '';
  const endDate = appointment.recurring_end_date ? 
    new Date(appointment.recurring_end_date).toLocaleDateString('pt-BR') : 
    'indefinidamente';

  return `${type} - ${day} ├ás ${time} at├® ${endDate}`;
}

