/**
 * Buscar hor├írios dispon├¡veis
 */
export async function getAvailableSlots(
  barbershopId: string,
  professionalId: string,
  date: Date
): Promise<string[]> {
  try {
    // Buscar agendamentos do dia
    const startOfDay = new Date(date);
    startOfDay.setHours(0, 0, 0, 0);
    
    const endOfDay = new Date(date);
    endOfDay.setHours(23, 59, 59, 999);

    const { data: appointments, error } = await (supabase as any)
      .from('appointments')
      .select('scheduled_at, status')
      .eq('barbershop_id', barbershopId)
      .eq('professional_id', professionalId)
      .gte('scheduled_at', startOfDay.toISOString())
      .lte('scheduled_at', endOfDay.toISOString());

    if (error) {
      console.error('Erro ao buscar agendamentos:', error);
      return [];
    }

    // Gerar slots de 30 em 30 minutos (8h ├ás 20h)
    const slots: string[] = [];
    for (let hour = 8; hour <= 20; hour++) {
      slots.push(`${hour}:00`);
      slots.push(`${hour}:30`);
    }

    // Remover slots ocupados
    const occupiedSlots = (appointments || []).map((a: any) => {
      const date = new Date(a.scheduled_at);
      return `${date.getHours()}:${date.getMinutes()}`;
    });

    return slots.filter(slot => !occupiedSlots.includes(slot));
  } catch (error) {
    console.error('Erro ao buscar hor├írios dispon├¡veis:', error);
    return [];
  }
}

/**
 * Buscar hor├írios dispon├¡veis para um dia espec├¡fico
 */
export async function getAvailableSlotsForDate(
  barbershopId: string,
  professionalId: string,
  date: Date
): Promise<string[]> {
  return getAvailableSlots(barbershopId, professionalId, date);
}

/**
 * Buscar hor├írios dispon├¡veis para uma semana
 */
export async function getAvailableSlotsForWeek(
  barbershopId: string,
  professionalId: string,
  startDate: Date
): Promise<Record<string, string[]>> {
  const slotsByDay: Record<string, string[]> = {};

  for (let i = 0; i < 7; i++) {
    const date = new Date(startDate);
    date.setDate(startDate.getDate() + i);
    
    const dayKey = date.toISOString().split('T')[0];
    slotsByDay[dayKey] = await getAvailableSlots(barbershopId, professionalId, date);
  }

  return slotsByDay;
}

