export const notifyNextInQueue = async (
  barbershopId: string,
  availableSlot: { date: string; time: string; professional_id: string; service_id: string }
): Promise<{ success: boolean; error: string | null; notifiedEntry?: WaitingListEntry }> => {
  try {
    const { data: nextInLine, error: fetchError } = await db
      .from("waiting_list")
      .select("*")
      .eq("barbershop_id", barbershopId)
      .eq("status", "waiting")
      .order("priority", { ascending: true })
      .order("created_at", { ascending: true })
      .limit(1)
      .single();

    if (fetchError || !nextInLine) {
      return { success: false, error: "Nenhum cliente na fila de espera" };
    }

    const expiresAt = new Date();
    expiresAt.setMinutes(expiresAt.getMinutes() + NOTIFICATION_TIMEOUT_MINUTES);

    const clientName = nextInLine.client_name || 'Cliente';
    const message = `Ol├í ${clientName}! Temos um hor├írio dispon├¡vel para voc├¬!\n\n­ƒôà Data: ${availableSlot.date}\n­ƒòÉ Hor├írio: ${availableSlot.time}\n\nPara confirmar seu agendamento, responda *CONFIRMAR* a esta mensagem.\n\nOu responda *MAIS TARDE* para indicar que prefere um hor├írio posterior.\n\nÔÅ░ Esta oferta expira em ${NOTIFICATION_TIMEOUT_MINUTES} minutos.`;

    const { error: updateError } = await db
      .from("waiting_list")
      .update({
        status: "notified",
        notified_at: new Date().toISOString(),
        expires_at: expiresAt.toISOString(),
      })
      .eq("id", nextInLine.id);

    if (updateError) throw updateError;

    // Try to send whatsapp notification (table may not exist yet)
    try {
      await db
        .from("whatsapp_outbound_messages")
        .insert({
          barbershop_id: barbershopId,
          to_number: nextInLine.client_whatsapp,
          message_body: message,
          status: "queued",
        });
    } catch (notifyError: any) {
      console.warn("Erro ao inserir mensagem na fila:", notifyError?.message);
    }

    toast.success(`Notifica├º├úo enviada para ${clientName}!`);

    return { success: true, error: null, notifiedEntry: nextInLine as WaitingListEntry };
  } catch (error: any) {
    console.error("Erro ao notificar pr├│ximo da fila:", error);
    return { success: false, error: error.message };
  }
};

export const confirmFromWaitingList = async (entryId: string): Promise<{ success: boolean; error: string | null }> => {
  return updateWaitingListStatus(entryId, "confirmed");
};

export const expireWaitingListNotification = async (entryId: string): Promise<{ success: boolean; error: string | null }> => {
  try {
    const { error } = await db
      .from("waiting_list")
      .update({ status: "expired", updated_at: new Date().toISOString() })
      .eq("id", entryId);

    if (error) throw error;
    return { success: true, error: null };
  } catch (error: any) {
    console.error("Erro ao expirar notifica├º├úo:", error);
    return { success: false, error: error.message };
  }
};

export const checkExpiredNotifications = async (barbershopId: string): Promise<{ expiredEntries: WaitingListEntry[] }> => {
  try {
    const now = new Date().toISOString();
    const { data, error } = await db
      .from("waiting_list")
      .select("*")
      .eq("barbershop_id", barbershopId)
      .eq("status", "notified")
      .lt("expires_at", now);

    if (error) throw error;

    const expiredEntries = data || [];

    for (const entry of expiredEntries) {
      await expireWaitingListNotification(entry.id);
    }

    return { expiredEntries: expiredEntries as WaitingListEntry[] };
  } catch (error: any) {
    console.error("Erro ao verificar notifica├º├Áes expiradas:", error);
    return { expiredEntries: [] };
  }
};

export const getWaitingListStats = async (barbershopId: string): Promise<{ total: number; waiting: number; notified: number }> => {
  try {
    const { count: total, error: totalError } = await db
      .from("waiting_list")
      .select("*", { count: "exact", head: true })
      .eq("barbershop_id", barbershopId);

    const { count: waiting, error: waitingError } = await db
      .from("waiting_list")
      .select("*", { count: "exact", head: true })
      .eq("barbershop_id", barbershopId)
      .eq("status", "waiting");

    const { count: notified, error: notifiedError } = await db
      .from("waiting_list")
      .select("*", { count: "exact", head: true })
      .eq("barbershop_id", barbershopId)
      .eq("status", "notified");

    if (totalError || waitingError || notifiedError) {
      throw new Error("Erro ao buscar estat├¡sticas");
    }

    return {
      total: total || 0,
      waiting: waiting || 0,
      notified: notified || 0,
    };
  } catch (error) {
    console.error("Erro ao buscar estat├¡sticas:", error);
    return { total: 0, waiting: 0, notified: 0 };
  }
};

// @ts-nocheck
/**
 * WaitlistManager - Sistema de Fila de Espera Inteligente
 * 
 * Gerencia automaticamente:
 * - Entrada de clientes na fila
 * - Libera├º├úo de vagas
 * - Antecipa├º├úo de hor├írios
 * - Pre├ºos din├ómicos
 * - Realoca├º├úo entre profissionais
 */

import { supabase } from "@/integrations/supabase/client";
import { enqueue } from "@/lib/adapters/queue-adapter";

export interface WaitlistEntry {
  id: string;
  barbershop_id: string;
  client_id: string;
  professional_preferred_id: string | null;
  service_id: string;
  desired_date: string;
  desired_time: string;
  accepts_other_professional: boolean;
  accepts_nearby_time: boolean;
  accepts_any_time: boolean;
  position_in_queue: number;
  status: "waiting" | "offered" | "accepted" | "declined" | "expired" | "cancelled";
  offered_at: string | null;
  offered_appointment_id: string | null;
  response_deadline: string | null;
  responded_at: string | null;
  notes: string | null;
  created_at: string;
  updated_at: string;
}

export interface AgendaIntelligenceSettings {
  id: string;
  barbershop_id: string;
  enable_waitlist: boolean;
  allow_professionals_view_queue: boolean;
  allow_professionals_offer_slots: boolean;
  waitlist_response_minutes: number;
  enable_auto_anticipation: boolean;
  anticipation_time_window_hours: number;
  allow_professionals_view_anticipations: boolean;
  enable_dynamic_pricing: boolean;
  allow_professionals_view_dynamic_pricing: boolean;
  enable_reallocation: boolean;
  allow_professionals_reallocation: boolean;
}

export interface DynamicPricingRule {
  id: string;
  barbershop_id: string;
  service_id: string | null;
  day_of_week: number; // 0=Dom, 1=Seg, ..., 6=S├íb
  start_time: string;
  end_time: string;
  price_type: "percentage" | "fixed";
  price_adjustment: number;
  is_active: boolean;
  min_capacity_threshold: number;
  description: string | null;
}

export interface WaitlistOffer {
  waitlist_id: string;
  appointment_id: string | null;
  offer_type: "slot_available" | "anticipation" | "reallocation";
  offered_at: string;
  response_deadline: string;
  response: "accepted" | "declined" | "expired" | null;
  responded_at: string | null;
  notes: string | null;
}

export interface WaitlistPreferences {
  professional_preferred_id: string | null;
  accepts_other_professional: boolean;
  accepts_nearby_time: boolean;
  accepts_any_time: boolean;
  notes?: string;
}

class WaitlistManager {
  /**
   * Adiciona cliente ├á fila de espera
   */
  async addToWaitlist(
    barbershopId: string,
    clientId: string,
    serviceId: string,
    desiredDate: string,
    desiredTime: string,
    preferences: WaitlistPreferences
  ): Promise<{ success: boolean; waitlistId?: string; error?: string }> {
    try {
      // Verificar se fila est├í ativa para esta barbearia
      const settings = await this.getAgendaSettings(barbershopId);
      if (!settings?.enable_waitlist) {
        return { success: false, error: "Fila de espera desativada" };
      }

      // Verificar se cliente j├í est├í na fila para este dia
      const existingEntry = await (supabase as any)
        .from("waitlist_queue")
        .select("id")
        .eq("barbershop_id", barbershopId)
        .eq("client_id", clientId)
        .eq("desired_date", desiredDate)
        .eq("status", "waiting")
        .single();

      if (existingEntry.data) {
        return { success: false, error: "Cliente j├í est├í na fila para esta data" };
      }

      // Inserir na fila
      const { data, error } = await (supabase as any)
        .from("waitlist_queue")
        .insert({
          barbershop_id: barbershopId,
          client_id: clientId,
          professional_preferred_id: preferences.professional_preferred_id,
          service_id: serviceId,
          desired_date: desiredDate,
          desired_time: desiredTime,
          accepts_other_professional: preferences.accepts_other_professional,
          accepts_nearby_time: preferences.accepts_nearby_time,
          accepts_any_time: preferences.accepts_any_time,
          notes: preferences.notes,
        })
        .select("id")
        .single();

      if (error) {
        console.error("[WAITLIST] Error adding to waitlist:", error);
        return { success: false, error: error.message };
      }

      // Enviar notifica├º├úo de confirma├º├úo
      await this.sendWaitlistConfirmation(data.id, clientId);

      return { success: true, waitlistId: data.id };
    } catch (error) {
      console.error("[WAITLIST] Unexpected error:", error);
      return { success: false, error: "Erro interno" };
    }
  }

  /**
   * Remove cliente da fila
   */
  async removeFromWaitlist(waitlistId: string, clientId: string): Promise<{ success: boolean; error?: string }> {
    try {
      const { error } = await (supabase as any)
        .from("waitlist_queue")
        .update({ status: "cancelled" })
        .eq("id", waitlistId)
        .eq("client_id", clientId);

      if (error) {
        console.error("[WAITLIST] Error removing from waitlist:", error);
        return { success: false, error: error.message };
      }

      return { success: true };
    } catch (error) {
      console.error("[WAITLIST] Unexpected error:", error);
      return { success: false, error: "Erro interno" };
    }
  }

  /**
   * Processa libera├º├úo de vaga automaticamente
   */
  async processSlotRelease(
    barbershopId: string,
    availableDate: string,
    availableTime: string,
    professionalId: string | null = null,
    serviceId: string | null = null
  ): Promise<{ processed: boolean; nextClientId?: string }> {
    try {
      const settings = await this.getAgendaSettings(barbershopId);
      if (!settings?.enable_waitlist) {
        return { processed: false };
      }

      // Buscar pr├│ximo cliente eleg├¡vel
      const { data: clients } = await (supabase as any).rpc("find_next_waitlist_client", {
        p_barbershop_id: barbershopId,
        p_available_date: availableDate,
        p_available_time: availableTime,
        p_professional_id: professionalId,
        p_service_id: serviceId,
      });

      if (!clients || clients.length === 0) {
        return { processed: false };
      }

      const nextClient = clients[0];
      
      // Criar oferta para o cliente
      const deadline = new Date();
      deadline.setMinutes(deadline.getMinutes() + settings.waitlist_response_minutes);

      const { error: offerError } = await (supabase as any)
        .from("waitlist_queue")
        .update({
          status: "offered",
          offered_at: new Date().toISOString(),
          response_deadline: deadline.toISOString(),
        })
        .eq("id", nextClient.waitlist_id);

      if (offerError) {
        console.error("[WAITLIST] Error creating offer:", offerError);
        return { processed: false };
      }

      // Registrar hist├│rico da oferta
      await (supabase as any)
        .from("waitlist_offer_history")
        .insert({
          waitlist_id: nextClient.waitlist_id,
          offer_type: "slot_available",
          response_deadline: deadline.toISOString(),
        });

      // Enviar notifica├º├úo ao cliente
      await this.sendSlotOffer(nextClient.waitlist_id, availableDate, availableTime, professionalId);

      return { processed: true, nextClientId: nextClient.client_id };
    } catch (error) {
      console.error("[WAITLIST] Error processing slot release:", error);
      return { processed: false };
    }
  }

  /**
   * Processa resposta do cliente ├á oferta
   */
  async processOfferResponse(
    waitlistId: string,
    response: "accepted" | "declined",
    appointmentId?: string
  ): Promise<{ success: boolean; error?: string }> {
    try {
      // Atualizar status na fila
      const { error: updateError } = await (supabase as any)
        .from("waitlist_queue")
        .update({
          status: response,
          responded_at: new Date().toISOString(),
          offered_appointment_id: appointmentId || null,
        })
        .eq("id", waitlistId);

      if (updateError) {
        console.error("[WAITLIST] Error updating response:", updateError);
        return { success: false, error: updateError.message };
      }

      // Atualizar hist├│rico
      await (supabase as any)
        .from("waitlist_offer_history")
        .update({
          response,
          responded_at: new Date().toISOString(),
          appointment_id: appointmentId || null,
        })
        .eq("waitlist_id", waitlistId)
        .eq("response", "expired") // Apenas o mais recente sem resposta
        .is("response", null);

      // Se aceitou, criar agendamento
      if (response === "accepted" && appointmentId) {
        await this.createAppointmentFromOffer(waitlistId, appointmentId);
      }

      // Se recusou, processar pr├│ximo cliente
      if (response === "declined") {
        await this.processNextInLine(waitlistId);
      }

      return { success: true };
    } catch (error) {
      console.error("[WAITLIST] Error processing response:", error);
      return { success: false, error: "Erro interno" };
    }
  }

  /**
   * Processa ofertas expiradas
   */
  async processExpiredOffers(): Promise<{ processed: number }> {
    try {
      const now = new Date().toISOString();

      // Buscar ofertas expiradas
      const { data: expiredOffers } = await (supabase as any)
        .from("waitlist_queue")
        .select("id, barbershop_id")
        .eq("status", "offered")
        .lt("response_deadline", now);

      if (!expiredOffers || expiredOffers.length === 0) {
        return { processed: 0 };
      }

      let processed = 0;

      for (const offer of expiredOffers) {
        // Marcar como expirado
        await (supabase as any)
          .from("waitlist_queue")
          .update({
            status: "expired",
            responded_at: now,
          })
          .eq("id", offer.id);

        // Atualizar hist├│rico
        await (supabase as any)
          .from("waitlist_offer_history")
          .update({
            response: "expired",
            responded_at: now,
          })
          .eq("waitlist_id", offer.id)
          .is("response", null);

        // Processar pr├│ximo da fila
        await this.processNextInLine(offer.id);

        processed++;
      }

      return { processed };
    } catch (error) {
      console.error("[WAITLIST] Error processing expired offers:", error);
      return { processed: 0 };
    }
  }

  /**
   * Calcula pre├ºo din├ómico para um servi├ºo
   */
  async calculateDynamicPrice(
    barbershopId: string,
    serviceId: string,
    date: string,
    time: string,
    basePrice: number
  ): Promise<{ finalPrice: number; adjustment?: number; rule?: DynamicPricingRule }> {
    try {
      const settings = await this.getAgendaSettings(barbershopId);
      if (!settings?.enable_dynamic_pricing) {
        return { finalPrice: basePrice };
      }

      // Usar fun├º├úo do banco para calcular pre├ºo
      const { data, error } = await (supabase as any).rpc("calculate_dynamic_price", {
        p_barbershop_id: barbershopId,
        p_service_id: serviceId,
        p_date: date,
        p_time: time,
        p_base_price: basePrice,
      });

      if (error) {
        console.error("[WAITLIST] Error calculating dynamic price:", error);
        return { finalPrice: basePrice };
      }

      const finalPrice = Number(data);
      const adjustment = finalPrice - basePrice;

      return { finalPrice, adjustment: adjustment !== 0 ? adjustment : undefined };
    } catch (error) {
      console.error("[WAITLIST] Error calculating dynamic price:", error);
      return { finalPrice: basePrice };
    }
  }

  /**
   * Busca configura├º├Áes de intelig├¬ncia de agenda
   */
  async getAgendaSettings(barbershopId: string): Promise<AgendaIntelligenceSettings | null> {
    try {
      const { data, error } = await (supabase as any)
        .from("agenda_intelligence_settings")
        .select("*")
        .eq("barbershop_id", barbershopId)
        .single();

      if (error) {
        console.error("[WAITLIST] Error getting settings:", error);
        return null;
      }

      return data;
    } catch (error) {
      console.error("[WAITLIST] Error getting settings:", error);
      return null;
    }
  }

  /**
   * Atualiza configura├º├Áes de intelig├¬ncia de agenda
   */
  async updateAgendaSettings(
