        `)
        .eq("waitlist_queue.client_id", clientId)
        .order("offered_at", { ascending: false });

      if (error) {
        console.error("[WAITLIST] Error getting offer history:", error);
        return [];
      }

      return data || [];
    } catch (error) {
      console.error("[WAITLIST] Error getting offer history:", error);
      return [];
    }
  }

