          offerCreated: updatedWaitlist.status === "offered"
        };
      }
    ));
    
    // Test 2: Fluxo de antecipa├º├úo completa
    tests.push(await this.runTest(
      "Fluxo completo - Antecipa├º├úo autom├ítica",
