export async function getInactiveClientsForCampaign(
  barbershopId: string,
  daysInactive: number = 15,
  limit: number = 100
): Promise<Array<{
  user_id: string;
  name: string;
  whatsapp: string;
  professional_id?: string;
  days_inactive: number;
  total_visits: number;
  favorite_service?: string;
}>> {
  try {
    const cutoffDate = new Date();
    cutoffDate.setDate(cutoffDate.getDate() - daysInactive);

    const { data: appointments } = await (supabase as any)
      .from('appointments')
      .select('client_user_id, client_name, client_whatsapp, scheduled_at, professionals(id)')
      .eq('barbershop_id', barbershopId)
      .eq('status', 'completed')
      .lte('scheduled_at', cutoffDate.toISOString())
      .order('scheduled_at', { ascending: false });

    const clientMap = new Map<string, any>();

    appointments?.forEach((apt: any) => {
      if (!apt.client_user_id) return;

      if (!clientMap.has(apt.client_user_id)) {
        clientMap.set(apt.client_user_id, {
          user_id: apt.client_user_id,
          name: apt.client_name,
          whatsapp: apt.client_whatsapp,
          professional_id: apt.professionals?.id,
          visits: [],
        });
      }
      clientMap.get(apt.client_user_id).visits.push(new Date(apt.scheduled_at));
    });

    const result: Array<{
      user_id: string;
      name: string;
      whatsapp: string;
      professional_id?: string;
      days_inactive: number;
      total_visits: number;
      favorite_service?: string;
    }> = [];

    for (const [userId, client] of clientMap.entries()) {
      if (client.whatsapp && client.whatsapp.length > 10) {
        const lastVisit = client.visits[0];
        const daysInactive = Math.floor(
          (new Date().getTime() - lastVisit.getTime()) / (1000 * 60 * 60 * 24)
        );

        result.push({
          user_id: client.user_id,
          name: client.name,
          whatsapp: client.whatsapp,
          professional_id: client.professional_id,
          days_inactive: daysInactive,
          total_visits: client.visits.length,
        });
      }
    }

    return result.slice(0, limit);
  } catch (error) {
    console.error('Erro ao buscar clientes inativos:', error);
    return [];
  }
}

// WhatsApp Worker Service
// Processamento ass├¡ncrono da fila de mensagens

import { supabase } from '@/integrations/supabase/client';
import {
  getNextAvailableNumber,
  registerUsage,
  WhatsAppNumber,
} from './messageBalanceService';
import {
  getJob,
  markJobAsProcessing,
  markJobAsComplete,
  markJobAsFailed,
  addReenvioJob,
  Job,
} from './jobQueueService';
import { createAlert } from './blockingAlertService';
import { sendWhatsAppMessage } from './twilioIntegrationService';

interface SendMessagePayload {
  type: string;
  barbershopId: string;
  whatsappNumberId: string;
  recipientPhone: string;
  messageContent: string;
  messageType: string;
  professionalId?: string;
  campaignId?: string;
}

export interface WorkerResult {
  success: boolean;
  processed: number;
  failed: number;
  errors: string[];
}

const PROCESSING_INTERVAL = 5000;

let isRunning = false;
let intervalId: ReturnType<typeof setInterval> | null = null;

export async function processNextJob(): Promise<{
  success: boolean;
  jobId?: string;
  error?: string;
}> {
  try {
    const { data: jobs, error } = await (supabase as any)
      .from('job_queue')
      .select('*')
      .eq('status', 'pendente')
      .is('scheduled_for', null)
      .lt('attempts', 3)
      .order('job_priority', { ascending: false })
      .order('created_at', { ascending: true })
      .limit(1);

    if (error) throw error;

    const job = jobs?.[0];
    if (!job) {
      return { success: true };
    }

    await markJobAsProcessing(job.id);

    if (job.job_type === 'envio_mensagem') {
      return await processSendMessageJob(job);
    } else if (job.job_type === 'reenvio') {
      return await processReenvioJob(job);
    } else if (job.job_type === 'alerta') {
      return await processAlertJob(job);
    } else {
      await markJobAsComplete(job.id);
      return { success: true, jobId: job.id };
    }
  } catch (error: any) {
    console.error('Erro ao processar job:', error);
    return { success: false, error: error.message };
  }
}

async function processSendMessageJob(job: Job): Promise<{
  success: boolean;
  jobId?: string;
  error?: string;
}> {
  const payload = job.payload as SendMessagePayload;

  try {
    let numberInfo: WhatsAppNumber | null = null;
    let selectedNumberId: string | null = null;

    if (payload.whatsappNumberId) {
      selectedNumberId = payload.whatsappNumberId;
    } else {
      const numberResult = await getNextAvailableNumber(payload.barbershopId);
      if (!numberResult.success || !numberResult.number) {
        await createAlert({
          barbershopId: payload.barbershopId,
          whatsappNumberId: '',
          alertType: 'no_available_numbers',
          severity: 'high',
          message: 'Nenhum n├║mero de WhatsApp dispon├¡vel para envio',
          suggestedAction: 'Verifique se h├í n├║meros cadastrados e ativos',
        });

        await markJobAsFailed(job.id, 'Nenhum n├║mero dispon├¡vel');
        return { success: false, jobId: job.id, error: 'Nenhum n├║mero dispon├¡vel' };
      }
      numberInfo = numberResult.number as WhatsAppNumber;
      selectedNumberId = numberInfo.id;
    }

    const result = await sendWhatsAppMessage({
      accountId: payload.whatsappNumberId || (numberInfo?.whatsapp_account_id || ''),
      to: payload.recipientPhone,
      body: payload.messageContent,
      professionalId: payload.professionalId,
      messageType: payload.messageType as any,
      campaignId: payload.campaignId,
    });

    if (result.success) {
      if (selectedNumberId) {
        await registerUsage(selectedNumberId, true);
      }

      await logSendAttempt({
        whatsappAccountId: payload.whatsappNumberId || (numberInfo?.whatsapp_account_id || ''),
        phoneNumber: payload.recipientPhone,
        recipientPhone: payload.recipientPhone,
        messageType: payload.messageType,
        status: 'success',
      });

      await markJobAsComplete(job.id);
      return { success: true, jobId: job.id };
    } else {
      if (selectedNumberId) {
        await registerUsage(selectedNumberId, false, result.error);

        if (result.error?.toLowerCase().includes('blocked') ||
            result.error?.toLowerCase().includes('bloqueado')) {
          await createAlert({
            barbershopId: payload.barbershopId,
            whatsappNumberId: selectedNumberId,
            alertType: 'blocked',
            severity: 'critical',
            message: `N├║mero bloqueado: ${result.error}`,
            suggestedAction: 'Substitua o n├║mero bloqueado ou aguarde o per├¡odo de cooldown',
          });
        }
      }

      await logSendAttempt({
        whatsappAccountId: payload.whatsappNumberId || (numberInfo?.whatsapp_account_id || ''),
        phoneNumber: payload.recipientPhone,
        recipientPhone: payload.recipientPhone,
        messageType: payload.messageType,
        status: 'failed',
        errorReason: result.error,
      });

      await addReenvioJob({
        originalJobId: job.id,
        reason: result.error || 'Erro desconhecido',
      });

      await markJobAsFailed(job.id, result.error || 'Erro desconhecido');
      return { success: false, jobId: job.id, error: result.error };
    }
  } catch (error: any) {
    console.error('Erro ao processar job de envio:', error);
    await markJobAsFailed(job.id, error.message);
    return { success: false, jobId: job.id, error: error.message };
  }
}

async function processReenvioJob(job: Job): Promise<{
  success: boolean;
  jobId?: string;
  error?: string;
}> {
  try {
    const originalJob = await getJob(job.payload.originalJobId);
    if (!originalJob) {
      await markJobAsFailed(job.id, 'Job original n├úo encontrado');
      return { success: false, jobId: job.id, error: 'Job original n├úo encontrado' };
    }

    if (originalJob.attempts >= originalJob.max_attempts) {
      await markJobAsComplete(job.id);
      return { success: true, jobId: job.id };
    }

    const payload = originalJob.payload as SendMessagePayload;
    const numberResult = await getNextAvailableNumber(payload.barbershopId);

    if (!numberResult.success || !numberResult.number) {
      await markJobAsFailed(job.id, 'Nenhum n├║mero dispon├¡vel para reenvio');
      return { success: false, jobId: job.id, error: 'Nenhum n├║mero dispon├¡vel' };
    }

    const numberInfo = numberResult.number as WhatsAppNumber;

    const result = await sendWhatsAppMessage({
      accountId: numberInfo.whatsapp_account_id,
      to: payload.recipientPhone,
      body: payload.messageContent,
      professionalId: payload.professionalId,
      messageType: payload.messageType as any,
      campaignId: payload.campaignId,
    });

    if (result.success) {
      await registerUsage(numberInfo.id, true);
      await markJobAsComplete(job.id);
      return { success: true, jobId: job.id };
    } else {
      await registerUsage(numberInfo.id, false, result.error);

      if (result.error?.toLowerCase().includes('blocked')) {
        await createAlert({
          barbershopId: payload.barbershopId,
          whatsappNumberId: numberInfo.id,
          alertType: 'blocked',
          severity: 'critical',
          message: `N├║mero bloqueado durante reenvio: ${result.error}`,
          suggestedAction: 'Verifique o n├║mero e tente novamente com outro',
        });
      }

      await markJobAsFailed(job.id, result.error);
      return { success: false, jobId: job.id, error: result.error };
    }
  } catch (error: any) {
    console.error('Erro ao processar reenvio:', error);
    await markJobAsFailed(job.id, error.message);
    return { success: false, jobId: job.id, error: error.message };
  }
}

async function processAlertJob(job: Job): Promise<{
  success: boolean;
  jobId?: string;
  error?: string;
}> {
  try {
    await markJobAsComplete(job.id);
    return { success: true, jobId: job.id };
  } catch (error: any) {
    console.error('Erro ao processar alerta:', error);
    await markJobAsFailed(job.id, error.message);
    return { success: false, jobId: job.id, error: error.message };
  }
}

async function logSendAttempt(params: {
  whatsappAccountId: string;
  phoneNumber: string;
  recipientPhone: string;
  messageType: string;
  status: 'success' | 'failed' | 'blocked';
  errorReason?: string;
}): Promise<void> {
  try {
    await (supabase as any).from('message_sending_logs').insert({
      whatsapp_account_id: params.whatsappAccountId || null,
      phone_number: params.phoneNumber,
      recipient_phone: params.recipientPhone,
      message_type: params.messageType,
      status: params.status,
      error_reason: params.errorReason,
      sent_at: new Date().toISOString(),
    });
  } catch (error) {
    console.error('Erro ao registrar log de envio:', error);
  }
}

export async function startWorker(): Promise<void> {
  if (isRunning) {
    console.log('[Worker] J├í est├í em execu├º├úo');
    return;
  }

  isRunning = true;
  console.log('[Worker] Iniciando processamento de fila...');

  const processJobs = async () => {
    if (!isRunning) return;

    try {
      const result = await processNextJob();
      if (!result.success && result.error) {
        console.error('[Worker] Erro ao processar job:', result.error);
      }
    } catch (error) {
      console.error('[Worker] Erro no loop de processamento:', error);
    }
  };

  await processJobs();
  intervalId = setInterval(processJobs, PROCESSING_INTERVAL);
}

export function stopWorker(): void {
  if (intervalId) {
    clearInterval(intervalId);
    intervalId = null;
  }
  isRunning = false;
  console.log('[Worker] Parado');
}

export function isWorkerRunning(): boolean {
  return isRunning;
}

export async function processAllPendingJobs(maxJobs: number = 50): Promise<WorkerResult> {
  let processed = 0;
  let failed = 0;
  const errors: string[] = [];

  for (let i = 0; i < maxJobs; i++) {
    const result = await processNextJob();
    if (result.success) {
      if (result.jobId) processed++;
    } else {
      failed++;
      if (result.error) errors.push(result.error);
    }

    if (!result.jobId) break;
  }

  return {
    success: failed === 0,
    processed,
    failed,
    errors,
  };
}

