// @ts-nocheck
import { supabase } from "@/integrations/supabase/client";
import {
  getConversation,
  createConversation,
  updateConversation,
  endConversation,
  getMessageTemplate,
  formatMessage,
  WhatsappConversation,
} from "./whatsappConversationService";
import { toast } from "sonner";

// Importar servi├ºos existentes para interagir com o banco de dados
import { getClientByWhatsApp, createClient, Client } from "@/services/clientService";
import { getServices, Service } from "@/services/serviceService";
import { getProfessionals, Professional } from "@/services/professionalService";
import { createAppointment, getClientAppointments, cancelAppointment, getAvailableSlotsForDate } from "@/services/schedulingService";


export const handleIncomingWhatsappMessage = async (
  barbershopId: string,
  clientWhatsapp: string,
  messageBody: string
): Promise<string> => {
  let conversation = await getConversation(barbershopId, clientWhatsapp);
  let responseMessage = "";
  let clientName = conversation?.conversation_state?.client_name || "Cliente";

  // Se n├úo h├í conversa ativa, ou se a conversa expirou, iniciar uma nova
  if (!conversation || !conversation.is_active || (new Date().getTime() - new Date(conversation.last_message_at).getTime() > 30 * 60 * 1000)) {
    conversation = await createConversation(barbershopId, clientWhatsapp);
    if (!conversation) {
      return "Desculpe, n├úo consegui iniciar a conversa. Por favor, tente novamente mais tarde.";
    }
    const welcomeTemplate = await getMessageTemplate(barbershopId, "welcome_message");
    responseMessage = formatMessage(welcomeTemplate?.template_content || "Ol├í {client_name}! Bem-vindo(a). Como posso ajudar?\n1. Agendar\n2. Ver Agendamentos\n3. Cancelar", { client_name: clientName });
    await updateConversation(conversation.id, { current_step: "initial", conversation_state: { client_name: clientName } });
    return responseMessage;
  }

  // Atualizar last_message_at
  await updateConversation(conversation.id, { last_message_at: new Date().toISOString() });

  // Processar a mensagem com base no current_step
  switch (conversation.current_step) {
    case "initial":
      responseMessage = await handleInitialStep(conversation, messageBody);
      break;
    case "ask_service":
      responseMessage = await handleAskServiceStep(conversation, messageBody);
      break;
    case "ask_date":
      responseMessage = await handleAskDateStep(conversation, messageBody);
      break;
    case "ask_time":
      responseMessage = await handleAskTimeStep(conversation, messageBody);
      break;
    case "ask_professional":
      responseMessage = await handleAskProfessionalStep(conversation, messageBody);
      break;
    case "confirm_booking":
      responseMessage = await handleConfirmBookingStep(conversation, messageBody);
      break;
    case "view_bookings":
      responseMessage = await handleViewBookingsStep(conversation, messageBody);
      break;
    case "cancel_booking_select":
      responseMessage = await handleCancelBookingSelectStep(conversation, messageBody);
      break;
    case "cancel_booking_confirm":
      responseMessage = await handleCancelBookingConfirmStep(conversation, messageBody);
      break;
    default:
      const invalidInputTemplate = await getMessageTemplate(barbershopId, "invalid_input");
      responseMessage = formatMessage(invalidInputTemplate?.template_content || "Desculpe, n├úo entendi. Tente novamente.", { client_name: clientName });
      await updateConversation(conversation.id, { current_step: "initial" });
      break;
  }

  return responseMessage;
};

const handleInitialStep = async (conversation: WhatsappConversation, messageBody: string): Promise<string> => {
  const barbershopId = conversation.barbershop_id;
  const clientName = conversation.conversation_state?.client_name || "Cliente";

  switch (messageBody.trim()) {
    case "1":
      const services = await getServices(barbershopId);
      const serviceList = services.map((s, i) => `${i + 1}. ${s.name}`).join("\n");
      await updateConversation(conversation.id, {
        current_step: "ask_service",
        conversation_state: { ...conversation.conversation_state, services, client_name: clientName },
      });
      const askServiceTemplate = await getMessageTemplate(barbershopId, "ask_service");
      return formatMessage(askServiceTemplate?.template_content || "Qual servi├ºo voc├¬ gostaria de agendar?\n{service_list}", { client_name: clientName, service_list: serviceList });
    case "2":
      await updateConversation(conversation.id, { current_step: "view_bookings" });
      return handleViewBookingsStep(conversation, messageBody);
    case "3":
      await updateConversation(conversation.id, { current_step: "cancel_booking_select" });
      return handleCancelBookingSelectStep(conversation, messageBody);
    case "4":
      await endConversation(conversation.id);
      return "Ok, {client_name}. Um de nossos atendentes entrar├í em contato em breve.".replace("{client_name}", clientName);
    default:
      const invalidInputTemplate = await getMessageTemplate(barbershopId, "invalid_input");
      return formatMessage(invalidInputTemplate?.template_content || "Desculpe, n├úo entendi. Tente novamente.", { client_name: clientName });
  }
};

const handleAskServiceStep = async (conversation: WhatsappConversation, messageBody: string): Promise<string> => {
  const barbershopId = conversation.barbershop_id;
  const clientName = conversation.conversation_state?.client_name || "Cliente";
  const services = conversation.conversation_state?.services || [];
  const serviceIndex = parseInt(messageBody.trim()) - 1;

  if (serviceIndex >= 0 && serviceIndex < services.length) {
    const selectedService = services[serviceIndex];
    await updateConversation(conversation.id, {
      current_step: "ask_date",
      conversation_state: { ...conversation.conversation_state, selectedService },
    });
    const askDateTemplate = await getMessageTemplate(barbershopId, "ask_date");
    return formatMessage(askDateTemplate?.template_content || "Para qual data, {client_name}? (Ex: DD/MM/AAAA)", { client_name: clientName });
  } else {
    const invalidInputTemplate = await getMessageTemplate(barbershopId, "invalid_input");
    return formatMessage(invalidInputTemplate?.template_content || "Servi├ºo inv├ílido. Por favor, escolha um n├║mero da lista.", { client_name: clientName });
  }
};

const handleAskDateStep = async (conversation: WhatsappConversation, messageBody: string): Promise<string> => {
  const barbershopId = conversation.barbershop_id;
  const clientName = conversation.conversation_state?.client_name || "Cliente";
  const dateRegex = /^(\d{2})\/(\d{2})\/(\d{4})$/;

  if (dateRegex.test(messageBody.trim())) {
    const [day, month, year] = messageBody.trim().split('/').map(Number);
    const date = new Date(year, month - 1, day);

    if (isNaN(date.getTime())) {
      const invalidInputTemplate = await getMessageTemplate(barbershopId, "invalid_input");
      return formatMessage(invalidInputTemplate?.template_content || "Data inv├ílida. Por favor, use o formato DD/MM/AAAA.", { client_name: clientName });
    }

    await updateConversation(conversation.id, {
      current_step: "ask_time",
      conversation_state: { ...conversation.conversation_state, selectedDate: date.toISOString().split('T')[0] },
    });
    const askTimeTemplate = await getMessageTemplate(barbershopId, "ask_time");
    return formatMessage(askTimeTemplate?.template_content || "E qual hor├írio, {client_name}? (Ex: HH:MM)", { client_name: clientName });
  } else {
    const invalidInputTemplate = await getMessageTemplate(barbershopId, "invalid_input");
    return formatMessage(invalidInputTemplate?.template_content || "Data inv├ílida. Por favor, use o formato DD/MM/AAAA.", { client_name: clientName });
  }
};

const handleAskTimeStep = async (conversation: WhatsappConversation, messageBody: string): Promise<string> => {
  const barbershopId = conversation.barbershop_id;
  const clientName = conversation.conversation_state?.client_name || "Cliente";
  const timeRegex = /^([01]\d|2[0-3]):([0-5]\d)$/;

  if (timeRegex.test(messageBody.trim())) {
    const selectedTime = messageBody.trim();
    await updateConversation(conversation.id, {
      current_step: "ask_professional",
      conversation_state: { ...conversation.conversation_state, selectedTime },
    });
    const askProfessionalTemplate = await getMessageTemplate(barbershopId, "ask_professional");
    return formatMessage(askProfessionalTemplate?.template_content || "Com qual profissional, {client_name}? (Se tiver prefer├¬ncia)", { client_name: clientName });
  } else {
    const invalidInputTemplate = await getMessageTemplate(barbershopId, "invalid_input");
    return formatMessage(invalidInputTemplate?.template_content || "Hor├írio inv├ílido. Por favor, use o formato HH:MM.", { client_name: clientName });
  }
};

const handleAskProfessionalStep = async (conversation: WhatsappConversation, messageBody: string): Promise<string> => {
  const barbershopId = conversation.barbershop_id;
  const clientName = conversation.conversation_state?.client_name || "Cliente";
  const { selectedService, selectedDate, selectedTime } = conversation.conversation_state;

  const professionalName = messageBody.trim();
  let selectedProfessional = null;

  if (professionalName && professionalName.toLowerCase() !== "pular") {
    const professionals = await getProfessionals(barbershopId);
    selectedProfessional = professionals.find(p => p.name.toLowerCase() === professionalName.toLowerCase());
    if (!selectedProfessional) {
      const invalidInputTemplate = await getMessageTemplate(barbershopId, "invalid_input");
      return formatMessage(invalidInputTemplate?.template_content || "Profissional n├úo encontrado. Por favor, digite o nome correto ou 'pular'.", { client_name: clientName });
    }
  }

  const availableSlots = await getAvailableSlotsForDate(
    barbershopId,
    selectedProfessional?.id || "",
    new Date(selectedDate)
  );

  if (availableSlots.includes(selectedTime)) {
    await updateConversation(conversation.id, {
      current_step: "confirm_booking",
      conversation_state: { ...conversation.conversation_state, selectedProfessional, availableSlots },
    });
    const confirmationTemplate = await getMessageTemplate(barbershopId, "booking_confirmation");
    return formatMessage(
      confirmationTemplate?.template_content || "Confirma seu agendamento de {service_name} com {professional_name} para {date} ├ás {time}? (Sim/N├úo)",
      {
        client_name: clientName,
        service_name: selectedService.name,
        professional_name: selectedProfessional?.name || "qualquer profissional",
        date: selectedDate,
        time: selectedTime,
      }
    );
  } else {
    const noSlotsTemplate = await getMessageTemplate(barbershopId, "no_slots_available");
    await endConversation(conversation.id);
    return formatMessage(noSlotsTemplate?.template_content || "Desculpe, n├úo h├í hor├írios dispon├¡veis para {service_name} com {professional_name} em {date} ├ás {time}. Gostaria de tentar outra data/hor├írio?", {
      client_name: clientName,
      service_name: selectedService.name,
      professional_name: selectedProfessional?.name || "o profissional escolhido",
      date: selectedDate,
      time: selectedTime,
    });
  }
};

const handleConfirmBookingStep = async (conversation: WhatsappConversation, messageBody: string): Promise<string> => {
  const barbershopId = conversation.barbershop_id;
  const clientWhatsapp = conversation.client_whatsapp;
  const clientName = conversation.conversation_state?.client_name || "Cliente";
  const { selectedService, selectedDate, selectedTime, selectedProfessional } = conversation.conversation_state;

  if (messageBody.trim().toLowerCase() === "sim") {
    let client = await getClientByWhatsApp(clientWhatsapp);
    if (!client) {
      client = await createClient({ name: clientName, whatsapp: clientWhatsapp });
    }

    if (!client) {
      await endConversation(conversation.id);
      return "Desculpe, {client_name}, n├úo foi poss├¡vel criar seu cadastro. Por favor, tente novamente.".replace("{client_name}", clientName);
    }

    const result = await createAppointment(
      barbershopId,
      selectedProfessional?.id || "",
      selectedService.id,
      client.id,
      client.name,
      client.whatsapp || clientWhatsapp,
      new Date(`${selectedDate}T${selectedTime}:00Z`)
    );

    if (result) {
      await endConversation(conversation.id);
      const confirmationTemplate = await getMessageTemplate(barbershopId, "booking_confirmation");
      return formatMessage(confirmationTemplate?.template_content || "Seu agendamento de {service_name} com {professional_name} para {date} ├ás {time} foi confirmado. Te esperamos!", {
        client_name: clientName,
        service_name: selectedService.name,
        professional_name: selectedProfessional?.name || "qualquer profissional",
        date: selectedDate,
        time: selectedTime,
      });
    } else {
      await endConversation(conversation.id);
      return "Desculpe, {client_name}, houve um erro ao confirmar seu agendamento. Por favor, tente novamente mais tarde.".replace("{client_name}", clientName);
    }
  } else if (messageBody.trim().toLowerCase() === "n├úo") {
    await endConversation(conversation.id);
    return "Agendamento cancelado. {client_name}, se precisar de algo mais, ├® s├│ chamar!".replace("{client_name}", clientName);
  } else {
    const invalidInputTemplate = await getMessageTemplate(barbershopId, "invalid_input");
    return formatMessage(invalidInputTemplate?.template_content || "Por favor, responda 'Sim' ou 'N├úo'.", { client_name: clientName });
  }
};

const handleViewBookingsStep = async (conversation: WhatsappConversation, messageBody: string): Promise<string> => {
  const barbershopId = conversation.barbershop_id;
  const clientWhatsapp = conversation.client_whatsapp;
  const clientName = conversation.conversation_state?.client_name || "Cliente";

  let client = await getClientByWhatsApp(clientWhatsapp);
  if (!client) {
    await endConversation(conversation.id);
    return "Ol├í {client_name}, n├úo encontramos nenhum agendamento para este n├║mero. Voc├¬ j├í se cadastrou?".replace("{client_name}", clientName);
  }

  const bookings = await getClientAppointments(client.id);

  if (bookings.length === 0) {
    await endConversation(conversation.id);
    return "Ol├í {client_name}, voc├¬ n├úo possui agendamentos futuros.".replace("{client_name}", clientName);
  }

  const bookingList = bookings.map((b: any, i: number) =>
    `${i + 1}. ${b.service_name || 'Servi├ºo'} em ${b.scheduled_at}`
  ).join("\n");

  await endConversation(conversation.id);
  return `Ol├í {client_name}, seus pr├│ximos agendamentos s├úo:\n${bookingList}\n\nSe precisar cancelar ou alterar, envie "3" para cancelar ou "1" para agendar novamente.`.replace("{client_name}", clientName);
};

const handleCancelBookingSelectStep = async (conversation: WhatsappConversation, messageBody: string): Promise<string> => {
  const barbershopId = conversation.barbershop_id;
  const clientWhatsapp = conversation.client_whatsapp;
  const clientName = conversation.conversation_state?.client_name || "Cliente";

  let client = await getClientByWhatsApp(clientWhatsapp);
  if (!client) {
    await endConversation(conversation.id);
    return "Ol├í {client_name}, n├úo encontramos nenhum agendamento para este n├║mero. Voc├¬ j├í se cadastrou?".replace("{client_name}", clientName);
  }

  const bookings = await getClientAppointments(client.id);
  if (bookings.length === 0) {
    await endConversation(conversation.id);
    return "Ol├í {client_name}, voc├¬ n├úo possui agendamentos futuros para cancelar.".replace("{client_name}", clientName);
  }

  const bookingList = bookings.map((b: any, i: number) =>
    `${i + 1}. ${b.service_name || 'Servi├ºo'} em ${b.scheduled_at}`
  ).join("\n");

  await updateConversation(conversation.id, {
    current_step: "cancel_booking_confirm",
    conversation_state: { ...conversation.conversation_state, client, bookings },
  });
  return `Ol├í {client_name}, qual agendamento voc├¬ gostaria de cancelar?\n${bookingList}\n\nResponda com o n├║mero do agendamento.`.replace("{client_name}", clientName);
};

const handleCancelBookingConfirmStep = async (conversation: WhatsappConversation, messageBody: string): Promise<string> => {
  const barbershopId = conversation.barbershop_id;
  const clientName = conversation.conversation_state?.client_name || "Cliente";
  const bookings = conversation.conversation_state?.bookings || [];
  const bookingIndex = parseInt(messageBody.trim()) - 1;

  if (bookingIndex >= 0 && bookingIndex < bookings.length) {
    const bookingToCancel = bookings[bookingIndex];
    const success = await cancelAppointment(bookingToCancel.id);

    if (success) {
      await endConversation(conversation.id);
      return "Agendamento cancelado com sucesso, {client_name}!".replace("{client_name}", clientName);
    } else {
      await endConversation(conversation.id);
      return "Desculpe, {client_name}, n├úo foi poss├¡vel cancelar o agendamento. Por favor, tente novamente.".replace("{client_name}", clientName);
    }
  } else {
    const invalidInputTemplate = await getMessageTemplate(barbershopId, "invalid_input");
    return formatMessage(invalidInputTemplate?.template_content || "N├║mero inv├ílido. Por favor, escolha um n├║mero da lista.", { client_name: clientName });
  }
};

// Servi├ºo de Integra├º├úo com WhatsApp
// Integra├º├úo com IA e automa├º├úo

import { supabase } from "@/integrations/supabase/client";

export interface WhatsAppMessage {
  id: string;
  from: string;
  to: string;
  message: string;
  type: 'text' | 'audio' | 'image' | 'document';
  status: 'sent' | 'delivered' | 'read' | 'failed';
  timestamp: string;
  ai_response?: string;
}

export interface WhatsAppConfig {
  api_url: string;
  api_key: string;
  phone_id: string;
  business_id: string;
}

interface SendResult {
  success: boolean;
  message_id?: string;
  error?: string;
  ai_response?: string;
}

/**
 * Enviar mensagem via WhatsApp
 */
export async function sendWhatsAppMessage(
  to: string,
  message: string,
  type: 'text' | 'audio' = 'text'
): Promise<SendResult> {
  try {
    const cleanNumber = to.replace(/\D/g, '');
    
    if (cleanNumber.length < 10) {
      return { success: false, error: 'N├║mero inv├ílido' };
    }

    const { data: config, error: configError } = await (supabase as any)
      .from('integration_settings')
      .select('*')
      .eq('service_name', 'whatsapp')
      .eq('environment', 'sandbox')
      .single();

    if (configError || !config) {
      console.warn('WhatsApp n├úo configurado, usando modo simulado');
      return { 
        success: true, 
        message_id: `sim-${Date.now()}`,
        error: 'Modo simulado - WhatsApp n├úo configurado' 
      };
    }

    const response = await fetch(`${config.api_url}/messages`, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${config.api_key}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        phone: cleanNumber,
        message: message,
        type: type,
      }),
    });

    if (!response.ok) {
      const errorData = await response.json();
      return { success: false, error: errorData.message || 'Erro ao enviar mensagem' };
    }

    const data = await response.json();
    
    await (supabase as any).from('whatsapp_messages').insert({
      from: config.phone_id,
      to: cleanNumber,
      message: message,
      type: 'text',
      status: 'sent',
      ai_response: data.response,
    });

    return { success: true, message_id: data.message_id, ai_response: data.ai_response };
  } catch (error: any) {
    console.error('Erro ao enviar mensagem:', error);
    return { success: false, error: error.message || 'Erro desconhecido' };
  }
}

/**
 * Enviar mensagem com IA
 */
export async function sendWhatsAppWithAI(
  to: string,
  message: string,
  clientId: string
): Promise<{ success: boolean; ai_response?: string }> {
  try {
    const { data: config } = await (supabase as any)
      .from('integration_settings')
      .select('*')
      .eq('service_name', 'whatsapp')
      .single();

    if (!config) {
      return { 
        success: true, 
        ai_response: 'Modo simulado - WhatsApp n├úo configurado' 
      };
    }

    const result = await sendWhatsAppMessage(to, message, 'text');

    if (result.success) {
      await (supabase as any).from('ai_memory').insert({
        client_id: clientId,
        message: message,
        response: result.ai_response || message,
        intent: 'whatsapp_response',
      });
    }

    return { 
      success: result.success, 
      ai_response: result.ai_response 
    };
  } catch (error) {
    console.error('Erro ao enviar com IA:', error);
    return { success: false };
  }
}

/**
 * Receber mensagem do WhatsApp (webhook)
 */
export async function receiveWhatsAppMessage(
  from: string,
  message: string,
  _type: 'text' | 'audio' = 'text'
): Promise<{ response: string; ai_response?: string }> {
  try {
    let clientId = from;
    
    const { data: profile } = await (supabase as any)
      .from('profiles')
      .select('id, user_id, name')
      .eq('whatsapp', from)
      .single();

    if (profile) {
      clientId = profile.user_id;
    }

    const responseMsg = 'Ol├í! Como posso ajudar?';

    return {
      response: responseMsg,
      ai_response: responseMsg,
    };
  } catch (error) {
    console.error('Erro ao receber mensagem:', error);
    return {
      response: 'Desculpe, ocorreu um erro ao processar sua mensagem.',
    };
  }
}

/**
 * Enviar mensagem de ├íudio (TTS)
 */
export async function sendAudioMessage(
  to: string,
  text: string,
  _voice: 'pt-BR' | 'pt-PT' = 'pt-BR'
): Promise<{ success: boolean; message_id?: string }> {
  try {
    const { data: config } = await (supabase as any)
      .from('integration_settings')
      .select('*')
      .eq('service_name', 'whatsapp')
      .single();

    if (!config) {
      return { 
        success: true, 
        message_id: `sim-audio-${Date.now()}` 
      };
    }

    const response = await fetch(`${config.api_url}/messages`, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${config.api_key}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        phone: to.replace(/\D/g, ''),
        message: text,
        type: 'audio',
        voice: _voice,
      }),
    });

    if (!response.ok) {
      return { success: false };
    }

    const data = await response.json();
    return { success: true, message_id: data.message_id };
  } catch (error) {
    console.error('Erro ao enviar ├íudio:', error);
    return { success: false };
  }
}

/**
 * Verificar status da mensagem
 */
export async function checkMessageStatus(messageId: string): Promise<{
  status: 'sent' | 'delivered' | 'read' | 'failed';
  timestamp?: string;
}> {
  try {
    const { data, error } = await (supabase as any)
      .from('whatsapp_messages')
      .select('status, timestamp')
      .eq('message_id', messageId)
      .single();

    if (error || !data) {
      return { status: 'failed' };
    }

    return {
      status: data.status,
      timestamp: data.timestamp,
    };
  } catch (error) {
    console.error('Erro ao verificar status:', error);
    return { status: 'failed' };
  }
}

/**
 * Buscar hist├│rico de mensagens
 */
export async function getWhatsAppHistory(
  clientId: string,
  limit: number = 50
): Promise<WhatsAppMessage[]> {
  try {
    const { data, error } = await (supabase as any)
      .from('whatsapp_messages')
      .select('*')
      .eq('client_id', clientId)
      .order('timestamp', { ascending: false })
      .limit(limit);

    if (error) {
      console.error('Erro ao buscar hist├│rico:', error);
      return [];
    }

    return data || [];
  } catch (error) {
    console.error('Erro ao buscar hist├│rico:', error);
    return [];
  }
}

/**
 * Configurar webhook do WhatsApp
 */
export async function setupWebhook(
  webhookUrl: string,
  verifyToken: string
): Promise<{ success: boolean; message?: string }> {
  try {
    const { data: config, error } = await (supabase as any)
      .from('integration_settings')
      .select('*')
      .eq('service_name', 'whatsapp')
      .single();

    if (error || !config) {
      return { success: false, message: 'WhatsApp n├úo configurado' };
    }

    const response = await fetch(`${config.api_url}/webhook`, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${config.api_key}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        callback_url: webhookUrl,
        verify_token: verifyToken,
        events: ['messages', 'statuses'],
      }),
    });

    if (!response.ok) {
      return { success: false, message: 'Erro ao configurar webhook' };
    }

    return { success: true };
  } catch (error) {
    console.error('Erro ao configurar webhook:', error);
    return { success: false, message: 'Erro ao configurar webhook' };
  }
}

/**
 * Enviar mensagem de reativa├º├úo
 */
export async function sendReactivationMessage(
  clientId: string,
  message: string
): Promise<{ success: boolean; message?: string }> {
  try {
    const { data: profile } = await (supabase as any)
      .from('profiles')
      .select('whatsapp')
      .eq('user_id', clientId)
      .single();

    if (!profile?.whatsapp) {
      return { success: false, message: 'Telefone n├úo encontrado' };
    }

    const result = await sendWhatsAppMessage(profile.whatsapp, message);
    return { success: result.success, message: result.error };
  } catch (error) {
    console.error('Erro ao enviar mensagem de reativa├º├úo:', error);
    return { success: false };
  }
}

/**
 * Enviar mensagem de lembrete de agendamento
 */
export async function sendAppointmentReminder(
  appointmentId: string,
  clientId: string
): Promise<{ success: boolean; message?: string }> {
  try {
    const { data: appointment } = await (supabase as any)
      .from('appointments')
      .select('*, services(name), professionals(name)')
      .eq('id', appointmentId)
      .single();

    if (!appointment) {
      return { success: false, message: 'Agendamento n├úo encontrado' };
    }

    const { data: profile } = await (supabase as any)
      .from('profiles')
      .select('whatsapp')
      .eq('user_id', clientId)
      .single();

    if (!profile?.whatsapp) {
      return { success: false, message: 'Telefone n├úo encontrado' };
    }

    const dataHora = new Date(appointment.scheduled_at);
    const dataFormatada = dataHora.toLocaleDateString('pt-BR');
    const horaFormatada = dataHora.toLocaleTimeString('pt-BR', { 
      hour: '2-digit', 
      minute: '2-digit' 
    });

    const reminderMessage = `Ol├í! Lembrete do seu agendamento ­ƒôà\n\n­ƒôà Data: ${dataFormatada}\nÔÅ░ Hora: ${horaFormatada}\n­ƒÆê Servi├ºo: ${appointment.services?.name}\nÔ£é´©Å Profissional: ${appointment.professionals?.name}\n\nAt├® logo!`;

    const result = await sendWhatsAppMessage(profile.whatsapp, reminderMessage);
    return { success: result.success, message: result.error };
  } catch (error) {
    console.error('Erro ao enviar lembrete:', error);
    return { success: false };
  }
}

